// ---------- Hard fail safe handlers ----------
register_shutdown_function(function () {
  $e = error_get_last();
  if ($e) { @error_log('FATAL: ' . json_encode($e, JSON_UNESCAPED_SLASHES)); }
});

set_exception_handler(function (Throwable $e) {
  @error_log('[API] Uncaught: ' . $e->getMessage() . ' in ' . $e->getFile() . ':' . $e->getLine());
  // ExitException is the MVC router's structured response mechanism.
  // When it escapes (e.g. from within the Router's emitResponse path or from
  // within this very handler), emit its payload directly rather than calling
  // api_json(), which would re-throw ExitException when API_THROW_RESPONSES
  // is true (test mode), causing a fatal "Uncaught ExitException" loop.
  if ($e instanceof \MOM\Api\Controllers\ExitException) {
    if (!headers_sent()) {
      http_response_code($e->getStatusCode());
      foreach ($e->getHeaders() as $name => $value) {
        header($name . ': ' . $value);
      }
    }
    $body = $e->getBody();
    if ($body !== '') {
      echo $body;
    }
    exit;
  }
  // For all other uncaught exceptions, send a plain server_error JSON response.
  // Use echo+exit directly here to avoid the ExitException re-throw loop that
  // would occur if api_json() is called while API_THROW_RESPONSES is true.
  if (!headers_sent()) {
    http_response_code(500);
    header('Content-Type: application/json; charset=utf-8');
    header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
    header('X-Content-Type-Options: nosniff');
  }
  echo json_encode(['ok' => false, 'error' => 'server_error', 'server_time' => gmdate('c')], JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
  exit;
});

set_error_handler(function (int $severity, string $message, string $file, int $line) {
  if (!(error_reporting() & $severity)) {
    return false;
  }
  throw new ErrorException($message, 0, $severity, $file, $line);
});

// ---------- Helpers ----------
function api_json(array $payload, int $code = 200): void {
  // Ensure session data is written before responding (important for OTP flow)
  if (session_status() === PHP_SESSION_ACTIVE) {
    @session_write_close();
  }

  if (defined('API_THROW_RESPONSES') && API_THROW_RESPONSES) {
    throw \MOM\Api\Controllers\ExitException::json($payload, $code, [
      'Cache-Control' => 'no-store, no-cache, must-revalidate, max-age=0',
      'X-Content-Type-Options' => 'nosniff',
      'X-Frame-Options' => 'SAMEORIGIN',
      'Referrer-Policy' => 'same-origin',
    ]);
  }

  http_response_code($code);
  header('Content-Type: application/json; charset=utf-8');
  header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
  header('X-Content-Type-Options: nosniff');
  header('X-Frame-Options: SAMEORIGIN');
  header('Referrer-Policy: same-origin');
  $encoded = json_encode($payload, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
  echo $encoded === false ? '{"ok":false,"error":"response_encode_failed"}' : $encoded;
  exit;
}

function api_stream_event(string $event, array $payload): void {
  echo 'event: ' . $event . "\n";
  $encoded = json_encode($payload, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
  echo 'data: ' . ($encoded === false ? '{"ok":false,"error":"sse_encode_failed"}' : $encoded) . "\n\n";
  @ob_flush();
  @flush();
}

function ensure_dir(string $dir): void {
  if (file_exists($dir) && !is_dir($dir)) {
    return;
  }
  if (!is_dir($dir)) {
    @mkdir($dir, 0775, true);
  }
  // Try to ensure directory is writable (shared hosting / CGI setups)
  if (is_dir($dir) && !is_writable($dir)) {
    $ownerId = @fileowner($dir);
    $effectiveUserId = function_exists('posix_geteuid') ? @posix_geteuid() : false;
    if ($ownerId !== false && $effectiveUserId !== false && (int)$ownerId !== (int)$effectiveUserId) {
      return;
    }
    try { @chmod($dir, 0775); } catch (\Throwable $e) {}
  }
}

function migrate_legacy_data_dir(string $legacyDir, string $targetDir, bool $onlyWhenTargetUninitialized = false): void {
  $legacyNorm = rtrim(str_replace('\\', '/', $legacyDir), '/');
  $targetNorm = rtrim(str_replace('\\', '/', $targetDir), '/');
  if ($legacyNorm === $targetNorm) return;
  if (!is_dir($legacyDir)) return;
  if ($onlyWhenTargetUninitialized && runtime_dir_has_bootstrap_files($targetDir)) return;

  ensure_dir($targetDir);
  $it = new RecursiveIteratorIterator(
    new RecursiveDirectoryIterator($legacyDir, FilesystemIterator::SKIP_DOTS),
    RecursiveIteratorIterator::SELF_FIRST
  );

  foreach ($it as $item) {
    $itemPath = str_replace('\\', '/', $item->getPathname());
    $rel = ltrim(substr($itemPath, strlen($legacyNorm)), '/');
    if ($rel === '') continue;
    $dst = $targetNorm . '/' . $rel;

    if ($item->isDir()) {
      if (!is_dir($dst)) @mkdir($dst, 0775, true);
      continue;
    }

    if (is_file($dst)) continue;
    $dstDir = dirname($dst);
    if (!is_dir($dstDir)) @mkdir($dstDir, 0775, true);
    @copy($item->getPathname(), $dst);
  }
}

