function user_has_any_role(array $user, array $roles): bool {
  $normalized = array_map(static fn($role) => strtolower(trim((string)$role)), $roles);
  $userRoles = is_array($user['roles'] ?? null) ? $user['roles'] : [(string)($user['role'] ?? '')];
  foreach ($userRoles as $userRole) {
    if (in_array(strtolower(trim((string)$userRole)), $normalized, true)) return true;
  }
  return false;
}

function safe_rel_path(string $p): string {
  // normalize to a safe relative path (no leading slash, no ..)
  $p = str_replace('\\', '/', $p);
  $p = preg_replace('#/+#', '/', $p);
  $p = ltrim((string)$p, '/');
  if ($p === '' || str_contains($p, '..')) {
    throw new RuntimeException('Invalid path');
  }
  return $p;
}

function join_in_root(string $root, string $rel): string {
  $rel = safe_rel_path($rel);
  $full = rtrim($root, '/\\') . '/' . $rel;
  // Resolve parent directory at least (file may not exist yet)
  $parent = realpath(dirname($full));
  if ($parent === false) {
    // try to create parent later; still enforce that dirname is within root
    $rootReal = realpath($root) ?: $root;
    $rootReal = rtrim(str_replace('\\','/',$rootReal), '/');
    $parentGuess = rtrim(str_replace('\\','/',dirname($full)), '/');
    if (!str_starts_with($parentGuess, $rootReal)) {
      throw new RuntimeException('Path escapes root');
    }
    return $full;
  }
  $rootReal = realpath($root) ?: $root;
  $rootReal = rtrim(str_replace('\\','/',$rootReal), '/');
  $parent = rtrim(str_replace('\\','/',$parent), '/');
  if (!str_starts_with($parent, $rootReal)) {
    throw new RuntimeException('Path escapes root');
  }
  return $full;
}

function is_inside_root(string $absPath, string $rootDir): bool {
  $rootReal = realpath($rootDir) ?: $rootDir;
  $rootNorm = rtrim(str_replace('\\', '/', $rootReal), '/');
  $pathReal = realpath($absPath);
  $pathNorm = rtrim(str_replace('\\', '/', ($pathReal ?: $absPath)), '/');
  return $pathNorm === $rootNorm || str_starts_with($pathNorm . '/', $rootNorm . '/');
}

function is_reserved_root_segment(string $relPath): bool {
  $relPath = safe_rel_path($relPath);

  // Allow the portal's controlled document corpus — every QMS doc lives under
  // mom/docs/{system,operations,forms,training,...}. The "mom" top-level
  // directory itself is reserved, so we only white-list its docs subtree.
  if (str_starts_with($relPath, 'mom/docs/') && !str_starts_with($relPath, 'mom/docs/glossary/')) {
    return false;
  }

  // First-segment guards keep the legacy contract (reject non-doc edits that
  // would otherwise clobber application source, generated reports, etc.).
  $first = explode('/', $relPath, 2)[0] ?? '';
  $reservedFirstSegments = ['assets', 'archive', '_Deleted', '.git'];
  if (in_array($first, $reservedFirstSegments, true)) {
    return true;
  }

  // Deny any sensitive subtree of the application root itself so the dialog
  // can never point at PHP, JS, SQL, CSS or runtime-data files.
  $reservedMomSubtrees = [
    'mom/api', 'mom/scripts', 'mom/styles', 'mom/database',
    'mom/assets', 'mom/data', 'mom/ops', 'mom/tools',
    'mom/vendor', 'mom/release', 'mom/contracts',
    'mom/docs/glossary',
  ];
  foreach ($reservedMomSubtrees as $sub) {
    if ($relPath === $sub || str_starts_with($relPath, $sub . '/')) {
      return true;
    }
  }

  // Bare "mom" or paths that resolve to an application file at the mom root
  // (e.g. "mom/portal.html", "mom/sw.js") remain off-limits.
  if ($relPath === 'mom' || ($first === 'mom' && !str_starts_with($relPath, 'mom/docs/'))) {
    return true;
  }
  return false;
}

function first_existing_rel_dir(array $candidates, string $rootDir): string {
  foreach ($candidates as $candidate) {
    $rel = safe_rel_path((string)$candidate);
    if (is_dir(rtrim($rootDir, '/\\') . '/' . $rel)) return $rel;
  }
  if (!empty($candidates)) return safe_rel_path((string)$candidates[0]);
  throw new RuntimeException('No candidate directories configured');
}

function default_folder_for_cat(string $cat, string $rootDir): string {
  $candidates = match ($cat) {
    'MAN' => ['mom/docs/system/quality-manual', '02-Tai-Lieu-He-Thong/01-Quality-Manual'],
    'POL' => ['mom/docs/system/policies', '02-Tai-Lieu-He-Thong/02-Policies-Objectives'],
    'ORG', 'JD', 'DEP' => ['mom/docs/system/organization', '02-Tai-Lieu-He-Thong/03-Organization'],
    'SOP', 'PROC' => ['mom/docs/operations/sops', '03-Tai-Lieu-Van-Hanh/01-SOPs'],
    'WI' => ['mom/docs/operations/work-instructions', '03-Tai-Lieu-Van-Hanh/02-Work-Instructions'],
    'ANNEX' => ['mom/docs/operations/references', '03-Tai-Lieu-Van-Hanh/03-Reference'],
    'FRM' => ['mom/docs/forms', '04-Bieu-Mau'],
    'TRN' => ['mom/docs/training', '10-Training-Academy'],
    default => ['mom/docs/operations/sops', '03-Tai-Lieu-Van-Hanh/01-SOPs'],
  };
  return first_existing_rel_dir($candidates, $rootDir);
}

function scan_derive_cat(string $topName): string {
  $map = [
    'Quality-Manual' => 'MAN',
    'Policies-Objectives' => 'POL',
    'SOPs' => 'SOP',
    'Processes' => 'PROC',
    'Work-Instructions' => 'WI',
    'Forms-Records' => 'FRM',
    'Bieu-Mau' => 'FRM',
    'Organization' => 'ORG',
    'Annexes-References' => 'ANNEX',
    'Training-Academy' => 'TRN',
    'Tai-Lieu-He-Thong' => 'SYS',
    'Tai-Lieu-Van-Hanh' => 'OPS',
    'Reference' => 'REF',
  ];
  foreach ($map as $k => $v) {
    if (stripos($topName, $k) !== false) return $v;
  }
  return strtoupper(substr(preg_replace('/[^A-Za-z]/', '', $topName), 0, 6));
}

function scan_cat_from_filename(string $fn): ?string {
  $fn = strtolower($fn);
  if (str_starts_with($fn, 'sop-')) return 'SOP';
  if (str_starts_with($fn, 'wi-')) return 'WI';
  if (str_starts_with($fn, 'frm-')) return 'FRM';
  if (str_starts_with($fn, 'ref-')) return 'ANNEX';
  if (str_starts_with($fn, 'qms-man')) return 'MAN';
  if (str_starts_with($fn, 'pol-')) return 'POL';
  if (str_starts_with($fn, 'jd-') || str_starts_with($fn, 'dept-') || str_starts_with($fn, 'raci-') || str_starts_with($fn, 'authority-')) return 'ORG';
  if (str_starts_with($fn, 'proc-')) return 'SOP';
  if (str_starts_with($fn, 'annex-')) return 'ANNEX';
  return null;
}

