function merge_role_permission_row(array $base, array $override): array {
  $merged = $base;

  if (array_key_exists('canEditDocs', $override)) {
    $merged['canEditDocs'] = (bool)$override['canEditDocs'];
  }

  if (array_key_exists('canCreateDocs', $override)) {
    $merged['canCreateDocs'] = (bool)$override['canCreateDocs'];
  }

  if (!empty($base['allowAllPermissions']) || !empty($override['allowAllPermissions'])) {
    $merged['allowAllPermissions'] = true;
  } else {
    unset($merged['allowAllPermissions']);
  }

  $mergedPermissions = array_values(array_unique(array_merge(
    normalize_permission_value_list($base['permissions'] ?? null),
    normalize_permission_value_list($override['permissions'] ?? null),
    normalize_permission_value_list($override['permission_keys'] ?? null),
    normalize_permission_value_list($override['grants'] ?? null)
  )));
  if ($mergedPermissions !== []) {
    $merged['permissions'] = $mergedPermissions;
  } else {
    unset($merged['permissions']);
  }

  $mergedDenies = array_values(array_unique(array_merge(
    normalize_permission_value_list($base['denies'] ?? null),
    normalize_permission_value_list($override['denies'] ?? null)
  )));
  if ($mergedDenies !== []) {
    $merged['denies'] = $mergedDenies;
  } else {
    unset($merged['denies']);
  }

  foreach ($override as $key => $value) {
    $permissionKey = trim((string)$key);
    if ($permissionKey === '' || in_array($permissionKey, ['canCreateDocs', 'allowAllPermissions', 'permissions', 'permission_keys', 'grants', 'denies'], true)) {
      continue;
    }
    if (!is_bool($value)) {
      continue;
    }
    $merged[$permissionKey] = $value;
  }

  return sanitize_role_permission_row($merged);
}

function portal_system_db_connection() {
  static $initialized = false;
  static $connection = null;

  if ($initialized) {
    return $connection;
  }
  $initialized = true;

  $configFile = __DIR__ . '/database/config.php';
  $connectionFile = __DIR__ . '/database/Connection.php';
  if (!is_file($configFile) || !is_file($connectionFile)) {
    return null;
  }

  $config = function_exists('runtime_data_layer_effective_config')
    ? runtime_data_layer_effective_config()
    : (array)(require $configFile);
  $host = trim((string)($config['host'] ?? ''));
  $database = trim((string)($config['database'] ?? ''));
  $username = trim((string)($config['username'] ?? ''));
  $password = trim((string)($config['password'] ?? ''));
  $allowEmptyPassword = !empty($config['allow_empty_password']);
  if ($host === '' || $database === '' || $username === '' || (!$allowEmptyPassword && $password === '')) {
    return null;
  }

  require_once $connectionFile;
  if (!class_exists('\MOM\Database\Connection')) {
    return null;
  }

  try {
    $connection = \MOM\Database\Connection::getInstance($config);
  } catch (Throwable $e) {
    @error_log('[API] system DB connection unavailable: ' . $e->getMessage());
    $connection = null;
  }

  return $connection;
}

function portal_system_config_shadow_read(string $key): ?array {
  $connection = portal_system_db_connection();
  if (!$connection) {
    return null;
  }

  try {
    $row = $connection->queryOne(
      "SELECT enum_values
         FROM variable_registry
        WHERE category = 'config' AND key = :key
        LIMIT 1",
      [':key' => $key]
    );
    if (!is_array($row) || !array_key_exists('enum_values', $row)) {
      return null;
    }
    $value = $row['enum_values'];
    if (is_array($value)) {
      return $value;
    }
    if (is_string($value)) {
      $decoded = json_decode($value, true);
      return is_array($decoded) ? $decoded : null;
    }
  } catch (Throwable $e) {
    @error_log('[API] config shadow read failed for ' . $key . ': ' . $e->getMessage());
  }

  return null;
}

function portal_system_config_shadow_write(string $key, array $value): void {
  $connection = portal_system_db_connection();
  if (!$connection) {
    return;
  }

  try {
    $connection->execute(
      "INSERT INTO variable_registry (category, key, label, data_type, enum_values)
       VALUES ('config', :key, :label, 'json', :value::jsonb)
       ON CONFLICT (category, key) DO UPDATE SET
         label = EXCLUDED.label,
         data_type = EXCLUDED.data_type,
         enum_values = EXCLUDED.enum_values",
      [
        ':key' => $key,
        ':label' => $key,
        ':value' => json_encode($value, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES),
      ]
    );
  } catch (Throwable $e) {
    @error_log('[API] config shadow write failed for ' . $key . ': ' . $e->getMessage());
  }
}

function portal_system_normalize_uuid(?string $value): ?string {
  $candidate = trim((string)$value);
  if ($candidate === '') {
    return null;
  }
  return preg_match('/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i', $candidate)
    ? strtolower($candidate)
    : null;
}

function portal_system_normalize_ip(?string $value): ?string {
  $candidate = trim((string)$value);
  if ($candidate === '') {
    return null;
  }
  return filter_var($candidate, FILTER_VALIDATE_IP) ? $candidate : null;
}

function portal_system_audit_shadow_write(array $entry): void {
  $connection = portal_system_db_connection();
  if (!$connection) {
    return;
  }

  $eventType = trim((string)($entry['event_type'] ?? ''));
  if ($eventType === '') {
    return;
  }

  $aggregateType = trim((string)($entry['aggregate_type'] ?? 'api_action'));
  $aggregateId = trim((string)($entry['aggregate_id'] ?? ''));
  $actorName = trim((string)($entry['actor_name'] ?? ''));
  $actorId = trim((string)($entry['actor_id'] ?? ''));
  $payload = is_array($entry['payload'] ?? null) ? (array)$entry['payload'] : [];
  $metadata = is_array($entry['metadata'] ?? null) ? (array)$entry['metadata'] : [];
  $recordedAt = trim((string)($entry['recorded_at'] ?? ''));
  $recordedAt = $recordedAt !== '' ? $recordedAt : gmdate('c');
  $ipAddress = portal_system_normalize_ip((string)($entry['ip_address'] ?? ''));
  $sessionId = portal_system_normalize_uuid((string)($entry['session_id'] ?? ''));
  $eventHash = sha1(json_encode([
    'event_type' => $eventType,
    'aggregate_type' => $aggregateType,
    'aggregate_id' => $aggregateId,
    'actor_id' => $actorId,
    'actor_name' => $actorName,
    'recorded_at' => $recordedAt,
    'payload' => $payload,
    'metadata' => $metadata,
    'ip_address' => $ipAddress,
  ], JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES));

  try {
    $connection->execute(
      'INSERT INTO audit_events (
          event_type,
          aggregate_type,
          aggregate_id,
          actor_id,
          actor_name,
          payload,
          metadata,
          ip_address,
          session_id,
          recorded_at,
          source_event_hash
       ) VALUES (
          :event_type,
          :aggregate_type,
          :aggregate_id,
          :actor_id,
          :actor_name,
          :payload::jsonb,
          :metadata::jsonb,
          :ip_address::inet,
          :session_id::uuid,
          :recorded_at::timestamptz,
          :event_hash
       )
       ON CONFLICT (source_event_hash) DO NOTHING',
      [
        ':event_type' => $eventType,
        ':aggregate_type' => $aggregateType,
        ':aggregate_id' => $aggregateId !== '' ? $aggregateId : null,
        ':actor_id' => $actorId !== '' ? $actorId : null,
        ':actor_name' => $actorName !== '' ? $actorName : null,
        ':payload' => json_encode($payload, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES),
        ':metadata' => json_encode($metadata, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES),
        ':ip_address' => $ipAddress,
        ':session_id' => $sessionId,
        ':recorded_at' => $recordedAt,
        ':event_hash' => $eventHash,
      ]
    );
  } catch (Throwable $e) {
    @error_log('[API] audit shadow write failed: ' . $e->getMessage());
  }
}

function portal_legacy_admin_audit_log(string $action, array $context = [], ?array $user = null): void {
  global $DATA_DIR;

  $username = trim((string)(($user['username'] ?? null) ?: ($_SESSION['user'] ?? 'anonymous')));
  $ip = (string)($_SERVER['REMOTE_ADDR'] ?? '');
  $timestamp = now_iso();
  $entry = [
    'action' => $action,
    'user' => $username,
    'ip' => $ip,
    'timestamp' => $timestamp,
    'context' => $context,
  ];
  if (is_string($DATA_DIR) && $DATA_DIR !== '') {
    $line = json_encode($entry, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
    if ($line !== false) {
      @file_put_contents(rtrim($DATA_DIR, '/\\') . '/audit.log', $line . "\n", FILE_APPEND | LOCK_EX);
    }
  }

  $aggregateId = '';
  foreach (['aggregate_id', 'id', 'username', 'code', 'record_id'] as $key) {
    if (!isset($context[$key]) || !is_scalar($context[$key])) continue;
    $candidate = trim((string)$context[$key]);
    if ($candidate === '') continue;
    $aggregateId = $candidate;
    break;
  }
  if ($aggregateId === '') {
    $aggregateId = $action;
  }

  portal_system_audit_shadow_write([
    'event_type' => $action,
    'aggregate_type' => 'api_action',
    'aggregate_id' => $aggregateId,
    'actor_name' => $username,
    'ip_address' => $ip,
    'session_id' => session_status() === PHP_SESSION_ACTIVE ? session_id() : null,
    'recorded_at' => $timestamp,
    'payload' => ['context' => $context],
    'metadata' => [
      'source' => 'legacy_api',
      'transport' => 'api.php',
      'context_keys' => array_values(array_map('strval', array_keys($context))),
    ],
  ]);
}

function portal_audit_session_event(string $eventType, string $username, array $meta = []): void {
  if ($username === '') return;
  try {
    runtime_data_layer()->logEvent($eventType, 'user_session', $username, [], [
      'actor_name' => $username,
      'ip_address'  => (string)($_SERVER['REMOTE_ADDR'] ?? ''),
      'session_id'  => session_status() === PHP_SESSION_ACTIVE ? session_id() : null,
      'metadata'    => array_merge(['source' => 'auth'], $meta),
    ]);
  } catch (Throwable $e) {
    @error_log('[api] session_audit failed: ' . $e->getMessage());
  }
}

function portal_system_audit_shadow_read(array $filters = []): ?array {
  $connection = portal_system_db_connection();
  if (!$connection) {
    return null;
  }

  $limit = max(1, min(1000, (int)($filters['limit'] ?? 200)));
  $where = [];
  $params = [':limit' => $limit];

  $scalarFilters = [
    'event_type' => 'event_type',
    'aggregate_type' => 'aggregate_type',
    'aggregate_id' => 'aggregate_id',
    'actor_name' => 'actor_name',
  ];
  foreach ($scalarFilters as $key => $column) {
    $value = trim((string)($filters[$key] ?? ''));
    if ($value === '') {
      continue;
    }
    $param = ':' . $key;
    $where[] = $column . ' = ' . $param;
    $params[$param] = $value;
  }

  $from = trim((string)($filters['from'] ?? ''));
  if ($from !== '') {
    $where[] = 'recorded_at >= :from::timestamptz';
    $params[':from'] = $from;
  }
  $to = trim((string)($filters['to'] ?? ''));
  if ($to !== '') {
    $where[] = 'recorded_at <= :to::timestamptz';
    $params[':to'] = $to;
  }

  $search = trim((string)($filters['search'] ?? ''));
  if ($search !== '') {
    $where[] = "(coalesce(actor_name,'') ILIKE :search OR coalesce(event_type,'') ILIKE :search OR coalesce(aggregate_type,'') ILIKE :search OR coalesce(aggregate_id,'') ILIKE :search OR CAST(payload AS text) ILIKE :search)";
    $params[':search'] = '%' . $search . '%';
  }

  if (!empty($filters['exclude_aggregate_types'])) {
    $excludeTypes = array_values(array_filter(array_map('strval', (array)$filters['exclude_aggregate_types'])));
    if ($excludeTypes !== []) {
      $excPlaceholders = [];
      foreach ($excludeTypes as $i => $et) {
        $ph = ':exc_agg_' . $i;
        $excPlaceholders[] = $ph;
        $params[$ph] = $et;
      }
      $where[] = "coalesce(aggregate_type,'') NOT IN (" . implode(',', $excPlaceholders) . ')';
    }
  }

  $sql = 'SELECT event_type, aggregate_type, aggregate_id, actor_id, actor_name, payload, metadata, ip_address::text AS ip_address, session_id::text AS session_id, recorded_at
            FROM audit_events';
  if ($where !== []) {
    $sql .= ' WHERE ' . implode(' AND ', $where);
  }
  $sql .= ' ORDER BY recorded_at DESC LIMIT :limit';

  try {
    $rows = $connection->query($sql, $params);
    return array_values(array_map(static function ($row): array {
      return [
        'event_type' => (string)($row['event_type'] ?? ''),
        'aggregate_type' => (string)($row['aggregate_type'] ?? ''),
        'aggregate_id' => (string)($row['aggregate_id'] ?? ''),
        'actor_id' => (string)($row['actor_id'] ?? ''),
        'actor_name' => (string)($row['actor_name'] ?? ''),
        'payload' => is_array($row['payload'] ?? null) ? (array)$row['payload'] : (json_decode((string)($row['payload'] ?? '{}'), true) ?: []),
        'metadata' => is_array($row['metadata'] ?? null) ? (array)$row['metadata'] : (json_decode((string)($row['metadata'] ?? '{}'), true) ?: []),
        'ip_address' => (string)($row['ip_address'] ?? ''),
        'session_id' => (string)($row['session_id'] ?? ''),
        'recorded_at' => (string)($row['recorded_at'] ?? ''),
      ];
    }, is_array($rows) ? $rows : []));
  } catch (Throwable $e) {
    @error_log('[API] audit shadow read failed: ' . $e->getMessage());
    return null;
  }
}

function portal_auth_shadow_sync_service(string $rootDir) {
  static $loaded = false;
  static $serviceClassReady = false;

  if (!$loaded) {
    $loaded = true;
    $connectionFile = __DIR__ . '/database/Connection.php';
    $serviceFile = __DIR__ . '/api/services/AuthUserShadowSyncService.php';
    if (is_file($connectionFile)) require_once $connectionFile;
    if (is_file($serviceFile)) require_once $serviceFile;
    $serviceClassReady = class_exists('\MOM\Api\Services\AuthUserShadowSyncService');
  }

  if (!$serviceClassReady) {
    return null;
  }

  try {
    return new \MOM\Api\Services\AuthUserShadowSyncService($rootDir);
  } catch (Throwable $e) {
    @error_log('[API] auth shadow sync service unavailable: ' . $e->getMessage());
    return null;
  }
}

function portal_auth_employee_id_for_user(array $user): string {
  $existing = strtoupper(trim((string)($user['employee_id'] ?? '')));
  if ($existing !== '') {
    $sanitized = preg_replace('/[^A-Z0-9_-]/', '', $existing);
    return substr((string)$sanitized, 0, 20);
  }

  $service = portal_auth_shadow_sync_service(__DIR__);
  if ($service && method_exists($service, 'canonicalEmployeeIdForUser')) {
    try {
      return \MOM\Api\Services\AuthUserShadowSyncService::canonicalEmployeeIdForUser($user);
    } catch (Throwable $e) {
      @error_log('[API] employee ID generation via shadow service failed: ' . $e->getMessage());
    }
  }

  $seed = strtolower(trim((string)($user['username'] ?? '')));
  if ($seed === '') $seed = strtolower(trim((string)($user['personal_email'] ?? $user['email'] ?? '')));
  if ($seed === '') $seed = strtolower(trim((string)($user['cccd'] ?? '')));
  if ($seed === '') $seed = json_encode($user, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES) ?: uniqid('emp', true);
  return 'EMP' . strtoupper(substr(sha1($seed), 0, 12));
}

function portal_auth_normalize_user_linkage(array $user, string $rootDir): array {
  $fallback = [
    'dept_code' => trim((string)($user['dept'] ?? '')) !== '' ? trim((string)$user['dept']) : null,
    'hcm_org_unit_id' => trim((string)($user['hcm_org_unit_id'] ?? '')) !== '' ? trim((string)$user['hcm_org_unit_id']) : null,
    'hcm_position_id' => trim((string)($user['hcm_position_id'] ?? '')) !== '' ? trim((string)$user['hcm_position_id']) : null,
    'position_title' => trim((string)($user['title'] ?? '')),
  ];

  $service = portal_auth_shadow_sync_service($rootDir);
  if (!$service || !method_exists($service, 'normalizeUserLinkage')) {
    return $fallback;
  }

  try {
    $normalized = $service->normalizeUserLinkage($user);
    return is_array($normalized) ? array_merge($fallback, $normalized) : $fallback;
  } catch (Throwable $e) {
    @error_log('[API] auth user linkage normalize failed: ' . $e->getMessage());
    return $fallback;
  }
}

function portal_auth_known_role_codes(string $rootDir, string $rolePermFile, array $store = []): array {
  $codes = [];

  $service = portal_auth_shadow_sync_service($rootDir);
  if ($service && method_exists($service, 'knownRoleCodes')) {
    try {
      foreach ((array)$service->knownRoleCodes() as $code) {
        $code = strtolower(trim((string)$code));
        if ($code !== '') $codes[$code] = true;
      }
    } catch (Throwable $e) {
      @error_log('[API] role catalog read via shadow service failed: ' . $e->getMessage());
    }
  }

  try {
    foreach (array_keys(load_role_permissions($rolePermFile)) as $code) {
      $code = strtolower(trim((string)$code));
      if ($code !== '') $codes[$code] = true;
    }
  } catch (Throwable $e) {
    @error_log('[API] role permission catalog read failed: ' . $e->getMessage());
  }

  foreach ((array)($store['users'] ?? []) as $user) {
    if (!is_array($user)) continue;
    $code = strtolower(trim((string)($user['role'] ?? '')));
    if ($code !== '') $codes[$code] = true;
  }

  return array_keys($codes);
}

function portal_auth_validate_runtime_role_code(string $roleCode, string $rootDir, string $rolePermFile, array $store = []): ?array {
  $roleCode = strtolower(trim($roleCode));
  if ($roleCode === '') {
    return null;
  }

  if (!preg_match('/^[a-z][a-z0-9_:-]{1,79}$/', $roleCode)) {
    return ['ok' => false, 'error' => 'invalid_role', 'message' => 'Role code format is invalid.'];
  }

  $knownRoles = portal_auth_known_role_codes($rootDir, $rolePermFile, $store);
  if ($knownRoles !== [] && !in_array($roleCode, $knownRoles, true)) {
    return ['ok' => false, 'error' => 'invalid_role', 'message' => 'Role must exist in the runtime role catalog.'];
  }

  return null;
}

function portal_auth_shadow_sync_user(array $user, string $rootDir): void {
  $service = portal_auth_shadow_sync_service($rootDir);
  if (!$service || !method_exists($service, 'syncUser')) {
    return;
  }
  try {
    $service->syncUser($user);
  } catch (Throwable $e) {
    @error_log('[API] auth user shadow sync failed: ' . $e->getMessage());
  }
  // ADR-0013: also write a row to the hash-chained audit log so the
  // legacy api.php upsert/reset_password/delete paths are auditable
  // alongside the new UserController path. Failure is non-fatal.
  portal_identity_audit_chain_record($user, 'identity_user_saved');
}

/**
 * Record an identity mutation in audit_event_chain (migration 174).
 * Best-effort — silently no-ops when PortalServices / DB is unavailable.
 */
function portal_identity_audit_chain_record(array $user, string $eventType): void {
  try {
    $servicesFile = __DIR__ . '/api/services/PortalServices.php';
    if (!is_file($servicesFile)) {
      return;
    }
    require_once $servicesFile;
    if (!class_exists('\MOM\Api\Services\PortalServices')) {
      return;
    }
    $audit = \MOM\Api\Services\PortalServices::auditChain();
    if ($audit === null) {
      return;
    }
    $username = strtolower(trim((string)($user['username'] ?? '')));
    if ($username === '') {
      return;
    }
    $audit->record(
      eventType: $eventType,
      aggregateType: 'identity.users',
      aggregateId: $username,
      actorId: null,
      actorName: 'legacy_api_php',
      payload: [
        'username'   => $username,
        'role'       => (string)($user['role'] ?? ''),
        'dept'       => (string)($user['dept'] ?? ''),
        'active'     => (bool)($user['active'] ?? true),
        'source'     => 'legacy_api_php',
      ],
    );
  } catch (Throwable $e) {
    @error_log('[API] audit_event_chain record failed: ' . $e->getMessage());
  }
}

function portal_auth_shadow_deactivate_user(string $username, ?string $employeeId, string $rootDir): void {
  $service = portal_auth_shadow_sync_service($rootDir);
  if (!$service || !method_exists($service, 'deactivateUser')) {
    return;
  }
  try {
    $service->deactivateUser($username, $employeeId);
  } catch (Throwable $e) {
    @error_log('[API] auth user shadow deactivate failed: ' . $e->getMessage());
  }
  portal_identity_audit_chain_record(
    ['username' => $username, 'employee_id' => $employeeId, 'active' => false],
    'identity_user_deactivated',
  );
}

/**
 * Load role permission grants from the canonical authority (roles.permissions
 * JSONB column, since 2026-05-09 per architecture_rbac_authority decision).
 *
 * Returns null on DB unavailability so the caller can fall back to the legacy
 * JSON file. Result is memoised per request.
 *
 * @return array<string, array<string, mixed>>|null
 */
function load_role_permissions_from_db(): ?array {
  static $cache = null;
  static $resolved = false;
  if ($resolved) return $cache;
  $connection = portal_system_db_connection();
  if (!$connection) {
    $resolved = true;
    return null;
  }
  try {
    $rows = $connection->query(
      "SELECT role_code, permissions
         FROM roles
        WHERE is_active = TRUE
          AND permissions IS NOT NULL
          AND permissions::text <> '{}'",
      []
    );
  } catch (Throwable $e) {
    @error_log('[API] load_role_permissions_from_db failed: ' . $e->getMessage());
    $resolved = true;
    return null;
  }
  $out = [];
  foreach ($rows as $r) {
    $code = strtolower(trim((string)($r['role_code'] ?? '')));
    if ($code === '') continue;
    $perm = $r['permissions'] ?? null;
    if (is_string($perm)) {
      $decoded = json_decode($perm, true);
      if (is_array($decoded)) $perm = $decoded;
    }
    if (is_array($perm) && !empty($perm)) {
      $out[$code] = $perm;
    }
  }
  $cache = $out;
  $resolved = true;
  return $cache;
}

function load_role_permissions(string $file): array {
  $defaults = default_role_permissions();
  // 1) Canonical: roles.permissions JSONB (single source of truth).
  $j = load_role_permissions_from_db();
  // 2) Variable registry shadow store.
  if (!is_array($j) || empty($j)) {
    $j = portal_system_config_shadow_read('role_permissions');
  }
  // 3) Legacy file fallback (deprecated, kept for offline/JSON_ONLY mode).
  if (!is_array($j) || empty($j)) {
    $j = read_json_file($file);
  }
  if (!is_array($j)) return $defaults;

  $merged = $defaults;
  foreach ($j as $role => $entry) {
    $normalizedRole = migrate_role(strtolower(trim((string)$role)));
    if ($normalizedRole === '' || !is_array($entry)) {
      continue;
    }
    $merged[$normalizedRole] = merge_role_permission_row($defaults[$normalizedRole] ?? [], $entry);
  }

  return $merged;
}

function save_role_permissions(string $file, array $perms): void {
  write_json_file($file, $perms);
  portal_system_config_shadow_write('role_permissions', $perms);
}

function role_can_edit_docs(array $user, string $file): bool {
  if (role_can_create_docs($user, $file)) {
    return true;
  }

  $role = (string)($user['role'] ?? '');
  $mRole = migrate_role($role);
  $perms = load_role_permissions($file);
  $entry = $perms[$role] ?? (($mRole !== '') ? ($perms[$mRole] ?? null) : null);
  if (is_array($entry) && array_key_exists('canEditDocs', $entry)) {
    return (bool)$entry['canEditDocs'];
  }

  $editors = [
    'qa_manager',
    'quality_manager',
    'qms_engineer',
    'ceo',
    'it_admin',
    'production_director',
    'cnc_workshop_manager',
    'engineering_manager',
    'engineering_lead',
    'process_engineer',
    'cam_nc_programmer',
    'quality_engineer',
    'supply_chain_manager',
    'finance_manager',
    'hr_manager',
    'epicor_admin',
  ];

  return in_array($role, $editors, true) || in_array($mRole, $editors, true);
}

function role_can_create_docs(array $user, string $file): bool {
  $role = (string)($user['role'] ?? '');
  $mRole = migrate_role($role);
  $perms = load_role_permissions($file);
  $entry = $perms[$role] ?? (($mRole !== '') ? ($perms[$mRole] ?? null) : null);
  if (is_array($entry) && array_key_exists('canCreateDocs', $entry)) {
    return (bool)$entry['canCreateDocs'];
  }
  // Hard fallback (safe)
  $creators = ['qa_manager', 'ceo', 'qms_engineer', 'it_admin', 'production_director'];
  return in_array($role, $creators, true) || in_array($mRole, $creators, true);
}

function normalize_permission_key(string $permission): string {
  return strtolower(trim($permission));
}

/**
 * @return array<int, string>
 */
function normalize_permission_patterns($patterns): array {
  if (!is_array($patterns)) return [];
  $normalized = [];
  foreach ($patterns as $pattern) {
    $value = normalize_permission_key((string)$pattern);
    if ($value !== '' && !in_array($value, $normalized, true)) {
      $normalized[] = $value;
    }
  }
  return $normalized;
}

function permission_pattern_matches(string $permission, string $pattern): bool {
  $permission = normalize_permission_key($permission);
  $pattern = normalize_permission_key($pattern);

  if ($permission === '' || $pattern === '') {
    return false;
  }
  if ($pattern === '*') {
    return true;
  }

  $regex = '/^' . str_replace('\*', '.*', preg_quote($pattern, '/')) . '$/';
  return preg_match($regex, $permission) === 1;
}

/**
 * @param array<string, mixed> $entry
 * @return array<int, string>
 */
function role_permission_grants(array $entry): array {
  $grants = normalize_permission_patterns($entry['permissions'] ?? []);
  if (!empty($entry['allowAllPermissions']) && !in_array('*', $grants, true)) {
    $grants[] = '*';
  }
  foreach ($entry as $key => $value) {
    if (in_array($key, ['canCreateDocs', 'permissions', 'denies', 'allowAllPermissions'], true)) {
      continue;
    }
    if (is_bool($value) && $value) {
      $normalized = normalize_permission_key((string)$key);
      if ($normalized !== '' && !in_array($normalized, $grants, true)) {
        $grants[] = $normalized;
      }
    }
  }
  return $grants;
}

/**
 * @param array<string, mixed> $entry
 * @return array<int, string>
 */
function role_permission_denies(array $entry): array {
  return normalize_permission_patterns($entry['denies'] ?? []);
}

/**
 * @param string|array<int, string> $permissions
 */
function permission_matrix_manages_permission($permissions, string $file): bool {
  $required = is_array($permissions) ? $permissions : [$permissions];
  $required = normalize_permission_patterns($required);
  if ($required === []) return false;

  $perms = load_role_permissions($file);
  foreach ($perms as $entry) {
    if (!is_array($entry)) {
      continue;
    }
    $patterns = array_merge(role_permission_grants($entry), role_permission_denies($entry));
    foreach ($required as $permission) {
      foreach ($patterns as $pattern) {
        if ($pattern === '*') {
          continue;
        }
        if (permission_pattern_matches($permission, $pattern)) {
          return true;
        }
      }
    }
  }

  return false;
}

/**
 * @param string|array<int, string> $permissions
 */
function user_permission_matrix_configured(array $user, string $file): bool {
  $perms = load_role_permissions($file);
  $userRoles = is_array($user['roles'] ?? null) ? $user['roles'] : [(string)($user['role'] ?? '')];

  foreach ($userRoles as $role) {
    $normalizedRole = migrate_role(strtolower(trim((string)$role)));
    if ($normalizedRole === '') {
      continue;
    }
    $entry = $perms[$normalizedRole] ?? null;
    if (!is_array($entry)) {
      continue;
    }
    if (!empty($entry['allowAllPermissions'])) {
      return true;
    }
    if (role_permission_grants($entry) !== [] || role_permission_denies($entry) !== []) {
      return true;
    }
  }

  return false;
}

/**
 * @param string|array<int, string> $permissions
 */
function user_has_any_permission(array $user, $permissions, string $file): bool {
  $required = is_array($permissions) ? $permissions : [$permissions];
  $required = normalize_permission_patterns($required);
  if ($required === []) return false;

  $perms = load_role_permissions($file);
  $userRoles = is_array($user['roles'] ?? null) ? $user['roles'] : [(string)($user['role'] ?? '')];

  $grants = [];
  $denies = [];
  foreach ($userRoles as $role) {
    $normalizedRole = migrate_role(strtolower(trim((string)$role)));
    if ($normalizedRole === '') {
      continue;
    }
    $entry = $perms[$normalizedRole] ?? null;
    if (!is_array($entry)) {
      continue;
    }
    $grants = array_merge($grants, role_permission_grants($entry));
    $denies = array_merge($denies, role_permission_denies($entry));
  }

  foreach ($required as $permission) {
    foreach ($denies as $pattern) {
      if (permission_pattern_matches($permission, $pattern)) {
        return false;
      }
    }
  }

  foreach ($required as $permission) {
    foreach ($grants as $pattern) {
      if (permission_pattern_matches($permission, $pattern)) {
        return true;
      }
    }
  }

  return false;
}

function user_is_admin(array $user): bool {
  $role = (string)($user['role'] ?? '');
  $mRole = migrate_role($role);
  $admins = admin_roles();
  return in_array($role, $admins, true) || in_array($mRole, $admins, true);
}

function require_doc_workflow_editor(array $user, string $rolePermFile): void {
  if (user_is_admin($user)) return;
  if (role_can_edit_docs($user, $rolePermFile)) return;
  api_json(['ok' => false, 'error' => 'forbidden'], 403);
}

function require_doc_workflow_approver(array $user): void {
  // Approval/reject must be elevated roles only (server-side gate).
  if (!user_is_admin($user)) {
    api_json(['ok' => false, 'error' => 'forbidden'], 403);
  }
}

// ---------- Custom documents list (server-backed) ----------
function parse_custom_docs_payload(string $file, ?bool &$found = null): array {
  $found = is_file($file);
  if (!$found) return [];
  $j = read_json_file($file);
  if (is_array($j)) {
    if (isset($j['docs']) && is_array($j['docs'])) return $j['docs'];
    // Backward-compatible: allow a plain array of docs
    $isList = true;
    $i = 0;
    foreach (array_keys($j) as $k) {
      if ($k !== $i) { $isList = false; break; }
      $i++;
    }
    if ($isList) return $j;
  }
  return [];
}

function custom_docs_legacy_file(string $file): string {
  $norm = str_replace('\\', '/', $file);
  if (str_ends_with($norm, '/docs_custom.local.json')) {
    return substr($norm, 0, -strlen('/docs_custom.local.json')) . '/docs_custom.json';
  }
  return $norm;
}

function load_custom_docs(string $file): array {
  $primaryFound = false;
  $docs = parse_custom_docs_payload($file, $primaryFound);
  if ($primaryFound) return $docs;

  $legacyFile = custom_docs_legacy_file($file);
  if ($legacyFile === $file) return [];

  $legacyFound = false;
  $legacyDocs = parse_custom_docs_payload($legacyFile, $legacyFound);
  if (!$legacyFound) return [];

  // One-time migration path: preserve existing tracked docs_custom.json data by
  // copying it into the ignored local override file as soon as new code runs.
  try {
    save_custom_docs($file, $legacyDocs);
  } catch (Throwable $e) {
    // Ignore migration write errors and still serve the legacy content.
  }
  return $legacyDocs;
}

function save_custom_docs(string $file, array $docs): void {
  // Store as an object so we can extend later
  write_json_file($file, ['docs' => array_values($docs), 'updated_at' => now_iso()]);
}

function path_equals_or_child(string $candidate, string $base): bool {
  $candidate = trim(str_replace('\\', '/', $candidate), '/');
  $base = trim(str_replace('\\', '/', $base), '/');
  if ($candidate === '' || $base === '') return false;
  $candidate = safe_rel_path($candidate);
  $base = safe_rel_path($base);
  return $candidate === $base || str_starts_with($candidate, $base . '/');
}

function patch_custom_doc_entries(string $file, string $code, array $patch): bool {
  $code = strtoupper(trim($code));
  if ($code === '' || empty($patch)) return false;
  $custom = load_custom_docs($file);
  $changed = false;
  foreach ($custom as &$doc) {
    if (!is_array($doc)) continue;
    if (strtoupper((string)($doc['code'] ?? '')) !== $code) continue;
    foreach ($patch as $key => $value) {
      if (($doc[$key] ?? null) !== $value) {
        $doc[$key] = $value;
        $changed = true;
      }
    }
  }
  unset($doc);
  if ($changed) save_custom_docs($file, $custom);
  return $changed;
}

// ---------- Document visibility (Effective docs) ----------
function load_doc_visibility(string $file): array {
  $j = portal_system_config_shadow_read('docs_visibility');
  if (!is_array($j)) {
    $j = read_json_file($file);
  }
  if (is_array($j)) {
    $hidden = $j['hidden'] ?? null;
    if (is_array($hidden)) return array_values($hidden);
  }
  return [];
}

function save_doc_visibility(string $file, array $hidden): void {
  // Store as object for extensibility
  $hidden = array_values(array_unique(array_map('strval', $hidden)));
  $payload = ['hidden' => $hidden, 'updated_at' => now_iso()];
  write_json_file($file, $payload);
  portal_system_config_shadow_write('docs_visibility', $payload);
}

function portal_default_doc_extensions(): array {
  static $extensions = ['html', 'pdf', 'doc', 'docx', 'docm', 'xls', 'xlsx', 'xlsm', 'xlsb', 'csv', 'ppt', 'pptx', 'pptm'];
  return $extensions;
}

function portal_normalize_extension_list(array $values): array {
  $out = [];
  $seen = [];
  foreach ($values as $value) {
    $ext = strtolower(trim((string)$value));
    $ext = ltrim($ext, '.');
    $ext = preg_replace('/[^a-z0-9]+/', '', $ext);
    if ($ext === '' || strlen($ext) > 16 || isset($seen[$ext])) continue;
    $seen[$ext] = true;
    $out[] = $ext;
  }
  return $out;
}

function portal_normalize_lower_id_list(array $values): array {
  $out = [];
  $seen = [];
  foreach ($values as $value) {
    $id = strtolower(trim((string)$value));
    $id = preg_replace('/[^a-z0-9_-]+/', '', $id);
    if ($id === '' || isset($seen[$id])) continue;
    $seen[$id] = true;
    $out[] = $id;
  }
  return $out;
}

function portal_normalize_upper_id_list(array $values): array {
  $out = [];
  $seen = [];
  foreach ($values as $value) {
    $id = strtoupper(trim((string)$value));
    $id = preg_replace('/[^A-Z0-9_-]+/', '', $id);
    if ($id === '' || isset($seen[$id])) continue;
    $seen[$id] = true;
    $out[] = $id;
  }
  return $out;
}

function portal_display_config_defaults(): array {
  return [
    'extensions' => [
      'enabled' => portal_default_doc_extensions(),
      'custom' => [],
    ],
    'sidebar' => [
      'hidden_core_items' => [],
      'hidden_sections' => [],
      'hidden_categories' => [],
    ],
  ];
}

function portal_display_config_known_extensions(array $config): array {
  $out = [];
  $seen = [];
  foreach (array_merge(portal_default_doc_extensions(), portal_normalize_extension_list($config['extensions']['custom'] ?? [])) as $ext) {
    if ($ext === '' || isset($seen[$ext])) continue;
    $seen[$ext] = true;
    $out[] = $ext;
  }
  return $out;
}

function portal_display_config_enabled_extensions(array $config): array {
  $known = portal_display_config_known_extensions($config);
  $enabledRaw = portal_normalize_extension_list($config['extensions']['enabled'] ?? []);
  $enabledLookup = array_fill_keys($enabledRaw, true);
  $out = [];
  foreach ($known as $ext) {
    if (isset($enabledLookup[$ext])) $out[] = $ext;
  }
  return $out;
}

function portal_load_display_config(string $file): array {
  $defaults = portal_display_config_defaults();
  $raw = read_json_file($file);
  if (!is_array($raw)) {
    $raw = [];
  }

  $config = [
    'extensions' => [
      'custom' => portal_normalize_extension_list($raw['extensions']['custom'] ?? []),
      'enabled' => portal_normalize_extension_list($raw['extensions']['enabled'] ?? $defaults['extensions']['enabled']),
    ],
    'sidebar' => [
      'hidden_core_items' => portal_normalize_lower_id_list($raw['sidebar']['hidden_core_items'] ?? []),
      'hidden_sections' => portal_normalize_lower_id_list($raw['sidebar']['hidden_sections'] ?? []),
      'hidden_categories' => portal_normalize_upper_id_list($raw['sidebar']['hidden_categories'] ?? []),
    ],
  ];

  $known = portal_display_config_known_extensions($config);
  $enabled = portal_display_config_enabled_extensions($config);
  $builtinLookup = array_fill_keys(portal_default_doc_extensions(), true);
  $custom = array_values(array_filter($known, function ($ext) use ($builtinLookup) {
    return !isset($builtinLookup[$ext]);
  }));

  $config['extensions']['custom'] = $custom;
  $config['extensions']['enabled'] = $enabled;

  return $config;
}

function portal_save_display_config(string $file, array $config): array {
  $normalized = portal_load_display_config($file);

  if (isset($config['extensions']) && is_array($config['extensions'])) {
    $normalized['extensions']['custom'] = portal_normalize_extension_list($config['extensions']['custom'] ?? []);
    $normalized['extensions']['enabled'] = portal_normalize_extension_list($config['extensions']['enabled'] ?? []);
  }

  if (isset($config['sidebar']) && is_array($config['sidebar'])) {
    $normalized['sidebar']['hidden_core_items'] = portal_normalize_lower_id_list($config['sidebar']['hidden_core_items'] ?? []);
    $normalized['sidebar']['hidden_sections'] = portal_normalize_lower_id_list($config['sidebar']['hidden_sections'] ?? []);
    $normalized['sidebar']['hidden_categories'] = portal_normalize_upper_id_list($config['sidebar']['hidden_categories'] ?? []);
  }

  $known = portal_display_config_known_extensions($normalized);
  $enabledLookup = array_fill_keys(portal_normalize_extension_list($normalized['extensions']['enabled'] ?? []), true);
  $enabled = [];
  foreach ($known as $ext) {
    if (isset($enabledLookup[$ext])) $enabled[] = $ext;
  }
  $builtinLookup = array_fill_keys(portal_default_doc_extensions(), true);
  $custom = array_values(array_filter($known, function ($ext) use ($builtinLookup) {
    return !isset($builtinLookup[$ext]);
  }));

  $normalized['extensions']['custom'] = $custom;
  $normalized['extensions']['enabled'] = $enabled;

  write_json_file($file, [
    'extensions' => [
      'custom' => $normalized['extensions']['custom'],
      'enabled' => $normalized['extensions']['enabled'],
    ],
    'sidebar' => [
      'hidden_core_items' => $normalized['sidebar']['hidden_core_items'],
      'hidden_sections' => $normalized['sidebar']['hidden_sections'],
      'hidden_categories' => $normalized['sidebar']['hidden_categories'],
    ],
    'updated_at' => now_iso(),
  ]);

  return $normalized;
}

function portal_display_config_public_payload(array $config): array {
  return [
    'extensions' => [
      'builtin' => portal_default_doc_extensions(),
      'custom' => $config['extensions']['custom'] ?? [],
      'known' => portal_display_config_known_extensions($config),
      'enabled' => portal_display_config_enabled_extensions($config),
    ],
    'sidebar' => [
      'hidden_core_items' => $config['sidebar']['hidden_core_items'] ?? [],
      'hidden_sections' => $config['sidebar']['hidden_sections'] ?? [],
      'hidden_categories' => $config['sidebar']['hidden_categories'] ?? [],
    ],
  ];
}

