function load_runtime_observability_store(): array {
  $file = runtime_observability_file();
  $dir = dirname($file);
  ensure_dir($dir);
  $data = read_json_file($file);
  if (!is_array($data)) {
    $data = runtime_observability_default();
    if (is_dir($dir) && is_writable($dir)) {
      try {
        write_json_file($file, $data);
      } catch (Throwable $e) {
        @error_log('[runtime-observability] bootstrap store write skipped: ' . $e->getMessage());
      }
    } else {
      @error_log('[runtime-observability] bootstrap store write skipped: directory is not writable');
    }
  }
  $defaults = runtime_observability_default();
  $data['_meta'] = is_array($data['_meta'] ?? null) ? $data['_meta'] : $defaults['_meta'];
  $data['shadow_sync'] = is_array($data['shadow_sync'] ?? null) ? $data['shadow_sync'] : $defaults['shadow_sync'];
  foreach (['master_data', 'orders', 'mes', 'epicor'] as $key) {
    $data['shadow_sync'][$key] = array_merge($defaults['shadow_sync'][$key], is_array($data['shadow_sync'][$key] ?? null) ? $data['shadow_sync'][$key] : []);
    $data['shadow_sync'][$key]['recent'] = array_values(is_array($data['shadow_sync'][$key]['recent'] ?? null) ? $data['shadow_sync'][$key]['recent'] : []);
  }
  $data['primary_reads'] = is_array($data['primary_reads'] ?? null) ? $data['primary_reads'] : $defaults['primary_reads'];
  foreach (['master_data', 'orders', 'mes', 'epicor'] as $key) {
    $data['primary_reads'][$key] = array_merge($defaults['primary_reads'][$key], is_array($data['primary_reads'][$key] ?? null) ? $data['primary_reads'][$key] : []);
    $data['primary_reads'][$key]['recent'] = array_values(is_array($data['primary_reads'][$key]['recent'] ?? null) ? $data['primary_reads'][$key]['recent'] : []);
  }
  $data['connector_ingest'] = is_array($data['connector_ingest'] ?? null) ? $data['connector_ingest'] : $defaults['connector_ingest'];
  $data['connector_ingest']['totals'] = array_merge($defaults['connector_ingest']['totals'], is_array($data['connector_ingest']['totals'] ?? null) ? $data['connector_ingest']['totals'] : []);
  $data['connector_ingest']['machines'] = is_array($data['connector_ingest']['machines'] ?? null) ? $data['connector_ingest']['machines'] : [];
  $data['connector_ingest']['recent'] = array_values(is_array($data['connector_ingest']['recent'] ?? null) ? $data['connector_ingest']['recent'] : []);
  $data['launch_blockers'] = is_array($data['launch_blockers'] ?? null) ? $data['launch_blockers'] : $defaults['launch_blockers'];
  $data['launch_blockers']['totals'] = array_merge($defaults['launch_blockers']['totals'], is_array($data['launch_blockers']['totals'] ?? null) ? $data['launch_blockers']['totals'] : []);
  $data['launch_blockers']['work_orders'] = is_array($data['launch_blockers']['work_orders'] ?? null) ? $data['launch_blockers']['work_orders'] : [];
  $data['launch_blockers']['recent'] = array_values(is_array($data['launch_blockers']['recent'] ?? null) ? $data['launch_blockers']['recent'] : []);
  return $data;
}

function save_runtime_observability_store(array $data): void {
  $file = runtime_observability_file();
  $dir = dirname($file);
  ensure_dir($dir);
  $data['_meta'] = is_array($data['_meta'] ?? null) ? $data['_meta'] : [];
  $data['_meta']['updated'] = now_iso();
  if (!is_dir($dir) || !is_writable($dir)) {
    @error_log('[runtime-observability] store write skipped: directory is not writable');
    return;
  }
  try {
    write_json_file($file, $data);
  } catch (Throwable $e) {
    @error_log('[runtime-observability] store write skipped: ' . $e->getMessage());
  }
}

function append_jsonl_line(string $file, array $entry): void {
  $dir = dirname($file);
  ensure_dir($dir);
  if (!is_dir($dir) || !is_writable($dir)) {
    @error_log('[runtime-observability] jsonl append skipped: ' . $file);
    return;
  }
  @file_put_contents(
    $file,
    json_encode($entry, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES) . "\n",
    FILE_APPEND | LOCK_EX
  );
}

function runtime_data_log_event(string $eventType, string $aggregateType, string $aggregateId, array $payload): void {
  try {
    runtime_data_layer()->logEvent($eventType, $aggregateType, $aggregateId, $payload);
  } catch (Throwable $e) {
    @error_log('[runtime-observability] audit log failed: ' . $e->getMessage());
  }
}

function observe_shadow_sync(string $storeKey, $ok, string $message, array $context = []): void {
  $store = load_runtime_observability_store();
  $status = is_bool($ok) ? ($ok ? 'success' : 'failure') : strtolower(trim((string)$ok));
  if (!in_array($status, ['success', 'failure', 'skipped'], true)) $status = 'failure';
  $entry = [
    'store_key' => $storeKey,
    'status' => $status,
    'message' => $message,
    'timestamp' => now_iso(),
    'context' => $context,
  ];
  $bucket = array_merge([
    'last_status' => 'never',
    'last_success_at' => '',
    'last_error_at' => '',
    'last_skipped_at' => '',
    'last_message' => '',
    'success_count' => 0,
    'failure_count' => 0,
    'skipped_count' => 0,
    'last_duration_ms' => null,
    'last_item_count' => 0,
    'last_mode' => '',
    'last_context' => [],
    'recent' => [],
  ], is_array($store['shadow_sync'][$storeKey] ?? null) ? $store['shadow_sync'][$storeKey] : []);
  $bucket['last_status'] = $entry['status'];
  $bucket['last_message'] = $message;
  $bucket['last_duration_ms'] = isset($context['duration_ms']) ? (float)$context['duration_ms'] : ($bucket['last_duration_ms'] ?? null);
  $bucket['last_item_count'] = isset($context['item_count']) ? (int)$context['item_count'] : (int)($bucket['last_item_count'] ?? 0);
  $bucket['last_mode'] = (string)($context['runtime_mode'] ?? $bucket['last_mode'] ?? '');
  $bucket['last_context'] = $context;
  if ($status === 'success') {
    $bucket['last_success_at'] = $entry['timestamp'];
    $bucket['success_count'] = (int)($bucket['success_count'] ?? 0) + 1;
  } elseif ($status === 'skipped') {
    $bucket['last_skipped_at'] = $entry['timestamp'];
    $bucket['skipped_count'] = (int)($bucket['skipped_count'] ?? 0) + 1;
  } else {
    $bucket['last_error_at'] = $entry['timestamp'];
    $bucket['failure_count'] = (int)($bucket['failure_count'] ?? 0) + 1;
  }
  $recent = array_values((array)($bucket['recent'] ?? []));
  array_unshift($recent, $entry);
  $bucket['recent'] = array_slice($recent, 0, 12);
  $store['shadow_sync'][$storeKey] = $bucket;
  save_runtime_observability_store($store);
  append_jsonl_line(runtime_observability_log_file('shadow-sync.jsonl'), $entry);
  runtime_data_log_event('runtime.shadow_sync.' . $entry['status'], 'runtime_shadow', $storeKey, $entry);
}

function observe_primary_read(string $storeKey, array $readMeta, array $context = []): void {
  $store = load_runtime_observability_store();
  $source = strtolower(trim((string)($readMeta['source'] ?? 'json')));
  if (!in_array($source, ['postgres', 'json', 'json_fallback', 'never'], true)) {
    $source = 'json';
  }
  $entry = [
    'store_key' => $storeKey,
    'source' => $source,
    'fallback' => (bool)($readMeta['fallback'] ?? false),
    'error' => trim((string)($readMeta['error'] ?? '')),
    'mode' => trim((string)($readMeta['mode'] ?? '')),
    'timestamp' => trim((string)($readMeta['timestamp'] ?? now_iso())) ?: now_iso(),
    'context' => $context,
  ];
  $bucket = array_merge([
    'last_source' => 'never',
    'last_read_at' => '',
    'last_error' => '',
    'last_mode' => '',
    'postgres_count' => 0,
    'json_count' => 0,
    'fallback_count' => 0,
    'last_context' => [],
    'recent' => [],
  ], is_array($store['primary_reads'][$storeKey] ?? null) ? $store['primary_reads'][$storeKey] : []);
  $bucket['last_source'] = $source;
  $bucket['last_read_at'] = $entry['timestamp'];
  $bucket['last_error'] = $entry['error'];
  $bucket['last_mode'] = $entry['mode'];
  $bucket['last_context'] = $context;
  if ($source === 'postgres') {
    $bucket['postgres_count'] = (int)($bucket['postgres_count'] ?? 0) + 1;
  } else {
    $bucket['json_count'] = (int)($bucket['json_count'] ?? 0) + 1;
    if ($source === 'json_fallback' || $entry['fallback']) {
      $bucket['fallback_count'] = (int)($bucket['fallback_count'] ?? 0) + 1;
    }
  }
  $recent = array_values((array)($bucket['recent'] ?? []));
  array_unshift($recent, $entry);
  $bucket['recent'] = array_slice($recent, 0, 15);
  $store['primary_reads'][$storeKey] = $bucket;
  save_runtime_observability_store($store);
  append_jsonl_line(runtime_observability_log_file('primary-reads.jsonl'), $entry);
  runtime_data_log_event('runtime.primary_read.' . $source, 'runtime_read_model', $storeKey, $entry);
}

function observe_connector_ingest(string $machineId, bool $ok, string $message, array $context = []): void {
  $store = load_runtime_observability_store();
  $entry = [
    'machine_id' => $machineId,
    'status' => $ok ? 'success' : 'failure',
    'message' => $message,
    'timestamp' => now_iso(),
    'context' => $context,
  ];
  $machines = is_array($store['connector_ingest']['machines'] ?? null) ? $store['connector_ingest']['machines'] : [];
  $machine = array_merge([
    'machine_id' => $machineId,
    'last_status' => 'never',
    'last_success_at' => '',
    'last_error_at' => '',
    'last_message' => '',
    'success_count' => 0,
    'failure_count' => 0,
    'recent' => [],
  ], is_array($machines[$machineId] ?? null) ? $machines[$machineId] : []);
  $machine['last_status'] = $entry['status'];
  $machine['last_message'] = $message;
  if ($ok) {
    $machine['last_success_at'] = $entry['timestamp'];
    $machine['success_count'] = (int)($machine['success_count'] ?? 0) + 1;
    $store['connector_ingest']['totals']['success'] = (int)($store['connector_ingest']['totals']['success'] ?? 0) + 1;
  } else {
    $machine['last_error_at'] = $entry['timestamp'];
    $machine['failure_count'] = (int)($machine['failure_count'] ?? 0) + 1;
    $store['connector_ingest']['totals']['failure'] = (int)($store['connector_ingest']['totals']['failure'] ?? 0) + 1;
  }
  $recentMachine = array_values((array)($machine['recent'] ?? []));
  array_unshift($recentMachine, $entry);
  $machine['recent'] = array_slice($recentMachine, 0, 12);
  $machines[$machineId] = $machine;
  $store['connector_ingest']['machines'] = $machines;
  $recentGlobal = array_values((array)($store['connector_ingest']['recent'] ?? []));
  array_unshift($recentGlobal, $entry);
  $store['connector_ingest']['recent'] = array_slice($recentGlobal, 0, 40);
  save_runtime_observability_store($store);
  append_jsonl_line(runtime_observability_log_file('connector-ingest.jsonl'), $entry);
  runtime_data_log_event('runtime.connector_ingest.' . $entry['status'], 'connector_feed', $machineId, $entry);
}

function observe_wo_launch_blocked(string $woNumber, string $targetStatus, array $blockers, array $snapshot = []): void {
  $store = load_runtime_observability_store();
  $timestamp = now_iso();
  $entry = [
    'wo_number' => $woNumber,
    'target_status' => $targetStatus,
    'timestamp' => $timestamp,
    'blockers' => array_values($blockers),
    'blocker_codes' => array_values(array_unique(array_filter(array_map(static fn($row) => is_array($row) ? (string)($row['code'] ?? '') : '', $blockers)))),
    'context' => $snapshot,
  ];

  $byWo = is_array($store['launch_blockers']['work_orders'] ?? null) ? $store['launch_blockers']['work_orders'] : [];
  $node = array_merge([
    'wo_number' => $woNumber,
    'last_blocked_at' => '',
    'last_target_status' => '',
    'count' => 0,
    'latest_blockers' => [],
    'latest_context' => [],
    'recent' => [],
  ], is_array($byWo[$woNumber] ?? null) ? $byWo[$woNumber] : []);
  $node['last_blocked_at'] = $timestamp;
  $node['last_target_status'] = $targetStatus;
  $node['count'] = (int)($node['count'] ?? 0) + 1;
  $node['latest_blockers'] = $entry['blockers'];
  $node['latest_context'] = $snapshot;
  $recentWo = array_values((array)($node['recent'] ?? []));
  array_unshift($recentWo, $entry);
  $node['recent'] = array_slice($recentWo, 0, 12);
  $byWo[$woNumber] = $node;
  $store['launch_blockers']['work_orders'] = $byWo;
  $store['launch_blockers']['totals']['count'] = (int)($store['launch_blockers']['totals']['count'] ?? 0) + 1;
  $recentGlobal = array_values((array)($store['launch_blockers']['recent'] ?? []));
  array_unshift($recentGlobal, $entry);
  $store['launch_blockers']['recent'] = array_slice($recentGlobal, 0, 40);
  save_runtime_observability_store($store);
  append_jsonl_line(runtime_observability_log_file('launch-blockers.jsonl'), $entry);
  runtime_data_log_event('runtime.wo_launch_blocked', 'work_order', $woNumber, $entry);
}

function mes_launch_blocker_rows(array $observability): array {
  $rows = [];
  foreach ((array)($observability['launch_blockers']['work_orders'] ?? []) as $woNumber => $node) {
    if (!is_array($node)) continue;
    $rows[] = [
      'wo_number' => (string)($node['wo_number'] ?? $woNumber),
      'target_status' => (string)($node['last_target_status'] ?? ''),
      'blocked_at' => (string)($node['last_blocked_at'] ?? ''),
      'count' => (int)($node['count'] ?? 0),
      'severity' => 'critical',
      'issue_codes' => array_values(array_unique(array_filter(array_map(static fn($row) => is_array($row) ? (string)($row['code'] ?? '') : '', (array)($node['latest_blockers'] ?? []))))),
      'message_vi' => 'WO đã bị chặn mở chạy do chưa đạt đủ điều kiện MES bắt buộc.',
      'message_en' => 'The WO was blocked from launch because mandatory MES conditions were not satisfied.',
      'latest_blockers' => array_values((array)($node['latest_blockers'] ?? [])),
      'context' => is_array($node['latest_context'] ?? null) ? $node['latest_context'] : [],
      'recent' => array_values((array)($node['recent'] ?? [])),
    ];
  }
  usort($rows, static function ($a, $b) {
    return strcmp((string)($b['blocked_at'] ?? ''), (string)($a['blocked_at'] ?? ''));
  });
  return $rows;
}

function mes_primary_read_rows(array $observability): array {
  $rows = [];
  foreach ((array)($observability['primary_reads'] ?? []) as $storeKey => $node) {
    if (!is_array($node)) continue;
    $source = strtolower(trim((string)($node['last_source'] ?? 'never')));
    $mode = strtoupper(trim((string)($node['last_mode'] ?? '')));
    $severity = 'ready';
    if ($source === 'json_fallback') {
      $severity = 'warning';
    } elseif ($source === 'json' && in_array($mode, ['POSTGRES_PRIMARY', 'POSTGRES_ONLY'], true)) {
      $severity = 'warning';
    } elseif ($source !== 'postgres' && $mode === 'POSTGRES_ONLY') {
      $severity = 'critical';
    }
    if ($severity === 'ready') {
      continue;
    }
    $rows[] = [
      'store_key' => (string)$storeKey,
      'severity' => $severity,
      'source' => $source,
      'runtime_mode' => $mode,
      'read_at' => (string)($node['last_read_at'] ?? ''),
      'fallback_count' => (int)($node['fallback_count'] ?? 0),
      'postgres_count' => (int)($node['postgres_count'] ?? 0),
      'json_count' => (int)($node['json_count'] ?? 0),
      'error' => (string)($node['last_error'] ?? ''),
      'message_vi' => 'Runtime Ä‘Ã£ pháº£i fallback vá» JSON thay vÃ¬ Ä‘á»c PostgreSQL mirror cho read model nÃ y.',
      'message_en' => 'Runtime had to fall back to JSON instead of reading the PostgreSQL mirror for this read model.',
      'recent' => array_values((array)($node['recent'] ?? [])),
    ];
  }
  usort($rows, static function ($a, $b) {
    return strcmp((string)($b['read_at'] ?? ''), (string)($a['read_at'] ?? ''));
  });
  return $rows;
}

function runtime_store_item_count(array $store): int {
  $total = 0;
  foreach ($store as $key => $value) {
    if ($key === '_meta') continue;
    if (is_array($value)) {
      $total += count($value);
    }
  }
  return $total;
}

function runtime_store_entity_counts(array $store, array $entityMap): array {
  $counts = [];
  foreach ($entityMap as $entityKey => $storeKey) {
    $counts[$entityKey] = count((array)($store[$storeKey] ?? []));
  }
  return $counts;
}

function runtime_cutover_postgres_counts(array $runtimeMode): array {
  $result = [
    'available' => false,
    'reason' => 'postgres_path_inactive',
    'error' => '',
    'groups' => [],
  ];

  if (!(bool)($runtimeMode['postgres_path_active'] ?? false)) {
    return $result;
  }

  if (!(bool)($runtimeMode['postgres_reachable'] ?? false)) {
    $result['reason'] = 'postgres_unreachable';
    $result['error'] = trim((string)($runtimeMode['postgres_error'] ?? '')) ?: 'postgres_unreachable';
    return $result;
  }

  require_once __DIR__ . '/database/Connection.php';
  $connection = \MOM\Database\Connection::getInstance((array)(require __DIR__ . '/database/config.php'));

  $operatorRolesSql = implode(',', array_map(
    static fn(string $role): string => "'" . str_replace("'", "''", $role) . "'",
    master_data_admin_operator_role_codes()
  ));

  $sqlMap = [
    'master_data' => [
      'customers' => "SELECT COUNT(*) AS c FROM customers WHERE COALESCE(metadata->>'customer_id', '') <> ''",
      'suppliers' => "SELECT COUNT(*) AS c FROM vendors WHERE COALESCE(metadata->>'supplier_id', '') <> ''",
      'parts' => "SELECT COUNT(*) AS c FROM items WHERE COALESCE(metadata->>'part_number', '') <> ''",
      'revisions' => "SELECT COUNT(*) AS c FROM item_revisions WHERE COALESCE(metadata->>'revision', '') <> ''",
      'work_centers' => "SELECT COUNT(*) AS c FROM work_centers WHERE COALESCE(metadata->>'work_center_id', '') <> ''",
      'machines' => "SELECT COUNT(*) AS c FROM equipment WHERE COALESCE(metadata->>'machine_id', '') <> ''",
      'operators' => "SELECT COUNT(*) AS c FROM v_user_canonical WHERE user_status = 'active' AND (role_code IN ({$operatorRolesSql}) OR lower(COALESCE(role_label, '')) LIKE '%operator%' OR lower(COALESCE(role_label, '')) LIKE '%technician%' OR lower(COALESCE(role_label, '')) LIKE '%inspector%')",
      'tooling_assets' => "SELECT COUNT(*) AS c FROM tools WHERE COALESCE(metadata->>'shadow_source', '') <> 'mes_runtime'",
      'capas' => "SELECT COUNT(*) AS c FROM records WHERE record_type = 'CAPA'",
    ],
    'orders' => [
      'sales_orders' => "SELECT COUNT(*) AS c FROM sales_orders WHERE COALESCE(metadata->>'so_number', '') <> ''",
      'job_orders' => "SELECT COUNT(*) AS c FROM job_orders WHERE COALESCE(metadata->>'jo_number', '') <> ''",
      'work_orders' => "SELECT COUNT(*) AS c FROM job_operations WHERE COALESCE(metadata->>'wo_number', '') <> ''",
    ],
    'mes' => [
      'runtime_machine_context' => "SELECT COUNT(*) AS c FROM mes_equipment_extended WHERE metadata ? 'machine_signal' OR metadata ? 'connector_feed'",
      'progress_reports' => "SELECT COUNT(*) AS c FROM mes_operation_execution WHERE metadata ? 'wo_number'",
      'downtime_events' => "SELECT COUNT(*) AS c FROM mes_downtime_events WHERE metadata ? 'shadow_id'",
      'maintenance_requests' => "SELECT COUNT(*) AS c FROM maintenance_work_orders WHERE COALESCE(metadata->>'request_id', '') <> ''",
      'material_consumption' => "SELECT COUNT(*) AS c FROM mes_material_consumption WHERE metadata ? 'consumption_id'",
      'part_genealogy' => "SELECT COUNT(*) AS c FROM mes_part_genealogy WHERE metadata ? 'genealogy_id'",
      'shift_handover' => "SELECT COUNT(*) AS c FROM mes_shift_handover WHERE metadata ? 'handover_id'",
      'machine_alarm_events' => "SELECT COUNT(*) AS c FROM mes_machine_alarms WHERE metadata ? 'alarm_event_id'",
      'nc_download_receipts' => "SELECT COUNT(*) AS c FROM mes_nc_download_receipts WHERE metadata ? 'receipt_id'",
      'dpp_passports' => "SELECT COUNT(*) AS c FROM mes_dpp_passports WHERE COALESCE(metadata->>'dpp_id', '') <> ''",
      'energy_snapshots' => "SELECT COUNT(*) AS c FROM mes_energy_snapshots WHERE COALESCE(metadata->>'energy_snapshot_id', '') <> ''",
      'cost_tracking' => "SELECT COUNT(*) AS c FROM mes_cost_tracking WHERE COALESCE(metadata->>'cost_id', '') <> ''",
    ],
    'epicor' => [
      'sync_runs' => "SELECT COUNT(*) AS c FROM mes_erp_sync_runs",
      'reconciliation_exceptions' => "SELECT COUNT(*) AS c FROM mes_erp_reconciliation_exceptions",
      'outbox_events' => "SELECT COUNT(*) AS c FROM mes_erp_outbound_queue",
    ],
  ];

  $groups = [];
  foreach ($sqlMap as $groupKey => $queries) {
    $groups[$groupKey] = [];
    foreach ($queries as $entityKey => $sql) {
      $row = $connection->queryOne($sql);
      $groups[$groupKey][$entityKey] = (int)($row['c'] ?? 0);
    }
  }

  $result['available'] = true;
  $result['reason'] = 'ok';
  $result['groups'] = $groups;
  return $result;
}

function build_runtime_cutover_audit(?array $bundle = null): array {
  $bundle = is_array($bundle) ? $bundle : runtime_read_model_bundle(true);
  $runtimeMode = is_array($bundle['runtime_mode'] ?? null) ? $bundle['runtime_mode'] : runtime_data_layer_summary();
  $master = is_array($bundle['master'] ?? null) ? $bundle['master'] : load_master_data_store();
  $orders = is_array($bundle['orders'] ?? null) ? $bundle['orders'] : load_orders_store();
  $mes = is_array($bundle['mes'] ?? null) ? $bundle['mes'] : load_mes_runtime_store();
  $epicor = load_epicor_runtime_store();

  $jsonGroups = [
    'master_data' => runtime_store_entity_counts($master, [
      'customers' => 'customers',
      'suppliers' => 'suppliers',
      'parts' => 'parts',
      'revisions' => 'revisions',
      'work_centers' => 'work_centers',
      'machines' => 'machines',
      'operators' => 'operators',
      'tooling_assets' => 'tooling_assets',
      'capas' => 'capas',
    ]),
    'orders' => runtime_store_entity_counts($orders, [
      'sales_orders' => 'sales_orders',
      'job_orders' => 'job_orders',
      'work_orders' => 'work_orders',
    ]),
    'mes' => [
      'runtime_machine_context' => count(array_unique(array_filter(array_merge(
        array_map(static fn($row): string => trim((string)($row['machine_id'] ?? '')), (array)($mes['connector_feeds'] ?? [])),
        array_map(static fn($row): string => trim((string)($row['machine_id'] ?? '')), (array)($mes['machine_signals'] ?? []))
      )))),
      'progress_reports' => count((array)($mes['progress_reports'] ?? [])),
      'downtime_events' => count((array)($mes['downtime_events'] ?? [])),
      'maintenance_requests' => count((array)($mes['maintenance_requests'] ?? [])),
      'material_consumption' => count((array)($mes['material_consumption'] ?? [])),
      'part_genealogy' => count((array)($mes['part_genealogy'] ?? [])),
      'shift_handover' => count((array)($mes['shift_handover'] ?? [])),
      'machine_alarm_events' => count((array)($mes['machine_alarm_events'] ?? [])),
      'nc_download_receipts' => count((array)($mes['nc_download_receipts'] ?? [])),
      'dpp_passports' => count((array)($mes['dpp_passports'] ?? [])),
      'energy_snapshots' => count((array)($mes['energy_snapshots'] ?? [])),
      'cost_tracking' => count((array)($mes['cost_tracking'] ?? [])),
    ],
    'epicor' => runtime_store_entity_counts($epicor, [
      'sync_runs' => 'sync_runs',
      'reconciliation_exceptions' => 'reconciliation_exceptions',
      'outbox_events' => 'outbox_events',
    ]),
  ];

  $pgData = runtime_cutover_postgres_counts($runtimeMode);
  $groups = [];
  $driftEntities = 0;
  $driftTotal = 0;

  foreach ($jsonGroups as $groupKey => $jsonCounts) {
    $pgCounts = is_array($pgData['groups'][$groupKey] ?? null) ? $pgData['groups'][$groupKey] : [];
    $rows = [];
    $groupJsonTotal = 0;
    $groupPgTotal = 0;
    foreach ($jsonCounts as $entityKey => $jsonCount) {
      $jsonValue = (int)$jsonCount;
      $pgValue = $pgData['available'] ? (int)($pgCounts[$entityKey] ?? 0) : null;
      $drift = $pgValue === null ? null : ($pgValue - $jsonValue);
      if ($drift !== null && $drift !== 0) {
        $driftEntities++;
        $driftTotal += abs($drift);
      }
      $groupJsonTotal += $jsonValue;
      $groupPgTotal += (int)($pgValue ?? 0);
      $rows[] = [
        'entity_key' => $entityKey,
        'json_count' => $jsonValue,
        'postgres_count' => $pgValue,
        'drift' => $drift,
        'status' => $pgValue === null ? 'unavailable' : ($drift === 0 ? 'aligned' : 'drift'),
      ];
    }
    $groups[$groupKey] = [
      'status' => !$pgData['available']
        ? ($pgData['reason'] === 'postgres_unreachable' ? 'postgres_unreachable' : 'json_only')
        : ($groupJsonTotal === $groupPgTotal && !array_filter($rows, static fn($row): bool => (int)($row['drift'] ?? 0) !== 0) ? 'aligned' : 'drift'),
      'json_total' => $groupJsonTotal,
      'postgres_total' => $pgData['available'] ? $groupPgTotal : null,
      'drift_total' => $pgData['available'] ? ($groupPgTotal - $groupJsonTotal) : null,
      'entities' => $rows,
    ];
  }

  $status = !$pgData['available']
    ? ($pgData['reason'] === 'postgres_unreachable' ? 'postgres_unreachable' : 'json_only')
    : ($driftEntities > 0 ? 'drift_detected' : 'aligned');

  return [
    'status' => $status,
    'reason' => (string)($pgData['reason'] ?? 'ok'),
    'error' => (string)($pgData['error'] ?? ''),
    'drift_entities' => $driftEntities,
    'drift_total' => $driftTotal,
    'groups' => $groups,
    'runtime_mode' => $runtimeMode,
    'updated_at' => now_iso(),
  ];
}

function runtime_read_model_bundle(bool $includeMes = true): array {
  $layer = runtime_data_layer();

  $master = $layer->getRuntimeMasterDataStore();
  $master = master_data_apply_admin_operator_projection($master);
  $masterRead = $layer->getLastReadMeta();
  observe_primary_read('master_data', $masterRead, [
    'item_count' => runtime_store_item_count($master),
    'scope' => $includeMes ? 'mes_bundle' : 'runtime_bundle',
  ]);

  $orders = $layer->getRuntimeOrdersStore();
  $ordersRead = $layer->getLastReadMeta();
  observe_primary_read('orders', $ordersRead, [
    'item_count' => runtime_store_item_count($orders),
    'scope' => $includeMes ? 'mes_bundle' : 'runtime_bundle',
  ]);

  $mes = [];
  $mesRead = [
    'source' => 'json',
    'fallback' => false,
    'error' => '',
    'mode' => (string)($layer->getModeSummary()['mode'] ?? 'JSON_ONLY'),
    'timestamp' => now_iso(),
  ];
  if ($includeMes) {
    $mes = $layer->getRuntimeMesRuntimeStore();
    $mesRead = $layer->getLastReadMeta();
    observe_primary_read('mes', $mesRead, [
      'item_count' => runtime_store_item_count($mes),
      'scope' => 'mes_bundle',
    ]);
  }

  return [
    'master' => $master,
    'orders' => $orders,
    'mes' => $mes,
    'sources' => [
      'master_data' => $masterRead,
      'orders' => $ordersRead,
      'mes' => $mesRead,
    ],
    'runtime_mode' => runtime_data_layer_summary(),
  ];
}

function build_exception_dashboard_data(array $bundle, ?array $mesSnapshot = null): array {
  global $DATA_DIR;

  $allocationStore = load_allocation_store();
  $allocations = (array)($allocationStore['allocations'] ?? []);
  $cutoff30 = date('c', strtotime('-30 days'));
  $overdueAllocations = 0;
  foreach ($allocations as $alloc) {
    if (!is_array($alloc)) continue;
    $st = allocation_status_normalize((string)($alloc['status'] ?? ''));
    if (!in_array($st, ['allocated', 'downloaded'], true)) continue;
    $dl = (string)($alloc['downloaded_at'] ?? '');
    if ($dl !== '' && $dl < $cutoff30) $overdueAllocations++;
  }

  require_once __DIR__ . '/api/services/UploadHardeningService.php';
  $uploadSvc = new UploadHardeningService($DATA_DIR);
  $failedUploads = count($uploadSvc->getExceptionQueue(30));

  $orders = $bundle['orders'];
  $master = $bundle['master'];
  $mes = $bundle['mes'];
  $today = date('Y-m-d');
  $overdueOrders = 0;
  foreach (['sales_orders', 'job_orders', 'work_orders'] as $key) {
    foreach ((array)($orders[$key] ?? []) as $ord) {
      if (!is_array($ord)) continue;
      $status = strtolower(trim((string)($ord['status'] ?? '')));
      if (in_array($status, ['closed', 'completed', 'cancelled', 'shipped'], true)) continue;
      $due = (string)($ord['due_date'] ?? '');
      if ($due !== '' && $due < $today) $overdueOrders++;
    }
  }

  $cutoff60 = date('Y-m-d', strtotime('-60 days'));
  $overdueCapas = 0;
  foreach ((array)($master['capas'] ?? []) as $capa) {
    if (!is_array($capa)) continue;
    $st = strtolower(trim((string)($capa['status'] ?? '')));
    if (in_array($st, ['closed', 'completed', 'cancelled'], true)) continue;
    $opened = (string)($capa['opened_date'] ?? $capa['created_at'] ?? '');
    if ($opened !== '' && substr($opened, 0, 10) < $cutoff60) $overdueCapas++;
  }

  $reviewSlaGaps = count(evidence_review_sla_queue_rows());
  $releaseFollowupOverdue = count(release_followup_queue_rows(true));
  $mesSnapshot = is_array($mesSnapshot) ? $mesSnapshot : build_mes_snapshot($orders, $master, $mes);
  $woMissingEvidence = count((array)($mesSnapshot['evidence_gate_queue'] ?? []));
  $programMismatches = count((array)($mesSnapshot['program_handshake_queue'] ?? []));
  $programReleaseRisk = count((array)($mesSnapshot['program_release_queue'] ?? []));
  $toolReadinessRisk = count((array)($mesSnapshot['tool_readiness_queue'] ?? []));
  $alarmAckGaps = count((array)($mesSnapshot['alarm_ack_queue'] ?? []));
  $operatorQualificationGaps = count((array)($mesSnapshot['operator_qualification_queue'] ?? []));
  $materialTraceGaps = count((array)($mesSnapshot['material_trace_queue'] ?? []));
  $materialGenealogyGaps = count((array)($mesSnapshot['material_genealogy_queue'] ?? []));
  $shiftHandoverGaps = count((array)($mesSnapshot['shift_handover_queue'] ?? []));
  $connectorGovernanceGaps = count((array)($mesSnapshot['connector_guard_queue'] ?? []));
  $adapterGovernanceRisk = count((array)($mesSnapshot['adapter_governance_queue'] ?? []));
  $alarmHotspots = count((array)($mesSnapshot['alarm_hotspot_queue'] ?? []));
  $ncDownloadMismatches = count((array)($mesSnapshot['nc_download_mismatch_queue'] ?? []));
  $toolOffsetRisk = count((array)($mesSnapshot['tool_offset_queue'] ?? []));
  $shadowSyncFailures = count((array)($mesSnapshot['shadow_sync_failures'] ?? []));
  $launchBlockerHotspots = count((array)($mesSnapshot['launch_blocker_queue'] ?? []));
  $primaryReadFallbacks = count((array)($mesSnapshot['primary_read_queue'] ?? []));
  $cutoverDriftEntities = (int)($mesSnapshot['kpis']['cutover_drift_entities'] ?? 0);
  $epicorSyncStatus = count((array)($mesSnapshot['epicor_sync_queue'] ?? []));
  $downtimeGovernanceGaps = count(mes_downtime_governance_gap_rows($mes, $master));
  $dppReadinessGaps = count((array)($mesSnapshot['dpp_queue'] ?? []));
  $energyTrackingGaps = count((array)($mesSnapshot['energy_queue'] ?? []));
  $costVarianceRisk = count((array)($mesSnapshot['cost_variance_queue'] ?? []));

  $orphanLinks = 0;
  foreach ((array)($orders['form_links'] ?? []) as $link) {
    if (!is_array($link)) continue;
    $ot = (string)($link['order_type'] ?? '');
    $oid = (string)($link['order_id'] ?? '');
    if ($ot === '' || $oid === '') {
      $orphanLinks++;
      continue;
    }
    $found = find_order_record($orders, $ot, $oid);
    if (!$found) $orphanLinks++;
  }

  return [
    'overdue_allocations' => $overdueAllocations,
    'failed_uploads' => $failedUploads,
    'overdue_orders' => $overdueOrders,
    'overdue_capas' => $overdueCapas,
    'review_sla_gaps' => $reviewSlaGaps,
    'release_followup_overdue' => $releaseFollowupOverdue,
    'wo_missing_evidence' => $woMissingEvidence,
    'program_mismatches' => $programMismatches,
    'program_release_risk' => $programReleaseRisk,
    'tool_readiness_risk' => $toolReadinessRisk,
    'alarm_ack_gaps' => $alarmAckGaps,
    'operator_qualification_gaps' => $operatorQualificationGaps,
    'material_trace_gaps' => $materialTraceGaps,
    'material_genealogy_gaps' => $materialGenealogyGaps,
    'shift_handover_gaps' => $shiftHandoverGaps,
    'connector_governance_gaps' => $connectorGovernanceGaps,
    'adapter_governance_risk' => $adapterGovernanceRisk,
    'alarm_hotspots' => $alarmHotspots,
    'nc_download_mismatches' => $ncDownloadMismatches,
    'tool_offset_risk' => $toolOffsetRisk,
    'shadow_sync_failures' => $shadowSyncFailures,
    'launch_blocker_hotspots' => $launchBlockerHotspots,
    'primary_read_fallbacks' => $primaryReadFallbacks,
    'cutover_drift_entities' => $cutoverDriftEntities,
    'epicor_sync_status' => $epicorSyncStatus,
    'downtime_governance_gaps' => $downtimeGovernanceGaps,
    'dpp_readiness_gaps' => $dppReadinessGaps,
    'energy_tracking_gaps' => $energyTrackingGaps,
    'cost_variance_risk' => $costVarianceRisk,
    'orphan_links' => $orphanLinks,
    'read_sources' => $bundle['sources'],
    'runtime_mode' => $bundle['runtime_mode'],
  ];
}

function mes_latest_signal_timestamp(array $mes, string $machineId): string {
  $latest = '';
  foreach ((array)($mes['machine_signals'] ?? []) as $row) {
    if (!is_array($row) || (string)($row['machine_id'] ?? '') !== $machineId) continue;
    $candidate = trim((string)($row['signal_at'] ?? ''));
    if ($candidate !== '' && $candidate > $latest) $latest = $candidate;
  }
  foreach ((array)($mes['connector_feeds'] ?? []) as $row) {
    if (!is_array($row) || (string)($row['machine_id'] ?? '') !== $machineId) continue;
    $candidate = trim((string)($row['last_signal_at'] ?? $row['last_heartbeat_at'] ?? ''));
    if ($candidate !== '' && $candidate > $latest) $latest = $candidate;
  }
  return $latest;
}

function mes_signal_replay_guard(array $mes, array $machine, array $normalized): ?array {
  $machineId = trim((string)($normalized['machine_id'] ?? $machine['machine_id'] ?? ''));
  if ($machineId === '') return null;
  $connectorType = strtolower(trim((string)($normalized['connector_type'] ?? $machine['connector_type'] ?? 'manual_bridge')));
  if (in_array($connectorType, ['manual_bridge', 'disabled'], true)) return null;
  $incoming = trim((string)($normalized['signal_at'] ?? ''));
  if ($incoming === '') return null;
  $latest = mes_latest_signal_timestamp($mes, $machineId);
  if ($latest === '' || $incoming >= $latest) return null;
  return [
    'ok' => false,
    'error' => 'stale_signal_timestamp',
    'message' => 'Incoming signal timestamp is older than the latest accepted machine signal.',
    'machine_id' => $machineId,
    'connector_type' => $connectorType,
    'incoming_signal_at' => $incoming,
    'latest_signal_at' => $latest,
  ];
}

function shadow_sync_master_data_store(array $data): void {
  $started = microtime(true);
  $itemCount = count((array)($data['customers'] ?? []))
    + count((array)($data['suppliers'] ?? []))
    + count((array)($data['parts'] ?? []))
    + count((array)($data['revisions'] ?? []))
    + count((array)($data['machines'] ?? []))
    + count((array)($data['work_centers'] ?? []));
  $mustSync = runtime_domain_requires_postgres_authority('master_data');
  try {
    $layer = runtime_data_layer();
    $mode = $layer->getMode();
    if ($mode === \MOM\Database\DataLayer::MODE_JSON_ONLY) {
      if ($mustSync) {
        throw new RuntimeException('runtime_master_data_authority_unavailable');
      }
      observe_shadow_sync('master_data', 'skipped', 'Shadow sync skipped because runtime is in JSON_ONLY mode.', [
        'runtime_mode' => $mode,
        'duration_ms' => round((microtime(true) - $started) * 1000, 2),
        'item_count' => $itemCount,
      ]);
      return;
    }
    $synced = $layer->syncMasterDataStore($data);
    if ($mustSync && $synced !== true) {
      throw new RuntimeException('runtime_master_data_shadow_sync_failed');
    }
    observe_shadow_sync('master_data', true, 'Shadow sync completed.', [
      'runtime_mode' => $mode,
      'duration_ms' => round((microtime(true) - $started) * 1000, 2),
      'item_count' => $itemCount,
      'customers' => count((array)($data['customers'] ?? [])),
      'parts' => count((array)($data['parts'] ?? [])),
      'machines' => count((array)($data['machines'] ?? [])),
    ]);
  } catch (Throwable $e) {
    @error_log('[runtime-shadow] master_data sync failed: ' . $e->getMessage());
    observe_shadow_sync('master_data', false, $e->getMessage(), [
      'duration_ms' => round((microtime(true) - $started) * 1000, 2),
      'item_count' => $itemCount,
    ]);
    if ($mustSync) {
      throw $e;
    }
  }
}

function shadow_sync_orders_store(array $data): void {
  $started = microtime(true);
  $itemCount = count((array)($data['sales_orders'] ?? []))
    + count((array)($data['job_orders'] ?? []))
    + count((array)($data['work_orders'] ?? []))
    + count((array)($data['form_links'] ?? []));
  $mustSync = runtime_domain_requires_postgres_authority('orders');
  try {
    $master = master_data_apply_admin_operator_projection(load_master_data_store());
    $layer = runtime_data_layer();
    $mode = $layer->getMode();
    if ($mode === \MOM\Database\DataLayer::MODE_JSON_ONLY) {
      if ($mustSync) {
        throw new RuntimeException('runtime_orders_authority_unavailable');
      }
      observe_shadow_sync('orders', 'skipped', 'Shadow sync skipped because runtime is in JSON_ONLY mode.', [
        'runtime_mode' => $mode,
        'duration_ms' => round((microtime(true) - $started) * 1000, 2),
        'item_count' => $itemCount,
      ]);
      return;
    }
    $masterSynced = $layer->syncMasterDataStore($master);
    $ordersSynced = $layer->syncOrdersStore($data);
    if ($mustSync && ($masterSynced !== true || $ordersSynced !== true)) {
      throw new RuntimeException('runtime_orders_shadow_sync_failed');
    }
    observe_shadow_sync('orders', true, 'Shadow sync completed.', [
      'runtime_mode' => $mode,
      'duration_ms' => round((microtime(true) - $started) * 1000, 2),
      'item_count' => $itemCount,
      'sales_orders' => count((array)($data['sales_orders'] ?? [])),
      'job_orders' => count((array)($data['job_orders'] ?? [])),
      'work_orders' => count((array)($data['work_orders'] ?? [])),
      'form_links' => count((array)($data['form_links'] ?? [])),
    ]);
  } catch (Throwable $e) {
    @error_log('[runtime-shadow] orders sync failed: ' . $e->getMessage());
    observe_shadow_sync('orders', false, $e->getMessage(), [
      'duration_ms' => round((microtime(true) - $started) * 1000, 2),
      'item_count' => $itemCount,
    ]);
    if ($mustSync) {
      throw $e;
    }
  }
}

function shadow_sync_mes_runtime_store(array $data, ?array $orders = null, ?array $master = null): void {
  $started = microtime(true);
  $itemCount = count((array)($data['downtime_events'] ?? []))
    + count((array)($data['maintenance_requests'] ?? []))
    + count((array)($data['progress_reports'] ?? []))
    + count((array)($data['tooling_status'] ?? []))
    + count((array)($data['connector_feeds'] ?? []))
    + count((array)($data['machine_signals'] ?? []))
    + count((array)($data['mes_connectivity_events'] ?? []))
    + count((array)($data['machine_alarm_events'] ?? []))
    + count((array)($data['nc_download_receipts'] ?? []))
    + count((array)($data['mes_tool_preset_offsets'] ?? []));
  $mustSync = runtime_domain_requires_postgres_authority('mes');
  try {
    $orders = is_array($orders) ? $orders : load_orders_store();
    $master = is_array($master) ? $master : load_master_data_store();
    $layer = runtime_data_layer();
    $mode = $layer->getMode();
    if ($mode === \MOM\Database\DataLayer::MODE_JSON_ONLY) {
      if ($mustSync) {
        throw new RuntimeException('runtime_mes_authority_unavailable');
      }
      observe_shadow_sync('mes', 'skipped', 'Shadow sync skipped because runtime is in JSON_ONLY mode.', [
        'runtime_mode' => $mode,
        'duration_ms' => round((microtime(true) - $started) * 1000, 2),
        'item_count' => $itemCount,
      ]);
      return;
    }
    $masterSynced = $layer->syncMasterDataStore($master);
    $ordersSynced = $layer->syncOrdersStore($orders);
    $mesSynced = $layer->syncMesRuntimeStore($data, $orders, $master);
    if ($mustSync && ($masterSynced !== true || $ordersSynced !== true || $mesSynced !== true)) {
      throw new RuntimeException('runtime_mes_shadow_sync_failed');
    }
    observe_shadow_sync('mes', true, 'Shadow sync completed.', [
      'runtime_mode' => $mode,
      'duration_ms' => round((microtime(true) - $started) * 1000, 2),
      'item_count' => $itemCount,
      'downtime_events' => count((array)($data['downtime_events'] ?? [])),
      'maintenance_requests' => count((array)($data['maintenance_requests'] ?? [])),
      'progress_reports' => count((array)($data['progress_reports'] ?? [])),
      'tooling_status' => count((array)($data['tooling_status'] ?? [])),
      'connector_feeds' => count((array)($data['connector_feeds'] ?? [])),
      'machine_signals' => count((array)($data['machine_signals'] ?? [])),
    ]);
  } catch (Throwable $e) {
    @error_log('[runtime-shadow] mes sync failed: ' . $e->getMessage());
    observe_shadow_sync('mes', false, $e->getMessage(), [
      'duration_ms' => round((microtime(true) - $started) * 1000, 2),
      'item_count' => $itemCount,
    ]);
    if ($mustSync) {
      throw $e;
    }
  }
}

