function build_manual_runtime_summary(array $master, array $orders, ?array $userStore = null): array {
  $master = master_data_apply_admin_operator_projection($master, $userStore);
  $masterCounts = [];
  foreach (array_unique(array_merge(
    ['customers', 'parts', 'revisions', 'operators'],
    manual_runtime_machine_entity_keys()
  )) as $key) {
    $masterCounts[$key] = count(array_values(is_array($master[$key] ?? null) ? $master[$key] : []));
  }
  $machineCounts = [];
  foreach (manual_runtime_machine_entity_keys() as $key) {
    $machineCounts[$key] = (int)($masterCounts[$key] ?? 0);
  }

  $salesOrders = array_values(is_array($orders['sales_orders'] ?? null) ? $orders['sales_orders'] : []);
  $jobOrders = array_values(is_array($orders['job_orders'] ?? null) ? $orders['job_orders'] : []);
  $workOrders = array_values(is_array($orders['work_orders'] ?? null) ? $orders['work_orders'] : []);
  $rows = [];

  foreach ($salesOrders as $so) {
    if (!is_array($so)) continue;
    $rows[] = [
      'type' => 'SO',
      'id' => (string)($so['so_number'] ?? ''),
      'title' => implode(' · ', array_values(array_filter([
        trim((string)($so['customer_name'] ?? $so['customer_id'] ?? '')),
        trim((string)($so['customer_po'] ?? '')) !== '' ? ('PO ' . trim((string)($so['customer_po'] ?? ''))) : '',
      ], static fn($value) => $value !== ''))),
      'status' => (string)($so['status'] ?? ''),
      'updated_at' => (string)($so['updated_at'] ?? $so['created_at'] ?? ''),
    ];
  }

  foreach ($jobOrders as $jo) {
    if (!is_array($jo)) continue;
    $rows[] = [
      'type' => 'JO',
      'id' => (string)($jo['jo_number'] ?? ''),
      'title' => implode(' / ', array_values(array_filter([
        trim((string)($jo['part_number'] ?? '')),
        trim((string)($jo['part_revision'] ?? '')),
      ], static fn($value) => $value !== ''))),
      'status' => (string)($jo['status'] ?? ''),
      'updated_at' => (string)($jo['updated_at'] ?? $jo['created_at'] ?? ''),
    ];
  }

  foreach ($workOrders as $wo) {
    if (!is_array($wo)) continue;
    $operation = trim((string)($wo['operation_number'] ?? ''));
    $rows[] = [
      'type' => 'WO',
      'id' => (string)($wo['wo_number'] ?? ''),
      'title' => implode(' · ', array_values(array_filter([
        $operation !== '' ? ('OP' . $operation) : '',
        trim((string)($wo['operation_desc'] ?? '')),
        trim((string)($wo['machine_id'] ?? '')),
      ], static fn($value) => $value !== ''))),
      'status' => (string)($wo['status'] ?? ''),
      'updated_at' => (string)($wo['updated_at'] ?? $wo['created_at'] ?? ''),
    ];
  }

  usort($rows, static function (array $a, array $b): int {
    return strcmp((string)($b['updated_at'] ?? ''), (string)($a['updated_at'] ?? ''));
  });

  $recentRows = array_slice($rows, 0, 10);

  return [
    'master_counts' => $masterCounts,
    'machine_runtime_entities' => manual_runtime_machine_entity_keys(),
    'machine_runtime_counts' => $machineCounts,
    'frontend_endpoint_contracts' => manual_runtime_frontend_endpoint_contracts(),
    'process_endpoint_contracts' => order_runtime_frontend_endpoint_contracts(),
    'order_counts' => [
      'so' => count($salesOrders),
      'jo' => count($jobOrders),
      'wo' => count($workOrders),
    ],
    'recent_rows' => $recentRows,
    'last_event_at' => (string)($recentRows[0]['updated_at'] ?? ''),
    'master_updated_at' => (string)($master['_meta']['updated'] ?? ''),
    'orders_updated_at' => (string)($orders['_meta']['updated'] ?? ''),
    'operator_authority' => is_array($master['_meta']['operator_authority'] ?? null) ? $master['_meta']['operator_authority'] : [],
  ];
}

function find_order_record(array $store, string $entity, string $id): ?array {
  $meta = order_entity_config($entity);
  foreach (($store[$meta['store_key']] ?? []) as $row) {
    if (is_array($row) && (string)($row[$meta['number_key']] ?? '') === $id) return $row;
  }
  return null;
}

function master_index_by(array $rows, string $key): array {
  $index = [];
  foreach ($rows as $row) {
    if (!is_array($row)) continue;
    $id = trim((string)($row[$key] ?? ''));
    if ($id === '') continue;
    $index[$id] = $row;
  }
  return $index;
}

function mes_clamp_percent(float $value): float {
  return round(max(0.0, min(100.0, $value)), 1);
}

function mes_percent(float $numerator, float $denominator, ?float $fallback = null): ?float {
  if ($denominator <= 0) return $fallback;
  return mes_clamp_percent(($numerator / $denominator) * 100);
}

function mes_minutes_between(string $startAt = '', string $endAt = '', ?DateTimeImmutable $now = null): float {
  if ($startAt === '') return 0.0;
  try {
    $start = new DateTimeImmutable($startAt);
    $end = $endAt !== '' ? new DateTimeImmutable($endAt) : ($now ?: new DateTimeImmutable('now', new DateTimeZone('Asia/Ho_Chi_Minh')));
    $seconds = max(0, $end->getTimestamp() - $start->getTimestamp());
    return round($seconds / 60, 1);
  } catch (Throwable) {
    return 0.0;
  }
}

function mes_timestamp_age_seconds(string $timestamp = '', ?DateTimeImmutable $now = null): ?int {
  $timestamp = trim($timestamp);
  if ($timestamp === '') return null;
  try {
    $dt = new DateTimeImmutable($timestamp);
  } catch (Throwable) {
    return null;
  }
  $now = $now ?: new DateTimeImmutable('now', new DateTimeZone('Asia/Ho_Chi_Minh'));
  return max(0, $now->getTimestamp() - $dt->getTimestamp());
}

function mes_machine_state_normalize(string $state = ''): string {
  $state = strtolower(trim($state));
  $map = [
    'running' => 'running',
    'executing' => 'running',
    'cycle' => 'running',
    'cutting' => 'running',
    'setup' => 'setup',
    'set_up' => 'setup',
    'inspection' => 'inspection',
    'probing' => 'inspection',
    'measure' => 'inspection',
    'on_hold' => 'on_hold',
    'hold' => 'on_hold',
    'feed_hold' => 'on_hold',
    'stopped' => 'idle',
    'idle' => 'idle',
    'ready' => 'idle',
    'scheduled' => 'scheduled',
    'maintenance' => 'maintenance',
    'service' => 'maintenance',
    'down' => 'down',
    'alarm' => 'down',
    'fault' => 'down',
    'estop' => 'down',
    'offline' => 'offline',
  ];
  return $map[$state] ?? $state;
}

function mes_connector_health_from_age(?int $ageSeconds, int $slaSeconds = 120, string $connectorType = 'manual_bridge'): string {
  $connectorType = strtolower(trim($connectorType));
  $slaSeconds = max(30, $slaSeconds);
  if ($connectorType === 'disabled') return 'disabled';
  if (in_array($connectorType, ['manual', 'manual_bridge'], true) && $ageSeconds === null) return 'manual_only';
  if ($ageSeconds === null) return 'offline';
  if ($ageSeconds <= $slaSeconds) return 'healthy';
  if ($ageSeconds <= ($slaSeconds * 3)) return 'delayed';
  return 'stale';
}

function mes_latest_rows_by_machine(array $rows, string $timeKey = 'updated_at'): array {
  $indexed = [];
  foreach ($rows as $row) {
    if (!is_array($row)) continue;
    $machineId = trim((string)($row['machine_id'] ?? ''));
    if ($machineId === '') continue;
    $candidateTs = trim((string)($row[$timeKey] ?? $row['last_heartbeat_at'] ?? $row['signal_at'] ?? ''));
    if (!isset($indexed[$machineId])) {
      $indexed[$machineId] = $row;
      continue;
    }
    $current = $indexed[$machineId];
    $currentTs = trim((string)($current[$timeKey] ?? $current['last_heartbeat_at'] ?? $current['signal_at'] ?? ''));
    if ($candidateTs !== '' && strcmp($candidateTs, $currentTs) >= 0) {
      $indexed[$machineId] = $row;
    }
  }
  return $indexed;
}

function mes_latest_rows_by_key(array $rows, string $key, array $timeKeys = ['updated_at', 'recorded_at', 'created_at']): array {
  $indexed = [];
  foreach ($rows as $row) {
    if (!is_array($row)) continue;
    $value = trim((string)($row[$key] ?? ''));
    if ($value === '') continue;
    $candidateTs = '';
    foreach ($timeKeys as $timeKey) {
      $candidateTs = trim((string)($row[$timeKey] ?? ''));
      if ($candidateTs !== '') break;
    }
    if (!isset($indexed[$value])) {
      $indexed[$value] = $row;
      continue;
    }
    $current = $indexed[$value];
    $currentTs = '';
    foreach ($timeKeys as $timeKey) {
      $currentTs = trim((string)($current[$timeKey] ?? ''));
      if ($currentTs !== '') break;
    }
    if ($candidateTs !== '' && strcmp($candidateTs, $currentTs) >= 0) {
      $indexed[$value] = $row;
    }
  }
  return $indexed;
}

function load_mes_gate_rules(): array {
  global $CONF_DIR;
  $file = $CONF_DIR . '/mes_evidence_gate_rules.json';
  $data = read_json_file($file);
  if (is_array($data) && is_array($data['rules'] ?? null)) {
    return array_values(array_filter($data['rules'], fn($row) => is_array($row)));
  }
  return [];
}

function load_mes_shift_patterns(): array {
  global $CONF_DIR;
  $file = $CONF_DIR . '/mes_shift_patterns.json';
  $data = read_json_file($file);
  if (!is_array($data)) {
    return [
      'timezone' => 'Asia/Ho_Chi_Minh',
      'shift_handover_grace_minutes' => 45,
      'stale_progress_minutes' => 90,
      'shifts' => [],
    ];
  }
  $data['timezone'] = trim((string)($data['timezone'] ?? 'Asia/Ho_Chi_Minh')) ?: 'Asia/Ho_Chi_Minh';
  $data['shift_handover_grace_minutes'] = max(0, (int)($data['shift_handover_grace_minutes'] ?? 45));
  $data['stale_progress_minutes'] = max(15, (int)($data['stale_progress_minutes'] ?? 90));
  $data['shifts'] = array_values(array_filter((array)($data['shifts'] ?? []), fn($row) => is_array($row)));
  return $data;
}

function mes_shift_time_to_minutes(string $value): ?int {
  $raw = trim($value);
  if (!preg_match('/^\d{2}:\d{2}$/', $raw)) return null;
  [$hours, $minutes] = array_map('intval', explode(':', $raw));
  if ($hours < 0 || $hours > 23 || $minutes < 0 || $minutes > 59) return null;
  return ($hours * 60) + $minutes;
}

function mes_resolve_current_shift(array $patterns, DateTimeImmutable $now): array {
  $timezone = new DateTimeZone((string)($patterns['timezone'] ?? 'Asia/Ho_Chi_Minh'));
  $localNow = $now->setTimezone($timezone);
  $currentMinutes = ((int)$localNow->format('H')) * 60 + (int)$localNow->format('i');

  foreach ((array)($patterns['shifts'] ?? []) as $shift) {
    if (!is_array($shift)) continue;
    $start = mes_shift_time_to_minutes((string)($shift['start'] ?? ''));
    $end = mes_shift_time_to_minutes((string)($shift['end'] ?? ''));
    if ($start === null || $end === null) continue;

    $wraps = $end <= $start;
    $inWindow = $wraps
      ? ($currentMinutes >= $start || $currentMinutes < $end)
      : ($currentMinutes >= $start && $currentMinutes < $end);
    if (!$inWindow) continue;

    $startDate = $localNow->setTime(intdiv($start, 60), $start % 60, 0);
    $endDate = $localNow->setTime(intdiv($end, 60), $end % 60, 0);
    if ($wraps) {
      if ($currentMinutes < $end) {
        $startDate = $startDate->modify('-1 day');
      } else {
        $endDate = $endDate->modify('+1 day');
      }
    }

    return [
      'shift_code' => (string)($shift['shift_code'] ?? ''),
      'shift_name_vi' => (string)($shift['shift_name_vi'] ?? $shift['shift_code'] ?? ''),
      'shift_name_en' => (string)($shift['shift_name_en'] ?? $shift['shift_code'] ?? ''),
      'start' => (string)($shift['start'] ?? ''),
      'end' => (string)($shift['end'] ?? ''),
      'window_start' => $startDate->format(DATE_ATOM),
      'window_end' => $endDate->format(DATE_ATOM),
      'is_wrap' => $wraps,
    ];
  }

  return [
    'shift_code' => '',
    'shift_name_vi' => 'Chưa xác định ca',
    'shift_name_en' => 'Unresolved shift',
    'start' => '',
    'end' => '',
    'window_start' => '',
    'window_end' => '',
    'is_wrap' => false,
  ];
}

function mes_latest_shift_handover_by_machine(array $rows): array {
  $indexed = [];
  foreach ($rows as $row) {
    if (!is_array($row)) continue;
    $machineId = trim((string)($row['machine_id'] ?? ''));
    if ($machineId === '') continue;
    $current = $indexed[$machineId] ?? null;
    $candidateTs = trim((string)($row['created_at'] ?? $row['acknowledged_at'] ?? ''));
    $currentTs = is_array($current) ? trim((string)($current['created_at'] ?? $current['acknowledged_at'] ?? '')) : '';
    if (!is_array($current) || strcmp($candidateTs, $currentTs) > 0) {
      $indexed[$machineId] = $row;
    }
  }
  return $indexed;
}

function mes_build_shift_handover_queue(array $machineWall, array $handoverByMachine, array $shiftPatterns, array $currentShift, DateTimeImmutable $now): array {
  $rows = [];
  $graceMinutes = max(0, (int)($shiftPatterns['shift_handover_grace_minutes'] ?? 45));
  $windowStart = trim((string)($currentShift['window_start'] ?? ''));
  $shiftCode = trim((string)($currentShift['shift_code'] ?? ''));
  $graceDeadline = '';
  if ($windowStart !== '' && $graceMinutes > 0) {
    try {
      $graceDeadline = (new DateTimeImmutable($windowStart))->modify('+' . $graceMinutes . ' minutes')->format(DATE_ATOM);
    } catch (Throwable) {
      $graceDeadline = '';
    }
  }

  foreach ($machineWall as $row) {
    if (!is_array($row)) continue;
    $machineId = trim((string)($row['machine_id'] ?? ''));
    if ($machineId === '') continue;

    $activeContext = (int)($row['queue_count'] ?? 0) > 0 || in_array((string)($row['status'] ?? ''), ['running', 'setup', 'inspection', 'down'], true);
    if (!$activeContext) continue;

    $handover = is_array($handoverByMachine[$machineId] ?? null) ? $handoverByMachine[$machineId] : [];
    $issues = [];
    $warnings = [];
    $ackAt = trim((string)($handover['acknowledged_at'] ?? ''));
    $createdAt = trim((string)($handover['created_at'] ?? ''));
    $shiftTo = trim((string)($handover['shift_to'] ?? ''));

    if ($shiftCode !== '') {
      if ($handover === []) {
        $issues[] = 'handover_missing';
      } elseif ($shiftTo !== '' && strcasecmp($shiftTo, $shiftCode) !== 0) {
        $issues[] = 'handover_shift_mismatch';
      }
    }

    if ($handover !== [] && $ackAt === '') {
      $ageToGrace = $graceDeadline !== '' ? mes_timestamp_age_seconds($graceDeadline, $now) : null;
      if ($ageToGrace !== null && $ageToGrace >= 0) {
        $issues[] = 'handover_ack_overdue';
      } else {
        $warnings[] = 'handover_ack_pending';
      }
    }

    $lastProgressAt = trim((string)($row['active_work_order']['actual_start'] ?? $row['active_work_order']['scheduled_start'] ?? ''));
    $staleProgressMinutes = max(15, (int)($shiftPatterns['stale_progress_minutes'] ?? 90));
    if ($lastProgressAt !== '' && $handover === []) {
      $ageSeconds = mes_timestamp_age_seconds($lastProgressAt, $now);
      if ($ageSeconds !== null && $ageSeconds > ($staleProgressMinutes * 60)) {
        $warnings[] = 'handover_stale_progress';
      }
    }

    if (!$issues && !$warnings) continue;

    $rows[] = [
      'machine_id' => $machineId,
      'machine_name' => (string)($row['machine_name'] ?? ''),
      'work_center_id' => (string)($row['work_center_id'] ?? ''),
      'wo_number' => (string)($row['active_work_order']['wo_number'] ?? ''),
      'customer_name' => (string)($row['active_work_order']['customer_name'] ?? ''),
      'part_number' => (string)($row['active_work_order']['part_number'] ?? ''),
      'part_revision' => (string)($row['active_work_order']['part_revision'] ?? ''),
      'current_shift' => $shiftCode,
      'handover_id' => (string)($handover['handover_id'] ?? ''),
      'shift_from' => (string)($handover['shift_from'] ?? ''),
      'shift_to' => $shiftTo,
      'operator_from' => (string)($handover['operator_from'] ?? ''),
      'operator_to' => (string)($handover['operator_to'] ?? ''),
      'acknowledged_at' => $ackAt,
      'created_at' => $createdAt,
      'issues_noted' => (string)($handover['issues_noted'] ?? ''),
      'pending_actions' => (string)($handover['pending_actions'] ?? ''),
      'quality_alerts' => (string)($handover['quality_alerts'] ?? ''),
      'tooling_status' => (string)($handover['tooling_status'] ?? ''),
      'issue_codes' => array_values(array_unique($issues)),
      'warning_codes' => array_values(array_unique($warnings)),
      'severity' => $issues ? 'critical' : 'warning',
      'message_vi' => $issues
        ? 'Máy chưa có bàn giao ca hợp lệ cho ca hiện tại hoặc chưa được xác nhận đúng hạn.'
        : 'Máy cần xác nhận bàn giao ca hoặc rà soát các điểm tồn đọng trước khi tiếp tục ca.',
      'message_en' => $issues
        ? 'The machine does not yet have a valid shift handover for the current shift or it is overdue for acknowledgement.'
        : 'The machine needs a shift handover acknowledgement or a quick review of pending carry-over items.',
    ];
  }

  usort($rows, static function ($a, $b) {
    $priority = ['critical' => 0, 'warning' => 1];
    $ap = $priority[(string)($a['severity'] ?? 'warning')] ?? 9;
    $bp = $priority[(string)($b['severity'] ?? 'warning')] ?? 9;
    if ($ap !== $bp) return $ap <=> $bp;
    return strcmp((string)($a['machine_id'] ?? ''), (string)($b['machine_id'] ?? ''));
  });

  return $rows;
}

function mes_form_link_index(array $orders): array {
  $index = ['so' => [], 'jo' => [], 'wo' => []];
  foreach ((array)($orders['form_links'] ?? []) as $link) {
    if (!is_array($link)) continue;
    $type = strtolower(trim((string)($link['order_type'] ?? '')));
    $id = trim((string)($link['order_id'] ?? ''));
    if ($id === '' || !isset($index[$type])) continue;
    $index[$type][$id][] = $link;
  }
  return $index;
}

function mes_gate_requirement_applies(array $rule, array $dispatchRow, array $jo, ?array $openDowntime, ?array $openMaintenance): bool {
  $statuses = array_map('strtolower', array_values((array)($rule['wo_statuses'] ?? [])));
  if (!empty($statuses) && !in_array(strtolower((string)($dispatchRow['status'] ?? '')), $statuses, true)) {
    return false;
  }
  $workCenters = array_map('strtoupper', array_values((array)($rule['work_center_ids'] ?? [])));
  if (!empty($workCenters) && !in_array(strtoupper((string)($dispatchRow['work_center_id'] ?? '')), $workCenters, true)) {
    return false;
  }
  $trigger = strtolower(trim((string)($rule['trigger'] ?? 'always')));
  return match ($trigger) {
    'always' => true,
    'open_downtime' => $openDowntime !== null,
    'open_maintenance' => $openMaintenance !== null,
    'fai_required' => (bool)($jo['fai_required'] ?? false),
    default => true,
  };
}

function mes_evidence_gate_summary(array $dispatchRow, array $jo, array $woLinks, ?array $openDowntime, ?array $openMaintenance, array $rules): array {
  $required = [];
  foreach ($rules as $rule) {
    if (!is_array($rule) || !mes_gate_requirement_applies($rule, $dispatchRow, $jo, $openDowntime, $openMaintenance)) continue;
    $required[] = [
      'rule_id' => (string)($rule['rule_id'] ?? ''),
      'label' => (string)($rule['label'] ?? ''),
      'label_vi' => (string)($rule['label_vi'] ?? $rule['label'] ?? ''),
      'required_form_codes' => array_values(array_filter(array_map('strtoupper', array_values((array)($rule['required_form_codes'] ?? []))))),
    ];
  }

  $linkedCodes = [];
  foreach ($woLinks as $link) {
    if (!is_array($link)) continue;
    $code = strtoupper(trim((string)($link['form_code'] ?? '')));
    if ($code !== '') $linkedCodes[$code] = true;
  }

  $items = [];
  $missingFormCodes = [];
  foreach ($required as $gate) {
    $codes = array_values((array)($gate['required_form_codes'] ?? []));
    $missing = array_values(array_filter($codes, fn($code) => empty($linkedCodes[$code])));
    $items[] = [
      'rule_id' => $gate['rule_id'],
      'label' => $gate['label'],
      'label_vi' => $gate['label_vi'],
      'required_form_codes' => $codes,
      'missing_form_codes' => $missing,
      'is_ready' => empty($missing),
    ];
    foreach ($missing as $code) $missingFormCodes[$code] = true;
  }

  $totalRequired = count($items);
  $completedCount = count(array_filter($items, fn($row) => !empty($row['is_ready'])));
  $status = 'not_required';
  if ($totalRequired > 0) {
    if ($completedCount === $totalRequired) $status = 'ready';
    elseif ($completedCount > 0) $status = 'partial';
    else $status = 'missing';
  }

  $summaryVi = match ($status) {
    'ready' => 'Đủ gate vận hành',
    'partial' => 'Thiếu một phần gate',
    'missing' => 'Thiếu gate bắt buộc',
    default => 'Không yêu cầu gate',
  };
  $summaryEn = match ($status) {
    'ready' => 'Ready',
    'partial' => 'Partial',
    'missing' => 'Missing gates',
    default => 'Not required',
  };

  return [
    'status' => $status,
    'total_required' => $totalRequired,
    'completed_count' => $completedCount,
    'items' => $items,
    'missing_form_codes' => array_keys($missingFormCodes),
    'linked_form_codes' => array_keys($linkedCodes),
    'summary_vi' => $summaryVi,
    'summary_en' => $summaryEn,
  ];
}

function mes_tool_life_percent(array $row): ?float {
  $values = [];
  $limitMinutes = (float)($row['life_limit_minutes'] ?? 0);
  $usedMinutes = (float)($row['life_used_minutes'] ?? 0);
  if ($limitMinutes > 0) $values[] = ($usedMinutes / $limitMinutes) * 100;
  $limitParts = (float)($row['life_limit_parts'] ?? 0);
  $usedParts = (float)($row['life_used_parts'] ?? 0);
  if ($limitParts > 0) $values[] = ($usedParts / $limitParts) * 100;
  if (empty($values)) return null;
  return mes_clamp_percent((float)max($values));
}

function mes_tool_alert_payload(array $row): array {
  $lifePct = mes_tool_life_percent($row);
  $warning = (float)($row['warning_pct'] ?? 80);
  $critical = (float)($row['critical_pct'] ?? 95);
  $toolStatus = strtolower(trim((string)($row['tool_status'] ?? 'loaded')));
  $offsetStatus = strtolower(trim((string)($row['offset_status'] ?? 'verified')));

  $level = 'healthy';
  if (in_array($toolStatus, ['broken', 'quarantine', 'expired'], true)) {
    $level = 'critical';
  } elseif ($lifePct !== null && $lifePct >= $critical) {
    $level = 'critical';
  } elseif ($offsetStatus === 'out_of_control') {
    $level = 'critical';
  } elseif ($lifePct !== null && $lifePct >= $warning) {
    $level = 'warning';
  } elseif (in_array($offsetStatus, ['adjustment_required', 'adjusted'], true)) {
    $level = 'warning';
  } elseif ($lifePct === null && trim((string)($row['tool_id'] ?? '')) === '') {
    $level = 'untracked';
  }

  $messageVi = 'Tool đang ổn định.';
  $messageEn = 'Tool condition is stable.';
  if ($level === 'critical') {
    if (in_array($toolStatus, ['broken', 'quarantine', 'expired'], true)) {
      $messageVi = 'Tool đã vượt ngưỡng an toàn hoặc bị cách ly.';
      $messageEn = 'Tool is beyond safe operating condition or quarantined.';
    } elseif ($offsetStatus === 'out_of_control') {
      $messageVi = 'Offset vượt giới hạn kiểm soát.';
      $messageEn = 'Offset is out of control.';
    } else {
      $messageVi = 'Tool đã chạm ngưỡng life tới hạn.';
      $messageEn = 'Tool has reached the critical life threshold.';
    }
  } elseif ($level === 'warning') {
    if (in_array($offsetStatus, ['adjustment_required', 'adjusted'], true)) {
      $messageVi = 'Tool cần xác nhận lại offset trước khi chạy tiếp.';
      $messageEn = 'Tool needs offset verification before the next run.';
    } else {
      $messageVi = 'Tool đang tiến gần ngưỡng thay dao.';
      $messageEn = 'Tool is approaching the change threshold.';
    }
  } elseif ($level === 'untracked') {
    $messageVi = 'WO chưa có tool-life runtime.';
    $messageEn = 'No tool-life runtime is tracked for this WO.';
  }

  $row['life_used_pct'] = $lifePct;
  $row['alert_level'] = $level;
  $row['alert_message_vi'] = $messageVi;
  $row['alert_message_en'] = $messageEn;
  return $row;
}

function mes_is_cutting_resource(string $workCenterId, string $machineType = ''): bool {
  $center = strtoupper(trim($workCenterId));
  $type = strtolower(trim($machineType));
  if (in_array($center, ['WC-5AX', 'WC-3AX', 'WC-TURN', 'WC-MTURN'], true)) return true;
  return in_array($type, ['5-axis', '3-axis', 'turning', 'mill-turn'], true);
}

function mes_program_release_summary(array $dispatchRow, array $programReleases): array {
  $expectedProgram = trim((string)($dispatchRow['nc_program_id'] ?? ''));
  $workCenterId = trim((string)($dispatchRow['work_center_id'] ?? ''));
  $machineType = trim((string)($dispatchRow['machine_type'] ?? ''));
  $partNumber = trim((string)($dispatchRow['part_number'] ?? ''));
  $partRevision = trim((string)($dispatchRow['part_revision'] ?? ''));
  $operationNumber = (int)($dispatchRow['operation_number'] ?? 0);

  if (!mes_is_cutting_resource($workCenterId, $machineType)) {
    return [
      'band' => 'not_required',
      'status' => 'not_required',
      'severity' => 'info',
      'release_found' => false,
      'summary_vi' => 'Không yêu cầu NC release',
      'summary_en' => 'NC release not required',
      'message_vi' => 'WO này không thuộc nhóm máy cắt cần khóa NC release.',
      'message_en' => 'This WO is not on a cutting resource that requires NC release governance.',
      'program_id' => $expectedProgram,
      'checksum' => '',
      'release_status' => '',
      'released_at' => '',
      'released_by' => '',
      'context_issues' => [],
      'cam_source_rev' => '',
      'post_processor_rev' => '',
      'release_title' => '',
    ];
  }

  if ($expectedProgram === '') {
    return [
      'band' => 'warning',
      'status' => 'missing_reference',
      'severity' => 'warning',
      'release_found' => false,
      'summary_vi' => 'WO chưa có mã NC kỳ vọng',
      'summary_en' => 'WO has no expected NC program',
      'message_vi' => 'Work order chưa khai báo nc_program_id nên không thể khóa handshake trước khi chạy.',
      'message_en' => 'The work order has no nc_program_id, so the handshake cannot be governed before run.',
      'program_id' => '',
      'checksum' => '',
      'release_status' => '',
      'released_at' => '',
      'released_by' => '',
      'context_issues' => [],
      'cam_source_rev' => '',
      'post_processor_rev' => '',
      'release_title' => '',
    ];
  }

  $release = is_array($programReleases[$expectedProgram] ?? null) ? $programReleases[$expectedProgram] : null;
  if ($release === null) {
    return [
      'band' => 'critical',
      'status' => 'missing_release',
      'severity' => 'critical',
      'release_found' => false,
      'summary_vi' => 'Không tìm thấy NC release',
      'summary_en' => 'Released NC not found',
      'message_vi' => 'WO đang tham chiếu chương trình NC chưa có trong controlled master.',
      'message_en' => 'The WO points to an NC program that does not exist in the controlled master.',
      'program_id' => $expectedProgram,
      'checksum' => '',
      'release_status' => '',
      'released_at' => '',
      'released_by' => '',
      'context_issues' => [],
      'cam_source_rev' => '',
      'post_processor_rev' => '',
      'release_title' => '',
    ];
  }

  $releaseStatus = strtolower(trim((string)($release['status'] ?? 'draft')));
  $contextIssues = [];
  if ($partNumber !== '' && trim((string)($release['part_number'] ?? '')) !== '' && strcasecmp((string)$release['part_number'], $partNumber) !== 0) {
    $contextIssues[] = 'part_mismatch';
  }
  if ($partRevision !== '' && trim((string)($release['part_revision'] ?? '')) !== '' && strcasecmp((string)$release['part_revision'], $partRevision) !== 0) {
    $contextIssues[] = 'revision_mismatch';
  }
  if ($operationNumber > 0 && (int)($release['operation_number'] ?? 0) > 0 && (int)$release['operation_number'] !== $operationNumber) {
    $contextIssues[] = 'operation_mismatch';
  }
  if ($machineType !== '' && trim((string)($release['machine_type'] ?? '')) !== '' && !in_array(strtolower((string)$release['machine_type']), ['multi', strtolower($machineType)], true)) {
    $contextIssues[] = 'machine_type_mismatch';
  }
  if ($workCenterId !== '' && trim((string)($release['work_center_id'] ?? '')) !== '' && strcasecmp((string)$release['work_center_id'], $workCenterId) !== 0) {
    $contextIssues[] = 'work_center_mismatch';
  }

  $band = 'ready';
  $status = 'released';
  $severity = 'info';
  $summaryVi = 'NC release hợp lệ';
  $summaryEn = 'NC release is valid';
  $messageVi = 'WO đang tham chiếu đúng bản release đã kiểm soát.';
  $messageEn = 'The WO points to the correct governed NC release.';

  if (!empty($contextIssues)) {
    $band = 'critical';
    $status = 'context_mismatch';
    $severity = 'critical';
    $summaryVi = 'NC release lệch ngữ cảnh';
    $summaryEn = 'NC release context mismatch';
    $messageVi = 'Bản NC release tồn tại nhưng không khớp part / rev / operation / machine context của WO.';
    $messageEn = 'The NC release exists but does not match the WO part / revision / operation / machine context.';
  } elseif ($releaseStatus !== 'released') {
    $band = in_array($releaseStatus, ['blocked', 'superseded', 'obsolete'], true) ? 'critical' : 'warning';
    $status = $releaseStatus === 'draft' ? 'not_released' : $releaseStatus;
    $severity = $band === 'critical' ? 'critical' : 'warning';
    $summaryVi = $releaseStatus === 'draft' ? 'NC chưa release' : 'NC release bị chặn';
    $summaryEn = $releaseStatus === 'draft' ? 'NC not released' : 'NC release blocked';
    $messageVi = $releaseStatus === 'draft'
      ? 'Chương trình NC đã có master record nhưng chưa ở trạng thái released.'
      : 'Chương trình NC master đang ở trạng thái không được phép đưa vào sản xuất.';
    $messageEn = $releaseStatus === 'draft'
      ? 'The NC program has a master record but it is not yet in released status.'
      : 'The NC program master is in a status that is not allowed for production use.';
  }

  return [
    'band' => $band,
    'status' => $status,
    'severity' => $severity,
    'release_found' => true,
    'summary_vi' => $summaryVi,
    'summary_en' => $summaryEn,
    'message_vi' => $messageVi,
    'message_en' => $messageEn,
    'program_id' => $expectedProgram,
    'checksum' => (string)($release['checksum'] ?? ''),
    'release_status' => (string)($release['status'] ?? ''),
    'released_at' => (string)($release['released_at'] ?? ''),
    'released_by' => (string)($release['released_by'] ?? ''),
    'context_issues' => $contextIssues,
    'cam_source_rev' => (string)($release['cam_source_rev'] ?? ''),
    'post_processor_rev' => (string)($release['post_processor_rev'] ?? ''),
    'release_title' => (string)($release['release_title'] ?? ''),
  ];
}

function mes_tool_readiness_summary(array $dispatchRow): array {
  $tooling = (array)($dispatchRow['tooling'] ?? []);
  $items = array_values((array)($tooling['items'] ?? []));
  $workCenterId = trim((string)($dispatchRow['work_center_id'] ?? ''));
  $machineType = trim((string)($dispatchRow['machine_type'] ?? ''));
  $loadedToolCount = (int)($tooling['loaded_tool_count'] ?? count($items));
  $needsTooling = mes_is_cutting_resource($workCenterId, $machineType);

  if (!$needsTooling) {
    return [
      'band' => 'not_required',
      'status' => 'not_required',
      'severity' => 'info',
      'summary_vi' => 'Không yêu cầu tooling runtime',
      'summary_en' => 'Tooling runtime not required',
      'message_vi' => 'WO này không thuộc nhóm công đoạn cần kiểm soát tool-life theo runtime MES.',
      'message_en' => 'This WO is not in a process family that requires MES tool-life runtime governance.',
      'loaded_tool_count' => $loadedToolCount,
      'alert_count' => 0,
      'top_tool_id' => '',
      'top_tool_runtime_id' => '',
      'top_issue' => '',
      'highest_life_pct' => null,
    ];
  }

  if ($loadedToolCount <= 0 || empty($items)) {
    return [
      'band' => 'warning',
      'status' => 'untracked',
      'severity' => 'warning',
      'summary_vi' => 'Chưa có tool-life runtime',
      'summary_en' => 'No tool-life runtime',
      'message_vi' => 'WO đang ở cell gia công nhưng chưa có runtime dao / tooling để khóa mức sẵn sàng.',
      'message_en' => 'The WO is on a machining cell but has no runtime tool / tooling data to govern readiness.',
      'loaded_tool_count' => 0,
      'alert_count' => 0,
      'top_tool_id' => '',
      'top_tool_runtime_id' => '',
      'top_issue' => 'missing_runtime',
      'highest_life_pct' => null,
    ];
  }

  $critical = null;
  $warning = null;
  $untracked = null;
  $highestLife = null;
  foreach ($items as $item) {
    if (!is_array($item)) continue;
    $life = isset($item['life_used_pct']) ? (float)$item['life_used_pct'] : null;
    if ($life !== null) $highestLife = $highestLife === null ? $life : max($highestLife, $life);
    $level = (string)($item['alert_level'] ?? 'healthy');
    if ($critical === null && $level === 'critical') $critical = $item;
    if ($warning === null && $level === 'warning') $warning = $item;
    if ($untracked === null && $level === 'untracked') $untracked = $item;
  }

  $focus = $critical ?? $warning ?? $untracked;
  $band = 'ready';
  $status = 'ready';
  $severity = 'info';
  $summaryVi = 'Tooling sẵn sàng chạy';
  $summaryEn = 'Tooling is ready';
  $messageVi = 'Tooling runtime đang ổn định và không có cảnh báo chặn chạy.';
  $messageEn = 'Tooling runtime is stable and there is no blocking readiness alert.';

  if ($critical) {
    $band = 'critical';
    $status = 'critical';
    $severity = 'critical';
    $summaryVi = 'Tooling tới hạn';
    $summaryEn = 'Tooling is critical';
    $messageVi = (string)($critical['alert_message_vi'] ?? 'Có tool đã tới hạn hoặc offset vượt kiểm soát.');
    $messageEn = (string)($critical['alert_message_en'] ?? 'A tool is critical or the offset is out of control.');
  } elseif ($warning) {
    $band = 'warning';
    $status = 'warning';
    $severity = 'warning';
    $summaryVi = 'Tooling cần xác nhận lại';
    $summaryEn = 'Tooling needs reconfirmation';
    $messageVi = (string)($warning['alert_message_vi'] ?? 'Có tool gần ngưỡng life hoặc cần xác nhận lại offset.');
    $messageEn = (string)($warning['alert_message_en'] ?? 'A tool is nearing its life limit or needs offset reconfirmation.');
  } elseif ($untracked) {
    $band = 'warning';
    $status = 'untracked';
    $severity = 'warning';
    $summaryVi = 'Tooling chưa được theo dõi chuẩn';
    $summaryEn = 'Tooling is not fully tracked';
    $messageVi = (string)($untracked['alert_message_vi'] ?? 'Có tooling chưa được theo dõi tool-life đúng chuẩn.');
    $messageEn = (string)($untracked['alert_message_en'] ?? 'Some tooling is not governed by the standard tool-life runtime.');
  }

  return [
    'band' => $band,
    'status' => $status,
    'severity' => $severity,
    'summary_vi' => $summaryVi,
    'summary_en' => $summaryEn,
    'message_vi' => $messageVi,
    'message_en' => $messageEn,
    'loaded_tool_count' => $loadedToolCount,
    'alert_count' => (int)($tooling['alert_count'] ?? 0),
    'top_tool_id' => (string)($focus['tool_id'] ?? ''),
    'top_tool_runtime_id' => (string)($focus['tool_runtime_id'] ?? ''),
    'top_issue' => $focus ? (string)($focus['alert_level'] ?? '') : '',
    'highest_life_pct' => $highestLife,
  ];
}

