      'message_vi' => (string)($summary['message_vi'] ?? ''),
      'message_en' => (string)($summary['message_en'] ?? ''),
    ];
  }
  usort($rows, static function ($a, $b) {
    $priority = ['critical' => 0, 'warning' => 1, 'info' => 2];
