    $priority = ['critical' => 0, 'warning' => 1, 'info' => 2];
    $ap = $priority[(string)($a['severity'] ?? 'info')] ?? 9;
    $bp = $priority[(string)($b['severity'] ?? 'info')] ?? 9;
    if ($ap !== $bp) return $ap <=> $bp;
    return strcmp((string)($a['wo_number'] ?? ''), (string)($b['wo_number'] ?? ''));
  });
  return $rows;
}

function mes_shadow_failure_rows(array $observability): array {
  $rows = [];
  foreach ((array)($observability['shadow_sync'] ?? []) as $storeKey => $node) {
    if (!is_array($node)) continue;
    if ((string)($node['last_status'] ?? '') !== 'failure') continue;
    $rows[] = [
      'store_key' => (string)$storeKey,
      'severity' => 'critical',
      'last_error_at' => (string)($node['last_error_at'] ?? ''),
      'message' => (string)($node['last_message'] ?? ''),
      'failure_count' => (int)($node['failure_count'] ?? 0),
      'recent' => array_values((array)($node['recent'] ?? [])),
    ];
  }
  usort($rows, static function ($a, $b) {
    return strcmp((string)($b['last_error_at'] ?? ''), (string)($a['last_error_at'] ?? ''));
  });
  return $rows;
}

function mes_recent_connector_ingest_failures(array $observability): array {
  $rows = [];
  foreach ((array)($observability['connector_ingest']['recent'] ?? []) as $entry) {
    if (!is_array($entry)) continue;
    if ((string)($entry['status'] ?? 'success') === 'success') continue;
    $rows[] = [
      'machine_id' => (string)($entry['machine_id'] ?? ''),
      'timestamp' => (string)($entry['timestamp'] ?? ''),
      'message' => (string)($entry['message'] ?? ''),
      'context' => is_array($entry['context'] ?? null) ? $entry['context'] : [],
    ];
  }
  return array_slice($rows, 0, 20);
}

function mes_upsert_connector_runtime(array &$mes, array $machine, array $normalized, string $username): array {
  $machineId = trim((string)($normalized['machine_id'] ?? $machine['machine_id'] ?? ''));
  $signalAt = trim((string)($normalized['signal_at'] ?? ''));
  if ($signalAt === '') $signalAt = now_iso();
  $lastHeartbeatAt = trim((string)($normalized['last_heartbeat_at'] ?? ''));
  if ($lastHeartbeatAt === '') $lastHeartbeatAt = $signalAt;

  $connectorType = strtolower(trim((string)($normalized['connector_type'] ?? $machine['connector_type'] ?? $machine['telemetry_mode'] ?? 'manual_bridge')));
  if ($connectorType === '') $connectorType = 'manual_bridge';
  $heartbeatSla = max(30, (int)($normalized['heartbeat_sla_seconds'] ?? $machine['heartbeat_sla_seconds'] ?? 120));
  $signalAge = mes_timestamp_age_seconds($lastHeartbeatAt);
  $connectorHealth = mes_connector_health_from_age($signalAge, $heartbeatSla, $connectorType);
  $ingest = is_array($normalized['_ingest'] ?? null) ? $normalized['_ingest'] : [];
  $ingestWarnings = array_values((array)($ingest['warnings'] ?? []));

  $feedPayload = [
    'feed_id' => '',
    'machine_id' => $machineId,
    'machine_name' => (string)($machine['machine_name'] ?? ''),
    'work_center_id' => (string)($machine['work_center_id'] ?? ''),
    'connector_type' => $connectorType,
    'connector_name' => trim((string)($normalized['connector_name'] ?? $machine['connector_name'] ?? strtoupper($connectorType))),
    'connector_endpoint' => trim((string)($normalized['connector_endpoint'] ?? $machine['connector_endpoint'] ?? '')),
    'telemetry_mode' => (string)($normalized['telemetry_mode'] ?? $machine['telemetry_mode'] ?? ($connectorType === 'manual_bridge' ? 'manual' : 'machine')),
    'heartbeat_sla_seconds' => $heartbeatSla,
    'last_heartbeat_at' => $lastHeartbeatAt,
    'last_signal_at' => $signalAt,
    'connection_status' => $connectorHealth,
    'enabled' => array_key_exists('enabled', $normalized) ? (bool)$normalized['enabled'] : true,
    'updated_at' => now_iso(),
    'updated_by' => $username,
    'ingested_at' => (string)($ingest['ingested_at'] ?? ''),
    'ingested_by' => (string)($ingest['ingested_by'] ?? $username),
    'source_payload_type' => (string)($ingest['source_payload_type'] ?? ''),
    'ingest_warnings' => $ingestWarnings,
  ];
  $feedSaved = null;
  foreach ($mes['connector_feeds'] as $idx => $row) {
    if (!is_array($row) || (string)($row['machine_id'] ?? '') !== $machineId) continue;
    $feedPayload['feed_id'] = (string)($row['feed_id'] ?? '');
    $mes['connector_feeds'][$idx] = array_merge($row, $feedPayload);
    $feedSaved = $mes['connector_feeds'][$idx];
    break;
  }
  if (!$feedSaved) {
    $feedPayload['feed_id'] = mes_runtime_id('CNX');
    $feedSaved = $feedPayload;
    $mes['connector_feeds'][] = $feedSaved;
  }

  $signalPayload = [
    'signal_id' => '',
    'machine_id' => $machineId,
    'machine_name' => (string)($machine['machine_name'] ?? ''),
    'work_center_id' => (string)($machine['work_center_id'] ?? ''),
    'source' => trim((string)($normalized['source'] ?? $connectorType)),
    'connector_type' => $connectorType,
    'machine_state' => mes_machine_state_normalize((string)($normalized['machine_state'] ?? 'idle')),
    'signal_at' => $signalAt,
    'last_heartbeat_at' => $lastHeartbeatAt,
    'wo_number' => trim((string)($normalized['wo_number'] ?? '')),
    'operator_id' => trim((string)($normalized['operator_id'] ?? '')),
    'current_program_id' => trim((string)($normalized['current_program_id'] ?? '')),
    'spindle_load_pct' => array_key_exists('spindle_load_pct', $normalized) && $normalized['spindle_load_pct'] !== '' ? max(0, min(100, (float)$normalized['spindle_load_pct'])) : null,
    'spindle_power_kw' => array_key_exists('spindle_power_kw', $normalized) && $normalized['spindle_power_kw'] !== '' ? max(0, (float)$normalized['spindle_power_kw']) : null,
    'total_power_kw' => array_key_exists('total_power_kw', $normalized) && $normalized['total_power_kw'] !== '' ? max(0, (float)$normalized['total_power_kw']) : null,
    'feed_override_pct' => array_key_exists('feed_override_pct', $normalized) && $normalized['feed_override_pct'] !== '' ? max(0, min(200, (float)$normalized['feed_override_pct'])) : null,
    'part_count' => array_key_exists('part_count', $normalized) && $normalized['part_count'] !== '' ? max(0, (int)$normalized['part_count']) : null,
    'note' => trim((string)($normalized['note'] ?? '')),
    'updated_at' => now_iso(),
    'updated_by' => $username,
    'ingested_at' => (string)($ingest['ingested_at'] ?? ''),
    'ingested_by' => (string)($ingest['ingested_by'] ?? $username),
    'source_payload_type' => (string)($ingest['source_payload_type'] ?? ''),
    'ingest_warnings' => $ingestWarnings,
  ];
  $signalSaved = null;
  foreach ($mes['machine_signals'] as $idx => $row) {
    if (!is_array($row) || (string)($row['machine_id'] ?? '') !== $machineId) continue;
    $signalPayload['signal_id'] = (string)($row['signal_id'] ?? '');
    $mes['machine_signals'][$idx] = array_merge($row, $signalPayload);
    $signalSaved = $mes['machine_signals'][$idx];
    break;
  }
  if (!$signalSaved) {
    $signalPayload['signal_id'] = mes_runtime_id('SIG');
    $signalSaved = $signalPayload;
    $mes['machine_signals'][] = $signalSaved;
  }

  return [
    'feed' => $feedSaved,
    'signal' => $signalSaved,
    'connector_health' => $connectorHealth,
    'ingest_warnings' => $ingestWarnings,
  ];
}

function mes_mtconnect_poll_url(string $endpoint): string {
  $url = trim($endpoint);
  if ($url === '') {
    throw new RuntimeException('missing_connector_endpoint');
  }
  if (!preg_match('~^https?://~i', $url)) {
    throw new RuntimeException('invalid_connector_endpoint');
  }
  if (preg_match('~/current(?:\?.*)?$~i', $url)) {
    return $url;
  }
  return rtrim($url, '/') . '/current';
}

function mes_http_fetch_text(string $url, int $timeoutSeconds = 10): string {
  if (function_exists('curl_init')) {
    $ch = curl_init($url);
    curl_setopt_array($ch, [
      CURLOPT_RETURNTRANSFER => true,
      CURLOPT_FOLLOWLOCATION => true,
      CURLOPT_CONNECTTIMEOUT => max(1, $timeoutSeconds),
      CURLOPT_TIMEOUT => max(2, $timeoutSeconds),
      CURLOPT_HTTPHEADER => ['Accept: application/xml, text/xml, */*'],
    ]);
    $body = curl_exec($ch);
    $status = (int)curl_getinfo($ch, CURLINFO_RESPONSE_CODE);
    $error = curl_error($ch);
    curl_close($ch);
    if ($body === false) {
      throw new RuntimeException('connector_http_failed: ' . ($error !== '' ? $error : 'unknown_error'));
    }
    if ($status >= 400) {
      throw new RuntimeException('connector_http_status_' . $status);
    }
    return (string)$body;
  }

  $context = stream_context_create([
    'http' => [
      'method' => 'GET',
      'timeout' => max(2, $timeoutSeconds),
      'ignore_errors' => true,
      'header' => "Accept: application/xml, text/xml, */*\r\n",
    ],
  ]);
  $body = @file_get_contents($url, false, $context);
  if ($body === false) {
    throw new RuntimeException('connector_http_failed');
  }
  return (string)$body;
}

function mes_append_connectivity_event(array &$mes, array $event): array {
  $rows = array_values((array)($mes['mes_connectivity_events'] ?? []));
  $saved = array_merge([
    'adapter_event_id' => mes_runtime_id('ADP-EVT'),
    'adapter_id' => '',
    'machine_id' => '',
    'event_time' => now_iso(),
    'event_type' => 'adapter_event',
    'severity' => 'INFO',
    'status' => 'closed',
    'message' => '',
    'payload_excerpt' => [],
    'recorded_by' => 'system',
    'recorded_at' => now_iso(),
  ], $event);
  $saved['payload_excerpt'] = is_array($saved['payload_excerpt'] ?? null) ? $saved['payload_excerpt'] : [];

  foreach ($rows as $idx => $row) {
    if (!is_array($row) || (string)($row['adapter_event_id'] ?? '') !== (string)$saved['adapter_event_id']) continue;
    $rows[$idx] = array_merge($row, $saved);
    $saved = $rows[$idx];
    $mes['mes_connectivity_events'] = $rows;
    return $saved;
  }

  array_unshift($rows, $saved);
  $mes['mes_connectivity_events'] = array_slice($rows, 0, 400);
  return $saved;
}

function mes_find_mtconnect_adapter(array $master, string $machineId = '', string $adapterId = ''): array {
  $machineId = trim($machineId);
  $adapterId = trim($adapterId);
  $machines = master_index_by((array)($master['machines'] ?? []), 'machine_id');
  $adapter = null;

  if ($adapterId !== '') {
    foreach ((array)($master['mes_connectivity_adapters'] ?? []) as $row) {
      if (!is_array($row) || (string)($row['adapter_id'] ?? '') !== $adapterId) continue;
      $adapter = $row;
      break;
    }
    if (is_array($adapter) && $machineId === '') {
      $machineId = trim((string)($adapter['machine_id'] ?? ''));
    }
  }

  $machine = $machines[$machineId] ?? null;
  if (!is_array($adapter) && $machineId !== '') {
    foreach ((array)($master['mes_connectivity_adapters'] ?? []) as $row) {
      if (!is_array($row) || (string)($row['machine_id'] ?? '') !== $machineId) continue;
      if (strtolower(trim((string)($row['adapter_type'] ?? ''))) !== 'mtconnect') continue;
      $adapter = $row;
      break;
    }
  }

  return [
    'machine_id' => $machineId,
    'machine' => is_array($machine) ? $machine : null,
    'adapter' => is_array($adapter) ? $adapter : null,
    'machines' => $machines,
  ];
}

function mes_mtconnect_poll_interval_seconds(array $adapter, array $machine = []): int {
  $candidate = (int)($adapter['poll_interval_seconds'] ?? $machine['poll_interval_seconds'] ?? 0);
  if ($candidate <= 0) {
    $candidate = max(30, min(300, (int)($adapter['heartbeat_sla_seconds'] ?? $machine['heartbeat_sla_seconds'] ?? 120)));
  }
  return max(15, min(3600, $candidate));
}

function mes_mtconnect_latest_event(array $mes, string $machineId, string $adapterId = ''): ?array {
  $latest = null;
  foreach ((array)($mes['mes_connectivity_events'] ?? []) as $row) {
    if (!is_array($row)) continue;
    if ($machineId !== '' && (string)($row['machine_id'] ?? '') !== $machineId) continue;
    if ($adapterId !== '' && (string)($row['adapter_id'] ?? '') !== $adapterId) continue;
    $eventType = strtolower(trim((string)($row['event_type'] ?? '')));
    if ($eventType !== '' && !str_contains($eventType, 'poll')) continue;
    if ($latest === null || strcmp((string)($row['event_time'] ?? ''), (string)($latest['event_time'] ?? '')) > 0) {
      $latest = $row;
    }
  }
  return $latest;
}

function mes_mtconnect_poll_due_state(array $mes, array $adapter, array $machine, bool $force = false): array {
  $intervalSeconds = mes_mtconnect_poll_interval_seconds($adapter, $machine);
  $machineId = trim((string)($machine['machine_id'] ?? $adapter['machine_id'] ?? ''));
  $adapterId = trim((string)($adapter['adapter_id'] ?? ''));
  $latestEvent = mes_mtconnect_latest_event($mes, $machineId, $adapterId);
  $lastPolledAt = trim((string)($latestEvent['event_time'] ?? ''));
  $nowTs = time();

  if ($force || $lastPolledAt === '') {
    return [
      'due' => true,
      'reason' => $lastPolledAt === '' ? 'never_polled' : 'forced',
      'interval_seconds' => $intervalSeconds,
      'last_polled_at' => $lastPolledAt,
      'next_due_at' => $lastPolledAt === '' ? now_iso() : $lastPolledAt,
    ];
  }

  $lastTs = strtotime($lastPolledAt);
  if ($lastTs === false) {
    return [
      'due' => true,
      'reason' => 'invalid_last_poll_timestamp',
      'interval_seconds' => $intervalSeconds,
      'last_polled_at' => $lastPolledAt,
      'next_due_at' => now_iso(),
    ];
  }

  $nextDueTs = $lastTs + $intervalSeconds;
  return [
    'due' => $nextDueTs <= $nowTs,
    'reason' => $nextDueTs <= $nowTs ? 'interval_elapsed' : 'interval_not_elapsed',
    'interval_seconds' => $intervalSeconds,
    'last_polled_at' => $lastPolledAt,
    'next_due_at' => gmdate('c', $nextDueTs),
  ];
}

function mes_mtconnect_poll_machine(array &$orders, array &$master, array &$mes, string $username, array $body = []): array {
  $machineId = trim((string)($body['machine_id'] ?? ''));
  $adapterId = trim((string)($body['adapter_id'] ?? ''));
  $operators = master_index_by((array)($master['operators'] ?? []), 'operator_id');
  $bundle = mes_find_mtconnect_adapter($master, $machineId, $adapterId);
  $machineId = trim((string)($bundle['machine_id'] ?? $machineId));
  $machine = is_array($bundle['machine'] ?? null) ? $bundle['machine'] : null;
  $adapter = is_array($bundle['adapter'] ?? null) ? $bundle['adapter'] : null;

  if ($machineId === '') {
    return ['ok' => false, 'status_code' => 400, 'error' => 'missing_machine_id'];
  }
  if (!is_array($machine)) {
    observe_connector_ingest($machineId, false, 'machine_not_found', ['action' => 'mes_mtconnect_poll_once']);
    return ['ok' => false, 'status_code' => 404, 'error' => 'machine_not_found'];
  }
  if (!is_array($adapter)) {
    observe_connector_ingest($machineId, false, 'adapter_not_found', ['action' => 'mes_mtconnect_poll_once']);
    return ['ok' => false, 'status_code' => 404, 'error' => 'adapter_not_found'];
  }

  $adapterType = strtolower(trim((string)($adapter['adapter_type'] ?? $machine['connector_type'] ?? '')));
  if ($adapterType !== 'mtconnect') {
    observe_connector_ingest($machineId, false, 'adapter_type_not_supported', [
      'action' => 'mes_mtconnect_poll_once',
      'adapter_id' => (string)($adapter['adapter_id'] ?? ''),
      'adapter_type' => $adapterType,
    ]);
    return ['ok' => false, 'status_code' => 422, 'error' => 'adapter_type_not_supported'];
  }
  if (strtolower(trim((string)($adapter['status'] ?? 'active'))) !== 'active') {
    observe_connector_ingest($machineId, false, 'adapter_not_active', [
      'action' => 'mes_mtconnect_poll_once',
      'adapter_id' => (string)($adapter['adapter_id'] ?? ''),
    ]);
    return ['ok' => false, 'status_code' => 409, 'error' => 'adapter_not_active'];
  }

  $pollUrl = '';
  try {
    $pollUrl = mes_mtconnect_poll_url((string)($body['endpoint_url'] ?? $adapter['endpoint_url'] ?? $machine['connector_endpoint'] ?? ''));
    $timeoutSeconds = min(30, max(3, (int)($body['timeout_seconds'] ?? $adapter['timeout_seconds'] ?? 10)));
    $xml = mes_http_fetch_text($pollUrl, $timeoutSeconds);
    $normalized = edge_connector_service()->normalize([
      'machine_id' => $machineId,
      'connector_type' => 'mtconnect',
      'connector_name' => (string)($adapter['adapter_name'] ?? $machine['connector_name'] ?? 'MTConnect Adapter'),
      'connector_endpoint' => $pollUrl,
      'telemetry_mode' => (string)($machine['telemetry_mode'] ?? 'machine'),
      'source' => 'mtconnect',
      'heartbeat_sla_seconds' => (int)($adapter['heartbeat_sla_seconds'] ?? $machine['heartbeat_sla_seconds'] ?? 120),
      'wo_number' => trim((string)($body['wo_number'] ?? '')),
      'operator_id' => trim((string)($body['operator_id'] ?? '')),
      'note' => trim((string)($body['note'] ?? 'Polled once from MTConnect adapter.')),
      'mtconnect_xml' => $xml,
    ], $machine, $username);
  } catch (Throwable $e) {
    $savedEvent = mes_append_connectivity_event($mes, [
      'adapter_id' => (string)($adapter['adapter_id'] ?? ''),
      'machine_id' => $machineId,
      'event_time' => now_iso(),
      'event_type' => 'mtconnect_poll_failed',
      'severity' => 'WARNING',
      'status' => 'open',
      'message' => 'MTConnect poll failed: ' . $e->getMessage(),
      'payload_excerpt' => [
        'endpoint_url' => $pollUrl !== '' ? $pollUrl : (string)($adapter['endpoint_url'] ?? ''),
      ],
      'recorded_by' => $username,
      'recorded_at' => now_iso(),
    ]);
    observe_connector_ingest($machineId, false, $e->getMessage(), [
      'action' => 'mes_mtconnect_poll_once',
      'adapter_id' => (string)($adapter['adapter_id'] ?? ''),
      'poll_url' => $pollUrl,
    ]);
    $code = str_starts_with($e->getMessage(), 'connector_http_') ? 502 : 422;
    return [
      'ok' => false,
      'status_code' => $code,
      'error' => $e->getMessage(),
      'poll_url' => $pollUrl,
      'event' => $savedEvent,
    ];
  }

  $woNumber = trim((string)($normalized['wo_number'] ?? ''));
  if ($woNumber !== '') {
    $wo = find_order_record($orders, 'wo', $woNumber);
    if (!$wo) {
      observe_connector_ingest($machineId, false, 'work_order_not_found', ['action' => 'mes_mtconnect_poll_once', 'wo_number' => $woNumber]);
      return ['ok' => false, 'status_code' => 404, 'error' => 'work_order_not_found'];
    }
    $woMachineId = trim((string)($wo['machine_id'] ?? ''));
    if ($woMachineId !== '' && $woMachineId !== $machineId) {
      observe_connector_ingest($machineId, false, 'wo_machine_mismatch', ['action' => 'mes_mtconnect_poll_once', 'wo_number' => $woNumber, 'wo_machine_id' => $woMachineId]);
      return ['ok' => false, 'status_code' => 409, 'error' => 'wo_machine_mismatch'];
    }
  }

  $operatorId = trim((string)($normalized['operator_id'] ?? ''));
  if ($operatorId !== '' && !isset($operators[$operatorId])) {
    observe_connector_ingest($machineId, false, 'operator_not_found', ['action' => 'mes_mtconnect_poll_once', 'operator_id' => $operatorId]);
    return ['ok' => false, 'status_code' => 404, 'error' => 'operator_not_found'];
  }

  $signalGuard = mes_signal_replay_guard($mes, $machine, $normalized);
  if ($signalGuard) {
    observe_connector_ingest($machineId, false, 'stale_signal_timestamp', [
      'action' => 'mes_mtconnect_poll_once',
      'incoming_signal_at' => (string)($signalGuard['incoming_signal_at'] ?? ''),
      'latest_signal_at' => (string)($signalGuard['latest_signal_at'] ?? ''),
      'connector_type' => (string)($signalGuard['connector_type'] ?? ''),
      'wo_number' => $woNumber,
    ]);
    $signalGuard['ok'] = false;
    $signalGuard['status_code'] = 409;
    return $signalGuard;
  }

  $saved = mes_upsert_connector_runtime($mes, $machine, $normalized, $username);
  $savedEvent = mes_append_connectivity_event($mes, [
    'adapter_id' => (string)($adapter['adapter_id'] ?? ''),
    'machine_id' => $machineId,
    'event_time' => now_iso(),
    'event_type' => 'mtconnect_poll_ok',
    'severity' => 'INFO',
    'status' => 'closed',
    'message' => 'MTConnect payload polled and ingested successfully.',
    'payload_excerpt' => [
      'endpoint_url' => $pollUrl,
      'signal_at' => (string)($saved['signal']['signal_at'] ?? ''),
      'program_id' => (string)($saved['signal']['current_program_id'] ?? ''),
    ],
    'recorded_by' => $username,
    'recorded_at' => now_iso(),
  ]);
  observe_connector_ingest($machineId, true, 'MTConnect poll completed.', [
    'action' => 'mes_mtconnect_poll_once',
    'adapter_id' => (string)($adapter['adapter_id'] ?? ''),
    'connector_type' => (string)($saved['feed']['connector_type'] ?? ''),
    'wo_number' => $woNumber,
    'warning_count' => count((array)($saved['ingest_warnings'] ?? [])),
    'source_payload_type' => (string)($normalized['_ingest']['source_payload_type'] ?? ''),
  ]);

  return [
    'ok' => true,
    'poll_url' => $pollUrl,
    'machine_id' => $machineId,
    'adapter_id' => (string)($adapter['adapter_id'] ?? ''),
    'signal' => $saved['signal'],
    'feed' => $saved['feed'],
    'event' => $savedEvent,
    'ingest_warnings' => array_values((array)($saved['ingest_warnings'] ?? [])),
    'data' => build_mes_snapshot($orders, $master, $mes),
  ];
}

function mes_mtconnect_poll_batch_runtime(array &$orders, array &$master, array &$mes, string $username, array $options = []): array {
  $machineFilter = trim((string)($options['machine_id'] ?? ''));
  $adapterFilter = trim((string)($options['adapter_id'] ?? ''));
  $force = (bool)($options['force'] ?? false);
  $dueOnly = array_key_exists('due_only', $options) ? (bool)$options['due_only'] : true;
  $limit = max(1, min(50, (int)($options['limit'] ?? 20)));
  $rows = [];
  $successCount = 0;
  $failedCount = 0;
  $skippedCount = 0;
  $processed = 0;

  $machineIndex = master_index_by((array)($master['machines'] ?? []), 'machine_id');
  foreach ((array)($master['mes_connectivity_adapters'] ?? []) as $adapter) {
    if (!is_array($adapter)) continue;
    if ($machineFilter !== '' && trim((string)($adapter['machine_id'] ?? '')) !== $machineFilter) continue;
    if ($adapterFilter !== '' && trim((string)($adapter['adapter_id'] ?? '')) !== $adapterFilter) continue;
    if (strtolower(trim((string)($adapter['adapter_type'] ?? ''))) !== 'mtconnect') continue;
    if (strtolower(trim((string)($adapter['status'] ?? 'active'))) !== 'active') continue;

    $machineId = trim((string)($adapter['machine_id'] ?? ''));
    $machine = is_array($machineIndex[$machineId] ?? null) ? $machineIndex[$machineId] : [];
    $dueState = mes_mtconnect_poll_due_state($mes, $adapter, $machine, $force);
    if ($dueOnly && !($dueState['due'] ?? false)) {
      $skippedCount++;
      $rows[] = [
        'machine_id' => $machineId,
        'adapter_id' => (string)($adapter['adapter_id'] ?? ''),
        'ok' => true,
        'skipped' => true,
        'reason' => (string)($dueState['reason'] ?? 'interval_not_elapsed'),
        'last_polled_at' => (string)($dueState['last_polled_at'] ?? ''),
        'next_due_at' => (string)($dueState['next_due_at'] ?? ''),
        'interval_seconds' => (int)($dueState['interval_seconds'] ?? 60),
      ];
      continue;
    }

    $processed++;
    $result = mes_mtconnect_poll_machine($orders, $master, $mes, $username, [
      'machine_id' => $machineId,
      'adapter_id' => (string)($adapter['adapter_id'] ?? ''),
      'timeout_seconds' => (int)($options['timeout_seconds'] ?? 10),
      'note' => trim((string)($options['note'] ?? 'Batch MTConnect polling cycle.')),
    ]);

    if ($result['ok'] ?? false) {
      $successCount++;
    } else {
      $failedCount++;
    }

    $rows[] = array_merge([
      'machine_id' => $machineId,
      'adapter_id' => (string)($adapter['adapter_id'] ?? ''),
      'skipped' => false,
      'last_polled_at' => (string)($dueState['last_polled_at'] ?? ''),
      'next_due_at' => (string)($dueState['next_due_at'] ?? ''),
      'interval_seconds' => (int)($dueState['interval_seconds'] ?? 60),
    ], $result);

    if ($processed >= $limit) break;
  }

  return [
    'ok' => true,
    'processed_count' => $processed,
    'success_count' => $successCount,
    'failed_count' => $failedCount,
    'skipped_count' => $skippedCount,
    'rows' => $rows,
    'data' => build_mes_snapshot($orders, $master, $mes),
  ];
}

function mes_pg_notify_channels(): array {
  return ['mes_telemetry', 'mes_alarm', 'mes_downtime'];
}

function mes_pg_open_notify_stream(): ?array {
  try {
    require_once __DIR__ . '/database/Connection.php';
    $connection = \MOM\Database\Connection::getInstance();
    $pdo = $connection->getPdo();
    if (!method_exists($pdo, 'pgsqlGetNotify')) {
      return null;
    }
    foreach (mes_pg_notify_channels() as $channel) {
      $pdo->exec('LISTEN ' . $channel);
    }
    return ['pdo' => $pdo, 'channels' => mes_pg_notify_channels()];
  } catch (Throwable) {
    return null;
  }
}

function mes_pg_wait_for_notify($pdo, int $timeoutMs = 1000): ?array {
  if (!is_object($pdo) || !method_exists($pdo, 'pgsqlGetNotify')) return null;
  try {
    $result = $pdo->pgsqlGetNotify(\PDO::FETCH_ASSOC, max(0, $timeoutMs));
  } catch (Throwable) {
    return null;
  }
  if (!is_array($result) || empty($result['message'])) return null;
  $payload = json_decode((string)$result['message'], true);
  return [
    'channel' => (string)($result['channel'] ?? ''),
    'pid' => (int)($result['pid'] ?? 0),
    'payload' => is_array($payload) ? $payload : ['raw' => (string)$result['message']],
  ];
}

function mes_governance_blockers_for_dispatch(array $dispatchRow): array {
  $blockers = [];

  $gate = (array)($dispatchRow['evidence_gate'] ?? []);
  $gateStatus = strtolower(trim((string)($gate['status'] ?? 'not_required')));
  if (!in_array($gateStatus, ['ready', 'not_required'], true)) {
    $blockers[] = [
      'code' => 'evidence_gate_incomplete',
      'severity' => 'critical',
      'message_vi' => 'WO còn thiếu gate chứng cứ bắt buộc trước khi chạy.',
      'message_en' => 'The WO is still missing required evidence gates before it can run.',
      'detail' => [
        'status' => $gateStatus,
        'summary_vi' => (string)($gate['summary_vi'] ?? ''),
        'summary_en' => (string)($gate['summary_en'] ?? ''),
        'missing_form_codes' => array_values((array)($gate['missing_form_codes'] ?? [])),
      ],
    ];
  }

  $release = (array)($dispatchRow['program_release'] ?? []);
  $releaseBand = strtolower(trim((string)($release['band'] ?? 'ready')));
  if (!in_array($releaseBand, ['ready', 'not_required'], true)) {
    $blockers[] = [
      'code' => 'nc_release_not_ready',
      'severity' => (string)($release['severity'] ?? 'warning'),
      'message_vi' => (string)($release['message_vi'] ?? 'NC release chưa sẵn sàng cho WO này.'),
      'message_en' => (string)($release['message_en'] ?? 'The NC release is not ready for this WO.'),
      'detail' => [
        'band' => $releaseBand,
        'status' => (string)($release['status'] ?? ''),
        'expected_program_id' => (string)($dispatchRow['nc_program_id'] ?? ''),
        'program_id' => (string)($release['program_id'] ?? ''),
        'release_status' => (string)($release['release_status'] ?? ''),
        'context_issues' => array_values((array)($release['context_issues'] ?? [])),
      ],
    ];
  }

  $tool = (array)($dispatchRow['tool_readiness'] ?? []);
  $toolBand = strtolower(trim((string)($tool['band'] ?? 'ready')));
  if (!in_array($toolBand, ['ready', 'not_required'], true)) {
    $blockers[] = [
      'code' => 'tool_readiness_not_ready',
      'severity' => (string)($tool['severity'] ?? 'warning'),
      'message_vi' => (string)($tool['message_vi'] ?? 'Tooling chưa sẵn sàng để chạy WO này.'),
      'message_en' => (string)($tool['message_en'] ?? 'Tooling is not ready for this WO.'),
      'detail' => [
        'band' => $toolBand,
        'status' => (string)($tool['status'] ?? ''),
        'top_tool_id' => (string)($tool['top_tool_id'] ?? ''),
        'top_issue' => (string)($tool['top_issue'] ?? ''),
        'alert_count' => (int)($tool['alert_count'] ?? 0),
        'highest_life_pct' => $tool['highest_life_pct'] ?? null,
      ],
    ];
  }

  $operator = (array)($dispatchRow['operator_governance'] ?? []);
  if (!empty($operator['blocker'])) {
    $blockers[] = [
      'code' => 'operator_not_qualified',
      'severity' => (string)($operator['severity'] ?? 'critical'),
      'message_vi' => (string)($operator['message_vi'] ?? 'Người vận hành chưa đủ điều kiện để chạy WO này.'),
      'message_en' => (string)($operator['message_en'] ?? 'The operator is not qualified to run this WO.'),
      'detail' => $operator,
    ];
  }

  $material = (array)($dispatchRow['material_trace'] ?? []);
  if (!empty($material['blocker'])) {
    $blockers[] = [
      'code' => 'material_trace_incomplete',
      'severity' => (string)($material['severity'] ?? 'critical'),
      'message_vi' => (string)($material['message_vi'] ?? 'Trace vật liệu chưa đủ để mở WO này.'),
      'message_en' => (string)($material['message_en'] ?? 'Material trace is incomplete for this WO.'),
      'detail' => $material,
    ];
  }

  $materialGenealogy = (array)($dispatchRow['material_genealogy'] ?? []);
  if (empty($material['blocker']) && !empty($materialGenealogy)) {
    $genealogySeverity = (string)($materialGenealogy['severity'] ?? '');
    if ($genealogySeverity === '' && !empty($materialGenealogy['issue_codes'])) $genealogySeverity = 'critical';
    elseif ($genealogySeverity === '' && !empty($materialGenealogy['warning_codes'])) $genealogySeverity = 'warning';
    if ($genealogySeverity !== '') {
      $blockers[] = [
        'code' => 'material_genealogy_incomplete',
        'severity' => $genealogySeverity,
        'message_vi' => (string)($materialGenealogy['message_vi'] ?? 'Genealogy vật liệu hoặc thành phẩm chưa khép kín để mở WO này.'),
        'message_en' => (string)($materialGenealogy['message_en'] ?? 'Material or finished-part genealogy is not closed for this WO.'),
        'detail' => $materialGenealogy,
      ];
    }
  }

  $connector = (array)($dispatchRow['connector_guard'] ?? []);
  if (!empty($connector['blocker'])) {
    $blockers[] = [
      'code' => 'connector_guard_failed',
      'severity' => (string)($connector['severity'] ?? 'critical'),
      'message_vi' => (string)($connector['message_vi'] ?? 'Kết nối máy chưa đạt điều kiện để mở WO này.'),
      'message_en' => (string)($connector['message_en'] ?? 'Machine connectivity does not satisfy launch conditions for this WO.'),
      'detail' => $connector,
    ];
  }

  $adapter = (array)($dispatchRow['adapter_governance'] ?? []);
  if (!empty($adapter['blocker'])) {
    $blockers[] = [
      'code' => 'adapter_governance_failed',
      'severity' => (string)($adapter['band'] ?? 'critical'),
      'message_vi' => (string)($adapter['message_vi'] ?? 'Adapter hoặc chính sách kết nối chưa đạt điều kiện MES.'),
      'message_en' => (string)($adapter['message_en'] ?? 'The adapter or its governance policy does not satisfy MES conditions.'),
      'detail' => $adapter,
    ];
  }

  $alarm = (array)($dispatchRow['alarm_runtime'] ?? []);
  if (!empty($alarm['blocker'])) {
    $blockers[] = [
      'code' => 'machine_alarm_active',
      'severity' => (string)($alarm['band'] ?? 'critical'),
      'message_vi' => (string)($alarm['message_vi'] ?? 'Có alarm nóng trên máy và phải khóa chạy.'),
      'message_en' => (string)($alarm['message_en'] ?? 'There is an active machine alarm and execution must be locked.'),
      'detail' => $alarm,
    ];
  }

  $download = (array)($dispatchRow['nc_download'] ?? []);
  if (!empty($download['blocker'])) {
    $blockers[] = [
      'code' => 'nc_download_not_ready',
      'severity' => (string)($download['band'] ?? 'critical'),
      'message_vi' => (string)($download['message_vi'] ?? 'Download NC hoặc xác minh trên máy chưa đạt điều kiện mở chạy.'),
      'message_en' => (string)($download['message_en'] ?? 'NC download or machine-side verification does not satisfy launch conditions.'),
      'detail' => $download,
    ];
  }

  $offset = (array)($dispatchRow['tool_offset'] ?? []);
  if (!empty($offset['blocker'])) {
    $blockers[] = [
      'code' => 'tool_offset_not_ready',
      'severity' => (string)($offset['band'] ?? 'critical'),
      'message_vi' => (string)($offset['message_vi'] ?? 'Preset/offset của tool chưa đạt điều kiện mở chạy.'),
      'message_en' => (string)($offset['message_en'] ?? 'Tool preset/offset does not satisfy the launch conditions.'),
      'detail' => $offset,
    ];
  }

  $shiftHandover = (array)($dispatchRow['shift_handover'] ?? []);
  if (!empty($shiftHandover)) {
    $handoverSeverity = (string)($shiftHandover['severity'] ?? '');
    if ($handoverSeverity === '' && !empty($shiftHandover['issue_codes'])) $handoverSeverity = 'critical';
    elseif ($handoverSeverity === '' && !empty($shiftHandover['warning_codes'])) $handoverSeverity = 'warning';
    if ($handoverSeverity !== '') {
      $blockers[] = [
        'code' => 'shift_handover_incomplete',
        'severity' => $handoverSeverity,
        'message_vi' => (string)($shiftHandover['message_vi'] ?? 'Bàn giao ca chưa hợp lệ hoặc chưa được xác nhận để mở WO này.'),
        'message_en' => (string)($shiftHandover['message_en'] ?? 'Shift handover is not valid or not acknowledged for this WO.'),
        'detail' => $shiftHandover,
      ];
    }
  }

  return $blockers;
}

function mes_wo_transition_guard(array $orders, array $master, array $mes, string $woNumber, string $targetStatus): ?array {
  if (!mes_wo_status_requires_governance($targetStatus)) return null;
  $snapshot = build_mes_snapshot($orders, $master, $mes);
  $dispatchRow = mes_dispatch_row_for_wo($snapshot, $woNumber);
  if (!$dispatchRow) {
    return [
      'ok' => false,
      'error' => 'work_order_not_in_mes_snapshot',
      'target_status' => $targetStatus,
    ];
  }
  $blockers = mes_governance_blockers_for_dispatch($dispatchRow);
  if (!$blockers) return null;

  $snapshotContext = [
    'evidence_gate' => (array)($dispatchRow['evidence_gate'] ?? []),
    'program_release' => (array)($dispatchRow['program_release'] ?? []),
    'tool_readiness' => (array)($dispatchRow['tool_readiness'] ?? []),
    'operator_governance' => (array)($dispatchRow['operator_governance'] ?? []),
    'material_trace' => (array)($dispatchRow['material_trace'] ?? []),
    'material_genealogy' => (array)($dispatchRow['material_genealogy'] ?? []),
    'connector_guard' => (array)($dispatchRow['connector_guard'] ?? []),
    'adapter_governance' => (array)($dispatchRow['adapter_governance'] ?? []),
    'alarm_runtime' => (array)($dispatchRow['alarm_runtime'] ?? []),
    'nc_download' => (array)($dispatchRow['nc_download'] ?? []),
    'tool_offset' => (array)($dispatchRow['tool_offset'] ?? []),
    'shift_handover' => (array)($dispatchRow['shift_handover'] ?? []),
  ];
  observe_wo_launch_blocked($woNumber, $targetStatus, $blockers, $snapshotContext);

  return [
    'ok' => false,
    'error' => 'wo_launch_blocked',
    'target_status' => $targetStatus,
    'wo_number' => $woNumber,
    'blockers' => $blockers,
    'snapshot' => $snapshotContext,
  ];
}

function mes_metric_band(?float $value, float $good = 85.0, float $watch = 65.0): string {
  if ($value === null) return 'unknown';
  if ($value >= $good) return 'strong';
  if ($value >= $watch) return 'watch';
  return 'risk';
}

function mes_build_oee_timeline(array $machineWall): array {
  $rows = [];
  foreach ($machineWall as $machine) {
    if (!is_array($machine)) continue;
    $oee = isset($machine['oee_pct']) ? (float)$machine['oee_pct'] : null;
    $availability = isset($machine['availability_pct']) ? (float)$machine['availability_pct'] : null;
    $performance = isset($machine['performance_pct']) ? (float)$machine['performance_pct'] : null;
    $quality = isset($machine['quality_pct']) ? (float)$machine['quality_pct'] : null;

    $lossMap = array_filter([
      'availability' => $availability,
      'performance' => $performance,
      'quality' => $quality,
    ], static fn($value) => $value !== null);

    $dominantLoss = '';
    $dominantValue = null;
    if ($lossMap) {
      asort($lossMap, SORT_NUMERIC);
      $dominantLoss = (string)array_key_first($lossMap);
      $dominantValue = (float)reset($lossMap);
    }

    $rows[] = [
      'machine_id' => (string)($machine['machine_id'] ?? ''),
      'machine_name' => (string)($machine['machine_name'] ?? ''),
      'work_center_id' => (string)($machine['work_center_id'] ?? ''),
      'status' => (string)($machine['status'] ?? 'idle'),
      'active_wo_number' => (string)($machine['active_work_order']['wo_number'] ?? ''),
      'part_number' => (string)($machine['active_work_order']['part_number'] ?? ''),
      'part_revision' => (string)($machine['active_work_order']['part_revision'] ?? ''),
      'customer_name' => (string)($machine['active_work_order']['customer_name'] ?? ''),
      'availability_pct' => $availability,
      'performance_pct' => $performance,
      'quality_pct' => $quality,
      'oee_pct' => $oee,
      'band' => mes_metric_band($oee),
      'dominant_loss' => $dominantLoss,
      'dominant_loss_pct' => $dominantValue,
      'open_downtime' => $machine['open_downtime'] ?? null,
      'connector_health' => (string)($machine['connector_health'] ?? 'offline'),
    ];
  }

  usort($rows, static function ($a, $b) {
    $priority = ['risk' => 0, 'watch' => 1, 'strong' => 2, 'unknown' => 3];
    $ap = $priority[(string)($a['band'] ?? 'unknown')] ?? 9;
    $bp = $priority[(string)($b['band'] ?? 'unknown')] ?? 9;
    if ($ap !== $bp) return $ap <=> $bp;
    return (float)($a['oee_pct'] ?? 0) <=> (float)($b['oee_pct'] ?? 0);
  });

  return $rows;
}

function mes_build_downtime_pareto(array $downtimeEvents, DateTimeImmutable $now): array {
  $grouped = [];
  $totalMinutes = 0.0;
  foreach ($downtimeEvents as $event) {
    if (!is_array($event)) continue;
    $category = trim((string)($event['category'] ?? 'uncategorized'));
    if ($category === '') $category = 'uncategorized';
    $reasonCode = trim((string)($event['reason_code'] ?? ''));
    $bucket = $reasonCode !== '' ? ('reason:' . $reasonCode) : ('category:' . $category);
    $labelVi = trim((string)($event['reason_name_vi'] ?? ''));
    $labelEn = trim((string)($event['reason_name'] ?? ''));
    $minutes = mes_minutes_between(
      (string)($event['started_at'] ?? ''),
      strtolower((string)($event['status'] ?? 'open')) === 'resolved' ? (string)($event['resolved_at'] ?? '') : '',
      $now
    );
    if ($minutes <= 0) continue;
    if (!isset($grouped[$bucket])) {
      $grouped[$bucket] = [
        'category' => $category,
        'reason_code' => $reasonCode,
        'label_vi' => $labelVi !== '' ? $labelVi : $category,
        'label_en' => $labelEn !== '' ? $labelEn : $category,
        'reason_group' => trim((string)($event['reason_group'] ?? '')),
        'minutes' => 0.0,
        'event_count' => 0,
        'open_count' => 0,
        'major_count' => 0,
        'latest_started_at' => '',
      ];
    }
    $grouped[$bucket]['minutes'] += $minutes;
    $grouped[$bucket]['event_count']++;
    if (strtolower((string)($event['status'] ?? 'open')) === 'open') $grouped[$bucket]['open_count']++;
    if (in_array(strtolower((string)($event['severity'] ?? 'minor')), ['major', 'critical'], true)) $grouped[$bucket]['major_count']++;
    $startedAt = (string)($event['started_at'] ?? '');
    if ($startedAt !== '' && $startedAt > (string)$grouped[$bucket]['latest_started_at']) {
      $grouped[$bucket]['latest_started_at'] = $startedAt;
    }
    $totalMinutes += $minutes;
  }

  $rows = array_values($grouped);
  usort($rows, static function ($a, $b) {
    return (float)($b['minutes'] ?? 0) <=> (float)($a['minutes'] ?? 0);
  });

  $runningShare = 0.0;
  foreach ($rows as &$row) {
    $share = $totalMinutes > 0 ? round(((float)$row['minutes'] / $totalMinutes) * 100, 1) : 0.0;
    $runningShare += $share;
    $row['share_pct'] = $share;
    $row['cumulative_pct'] = min(100.0, round($runningShare, 1));
  }
  unset($row);

  return $rows;
}

function mes_downtime_governance_gap_rows(array $mes, array $master): array {
  $rows = [];
  $reasonCodes = master_index_by((array)($master['downtime_reason_codes'] ?? []), 'reason_code');
  $resolutionCodes = master_index_by((array)($master['downtime_resolution_codes'] ?? []), 'resolution_code');
  foreach ((array)($mes['downtime_events'] ?? []) as $event) {
    if (!is_array($event)) continue;
    $issues = [];
    $reasonCode = trim((string)($event['reason_code'] ?? ''));
    $reasonMeta = $reasonCode !== '' ? ($reasonCodes[$reasonCode] ?? null) : null;
    if ($reasonCode === '') {
      $issues[] = 'missing_reason_code';
    } elseif (!is_array($reasonMeta)) {
      $issues[] = 'invalid_reason_code';
    } elseif (strtolower(trim((string)($reasonMeta['status'] ?? 'active'))) !== 'active') {
      $issues[] = 'inactive_reason_code';
    }

    $status = strtolower(trim((string)($event['status'] ?? 'open')));
    $resolutionCode = trim((string)($event['resolution_code'] ?? ''));
    $resolutionMeta = $resolutionCode !== '' ? ($resolutionCodes[$resolutionCode] ?? null) : null;
    if ($status === 'resolved') {
      if ($resolutionCode === '') {
        $issues[] = 'missing_resolution_code';
      } elseif (!is_array($resolutionMeta)) {
        $issues[] = 'invalid_resolution_code';
      } elseif (strtolower(trim((string)($resolutionMeta['status'] ?? 'active'))) !== 'active') {
        $issues[] = 'inactive_resolution_code';
      }
    }

    if (!$issues) continue;
    $rows[] = [
      'downtime_id' => (string)($event['downtime_id'] ?? ''),
      'machine_id' => (string)($event['machine_id'] ?? ''),
      'wo_number' => (string)($event['wo_number'] ?? ''),
      'status' => $status,
      'started_at' => (string)($event['started_at'] ?? ''),
      'reported_by' => (string)($event['reported_by'] ?? ''),
      'reason_code' => $reasonCode,
      'reason_name_vi' => (string)($event['reason_name_vi'] ?? ''),
      'reason_name' => (string)($event['reason_name'] ?? ''),
      'resolution_code' => $resolutionCode,
      'issues' => $issues,
    ];
  }
  return $rows;
}

function mes_build_program_handshake_queue(array $dispatch): array {
  $rows = [];
  foreach ($dispatch as $row) {
    if (!is_array($row)) continue;
    $status = strtolower((string)($row['status'] ?? 'scheduled'));
    if (!in_array($status, ['setup', 'running', 'inspection', 'on_hold'], true)) continue;

    $expectedProgram = trim((string)($row['nc_program_id'] ?? ''));
    if ($expectedProgram === '') continue;

    $telemetry = (array)($row['telemetry'] ?? []);
    $actualProgram = trim((string)($telemetry['current_program_id'] ?? ''));
    $connectorHealth = strtolower((string)($telemetry['connector_health'] ?? 'offline'));
    $freshSignal = in_array($connectorHealth, ['healthy', 'delayed', 'manual_only'], true);

    $issueType = '';
    $severity = 'info';
    if ($actualProgram === '' && $freshSignal) {
      $issueType = 'missing_program';
      $severity = 'warning';
    } elseif ($actualProgram !== '' && strcasecmp($actualProgram, $expectedProgram) !== 0) {
      $issueType = 'program_mismatch';
      $severity = $freshSignal ? 'critical' : 'warning';
    }
    if ($issueType === '') continue;

    $rows[] = [
      'wo_number' => (string)($row['wo_number'] ?? ''),
      'jo_number' => (string)($row['jo_number'] ?? ''),
      'so_number' => (string)($row['so_number'] ?? ''),
      'machine_id' => (string)($row['machine_id'] ?? ''),
      'machine_name' => (string)($row['machine_name'] ?? ''),
      'work_center_id' => (string)($row['work_center_id'] ?? ''),
      'operator_id' => (string)($row['operator_id'] ?? ''),
      'operator_name' => (string)($row['operator_name'] ?? ''),
      'customer_name' => (string)($row['customer_name'] ?? ''),
      'part_number' => (string)($row['part_number'] ?? ''),
      'part_revision' => (string)($row['part_revision'] ?? ''),
      'status' => $status,
      'issue_type' => $issueType,
      'severity' => $severity,
      'expected_program_id' => $expectedProgram,
      'actual_program_id' => $actualProgram,
      'connector_health' => $connectorHealth,
      'signal_state' => (string)($telemetry['signal_state'] ?? ''),
      'last_heartbeat_at' => (string)($telemetry['last_heartbeat_at'] ?? ''),
      'signal_freshness_seconds' => $telemetry['signal_freshness_seconds'] ?? null,
      'message_vi' => $issueType === 'missing_program'
        ? 'Máy chưa trả về mã chương trình NC đang chạy.'
        : 'Chương trình NC trên máy không khớp với WO phát hành.',
      'message_en' => $issueType === 'missing_program'
        ? 'Machine did not report the active NC program.'
        : 'Machine NC program does not match the released WO.',
    ];
  }

  usort($rows, static function ($a, $b) {
    $priority = ['critical' => 0, 'warning' => 1, 'info' => 2];
    $ap = $priority[(string)($a['severity'] ?? 'info')] ?? 9;
    $bp = $priority[(string)($b['severity'] ?? 'info')] ?? 9;
    if ($ap !== $bp) return $ap <=> $bp;
    return strcmp((string)($a['wo_number'] ?? ''), (string)($b['wo_number'] ?? ''));
  });

  return $rows;
}

function mes_group_rows_by(array $rows, string $field): array {
  $grouped = [];
  foreach ($rows as $row) {
    if (!is_array($row)) continue;
    $key = trim((string)($row[$field] ?? ''));
    if ($key === '') continue;
    $grouped[$key][] = $row;
  }
  return $grouped;
}

function mes_latest_runtime_receipts(array $rows): array {
  usort($rows, function ($a, $b) {
    return strcmp((string)($b['downloaded_at'] ?? ''), (string)($a['downloaded_at'] ?? ''));
  });
  return $rows;
}

function mes_alarm_playbook_index(array $rows): array {
  $index = [];
  foreach ($rows as $row) {
    if (!is_array($row)) continue;
    $alarmCode = strtoupper(trim((string)($row['alarm_code'] ?? '')));
    if ($alarmCode === '') continue;
    if (!isset($index[$alarmCode])) {
      $index[$alarmCode] = $row;
    }
  }
  return $index;
}

function mes_adapter_governance_summary(array $machine, ?array $adapter, array $telemetry, array $events, DateTimeImmutable $now): array {
  $issues = [];
  $warnings = [];
  $recentOpenEvents = [];

  foreach ($events as $event) {
    if (!is_array($event)) continue;
    $eventTime = trim((string)($event['event_time'] ?? $event['recorded_at'] ?? ''));
    $ageSeconds = mes_timestamp_age_seconds($eventTime, $now);
    if ($ageSeconds !== null && $ageSeconds <= 86400 && strtolower(trim((string)($event['status'] ?? 'open'))) !== 'closed') {
      $recentOpenEvents[] = $event;
    }
  }

  $requiresConnector = mes_truthy($machine['connector_required_for_release'] ?? '') || strtolower(trim((string)($machine['telemetry_mode'] ?? 'machine'))) === 'machine';
  if ($requiresConnector && !$adapter) {
    $issues[] = 'adapter_missing';
  } elseif ($adapter) {
    $status = strtolower(trim((string)($adapter['status'] ?? 'active')));
    if (!in_array($status, ['active', 'approved', 'released'], true)) {
      $issues[] = 'adapter_not_active';
    }
    if (trim((string)($adapter['endpoint_url'] ?? '')) === '' && !in_array(strtolower(trim((string)($adapter['adapter_type'] ?? ''))), ['manual', 'manual_bridge'], true)) {
      $issues[] = 'endpoint_missing';
    }
    if ((int)($adapter['heartbeat_sla_seconds'] ?? 0) < 30) {
      $warnings[] = 'heartbeat_sla_invalid';
    }
    $lastValidatedAt = trim((string)($adapter['last_validated_at'] ?? ''));
    $validationAge = mes_timestamp_age_seconds($lastValidatedAt, $now);
    if ($lastValidatedAt === '') {
      $warnings[] = 'validation_missing';
    } elseif ($validationAge !== null && $validationAge > 86400 * 30) {
      $warnings[] = 'validation_stale';
    }
  }

  foreach ($recentOpenEvents as $event) {
    $severity = strtoupper(trim((string)($event['severity'] ?? 'WARNING')));
    if (in_array($severity, ['CRITICAL', 'EMERGENCY'], true)) {
      $issues[] = 'critical_adapter_event';
      break;
    }
    if ($severity === 'ALARM') {
      $warnings[] = 'alarm_adapter_event';
    }
  }

  $band = $issues ? 'critical' : ($warnings ? 'warning' : 'ready');
  return [
    'band' => $band,
    'blocker' => !empty($issues),
    'issue_codes' => array_values(array_unique($issues)),
    'warning_codes' => array_values(array_unique($warnings)),
    'adapter_id' => (string)($adapter['adapter_id'] ?? ''),
    'adapter_type' => (string)($adapter['adapter_type'] ?? $telemetry['connector_type'] ?? ''),
    'status' => (string)($adapter['status'] ?? ''),
    'open_event_count' => count($recentOpenEvents),
    'message_vi' => $issues
      ? 'Adapter hoặc chính sách kết nối chưa đạt điều kiện MES.'
      : ($warnings ? 'Adapter đang chạy nhưng có điểm cần rà soát.' : 'Adapter đang đáp ứng điều kiện MES.'),
    'message_en' => $issues
      ? 'The adapter or its governance policy does not satisfy MES conditions.'
      : ($warnings ? 'The adapter is operating but requires governance review.' : 'The adapter satisfies MES governance conditions.'),
  ];
}

function mes_alarm_due_at(string $alarmTime, int $minutes): string {
  if ($alarmTime === '' || $minutes <= 0) return '';
  try {
    return (new DateTimeImmutable($alarmTime))->modify('+' . $minutes . ' minutes')->format(DATE_ATOM);
  } catch (Throwable) {
    return '';
  }
}

function mes_alarm_runtime_summary(array $machine, array $rows, array $catalogIndex, array $playbookIndex, DateTimeImmutable $now): array {
  $activeRows = array_values(array_filter($rows, fn($row) => is_array($row) && mes_truthy($row['active_flag'] ?? true)));
  $issues = [];
  $warnings = [];
  $highestSeverity = 'INFO';
  $severityPriority = ['INFO' => 0, 'WARNING' => 1, 'ALARM' => 2, 'CRITICAL' => 3, 'EMERGENCY' => 4];
  $ackPendingCount = 0;
  $ackOverdueCount = 0;
  $escalationDueCount = 0;

  foreach ($activeRows as &$row) {
    $alarmCode = strtoupper(trim((string)($row['alarm_code'] ?? '')));
    $catalog = is_array($catalogIndex[$alarmCode] ?? null) ? $catalogIndex[$alarmCode] : [];
    $playbook = is_array($playbookIndex[$alarmCode] ?? null) ? $playbookIndex[$alarmCode] : [];
    $severity = strtoupper(trim((string)($row['severity'] ?? $catalog['severity_default'] ?? 'ALARM')));
    if (($severityPriority[$severity] ?? 0) > ($severityPriority[$highestSeverity] ?? 0)) {
      $highestSeverity = $severity;
    }
    $row['catalog_found'] = !empty($catalog);
    $row['playbook_found'] = !empty($playbook);
    $row['playbook_id'] = (string)($row['playbook_id'] ?? $playbook['playbook_id'] ?? '');
    $row['severity'] = $severity;

    $ackRequired = mes_truthy($row['ack_required'] ?? ($catalog['ack_required'] ?? false));
    $ackSla = max(0, (int)($row['ack_sla_minutes'] ?? $playbook['acknowledge_within_minutes'] ?? $catalog['ack_sla_minutes'] ?? $catalog['response_target_minutes'] ?? 0));
    $alarmTime = trim((string)($row['alarm_time'] ?? ''));
    $ackDueAt = trim((string)($row['ack_due_at'] ?? ''));
    if ($ackDueAt === '') {
      $ackDueAt = mes_alarm_due_at($alarmTime, $ackSla);
    }
    $acknowledged = trim((string)($row['acknowledged_at'] ?? '')) !== ''
      || trim((string)($row['acknowledged_by'] ?? '')) !== ''
      || strtolower(trim((string)($row['ack_status'] ?? ''))) === 'acknowledged';

    $escalationSla = max(0, (int)($row['escalation_sla_minutes'] ?? $catalog['escalation_sla_minutes'] ?? $playbook['response_target_minutes'] ?? $catalog['response_target_minutes'] ?? 0));
    $escalationDueAt = trim((string)($row['escalation_due_at'] ?? ''));
    if ($escalationDueAt === '') {
      $escalationDueAt = mes_alarm_due_at($alarmTime, $escalationSla);
    }
    $escalated = trim((string)($row['escalated_at'] ?? '')) !== ''
      || strtolower(trim((string)($row['escalation_status'] ?? ''))) === 'escalated';
    $requiresLockout = mes_truthy($row['requires_lockout'] ?? ($catalog['requires_lockout'] ?? $playbook['lockout_release_required'] ?? false));

    $row['ack_required'] = $ackRequired;
    $row['ack_sla_minutes'] = $ackSla;
    $row['ack_due_at'] = $ackDueAt;
    $row['acknowledged'] = $acknowledged;
    $row['escalation_sla_minutes'] = $escalationSla;
    $row['escalation_due_at'] = $escalationDueAt;
    $row['escalated'] = $escalated;
    $row['requires_lockout'] = $requiresLockout;

    if (!$row['catalog_found']) $issues[] = 'alarm_missing_catalog';
    if (!$row['playbook_found']) $warnings[] = 'alarm_missing_playbook';

    if ($ackRequired && !$acknowledged) {
      $ackPendingCount++;
      $row['ack_status'] = trim((string)($row['ack_status'] ?? 'pending')) ?: 'pending';
      $ageToAckDue = mes_timestamp_age_seconds($ackDueAt, $now);
      if ($ackDueAt !== '' && $ageToAckDue !== null && $ageToAckDue >= 0) {
        $issues[] = 'alarm_ack_overdue';
        $ackOverdueCount++;
      } else {
        $warnings[] = 'alarm_ack_pending';
      }
    } else {
      $row['ack_status'] = 'acknowledged';
    }

    $ageToEscalationDue = mes_timestamp_age_seconds($escalationDueAt, $now);
    if (!$escalated && $escalationDueAt !== '' && $ageToEscalationDue !== null && $ageToEscalationDue >= 0) {
      $warnings[] = 'alarm_escalation_due';
      $escalationDueCount++;
    }

    if ($requiresLockout) {
      $issues[] = 'lockout_required';
    }
  }
  unset($row);

  if (in_array($highestSeverity, ['CRITICAL', 'EMERGENCY'], true)) {
    $issues[] = 'critical_active_alarm';
  } elseif ($highestSeverity === 'ALARM') {
    $warnings[] = 'active_alarm';
  }

  $band = $issues ? 'critical' : ($warnings ? 'warning' : 'ready');
  return [
    'band' => $band,
    'blocker' => !empty($issues),
    'active_count' => count($activeRows),
    'highest_severity' => $highestSeverity,
    'ack_pending_count' => $ackPendingCount,
    'ack_overdue_count' => $ackOverdueCount,
    'escalation_due_count' => $escalationDueCount,
    'issue_codes' => array_values(array_unique($issues)),
    'warning_codes' => array_values(array_unique($warnings)),
    'hot_alarms' => array_slice($activeRows, 0, 5),
    'message_vi' => $issues
      ? 'C? alarm ?ang ho?t ??ng v? ch?a ??t ?i?u ki?n acknowledge / lockout / escalation.'
      : ($warnings ? 'C? alarm c?n acknowledge ho?c theo d?i escalation theo playbook.' : 'Kh?ng c? alarm n?ng tr?n m?y n?y.'),
    'message_en' => $issues
      ? 'There are active alarms that have not satisfied acknowledgement / lockout / escalation conditions.'
      : ($warnings ? 'There are active alarms that require acknowledgement or escalation follow-up.' : 'No active alarm hotspots on this machine.'),
  ];
}

function mes_material_genealogy_overlay(array $dispatchRow, array $part, array $materialRows, array $genealogyRows): array {
  $woNumber = trim((string)($dispatchRow['wo_number'] ?? ''));
  $partNumber = trim((string)($dispatchRow['part_number'] ?? ''));
  $partRevision = trim((string)($dispatchRow['part_revision'] ?? ''));
  $traceabilityLevel = strtolower(trim((string)($part['traceability_level'] ?? '')));
  $required = mes_truthy($part['material_trace_required'] ?? '') || $traceabilityLevel !== '';

  if (!$required) {
    return [
      'issue_codes' => [],
      'warning_codes' => [],
      'consumption_count' => 0,
      'genealogy_count' => 0,
      'issued_qty' => 0.0,
      'missing_fields' => [],
      'blocker' => false,
      'summary_vi' => 'Không yêu cầu genealogy vật liệu',
      'summary_en' => 'Material genealogy not required',
    ];
  }

  $consumption = array_values(array_filter($materialRows, static function ($row) use ($woNumber) {
    return is_array($row) && trim((string)($row['wo_number'] ?? '')) === $woNumber;
  }));
  $genealogy = array_values(array_filter($genealogyRows, static function ($row) use ($woNumber) {
    return is_array($row) && trim((string)($row['wo_number'] ?? '')) === $woNumber;
  }));

  $issues = [];
  $warnings = [];
  $issuedQty = 0.0;
  foreach ($consumption as $row) {
    $issuedQty += (float)($row['qty_consumed'] ?? 0);
  }

  if (!$consumption) {
    $issues[] = 'consumption_missing';
  }

  $dispatchLot = trim((string)($dispatchRow['material_lot_number'] ?? ''));
  if ($dispatchLot !== '' && $consumption) {
    $lotMatch = false;
    foreach ($consumption as $row) {
      if (strcasecmp(trim((string)($row['lot_number'] ?? '')), $dispatchLot) === 0) {
        $lotMatch = true;
        break;
      }
    }
    if (!$lotMatch) {
      $issues[] = 'consumption_lot_mismatch';
    }
  }

  $dispatchHeat = trim((string)($dispatchRow['heat_number'] ?? ''));
  if ($dispatchHeat !== '' && $consumption) {
    $heatMatch = false;
    foreach ($consumption as $row) {
      if (strcasecmp(trim((string)($row['heat_number'] ?? '')), $dispatchHeat) === 0) {
        $heatMatch = true;
        break;
      }
    }
    if (!$heatMatch) {
      $issues[] = 'consumption_heat_mismatch';
    }
  }

  $qtyCompleted = (int)($dispatchRow['qty_completed'] ?? 0);
  if ($qtyCompleted > 0 && !$genealogy) {
    $issues[] = 'genealogy_missing_after_completion';
  }

  foreach ($genealogy as $row) {
    if ($partNumber !== '' && strcasecmp(trim((string)($row['part_number'] ?? '')), $partNumber) !== 0) {
      $issues[] = 'genealogy_part_mismatch';
    }
    if ($partRevision !== '' && strcasecmp(trim((string)($row['part_revision'] ?? '')), $partRevision) !== 0) {
      $issues[] = 'genealogy_revision_mismatch';
    }
    if ($dispatchLot !== '' && trim((string)($row['material_lot_number'] ?? '')) !== '' && strcasecmp(trim((string)($row['material_lot_number'] ?? '')), $dispatchLot) !== 0) {
      $issues[] = 'genealogy_lot_mismatch';
    }
    if ($dispatchHeat !== '' && trim((string)($row['raw_material_heat'] ?? '')) !== '' && strcasecmp(trim((string)($row['raw_material_heat'] ?? '')), $dispatchHeat) !== 0) {
      $issues[] = 'genealogy_heat_mismatch';
    }
  }

  if ($qtyCompleted > 0 && $issuedQty > 0 && $issuedQty < $qtyCompleted) {
    $warnings[] = 'issued_qty_below_completed_qty';
  }

  return [
    'issue_codes' => array_values(array_unique($issues)),
    'warning_codes' => array_values(array_unique($warnings)),
    'consumption_count' => count($consumption),
    'genealogy_count' => count($genealogy),
    'issued_qty' => $issuedQty,
    'missing_fields' => array_values(array_unique($issues)),
    'blocker' => !empty($issues),
    'summary_vi' => $issues ? 'Genealogy vật liệu chưa kín' : ($warnings ? 'Genealogy cần xác nhận thêm' : 'Genealogy vật liệu đầy đủ'),
    'summary_en' => $issues ? 'Material genealogy is incomplete' : ($warnings ? 'Material genealogy needs reconfirmation' : 'Material genealogy is complete'),
  ];
}

function mes_merge_material_trace_with_genealogy(array $baseSummary, array $overlay): array {
  $issues = array_values(array_unique(array_merge((array)($baseSummary['missing_fields'] ?? []), (array)($overlay['issue_codes'] ?? []))));
  $warnings = array_values(array_unique(array_merge((array)($baseSummary['warning_codes'] ?? []), (array)($overlay['warning_codes'] ?? []))));
  $merged = $baseSummary;
  $merged['warning_codes'] = $warnings;
  $merged['consumption_count'] = (int)($overlay['consumption_count'] ?? 0);
  $merged['genealogy_count'] = (int)($overlay['genealogy_count'] ?? 0);
  $merged['issued_qty'] = (float)($overlay['issued_qty'] ?? 0);
  if ($issues) {
    $merged['band'] = 'critical';
    $merged['status'] = 'critical';
    $merged['severity'] = 'critical';
    $merged['blocker'] = true;
    $merged['missing_fields'] = $issues;
    $merged['summary_vi'] = 'Thiếu trace / genealogy vật liệu';
    $merged['summary_en'] = 'Material trace / genealogy missing';
    $merged['message_vi'] = 'WO chưa khép kín dữ liệu issue tiêu hao hoặc genealogy vật liệu theo yêu cầu MES.';
    $merged['message_en'] = 'The WO does not yet have a closed-loop material consumption or genealogy record required by MES.';
  } elseif ($warnings) {
    $merged['band'] = 'warning';
    $merged['status'] = 'warning';
    $merged['severity'] = 'warning';
    $merged['warning_codes'] = $warnings;
    $merged['summary_vi'] = 'Genealogy vật liệu cần xác nhận thêm';
    $merged['summary_en'] = 'Material genealogy needs reconfirmation';
  }
  return $merged;
}

function mes_build_material_genealogy_queue(array $dispatch): array {
  $rows = [];
  foreach ($dispatch as $row) {
    if (!is_array($row)) continue;
    $summary = (array)($row['material_trace'] ?? []);
    if (
      empty($summary['consumption_count'])
      && empty($summary['genealogy_count'])
      && empty($summary['warning_codes'])
      && empty($summary['missing_fields'])
    ) {
      continue;
    }
    $issues = array_values((array)($summary['missing_fields'] ?? []));
    $warnings = array_values((array)($summary['warning_codes'] ?? []));
    $interesting = false;
    foreach (array_merge($issues, $warnings) as $code) {
      if (strpos((string)$code, 'genealogy_') === 0 || strpos((string)$code, 'consumption_') === 0 || (string)$code === 'issued_qty_below_completed_qty') {
        $interesting = true;
        break;
      }
    }
    if (!$interesting) continue;
    $rows[] = [
      'wo_number' => (string)($row['wo_number'] ?? ''),
      'jo_number' => (string)($row['jo_number'] ?? ''),
      'machine_id' => (string)($row['machine_id'] ?? ''),
      'customer_name' => (string)($row['customer_name'] ?? ''),
      'part_number' => (string)($row['part_number'] ?? ''),
      'part_revision' => (string)($row['part_revision'] ?? ''),
      'consumption_count' => (int)($summary['consumption_count'] ?? 0),
      'genealogy_count' => (int)($summary['genealogy_count'] ?? 0),
      'issued_qty' => (float)($summary['issued_qty'] ?? 0),
      'issue_codes' => $issues,
      'warning_codes' => $warnings,
      'material_lot_number' => (string)($summary['material_lot_number'] ?? ''),
      'heat_number' => (string)($summary['heat_number'] ?? ''),
      'traveler_number' => (string)($summary['traveler_number'] ?? ''),
      'severity' => !empty($issues) ? 'critical' : 'warning',
      'message_vi' => (string)($summary['message_vi'] ?? ''),
      'message_en' => (string)($summary['message_en'] ?? ''),
    ];
  }
  return $rows;
}

function mes_build_alarm_ack_queue(array $dispatch): array {
  $rows = [];
  foreach ($dispatch as $row) {
    if (!is_array($row)) continue;
    $summary = (array)($row['alarm_runtime'] ?? []);
    foreach ((array)($summary['hot_alarms'] ?? []) as $alarm) {
      if (!is_array($alarm)) continue;
      $ackPending = !empty($alarm['ack_required']) && empty($alarm['acknowledged']);
      $escalationDue = !empty($alarm['escalation_due_at']) && empty($alarm['escalated']);
      if (!$ackPending && !$escalationDue) continue;
      $rows[] = [
        'wo_number' => (string)($row['wo_number'] ?? ''),
        'jo_number' => (string)($row['jo_number'] ?? ''),
        'machine_id' => (string)($row['machine_id'] ?? ''),
        'machine_name' => (string)($row['machine_name'] ?? ''),
        'customer_name' => (string)($row['customer_name'] ?? ''),
        'part_number' => (string)($row['part_number'] ?? ''),
        'part_revision' => (string)($row['part_revision'] ?? ''),
        'alarm_event_id' => (string)($alarm['alarm_event_id'] ?? ''),
        'alarm_code' => (string)($alarm['alarm_code'] ?? ''),
        'alarm_text' => (string)($alarm['alarm_text'] ?? ''),
        'severity' => strtolower((string)($alarm['severity'] ?? 'alarm')),
        'ack_required' => !empty($alarm['ack_required']),
        'ack_status' => (string)($alarm['ack_status'] ?? ''),
        'ack_due_at' => (string)($alarm['ack_due_at'] ?? ''),
        'escalation_due_at' => (string)($alarm['escalation_due_at'] ?? ''),
        'escalation_status' => (string)($alarm['escalation_status'] ?? ''),
        'playbook_id' => (string)($alarm['playbook_id'] ?? ''),
        'requires_lockout' => !empty($alarm['requires_lockout']),
      ];
    }
  }
  usort($rows, static function ($a, $b) {
    return strcmp((string)($a['ack_due_at'] ?: $a['escalation_due_at']), (string)($b['ack_due_at'] ?: $b['escalation_due_at']));
  });
  return $rows;
}

function mes_nc_download_summary(array $dispatchRow, array $releaseIndex, array $receiptRows): array {
  $expectedProgramId = trim((string)($dispatchRow['nc_program_id'] ?? ''));
  $machineId = trim((string)($dispatchRow['machine_id'] ?? ''));
  $woNumber = trim((string)($dispatchRow['wo_number'] ?? ''));
  $issues = [];
  $warnings = [];
  $release = is_array($releaseIndex[$expectedProgramId] ?? null) ? $releaseIndex[$expectedProgramId] : [];
  $receipt = [];

  foreach ($receiptRows as $row) {
    if (!is_array($row)) continue;
    if ((string)($row['wo_number'] ?? '') === $woNumber && (string)($row['machine_id'] ?? '') === $machineId) {
      $receipt = $row;
      break;
    }
  }
  if ($receipt === []) {
    foreach ($receiptRows as $row) {
      if (!is_array($row)) continue;
      if ((string)($row['program_id'] ?? '') === $expectedProgramId && (string)($row['machine_id'] ?? '') === $machineId) {
        $receipt = $row;
        break;
      }
    }
  }

  if ($expectedProgramId === '') {
    return [
      'band' => 'not_required',
      'blocker' => false,
      'issue_codes' => [],
      'warning_codes' => [],
      'message_vi' => 'WO này chưa khai báo yêu cầu download NC.',
      'message_en' => 'No governed NC download is declared for this WO.',
    ];
  }

  if ($release === []) {
    $issues[] = 'release_package_missing';
  }
  if ($receipt === []) {
    $issues[] = 'download_receipt_missing';
  } else {
    if (!mes_truthy($receipt['verified_match'] ?? false)) {
      $issues[] = 'download_verification_failed';
    }
    $expectedControllerName = trim((string)($release['controller_program_name'] ?? $expectedProgramId));
    $actualControllerName = trim((string)($receipt['controller_program_name'] ?? ''));
    if ($expectedControllerName !== '' && $actualControllerName !== '' && strcasecmp($expectedControllerName, $actualControllerName) !== 0) {
      $issues[] = 'controller_program_name_mismatch';
    }
  }

  if ($release !== [] && strtolower(trim((string)($release['status'] ?? 'released'))) !== 'released') {
    $warnings[] = 'release_not_released';
  }

  $band = $issues ? 'critical' : ($warnings ? 'warning' : 'ready');
  return [
    'band' => $band,
    'blocker' => !empty($issues),
    'issue_codes' => array_values(array_unique($issues)),
    'warning_codes' => array_values(array_unique($warnings)),
    'expected_program_id' => $expectedProgramId,
    'package_id' => (string)($release['package_id'] ?? ''),
    'controller_program_name' => (string)($release['controller_program_name'] ?? $expectedProgramId),
    'checksum_sha256' => (string)($release['checksum_sha256'] ?? $release['checksum'] ?? ''),
    'release_status' => (string)($release['status'] ?? ''),
    'receipt' => $receipt,
    'message_vi' => $issues
      ? 'Download NC hoặc xác minh trên máy chưa đạt điều kiện mở chạy.'
      : ($warnings ? 'Download NC có cảnh báo cần xác nhận thêm.' : 'Download NC và xác minh trên máy đã đạt điều kiện.'),
    'message_en' => $issues
      ? 'NC download or machine-side verification does not satisfy launch conditions.'
      : ($warnings ? 'NC download is available but requires additional confirmation.' : 'NC download and machine-side verification satisfy the launch conditions.'),
  ];
}

function mes_tool_offset_summary(array $dispatchRow, array $offsetRows, array $toolRows, array $toolAssemblyIndex, DateTimeImmutable $now): array {
  $issues = [];
  $warnings = [];
  $machineId = trim((string)($dispatchRow['machine_id'] ?? ''));
  $woNumber = trim((string)($dispatchRow['wo_number'] ?? ''));
  $loadedTools = array_values(array_filter($toolRows, fn($row) => is_array($row) && trim((string)($row['tool_id'] ?? '')) !== ''));
  $selectedOffsets = [];

  foreach ($loadedTools as $tool) {
    $toolId = trim((string)($tool['tool_id'] ?? ''));
    $candidate = null;
    foreach ($offsetRows as $row) {
      if (!is_array($row)) continue;
      if ((string)($row['tool_id'] ?? '') !== $toolId) continue;
      if ((string)($row['machine_id'] ?? '') !== $machineId) continue;
      if ($woNumber !== '' && (string)($row['wo_number'] ?? '') !== '' && (string)($row['wo_number'] ?? '') !== $woNumber) continue;
      if ($candidate === null || strcmp((string)($row['measured_at'] ?? ''), (string)($candidate['measured_at'] ?? '')) > 0) {
        $candidate = $row;
      }
    }
    if ($candidate === null) {
      $issues[] = 'offset_missing';
      continue;
    }
    $selectedOffsets[] = $candidate;
    $verifiedStatus = strtolower(trim((string)($candidate['verified_status'] ?? 'verified')));
    if (!in_array($verifiedStatus, ['verified', 'ok', 'released'], true)) {
      $issues[] = 'offset_not_verified';
    }
    $drift = isset($candidate['offset_drift_mm']) ? abs((float)$candidate['offset_drift_mm']) : 0.0;
    $band = (float)($tool['default_offset_band_mm'] ?? 0.02);
    if ($drift > $band) {
      $issues[] = 'offset_drift_exceeded';
    }
    $measuredAt = trim((string)($candidate['measured_at'] ?? ''));
    $measuredAge = mes_timestamp_age_seconds($measuredAt, $now);
    if ($measuredAge !== null && $measuredAge > 86400) {
      $warnings[] = 'offset_measurement_stale';
    }
    $lastChangeAt = trim((string)($tool['last_change_at'] ?? ''));
    if ($lastChangeAt !== '' && $measuredAt !== '' && strcmp($measuredAt, $lastChangeAt) < 0) {
      $issues[] = 'offset_before_tool_change';
    }
    if (!empty($toolAssemblyIndex[$toolId]) && count((array)$toolAssemblyIndex[$toolId]) === 0) {
      $warnings[] = 'assembly_not_governed';
    }
  }

  $band = $issues ? 'critical' : ($warnings ? 'warning' : 'ready');
  $topOffset = $selectedOffsets[0] ?? [];
  return [
    'band' => $band,
    'blocker' => !empty($issues),
    'issue_codes' => array_values(array_unique($issues)),
    'warning_codes' => array_values(array_unique($warnings)),
    'loaded_tool_count' => count($loadedTools),
    'verified_offset_count' => count($selectedOffsets),
    'top_tool_id' => (string)($topOffset['tool_id'] ?? ''),
    'top_offset_number' => (string)($topOffset['offset_number'] ?? ''),
    'top_drift_mm' => isset($topOffset['offset_drift_mm']) ? (float)$topOffset['offset_drift_mm'] : null,
    'message_vi' => $issues
      ? 'Preset/offset của tool chưa đạt điều kiện để mở chạy.'
      : ($warnings ? 'Preset/offset có cảnh báo cần rà soát trước khi chạy tiếp.' : 'Preset/offset của tool đang đạt điều kiện vận hành.'),
    'message_en' => $issues
      ? 'Tool preset/offset does not satisfy the launch conditions.'
      : ($warnings ? 'Tool preset/offset requires review before continued execution.' : 'Tool preset/offset satisfies the operating conditions.'),
  ];
}

