function mes_build_dpp_queue(array $dispatch, array $genealogyRows, array $dppRows): array {
  $rows = [];
  $genealogyByWo = mes_latest_rows_by_key($genealogyRows, 'wo_number', ['recorded_at', 'updated_at', 'created_at']);
  $passportByWo = mes_latest_rows_by_key($dppRows, 'wo_number', ['updated_at', 'published_at', 'created_at']);

  foreach ($dispatch as $row) {
    if (!is_array($row)) continue;
    $status = strtolower(trim((string)($row['status'] ?? 'scheduled')));
    $completedQty = (int)($row['qty_completed'] ?? 0);
    if (!in_array($status, ['inspection', 'completed'], true) && $completedQty <= 0) continue;

    $woNumber = (string)($row['wo_number'] ?? '');
    $genealogy = (array)($genealogyByWo[$woNumber] ?? []);
    $passport = (array)($passportByWo[$woNumber] ?? []);
    $issueCodes = [];
    $warningCodes = [];

    if ($genealogy === []) {
      $issueCodes[] = 'missing_genealogy';
    }
    if ($passport === []) {
      $issueCodes[] = 'missing_dpp_passport';
    } else {
      if (trim((string)($passport['origin_country'] ?? '')) === '') $issueCodes[] = 'missing_origin_country';
      if (!isset($passport['carbon_footprint_kg_co2e']) || $passport['carbon_footprint_kg_co2e'] === '' || $passport['carbon_footprint_kg_co2e'] === null) $issueCodes[] = 'missing_carbon_footprint';
      if (!isset($passport['energy_consumption_kwh']) || $passport['energy_consumption_kwh'] === '' || $passport['energy_consumption_kwh'] === null) $issueCodes[] = 'missing_energy_consumption';
      if (trim((string)($passport['qr_code'] ?? '')) === '' && trim((string)($passport['passport_url'] ?? '')) === '') $warningCodes[] = 'missing_dpp_access_link';
      if (trim((string)($passport['quality_certificate_status'] ?? $genealogy['certificate_of_conformance'] ?? '')) === '') $warningCodes[] = 'missing_quality_certificate';
    }

    if ($issueCodes === [] && $warningCodes === []) continue;
    $band = $issueCodes !== [] ? 'critical' : 'warning';
    $rows[] = [
      'wo_number' => $woNumber,
      'machine_id' => (string)($row['machine_id'] ?? ''),
      'work_center_id' => (string)($row['work_center_id'] ?? ''),
      'customer_name' => (string)($row['customer_name'] ?? ''),
      'part_number' => (string)($row['part_number'] ?? ''),
      'part_revision' => (string)($row['part_revision'] ?? ''),
      'genealogy_id' => (string)($genealogy['genealogy_id'] ?? ''),
      'dpp_id' => (string)($passport['dpp_id'] ?? ''),
      'serial_number' => (string)($passport['serial_number'] ?? $genealogy['serial_number'] ?? ''),
      'lot_number' => (string)($passport['lot_number'] ?? $genealogy['lot_number'] ?? ''),
      'dpp_status' => (string)($passport['status'] ?? 'missing'),
      'origin_country' => (string)($passport['origin_country'] ?? ''),
      'carbon_footprint_kg_co2e' => isset($passport['carbon_footprint_kg_co2e']) ? (float)$passport['carbon_footprint_kg_co2e'] : null,
      'energy_consumption_kwh' => isset($passport['energy_consumption_kwh']) ? (float)$passport['energy_consumption_kwh'] : null,
      'issue_codes' => $issueCodes,
      'warning_codes' => $warningCodes,
      'severity' => $band,
      'message_vi' => $band === 'critical'
        ? 'DPP cua WO chua du du lieu de cong bo passport va truy xuat ben ngoai.'
        : 'DPP da co khung nhung van con metadata can bo sung de dat muc world-class.',
      'message_en' => $band === 'critical'
        ? 'The WO digital product passport is not complete enough for governed external traceability.'
        : 'The passport frame exists but still needs additional metadata to reach world-class readiness.',
    ];
  }

  return $rows;
}

function mes_build_energy_queue(array $machineWall, array $energySnapshots): array {
  $rows = [];
  $snapshotByMachine = mes_latest_rows_by_key($energySnapshots, 'machine_id', ['updated_at', 'captured_at', 'created_at']);

  foreach ($machineWall as $row) {
    if (!is_array($row)) continue;
    $machineId = (string)($row['machine_id'] ?? '');
    if ($machineId === '') continue;
    $snapshot = (array)($snapshotByMachine[$machineId] ?? []);
    $powerKw = isset($row['total_power_kw']) && $row['total_power_kw'] !== null
      ? (float)$row['total_power_kw']
      : (isset($row['spindle_power_kw']) && $row['spindle_power_kw'] !== null ? (float)$row['spindle_power_kw'] : null);
    $status = strtolower(trim((string)($row['status'] ?? 'idle')));
    $issueCodes = [];
    $warningCodes = [];

    if (in_array($status, ['running', 'setup', 'inspection'], true) && $powerKw === null) {
      $issueCodes[] = 'missing_power_signal';
    }
    if (in_array($status, ['idle', 'on_hold'], true) && $powerKw !== null && $powerKw >= 2.5) {
      $warningCodes[] = 'idle_energy_draw';
    }
    $energyPerUnit = isset($snapshot['energy_per_unit_kwh']) && $snapshot['energy_per_unit_kwh'] !== '' ? (float)$snapshot['energy_per_unit_kwh'] : null;
    $target = isset($snapshot['target_energy_per_unit_kwh']) && $snapshot['target_energy_per_unit_kwh'] !== '' ? (float)$snapshot['target_energy_per_unit_kwh'] : 1.5;
    if ($energyPerUnit !== null && $energyPerUnit > $target) {
      $issueCodes[] = 'high_energy_intensity';
    } elseif ($powerKw !== null && $energyPerUnit === null && in_array($status, ['running', 'setup', 'inspection'], true)) {
      $warningCodes[] = 'missing_energy_snapshot';
    }

    if ($issueCodes === [] && $warningCodes === []) continue;
    $band = $issueCodes !== [] ? 'critical' : 'warning';
    $rows[] = [
      'machine_id' => $machineId,
      'machine_name' => (string)($row['machine_name'] ?? ''),
      'work_center_id' => (string)($row['work_center_id'] ?? ''),
      'wo_number' => (string)($row['active_work_order']['wo_number'] ?? ''),
      'power_kw' => $powerKw,
      'energy_snapshot_id' => (string)($snapshot['energy_snapshot_id'] ?? ''),
      'energy_kwh' => isset($snapshot['energy_kwh']) ? (float)$snapshot['energy_kwh'] : null,
      'good_qty' => isset($snapshot['good_qty']) ? (int)$snapshot['good_qty'] : null,
      'energy_per_unit_kwh' => $energyPerUnit,
      'target_energy_per_unit_kwh' => $target,
      'issue_codes' => $issueCodes,
      'warning_codes' => $warningCodes,
      'severity' => $band,
      'message_vi' => $band === 'critical'
        ? 'May dang co dau hieu vuot nguong nang luong hoac thieu tin hieu power can thiet cho governance ISO 50001.'
        : 'Can bo sung snapshot nang luong hoac giam hao phi khi may khong cat nhưng van tieu thu dien.',
      'message_en' => $band === 'critical'
        ? 'The machine is exceeding the governed energy threshold or missing required power telemetry for ISO 50001-style control.'
        : 'Add governed energy snapshots or reduce wasted draw while the machine is not actively cutting.',
    ];
  }

  return $rows;
}

function mes_build_cost_variance_queue(array $dispatch, array $costRows): array {
  $rows = [];
  $costByWo = mes_latest_rows_by_key($costRows, 'wo_number', ['updated_at', 'captured_at', 'created_at']);

  foreach ($dispatch as $row) {
    if (!is_array($row)) continue;
    $status = strtolower(trim((string)($row['status'] ?? 'scheduled')));
    $woNumber = (string)($row['wo_number'] ?? '');
    if ($woNumber === '') continue;
    if (!in_array($status, ['running', 'inspection', 'completed'], true) && (int)($row['qty_completed'] ?? 0) <= 0) continue;

    $cost = (array)($costByWo[$woNumber] ?? []);
    $issueCodes = [];
    $warningCodes = [];
    $standard = isset($cost['standard_cost_total']) ? (float)$cost['standard_cost_total'] : null;
    $actual = isset($cost['actual_cost_total']) ? (float)$cost['actual_cost_total'] : null;
    $threshold = isset($cost['variance_threshold_pct']) && $cost['variance_threshold_pct'] !== '' ? (float)$cost['variance_threshold_pct'] : 15.0;
    $variance = isset($cost['variance_pct']) && $cost['variance_pct'] !== '' ? (float)$cost['variance_pct'] : null;

    if ($cost === []) {
      $warningCodes[] = 'missing_cost_snapshot';
    } else {
      if ($variance === null && $standard !== null && $standard > 0 && $actual !== null) {
        $variance = round((($actual - $standard) / $standard) * 100, 2);
      }
      if ($variance !== null && $variance > $threshold) {
        $issueCodes[] = 'cost_variance_high';
      }
      if (($cost['cost_per_good_unit'] ?? null) === null && (int)($row['qty_completed'] ?? 0) > 0) {
        $warningCodes[] = 'missing_unit_cost';
      }
    }

    if ($issueCodes === [] && $warningCodes === []) continue;
    $band = $issueCodes !== [] ? 'critical' : 'warning';
    $rows[] = [
      'wo_number' => $woNumber,
      'machine_id' => (string)($row['machine_id'] ?? ''),
      'work_center_id' => (string)($row['work_center_id'] ?? ''),
      'customer_name' => (string)($row['customer_name'] ?? ''),
      'part_number' => (string)($row['part_number'] ?? ''),
      'part_revision' => (string)($row['part_revision'] ?? ''),
      'cost_id' => (string)($cost['cost_id'] ?? ''),
      'standard_cost_total' => $standard,
      'actual_cost_total' => $actual,
      'variance_pct' => $variance,
      'cost_per_good_unit' => isset($cost['cost_per_good_unit']) ? (float)$cost['cost_per_good_unit'] : null,
      'variance_threshold_pct' => $threshold,
      'issue_codes' => $issueCodes,
      'warning_codes' => $warningCodes,
      'severity' => $band,
      'message_vi' => $band === 'critical'
        ? 'WO dang vuot nguong chi phi thuc te so voi muc ke hoach va can dieu do xem lai ngay.'
        : 'WO can duoc cap nhat snapshot costing de dashboard va doi soat khong bi mu thong tin.',
      'message_en' => $band === 'critical'
        ? 'The WO is exceeding its governed actual-versus-standard cost threshold and needs immediate review.'
        : 'The WO still needs a governed costing snapshot so dashboards and reconciliation stay trustworthy.',
    ];
  }

  return $rows;
}

function build_mes_snapshot(array $orders, array $master, array $mes): array {
  $customers = master_index_by((array)($master['customers'] ?? []), 'customer_id');
  $parts = master_index_by((array)($master['parts'] ?? []), 'part_number');
  $programReleases = master_index_by((array)($master['nc_program_releases'] ?? []), 'program_id');
  $workCenters = master_index_by((array)($master['work_centers'] ?? []), 'work_center_id');
  $machines = master_index_by((array)($master['machines'] ?? []), 'machine_id');
  $operators = master_index_by((array)($master['operators'] ?? []), 'operator_id');
  $toolingAssets = master_index_by((array)($master['tooling_assets'] ?? []), 'tool_id');
  $connectivityAdaptersByMachine = master_index_by((array)($master['mes_connectivity_adapters'] ?? []), 'machine_id');
  $alarmCatalog = master_index_by((array)($master['mes_alarm_catalog'] ?? []), 'alarm_code');
  $alarmPlaybooks = mes_alarm_playbook_index((array)($master['mes_alarm_playbooks'] ?? []));
  $toolAssembliesByParent = mes_group_rows_by((array)($master['tool_assemblies'] ?? []), 'parent_tool_id');
  $formLinksByOrder = mes_form_link_index($orders);
  $gateRules = load_mes_gate_rules();
  $shiftPatterns = load_mes_shift_patterns();
  $now = new DateTimeImmutable('now', new DateTimeZone('Asia/Ho_Chi_Minh'));
  $currentShift = mes_resolve_current_shift($shiftPatterns, $now);
  $connectorFeeds = mes_latest_rows_by_machine((array)($mes['connector_feeds'] ?? []), 'updated_at');
  $machineSignals = mes_latest_rows_by_machine((array)($mes['machine_signals'] ?? []), 'signal_at');
  $connectivityEventsByMachine = mes_group_rows_by((array)($mes['mes_connectivity_events'] ?? []), 'machine_id');
  $machineAlarmEventsByMachine = mes_group_rows_by((array)($mes['machine_alarm_events'] ?? []), 'machine_id');
  $ncDownloadReceipts = mes_latest_runtime_receipts((array)($mes['nc_download_receipts'] ?? []));
  $toolPresetOffsets = (array)($mes['mes_tool_preset_offsets'] ?? []);
  $materialConsumptionRows = array_values((array)($mes['material_consumption'] ?? []));
  $genealogyRows = array_values((array)($mes['part_genealogy'] ?? []));
  $shiftHandoverRows = array_values((array)($mes['shift_handover'] ?? []));
  $dppRows = array_values((array)($mes['dpp_passports'] ?? []));
  $energySnapshotRows = array_values((array)($mes['energy_snapshots'] ?? []));
  $costTrackingRows = array_values((array)($mes['cost_tracking'] ?? []));
  $dppByWo = mes_latest_rows_by_key($dppRows, 'wo_number', ['updated_at', 'published_at', 'created_at']);
  $costByWo = mes_latest_rows_by_key($costTrackingRows, 'wo_number', ['updated_at', 'captured_at', 'created_at']);
  $energyByMachine = mes_latest_rows_by_machine($energySnapshotRows, 'captured_at');

  $jos = master_index_by((array)($orders['job_orders'] ?? []), 'jo_number');
  $wos = master_index_by((array)($orders['work_orders'] ?? []), 'wo_number');
  $sales = master_index_by((array)($orders['sales_orders'] ?? []), 'so_number');

  $activeDowntimeByMachine = [];
  foreach ((array)($mes['downtime_events'] ?? []) as $event) {
    if (!is_array($event) || strtolower((string)($event['status'] ?? 'open')) !== 'open') continue;
    $machineId = trim((string)($event['machine_id'] ?? ''));
    if ($machineId === '') continue;
    $activeDowntimeByMachine[$machineId] = $event;
  }

  $activeMaintenanceByMachine = [];
  foreach ((array)($mes['maintenance_requests'] ?? []) as $request) {
    if (!is_array($request)) continue;
    $status = strtolower((string)($request['status'] ?? 'open'));
    if (!in_array($status, ['open', 'approved', 'in_progress'], true)) continue;
    $machineId = trim((string)($request['machine_id'] ?? ''));
    if ($machineId === '') continue;
    $activeMaintenanceByMachine[$machineId] = $request;
  }

  $toolingByMachine = [];
  $toolingByWo = [];
  $toolingAlerts = [];
  foreach ((array)($mes['tooling_status'] ?? []) as $toolRow) {
    if (!is_array($toolRow)) continue;
    $toolId = trim((string)($toolRow['tool_id'] ?? ''));
    $asset = $toolId !== '' ? ($toolingAssets[$toolId] ?? []) : [];
    $merged = array_merge($asset, $toolRow);
    $merged['tool_id'] = $toolId !== '' ? $toolId : (string)($asset['tool_id'] ?? '');
    $merged['tool_name'] = (string)($merged['tool_name'] ?? $asset['tool_name'] ?? '');
    $merged = mes_tool_alert_payload($merged);
    $machineId = trim((string)($merged['machine_id'] ?? ''));
    $woNumber = trim((string)($merged['wo_number'] ?? ''));
    if ($machineId !== '') $toolingByMachine[$machineId][] = $merged;
    if ($woNumber !== '') $toolingByWo[$woNumber][] = $merged;
    if (in_array((string)($merged['alert_level'] ?? 'healthy'), ['warning', 'critical', 'untracked'], true)) {
      $toolingAlerts[] = $merged;
    }
  }

  usort($toolingAlerts, function ($a, $b) {
    $priority = ['critical' => 0, 'warning' => 1, 'untracked' => 2, 'healthy' => 3];
    $ap = $priority[(string)($a['alert_level'] ?? 'healthy')] ?? 9;
    $bp = $priority[(string)($b['alert_level'] ?? 'healthy')] ?? 9;
    if ($ap !== $bp) return $ap <=> $bp;
    return (float)($b['life_used_pct'] ?? 0) <=> (float)($a['life_used_pct'] ?? 0);
  });

  $dispatch = [];
  $workOrdersByMachine = [];
  foreach ((array)($orders['work_orders'] ?? []) as $wo) {
    if (!is_array($wo)) continue;
    $woNumber = trim((string)($wo['wo_number'] ?? ''));
    $joNumber = trim((string)($wo['jo_number'] ?? ''));
    $machineId = trim((string)($wo['machine_id'] ?? ''));
    $status = strtolower((string)($wo['status'] ?? 'scheduled'));
    $jo = $jos[$joNumber] ?? [];
    $so = $sales[(string)($jo['so_number'] ?? '')] ?? [];
    $customerId = (string)($jo['customer_id'] ?? $so['customer_id'] ?? '');
    $partNumber = (string)($jo['part_number'] ?? '');
    $partMeta = $parts[$partNumber] ?? [];
    $dispatchRow = [
      'wo_number' => $woNumber,
      'jo_number' => $joNumber,
      'so_number' => (string)($jo['so_number'] ?? ''),
      'status' => $status,
      'operation_number' => (int)($wo['operation_number'] ?? 0),
      'operation_desc' => (string)($wo['operation_desc'] ?? ''),
      'machine_id' => $machineId,
      'machine_name' => (string)($machines[$machineId]['machine_name'] ?? ''),
      'machine_type' => (string)($machines[$machineId]['machine_type'] ?? ''),
      'work_center_id' => (string)($wo['work_center_id'] ?? ''),
      'work_center_name' => (string)($workCenters[(string)($wo['work_center_id'] ?? '')]['work_center_name'] ?? ''),
      'operator_id' => (string)($wo['operator_id'] ?? ''),
      'operator_name' => (string)($operators[(string)($wo['operator_id'] ?? '')]['operator_name'] ?? ''),
      'customer_id' => $customerId,
      'customer_name' => (string)($customers[$customerId]['customer_name'] ?? $so['customer_name'] ?? ''),
      'part_number' => $partNumber,
      'part_revision' => (string)($jo['part_revision'] ?? ''),
      'part_description' => (string)($jo['part_description'] ?? $partMeta['part_description'] ?? ''),
      'material_spec' => (string)($jo['material_spec'] ?? ''),
      'material_lot_number' => (string)($wo['material_lot_number'] ?? ''),
      'heat_number' => (string)($wo['heat_number'] ?? ''),
      'traveler_number' => (string)($wo['traveler_number'] ?? ''),
      'traveler_status' => (string)($wo['traveler_status'] ?? ''),
      'material_cert_status' => (string)($wo['material_cert_status'] ?? ''),
      'qty_ordered' => (int)($jo['qty_ordered'] ?? 0),
      'qty_completed' => (int)($wo['qty_completed'] ?? 0),
      'qty_scrap' => (int)($wo['qty_scrap'] ?? 0),
      'scheduled_start' => (string)($wo['scheduled_start'] ?? ''),
      'scheduled_end' => (string)($wo['scheduled_end'] ?? ''),
      'actual_start' => (string)($wo['actual_start'] ?? ''),
      'actual_end' => (string)($wo['actual_end'] ?? ''),
      'setup_time_est' => (float)($wo['setup_time_est'] ?? 0),
      'run_time_est' => (float)($wo['run_time_est'] ?? 0),
      'setup_time_actual' => (float)($wo['setup_time_actual'] ?? 0),
      'run_time_actual' => (float)($wo['run_time_actual'] ?? 0),
      'fixture_id' => (string)($wo['fixture_id'] ?? ''),
      'nc_program_id' => (string)($wo['nc_program_id'] ?? ''),
      'fai_required' => (bool)($jo['fai_required'] ?? false),
      'priority' => (string)($so['priority'] ?? 'normal'),
    ];

    $machineMeta = $machines[$machineId] ?? [];
    $feed = $machineId !== '' ? ($connectorFeeds[$machineId] ?? []) : [];
    $signal = $machineId !== '' ? ($machineSignals[$machineId] ?? []) : [];
    $connectorType = (string)($feed['connector_type'] ?? $machineMeta['connector_type'] ?? $machineMeta['telemetry_mode'] ?? $signal['source'] ?? 'manual_bridge');
    $heartbeatSla = (int)($feed['heartbeat_sla_seconds'] ?? $machineMeta['heartbeat_sla_seconds'] ?? 120);
    $lastHeartbeatAt = (string)($signal['last_heartbeat_at'] ?? $feed['last_heartbeat_at'] ?? $signal['signal_at'] ?? '');
    $signalAgeSeconds = mes_timestamp_age_seconds($lastHeartbeatAt, $now);
    $connectorHealth = mes_connector_health_from_age($signalAgeSeconds, $heartbeatSla, $connectorType);
    $signalState = mes_machine_state_normalize((string)($signal['machine_state'] ?? ''));
    $dispatchRow['telemetry'] = [
      'connector_type' => $connectorType,
      'connector_name' => (string)($feed['connector_name'] ?? $machineMeta['connector_name'] ?? strtoupper($connectorType)),
      'connector_health' => $connectorHealth,
      'heartbeat_sla_seconds' => $heartbeatSla,
      'last_heartbeat_at' => $lastHeartbeatAt,
      'signal_state' => $signalState,
      'signal_source' => (string)($signal['source'] ?? $connectorType),
      'signal_freshness_seconds' => $signalAgeSeconds,
      'current_program_id' => (string)($signal['current_program_id'] ?? $wo['nc_program_id'] ?? ''),
      'spindle_load_pct' => isset($signal['spindle_load_pct']) ? (float)$signal['spindle_load_pct'] : null,
      'spindle_power_kw' => isset($signal['spindle_power_kw']) ? (float)$signal['spindle_power_kw'] : null,
      'total_power_kw' => isset($signal['total_power_kw']) ? (float)$signal['total_power_kw'] : null,
      'feed_override_pct' => isset($signal['feed_override_pct']) ? (float)$signal['feed_override_pct'] : null,
      'part_count' => isset($signal['part_count']) ? (int)$signal['part_count'] : null,
      'telemetry_mode' => (string)($machineMeta['telemetry_mode'] ?? ($connectorType === 'manual_bridge' ? 'manual' : 'machine')),
    ];

    $woLinks = array_values((array)($formLinksByOrder['wo'][$woNumber] ?? []));
    $openDowntime = $machineId !== '' ? ($activeDowntimeByMachine[$machineId] ?? null) : null;
    $openMaintenance = $machineId !== '' ? ($activeMaintenanceByMachine[$machineId] ?? null) : null;
    $dispatchRow['evidence_gate'] = mes_evidence_gate_summary($dispatchRow, $jo, $woLinks, $openDowntime, $openMaintenance, $gateRules);

    $toolRows = !empty($toolingByWo[$woNumber]) ? array_values($toolingByWo[$woNumber]) : array_values((array)($toolingByMachine[$machineId] ?? []));
    $toolAlertCount = count(array_filter($toolRows, fn($row) => in_array((string)($row['alert_level'] ?? 'healthy'), ['warning', 'critical', 'untracked'], true)));
    $toolStatus = 'healthy';
    if ($toolAlertCount > 0) {
      $toolStatus = count(array_filter($toolRows, fn($row) => (string)($row['alert_level'] ?? '') === 'critical')) > 0 ? 'critical' : 'warning';
    } elseif (empty($toolRows) && in_array((string)($dispatchRow['work_center_id'] ?? ''), ['WC-5AX', 'WC-3AX'], true)) {
      $toolStatus = 'untracked';
    }
    $dispatchRow['tooling'] = [
      'status' => $toolStatus,
      'loaded_tool_count' => count($toolRows),
      'alert_count' => $toolAlertCount,
      'items' => $toolRows,
      'summary_vi' => $toolStatus === 'critical' ? 'Có tool tới hạn' : ($toolStatus === 'warning' ? 'Có tool cần chú ý' : ($toolStatus === 'untracked' ? 'Chưa theo dõi tool-life' : 'Tooling ổn định')),
      'summary_en' => $toolStatus === 'critical' ? 'Critical tool risk' : ($toolStatus === 'warning' ? 'Tool warning' : ($toolStatus === 'untracked' ? 'Tool-life not tracked' : 'Tooling stable')),
    ];
    $dispatchRow['program_release'] = mes_program_release_summary($dispatchRow, $programReleases);
    $dispatchRow['tool_readiness'] = mes_tool_readiness_summary($dispatchRow);
    $dispatchRow['operator_governance'] = mes_operator_governance_summary(
      $dispatchRow,
      $operators[(string)($dispatchRow['operator_id'] ?? '')] ?? [],
      $machineMeta,
      $now
    );
    $dispatchRow['material_trace'] = mes_material_trace_summary($dispatchRow, $partMeta);
    $dispatchRow['material_trace'] = mes_merge_material_trace_with_genealogy(
      $dispatchRow['material_trace'],
      mes_material_genealogy_overlay($dispatchRow, $partMeta, $materialConsumptionRows, $genealogyRows)
    );
    $dispatchRow['dpp_passport'] = (array)($dppByWo[$woNumber] ?? []);
    $dispatchRow['cost_tracking'] = (array)($costByWo[$woNumber] ?? []);
    $dispatchRow['connector_guard'] = mes_connector_guard_summary($dispatchRow, $machineMeta);
    $dispatchRow['adapter_governance'] = mes_adapter_governance_summary(
      $machineMeta,
      is_array($connectivityAdaptersByMachine[$machineId] ?? null) ? $connectivityAdaptersByMachine[$machineId] : null,
      [
        'connector_type' => $connectorType,
        'connector_health' => $connectorHealth,
      ],
      (array)($connectivityEventsByMachine[$machineId] ?? []),
      $now
    );
    $dispatchRow['alarm_runtime'] = mes_alarm_runtime_summary(
      $machineMeta,
      (array)($machineAlarmEventsByMachine[$machineId] ?? []),
      $alarmCatalog,
      $alarmPlaybooks,
      $now
    );
    $dispatchRow['nc_download'] = mes_nc_download_summary($dispatchRow, $programReleases, $ncDownloadReceipts);
    $dispatchRow['tool_offset'] = mes_tool_offset_summary($dispatchRow, $toolPresetOffsets, $toolRows, $toolAssembliesByParent, $now);
    $dispatch[] = $dispatchRow;
    if ($machineId !== '') $workOrdersByMachine[$machineId][] = $dispatchRow;
  }

  usort($dispatch, function ($a, $b) {
    return strcmp((string)($a['scheduled_start'] ?? ''), (string)($b['scheduled_start'] ?? ''));
  });

  $machineWall = [];
  $oeeRows = [];
  foreach ((array)($master['machines'] ?? []) as $machine) {
    if (!is_array($machine)) continue;
    $machineId = trim((string)($machine['machine_id'] ?? ''));
    if ($machineId === '') continue;
    $queue = array_values((array)($workOrdersByMachine[$machineId] ?? []));
    $activeWo = null;
    foreach ($queue as $candidate) {
      if (in_array((string)($candidate['status'] ?? ''), ['running', 'setup', 'inspection', 'on_hold'], true)) {
        $activeWo = $candidate;
        break;
      }
    }
    if ($activeWo === null && !empty($queue)) $activeWo = $queue[0];

    $feed = $connectorFeeds[$machineId] ?? [];
    $signal = $machineSignals[$machineId] ?? [];
    $connectorType = (string)($feed['connector_type'] ?? $machine['connector_type'] ?? $machine['telemetry_mode'] ?? $signal['source'] ?? 'manual_bridge');
    $heartbeatSla = (int)($feed['heartbeat_sla_seconds'] ?? $machine['heartbeat_sla_seconds'] ?? 120);
    $lastHeartbeatAt = (string)($signal['last_heartbeat_at'] ?? $feed['last_heartbeat_at'] ?? $signal['signal_at'] ?? '');
    $signalAgeSeconds = mes_timestamp_age_seconds($lastHeartbeatAt, $now);
    $connectorHealth = mes_connector_health_from_age($signalAgeSeconds, $heartbeatSla, $connectorType);
    $signalState = mes_machine_state_normalize((string)($signal['machine_state'] ?? ''));
    $signalIsFresh = in_array($connectorHealth, ['healthy', 'delayed'], true);

    $status = 'idle';
    if (isset($activeDowntimeByMachine[$machineId])) {
      $status = 'down';
    } elseif (isset($activeMaintenanceByMachine[$machineId])) {
      $status = 'maintenance';
    } elseif ($signalIsFresh && $signalState !== '' && $signalState !== 'offline') {
      $status = $signalState;
    } elseif ($activeWo) {
      $status = (string)($activeWo['status'] ?? 'scheduled');
    } elseif (!empty($queue)) {
      $status = 'scheduled';
    }

    $machineToolRows = array_values((array)($toolingByMachine[$machineId] ?? []));
    $machineAlertCount = count(array_filter($machineToolRows, fn($row) => in_array((string)($row['alert_level'] ?? 'healthy'), ['warning', 'critical', 'untracked'], true)));
    $machineDowntimeMinutes = 0.0;
    foreach ((array)($mes['downtime_events'] ?? []) as $event) {
      if (!is_array($event) || (string)($event['machine_id'] ?? '') !== $machineId) continue;
      $machineDowntimeMinutes += mes_minutes_between((string)($event['started_at'] ?? ''), strtolower((string)($event['status'] ?? 'open')) === 'resolved' ? (string)($event['resolved_at'] ?? '') : '', $now);
    }
    $plannedMinutes = array_reduce($queue, fn($carry, $row) => $carry + (float)($row['setup_time_est'] ?? 0) + (float)($row['run_time_est'] ?? 0), 0.0);
    $actualMinutes = array_reduce($queue, function ($carry, $row) use ($now) {
      $reported = (float)($row['setup_time_actual'] ?? 0) + (float)($row['run_time_actual'] ?? 0);
      if ($reported > 0) return $carry + $reported;
      $status = strtolower((string)($row['status'] ?? ''));
      if (in_array($status, ['setup', 'running', 'inspection', 'on_hold'], true)) {
        $start = (string)($row['actual_start'] ?? $row['scheduled_start'] ?? '');
        return $carry + mes_minutes_between($start, (string)($row['actual_end'] ?? ''), $now);
      }
      return $carry;
    }, 0.0);
    $goodQty = array_reduce($queue, fn($carry, $row) => $carry + (int)($row['qty_completed'] ?? 0), 0);
    $scrapQty = array_reduce($queue, fn($carry, $row) => $carry + (int)($row['qty_scrap'] ?? 0), 0);
    $totalQty = $goodQty + $scrapQty;
    $availability = mes_percent($actualMinutes, $actualMinutes + $machineDowntimeMinutes, null);
    $performance = ($actualMinutes > 0 && $plannedMinutes > 0) ? mes_clamp_percent(($plannedMinutes / $actualMinutes) * 100) : null;
    $quality = $totalQty > 0 ? mes_percent((float)$goodQty, (float)$totalQty, null) : 100.0;
    $oee = ($availability !== null && $performance !== null && $quality !== null) ? mes_clamp_percent(($availability * $performance * $quality) / 10000) : null;
    if ($availability !== null || $performance !== null || $quality !== null || $oee !== null) {
      $oeeRows[] = [
        'machine_id' => $machineId,
        'availability_pct' => $availability,
        'performance_pct' => $performance,
        'quality_pct' => $quality,
        'oee_pct' => $oee,
      ];
    }

    $activeEvidenceGate = $activeWo['evidence_gate'] ?? ['status' => 'not_required', 'total_required' => 0, 'completed_count' => 0, 'missing_form_codes' => []];
    $adapterMeta = $connectivityAdaptersByMachine[$machineId] ?? null;
    $adapterGovernance = mes_adapter_governance_summary(
      $machine,
      is_array($adapterMeta) ? $adapterMeta : null,
      [
        'connector_type' => $connectorType,
        'connector_health' => $connectorHealth,
      ],
      (array)($connectivityEventsByMachine[$machineId] ?? []),
      $now
    );
    $alarmRuntime = mes_alarm_runtime_summary(
      $machine,
      (array)($machineAlarmEventsByMachine[$machineId] ?? []),
      $alarmCatalog,
      $alarmPlaybooks,
      $now
    );
    $energySnapshot = (array)($energyByMachine[$machineId] ?? []);
    $machineWall[] = [
      'machine_id' => $machineId,
      'machine_name' => (string)($machine['machine_name'] ?? ''),
      'machine_type' => (string)($machine['machine_type'] ?? ''),
      'status' => $status,
      'work_center_id' => (string)($machine['work_center_id'] ?? ''),
      'work_center_name' => (string)($workCenters[(string)($machine['work_center_id'] ?? '')]['work_center_name'] ?? ''),
      'location' => (string)($machine['location'] ?? ''),
      'telemetry_mode' => (string)($machine['telemetry_mode'] ?? ($connectorType === 'manual_bridge' ? 'manual' : 'machine')),
      'connector_type' => $connectorType,
      'connector_name' => (string)($feed['connector_name'] ?? $machine['connector_name'] ?? strtoupper($connectorType)),
      'connector_endpoint' => (string)($feed['connector_endpoint'] ?? $machine['connector_endpoint'] ?? ''),
      'connector_health' => $connectorHealth,
      'heartbeat_sla_seconds' => $heartbeatSla,
      'last_heartbeat_at' => $lastHeartbeatAt,
      'signal_state' => $signalState,
      'signal_source' => (string)($signal['source'] ?? $connectorType),
      'signal_freshness_seconds' => $signalAgeSeconds,
      'current_program_id' => (string)($signal['current_program_id'] ?? $activeWo['nc_program_id'] ?? ''),
      'spindle_load_pct' => isset($signal['spindle_load_pct']) ? (float)$signal['spindle_load_pct'] : null,
      'spindle_power_kw' => isset($signal['spindle_power_kw']) ? (float)$signal['spindle_power_kw'] : null,
      'total_power_kw' => isset($signal['total_power_kw']) ? (float)$signal['total_power_kw'] : null,
      'feed_override_pct' => isset($signal['feed_override_pct']) ? (float)$signal['feed_override_pct'] : null,
      'part_count' => isset($signal['part_count']) ? (int)$signal['part_count'] : null,
      'energy_snapshot' => $energySnapshot,
      'energy_per_unit_kwh' => isset($energySnapshot['energy_per_unit_kwh']) ? (float)$energySnapshot['energy_per_unit_kwh'] : null,
      'preferred_operator_id' => (string)($machine['preferred_operator_id'] ?? ''),
      'preferred_operator_name' => (string)($operators[(string)($machine['preferred_operator_id'] ?? '')]['operator_name'] ?? ''),
      'adapter_governance' => $adapterGovernance,
      'alarm_runtime' => $alarmRuntime,
      'queue_count' => count($queue),
      'active_work_order' => $activeWo,
      'open_downtime' => $activeDowntimeByMachine[$machineId] ?? null,
      'open_maintenance' => $activeMaintenanceByMachine[$machineId] ?? null,
      'last_pm_date' => (string)($machine['last_pm_date'] ?? ''),
      'next_pm_date' => (string)($machine['next_pm_date'] ?? ''),
      'loaded_tool_count' => count($machineToolRows),
      'tool_alert_count' => $machineAlertCount,
      'tooling_items' => $machineToolRows,
      'program_release' => (array)($activeWo['program_release'] ?? []),
      'nc_download' => (array)($activeWo['nc_download'] ?? []),
      'tool_readiness' => (array)($activeWo['tool_readiness'] ?? []),
      'tool_offset' => (array)($activeWo['tool_offset'] ?? []),
      'dpp_passport' => (array)($activeWo['dpp_passport'] ?? []),
      'cost_tracking' => (array)($activeWo['cost_tracking'] ?? []),
      'operator_governance' => (array)($activeWo['operator_governance'] ?? []),
      'material_trace' => (array)($activeWo['material_trace'] ?? []),
      'connector_guard' => (array)($activeWo['connector_guard'] ?? []),
      'availability_pct' => $availability,
      'performance_pct' => $performance,
      'quality_pct' => $quality,
      'oee_pct' => $oee,
      'evidence_gate' => $activeEvidenceGate,
    ];
  }

  usort($machineWall, function ($a, $b) {
    return strcmp((string)($a['machine_id'] ?? ''), (string)($b['machine_id'] ?? ''));
  });

  $latestShiftHandoverByMachine = mes_latest_shift_handover_by_machine($shiftHandoverRows);

  $openDowntimes = array_values(array_filter((array)($mes['downtime_events'] ?? []), fn($row) => is_array($row) && strtolower((string)($row['status'] ?? 'open')) === 'open'));
  usort($openDowntimes, function ($a, $b) {
    return strcmp((string)($b['started_at'] ?? ''), (string)($a['started_at'] ?? ''));
  });

  $maintenanceQueue = array_values(array_filter((array)($mes['maintenance_requests'] ?? []), fn($row) => is_array($row) && !in_array(strtolower((string)($row['status'] ?? 'open')), ['completed', 'cancelled'], true)));
  usort($maintenanceQueue, function ($a, $b) {
    return strcmp((string)($a['requested_at'] ?? ''), (string)($b['requested_at'] ?? ''));
  });

  $overdueWo = count(array_filter($dispatch, function ($row) use ($now) {
    $status = strtolower((string)($row['status'] ?? ''));
    if (in_array($status, ['completed', 'closed'], true)) return false;
    $scheduledEnd = trim((string)($row['scheduled_end'] ?? ''));
    if ($scheduledEnd === '') return false;
    try {
      return new DateTimeImmutable($scheduledEnd) < $now;
    } catch (Throwable) {
      return false;
    }
  }));

  $kpis = [
    'machines_total' => count($machineWall),
    'machines_running' => count(array_filter($machineWall, fn($row) => in_array((string)($row['status'] ?? ''), ['running', 'setup', 'inspection'], true))),
    'machines_down' => count(array_filter($machineWall, fn($row) => (string)($row['status'] ?? '') === 'down')),
    'connectors_total' => count($machineWall),
    'connectors_healthy' => count(array_filter($machineWall, fn($row) => in_array((string)($row['connector_health'] ?? ''), ['healthy', 'delayed'], true))),
    'connectors_stale' => count(array_filter($machineWall, fn($row) => in_array((string)($row['connector_health'] ?? ''), ['stale', 'offline'], true))),
    'manual_bridges' => count(array_filter($machineWall, fn($row) => in_array((string)($row['connector_type'] ?? ''), ['manual', 'manual_bridge'], true))),
    'maintenance_open' => count($maintenanceQueue),
    'downtime_open' => count($openDowntimes),
    'wo_active' => count(array_filter($dispatch, fn($row) => in_array((string)($row['status'] ?? ''), ['scheduled', 'setup', 'running', 'inspection', 'on_hold'], true))),
    'wo_overdue' => $overdueWo,
    'tooling_alerts' => count($toolingAlerts),
    'wo_gate_missing' => count(array_filter($dispatch, fn($row) => in_array((string)($row['evidence_gate']['status'] ?? 'not_required'), ['missing', 'partial'], true))),
    'operator_qualification_gaps' => count(array_filter($dispatch, fn($row) => in_array((string)($row['operator_governance']['band'] ?? 'ready'), ['critical', 'warning'], true))),
    'material_trace_gaps' => count(array_filter($dispatch, fn($row) => in_array((string)($row['material_trace']['band'] ?? 'ready'), ['critical', 'warning'], true))),
    'connector_guard_gaps' => count(array_filter($dispatch, fn($row) => in_array((string)($row['connector_guard']['band'] ?? 'ready'), ['critical', 'warning'], true))),
    'adapter_governance_gaps' => count(array_filter($machineWall, fn($row) => in_array((string)($row['adapter_governance']['band'] ?? 'ready'), ['critical', 'warning'], true))),
    'active_alarm_hotspots' => count(array_filter($machineWall, fn($row) => (int)($row['alarm_runtime']['active_count'] ?? 0) > 0)),
    'availability_pct' => count($oeeRows) ? round(array_sum(array_map(fn($row) => (float)($row['availability_pct'] ?? 0), $oeeRows)) / count($oeeRows), 1) : null,
    'performance_pct' => count($oeeRows) ? round(array_sum(array_map(fn($row) => (float)($row['performance_pct'] ?? 0), $oeeRows)) / count($oeeRows), 1) : null,
    'quality_pct' => count($oeeRows) ? round(array_sum(array_map(fn($row) => (float)($row['quality_pct'] ?? 0), $oeeRows)) / count($oeeRows), 1) : null,
    'oee_pct' => count($oeeRows) ? round(array_sum(array_map(fn($row) => (float)($row['oee_pct'] ?? 0), $oeeRows)) / count($oeeRows), 1) : null,
  ];

  $workCenterSummary = [];
  foreach ((array)($master['work_centers'] ?? []) as $center) {
    if (!is_array($center)) continue;
    $centerId = trim((string)($center['work_center_id'] ?? ''));
    if ($centerId === '') continue;
    $centerOrders = array_values(array_filter($dispatch, fn($row) => (string)($row['work_center_id'] ?? '') === $centerId));
    $centerMachines = array_values(array_filter($machineWall, fn($row) => (string)($row['work_center_id'] ?? '') === $centerId));
    $workCenterSummary[] = [
      'work_center_id' => $centerId,
      'work_center_name' => (string)($center['work_center_name'] ?? ''),
      'department' => (string)($center['department'] ?? ''),
      'machine_count' => count($centerMachines),
      'wo_count' => count($centerOrders),
      'running_count' => count(array_filter($centerMachines, fn($row) => in_array((string)($row['status'] ?? ''), ['running', 'setup', 'inspection'], true))),
      'down_count' => count(array_filter($centerMachines, fn($row) => (string)($row['status'] ?? '') === 'down')),
      'connector_risk_count' => count(array_filter($centerMachines, fn($row) => in_array((string)($row['connector_health'] ?? ''), ['stale', 'offline'], true))),
      'tooling_alert_count' => count(array_filter($centerMachines, fn($row) => (int)($row['tool_alert_count'] ?? 0) > 0)),
      'gate_missing_count' => count(array_filter($centerOrders, fn($row) => in_array((string)($row['evidence_gate']['status'] ?? 'not_required'), ['missing', 'partial'], true))),
      'operator_gap_count' => count(array_filter($centerOrders, fn($row) => in_array((string)($row['operator_governance']['band'] ?? 'ready'), ['critical', 'warning'], true))),
      'material_gap_count' => count(array_filter($centerOrders, fn($row) => in_array((string)($row['material_trace']['band'] ?? 'ready'), ['critical', 'warning'], true))),
      'oee_pct' => count($centerMachines) ? round(array_sum(array_map(fn($row) => (float)($row['oee_pct'] ?? 0), array_filter($centerMachines, fn($row) => $row['oee_pct'] !== null))) / max(1, count(array_filter($centerMachines, fn($row) => $row['oee_pct'] !== null))), 1) : null,
    ];
  }

  $connectorSummary = array_map(function ($row) {
    return [
      'machine_id' => (string)($row['machine_id'] ?? ''),
      'machine_name' => (string)($row['machine_name'] ?? ''),
      'work_center_id' => (string)($row['work_center_id'] ?? ''),
      'connector_type' => (string)($row['connector_type'] ?? ''),
      'connector_name' => (string)($row['connector_name'] ?? ''),
      'connector_health' => (string)($row['connector_health'] ?? 'offline'),
      'heartbeat_sla_seconds' => (int)($row['heartbeat_sla_seconds'] ?? 120),
      'last_heartbeat_at' => (string)($row['last_heartbeat_at'] ?? ''),
      'signal_state' => (string)($row['signal_state'] ?? ''),
      'signal_source' => (string)($row['signal_source'] ?? ''),
      'signal_freshness_seconds' => $row['signal_freshness_seconds'] ?? null,
      'telemetry_mode' => (string)($row['telemetry_mode'] ?? ''),
      'current_program_id' => (string)($row['current_program_id'] ?? ''),
      'spindle_load_pct' => $row['spindle_load_pct'] ?? null,
      'spindle_power_kw' => $row['spindle_power_kw'] ?? null,
      'total_power_kw' => $row['total_power_kw'] ?? null,
      'feed_override_pct' => $row['feed_override_pct'] ?? null,
      'part_count' => $row['part_count'] ?? null,
      'status' => (string)($row['status'] ?? 'idle'),
    ];
  }, $machineWall);

  usort($connectorSummary, function ($a, $b) {
    $priority = ['stale' => 0, 'offline' => 1, 'delayed' => 2, 'manual_only' => 3, 'healthy' => 4, 'disabled' => 5];
    $ap = $priority[(string)($a['connector_health'] ?? 'offline')] ?? 9;
    $bp = $priority[(string)($b['connector_health'] ?? 'offline')] ?? 9;
    if ($ap !== $bp) return $ap <=> $bp;
    return strcmp((string)($a['machine_id'] ?? ''), (string)($b['machine_id'] ?? ''));
  });

  $evidenceGateQueue = array_values(array_map(function ($row) {
    return [
      'wo_number' => (string)($row['wo_number'] ?? ''),
      'jo_number' => (string)($row['jo_number'] ?? ''),
      'machine_id' => (string)($row['machine_id'] ?? ''),
      'machine_name' => (string)($row['machine_name'] ?? ''),
      'work_center_id' => (string)($row['work_center_id'] ?? ''),
      'customer_name' => (string)($row['customer_name'] ?? ''),
      'part_number' => (string)($row['part_number'] ?? ''),
      'part_revision' => (string)($row['part_revision'] ?? ''),
      'status' => (string)($row['evidence_gate']['status'] ?? 'not_required'),
      'total_required' => (int)($row['evidence_gate']['total_required'] ?? 0),
      'completed_count' => (int)($row['evidence_gate']['completed_count'] ?? 0),
      'missing_form_codes' => array_values((array)($row['evidence_gate']['missing_form_codes'] ?? [])),
      'summary_vi' => (string)($row['evidence_gate']['summary_vi'] ?? ''),
      'summary_en' => (string)($row['evidence_gate']['summary_en'] ?? ''),
    ];
  }, array_values(array_filter($dispatch, fn($row) => in_array((string)($row['evidence_gate']['status'] ?? 'not_required'), ['missing', 'partial'], true)))));

  $oeeTimeline = mes_build_oee_timeline($machineWall);
  $downtimePareto = mes_build_downtime_pareto((array)($mes['downtime_events'] ?? []), $now);
  $programHandshakeQueue = mes_build_program_handshake_queue($dispatch);
  $programReleaseQueue = mes_build_program_release_queue($dispatch);
  $toolReadinessQueue = mes_build_tool_readiness_queue($dispatch);
  $ncDownloadMismatchQueue = mes_build_nc_download_mismatch_queue($dispatch);
  $toolOffsetQueue = mes_build_tool_offset_queue($dispatch);
  $operatorQualificationQueue = mes_build_operator_qualification_queue($dispatch);
  $materialTraceQueue = mes_build_material_trace_queue($dispatch);
  $materialGenealogyQueue = mes_build_material_genealogy_queue($dispatch);
  $alarmAckQueue = mes_build_alarm_ack_queue($dispatch);
  $connectorGuardQueue = mes_build_connector_guard_queue($dispatch);
  $adapterGovernanceQueue = mes_build_adapter_governance_queue($machineWall);
  $alarmHotspotQueue = mes_build_alarm_hotspot_queue($machineWall);
  $dppQueue = mes_build_dpp_queue($dispatch, $genealogyRows, $dppRows);
  $energyQueue = mes_build_energy_queue($machineWall, $energySnapshotRows);
  $costVarianceQueue = mes_build_cost_variance_queue($dispatch, $costTrackingRows);
  $reviewSlaQueue = evidence_review_sla_queue_rows();
  $releaseFollowupQueue = release_followup_queue_rows();
  $releaseFollowupSummary = release_followup_summary($releaseFollowupQueue);
  $shiftHandoverQueue = mes_build_shift_handover_queue($machineWall, $latestShiftHandoverByMachine, $shiftPatterns, $currentShift, $now);
  $epicorPolicy = load_epicor_integration_policy();
  $epicorStore = load_epicor_runtime_store();
  $epicorSnapshot = epicor_integration_service()->buildSnapshot($epicorStore, $orders, $master, $mes, $epicorPolicy);
  $materialGenealogyByWo = master_index_by($materialGenealogyQueue, 'wo_number');
  $shiftHandoverByMachineQueue = master_index_by($shiftHandoverQueue, 'machine_id');
  foreach ($dispatch as &$dispatchRow) {
    if (!is_array($dispatchRow)) continue;
    $dispatchRow['material_genealogy'] = (array)($materialGenealogyByWo[(string)($dispatchRow['wo_number'] ?? '')] ?? []);
    $dispatchRow['shift_handover'] = (array)($shiftHandoverByMachineQueue[(string)($dispatchRow['machine_id'] ?? '')] ?? []);
  }
  unset($dispatchRow);
  foreach ($machineWall as &$machineRow) {
    if (!is_array($machineRow)) continue;
    $activeWoNumber = (string)($machineRow['active_work_order']['wo_number'] ?? '');
    $machineId = (string)($machineRow['machine_id'] ?? '');
    $machineRow['material_genealogy'] = (array)($materialGenealogyByWo[$activeWoNumber] ?? []);
    $machineRow['shift_handover'] = (array)($shiftHandoverByMachineQueue[$machineId] ?? []);
  }
  unset($machineRow);
  $observability = load_runtime_observability_store();
  $runtimeMode = runtime_data_layer_summary();
  $cutoverAudit = build_runtime_cutover_audit([
    'master' => $master,
    'orders' => $orders,
    'mes' => $mes,
    'runtime_mode' => $runtimeMode,
  ]);
  $shadowSyncFailures = mes_shadow_failure_rows($observability);
  $launchBlockerQueue = mes_launch_blocker_rows($observability);
  $primaryReadQueue = mes_primary_read_rows($observability);
  $epicorSyncQueue = array_values((array)($epicorSnapshot['exception_queue'] ?? []));
  $energyIntensitySamples = array_values(array_filter(array_map(static function ($row) {
    if (!is_array($row)) return null;
    $value = $row['energy_per_unit_kwh'] ?? null;
    if ($value === null || $value === '') return null;
    return (float)$value;
  }, $energySnapshotRows), static fn($value) => $value !== null));
  $avgEnergyPerUnit = $energyIntensitySamples ? round(array_sum($energyIntensitySamples) / count($energyIntensitySamples), 3) : null;

  $kpis['program_mismatches'] = count($programHandshakeQueue);
  $kpis['program_release_risk'] = count($programReleaseQueue);
  $kpis['tool_readiness_risk'] = count($toolReadinessQueue);
  $kpis['nc_download_mismatches'] = count($ncDownloadMismatchQueue);
  $kpis['tool_offset_risk'] = count($toolOffsetQueue);
  $kpis['adapter_governance_risk'] = count($adapterGovernanceQueue);
  $kpis['alarm_hotspots'] = count($alarmHotspotQueue);
  $kpis['alarm_ack_gaps'] = count($alarmAckQueue);
  $kpis['review_sla_gaps'] = count($reviewSlaQueue);
  $kpis['release_followup_open'] = (int)($releaseFollowupSummary['total_open'] ?? 0);
  $kpis['release_followup_overdue'] = (int)($releaseFollowupSummary['overdue'] ?? 0);
  $kpis['material_genealogy_gaps'] = count($materialGenealogyQueue);
  $kpis['shift_handover_gaps'] = count($shiftHandoverQueue);
  $kpis['shadow_sync_failures'] = count($shadowSyncFailures);
  $kpis['launch_blocker_hotspots'] = count($launchBlockerQueue);
  $kpis['primary_read_fallbacks'] = count($primaryReadQueue);
  $kpis['cutover_drift_entities'] = (int)($cutoverAudit['drift_entities'] ?? 0);
  $kpis['epicor_sync_status'] = count($epicorSyncQueue);
  $kpis['epicor_reconciliation_open'] = (int)($epicorSnapshot['kpis']['reconciliation_open'] ?? 0);
  $kpis['epicor_outbox_pending'] = (int)($epicorSnapshot['kpis']['outbox_pending'] ?? 0);
  $kpis['dpp_readiness_gaps'] = count($dppQueue);
  $kpis['energy_tracking_gaps'] = count($energyQueue);
  $kpis['cost_variance_risk'] = count($costVarianceQueue);
  $kpis['energy_per_unit_kwh'] = $avgEnergyPerUnit;

  return [
    'kpis' => $kpis,
    'machine_wall' => $machineWall,
    'dispatch' => $dispatch,
    'open_downtimes' => $openDowntimes,
    'maintenance_queue' => $maintenanceQueue,
    'progress_reports' => array_slice(array_values(array_reverse((array)($mes['progress_reports'] ?? []))), 0, 20),
    'work_center_summary' => $workCenterSummary,
    'connector_summary' => $connectorSummary,
    'oee_timeline' => array_slice($oeeTimeline, 0, 12),
    'downtime_pareto' => array_slice($downtimePareto, 0, 8),
    'program_handshake_queue' => array_slice($programHandshakeQueue, 0, 20),
    'program_release_queue' => array_slice($programReleaseQueue, 0, 20),
    'tool_readiness_queue' => array_slice($toolReadinessQueue, 0, 20),
    'alarm_ack_queue' => array_slice($alarmAckQueue, 0, 20),
    'review_sla_queue' => array_slice($reviewSlaQueue, 0, 20),
    'release_followup_queue' => array_slice($releaseFollowupQueue, 0, 20),
    'release_followup_summary' => $releaseFollowupSummary,
    'nc_download_mismatch_queue' => array_slice($ncDownloadMismatchQueue, 0, 20),
    'tool_offset_queue' => array_slice($toolOffsetQueue, 0, 20),
    'dpp_queue' => array_slice($dppQueue, 0, 20),
    'energy_queue' => array_slice($energyQueue, 0, 20),
    'cost_variance_queue' => array_slice($costVarianceQueue, 0, 20),
    'operator_qualification_queue' => array_slice($operatorQualificationQueue, 0, 20),
    'material_trace_queue' => array_slice($materialTraceQueue, 0, 20),
    'material_genealogy_queue' => array_slice($materialGenealogyQueue, 0, 20),
    'shift_handover_queue' => array_slice($shiftHandoverQueue, 0, 20),
    'connector_guard_queue' => array_slice($connectorGuardQueue, 0, 20),
    'adapter_governance_queue' => array_slice($adapterGovernanceQueue, 0, 20),
    'alarm_hotspot_queue' => array_slice($alarmHotspotQueue, 0, 20),
    'shadow_sync_failures' => array_slice($shadowSyncFailures, 0, 20),
    'launch_blocker_queue' => array_slice($launchBlockerQueue, 0, 20),
    'primary_read_queue' => array_slice($primaryReadQueue, 0, 20),
    'cutover_audit' => $cutoverAudit,
    'epicor_sync' => $epicorSnapshot,
    'epicor_sync_queue' => array_slice($epicorSyncQueue, 0, 20),
    'shadow_status' => $observability['shadow_sync'] ?? [],
    'primary_read_status' => $observability['primary_reads'] ?? [],
    'connector_ingest_status' => $observability['connector_ingest'] ?? [],
    'launch_blocker_status' => $observability['launch_blockers'] ?? [],
    'runtime_mode' => $runtimeMode,
    'current_shift' => $currentShift,
    'tooling_alerts' => array_slice($toolingAlerts, 0, 20),
    'evidence_gate_queue' => array_slice($evidenceGateQueue, 0, 20),
    'dpp_passports' => array_slice($dppRows, 0, 50),
    'energy_snapshots' => array_slice($energySnapshotRows, 0, 50),
    'cost_tracking' => array_slice($costTrackingRows, 0, 50),
  ];
}

function upsert_master_data_item(array &$store, string $entity, array $item, string $username): array {
  $map = [
    'customers' => 'customer_id',
    'customer_sites' => 'site_id',
    'commercial_accounts' => 'account_id',
    'suppliers' => 'supplier_id',
    'parts' => 'part_number',
    'revisions' => 'revision_id',
    'incoterms' => 'incoterm_code',
    'payment_terms' => 'payment_term_code',
    'shipping_methods' => 'shipping_method_id',
    'promise_policies' => 'promise_policy_id',
    'routing_library' => 'routing_id',
    'bom_library' => 'bom_id',
    'control_plans' => 'control_plan_id',
    'inspection_plans' => 'inspection_plan_id',
    'traveler_templates' => 'traveler_template_id',
    'quality_gate_profiles' => 'quality_gate_profile_id',
    'launch_gate_templates' => 'gate_template_id',
    'customer_item_approvals' => 'approval_id',
    'supplier_process_approvals' => 'approval_id',
    'warehouse_locations' => 'warehouse_id',
    'defect_catalog' => 'defect_code',
    'nc_program_releases' => 'program_id',
    'capas' => 'capa_number',
    'work_centers' => 'work_center_id',
    'machines' => 'machine_id',
    'operators' => 'operator_id',
    'tooling_assets' => 'tool_id',
    'downtime_reason_codes' => 'reason_code',
    'downtime_resolution_codes' => 'resolution_code',
    'mes_connectivity_adapters' => 'adapter_id',
    'mes_alarm_catalog' => 'alarm_code',
    'mes_alarm_playbooks' => 'playbook_id',
    'tool_assemblies' => 'assembly_id',
  ];
  if (!isset($map[$entity])) throw new RuntimeException('invalid_master_entity');
  $idKey = $map[$entity];
  $id = trim((string)($item[$idKey] ?? ''));
  if ($id === '') throw new RuntimeException('missing_master_key');

  $normalized = master_data_normalize_item($entity, $item);
  $normalized[$idKey] = $id;
  $normalized['updated_at'] = now_iso();
  $normalized['updated_by'] = $username;
  if (empty($normalized['created_at'])) $normalized['created_at'] = now_iso();

  $found = false;
  foreach ($store[$entity] as $idx => $row) {
    if (!is_array($row)) continue;
    if ((string)($row[$idKey] ?? '') !== $id) continue;
    $normalized['created_at'] = (string)($row['created_at'] ?? $normalized['created_at']);
    $normalized['created_by'] = (string)($row['created_by'] ?? $username);
    $store[$entity][$idx] = array_merge($row, $normalized);
    $found = true;
    break;
  }
  if (!$found) {
    $normalized['created_by'] = $username;
    $store[$entity][] = $normalized;
  }
  return $normalized;
}

function load_record_type_registry(): array {
  global $DATA_DIR;
  $file = $DATA_DIR . '/config/record_type_expanded.json';
  if (!is_file($file)) return [];
  $data = json_decode((string)file_get_contents($file), true);
  $recordTypes = is_array($data['record_types'] ?? null) ? $data['record_types'] : [];
  foreach ($recordTypes as $code => &$recordType) {
    if (!is_array($recordType)) continue;
    $recordType['retention_policy'] = evidence_retention_policy_for_type((string)$code, $recordTypes);
    $recordType['review_sla_policy'] = evidence_review_sla_policy_for_type((string)$code, $recordTypes);
  }
  unset($recordType);
  return $recordTypes;
}

function evidence_retention_default_store(array $recordTypes = []): array {
  $defaults = [
    'retention_years' => 5,
    'retention_trigger' => 'approved',
    'disposition_action' => 'review_before_disposal',
    'legal_hold_allowed' => true,
  ];
  $overrides = [
    'NCR' => ['retention_years' => 5, 'retention_trigger' => 'approved'],
    'CAPA' => ['retention_years' => 5, 'retention_trigger' => 'approved'],
    'FAI' => ['retention_years' => 10, 'retention_trigger' => 'approved'],
    'TRN' => ['retention_years' => 5, 'retention_trigger' => 'approved'],
    'AUD' => ['retention_years' => 5, 'retention_trigger' => 'approved'],
    'ECR' => ['retention_years' => 10, 'retention_trigger' => 'approved'],
    'MR' => ['retention_years' => 10, 'retention_trigger' => 'approved'],
    'RISK' => ['retention_years' => 5, 'retention_trigger' => 'approved'],
    'CAL' => ['retention_years' => 5, 'retention_trigger' => 'approved'],
    'SCAR' => ['retention_years' => 7, 'retention_trigger' => 'approved'],
  ];

  if (!$recordTypes) {
    global $DATA_DIR;
    $file = $DATA_DIR . '/config/record_type_expanded.json';
    if (is_file($file)) {
      $data = json_decode((string)file_get_contents($file), true);
      $recordTypes = is_array($data['record_types'] ?? null) ? $data['record_types'] : [];
    }
  }

  $recordTypePolicies = [];
  foreach ($recordTypes as $code => $recordType) {
    $category = strtolower(trim((string)($recordType['category'] ?? '')));
    $categoryDefaults = [];
    if ($category === 'admin') $categoryDefaults = ['retention_years' => 10];
    if ($category === 'engineering') $categoryDefaults = ['retention_years' => 10];
    if ($category === 'hr') $categoryDefaults = ['retention_years' => 5];
    $recordTypePolicies[$code] = array_merge($defaults, $categoryDefaults, $overrides[$code] ?? []);
  }

  return [
    '_meta' => [
      'version' => '1.0',
      'updated_at' => now_iso(),
      'updated_by' => 'system',
    ],
    'defaults' => $defaults,
    'record_types' => $recordTypePolicies,
  ];
}

function load_evidence_retention_policy_store(array $recordTypes = []): array {
  global $EVIDENCE_RETENTION_POLICY_FILE;
  if (!is_file($EVIDENCE_RETENTION_POLICY_FILE)) {
    return evidence_retention_default_store($recordTypes);
  }
  $data = json_decode((string)file_get_contents($EVIDENCE_RETENTION_POLICY_FILE), true);
  if (!is_array($data)) return evidence_retention_default_store($recordTypes);
  $defaults = is_array($data['defaults'] ?? null) ? $data['defaults'] : [];
  $recordTypePolicies = is_array($data['record_types'] ?? null) ? $data['record_types'] : [];
  return [
    '_meta' => is_array($data['_meta'] ?? null) ? $data['_meta'] : ['version' => '1.0', 'updated_at' => now_iso(), 'updated_by' => 'system'],
    'defaults' => array_merge(evidence_retention_default_store($recordTypes)['defaults'], $defaults),
    'record_types' => $recordTypePolicies,
  ];
}

function save_evidence_retention_policy_store(array $store): void {
  global $EVIDENCE_RETENTION_POLICY_FILE;
  $store['_meta']['updated_at'] = now_iso();
  file_put_contents($EVIDENCE_RETENTION_POLICY_FILE, json_encode($store, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES), LOCK_EX);
}

function evidence_retention_policy_for_type(string $recordType, array $recordTypes = []): array {
  $recordType = strtoupper(trim($recordType));
  $defaultStore = evidence_retention_default_store($recordTypes);
  $store = load_evidence_retention_policy_store($recordTypes);
  $defaults = is_array($defaultStore['defaults'] ?? null) ? $defaultStore['defaults'] : [];
  $baseByType = is_array($defaultStore['record_types'][$recordType] ?? null) ? $defaultStore['record_types'][$recordType] : [];
  $savedByType = is_array($store['record_types'][$recordType] ?? null) ? $store['record_types'][$recordType] : [];
  return array_merge($defaults, $baseByType, $savedByType, ['record_type' => $recordType]);
}

function evidence_retention_management_roles(): array {
  return ['admin', 'it_admin', 'ceo', 'qa_manager', 'quality_manager', 'engineering_manager', 'production_manager', 'qms_engineer'];
}

function evidence_retention_can_manage(array $user): bool {
  return user_has_any_role($user, evidence_retention_management_roles());
}

function evidence_retention_trigger_value(array $allocation, string $trigger): string {
  $trigger = strtolower(trim($trigger));
  $map = [
    'approved' => (string)($allocation['approved_at'] ?? ''),
    'received' => (string)($allocation['latest_upload_timestamp'] ?? $allocation['received_at'] ?? ''),
    'submitted' => (string)($allocation['online_submission']['submitted_at'] ?? $allocation['submitted_at'] ?? ''),
    'created' => (string)($allocation['created_at'] ?? ''),
    'updated' => (string)($allocation['updated_at'] ?? ''),
  ];
  $candidate = trim((string)($map[$trigger] ?? ''));
  if ($candidate !== '') return $candidate;
  foreach (['approved', 'received', 'submitted', 'updated', 'created'] as $fallback) {
    $value = trim((string)($map[$fallback] ?? ''));
    if ($value !== '') return $value;
  }
  return '';
}

function evidence_retention_evaluate(array $allocation, array $recordTypes = []): array {
  $recordType = strtoupper(trim((string)($allocation['record_type'] ?? '')));
  $policy = evidence_retention_policy_for_type($recordType, $recordTypes);
  $trigger = strtolower(trim((string)($policy['retention_trigger'] ?? 'approved')));
  $years = max(1, (int)($policy['retention_years'] ?? 5));
  $startRaw = evidence_retention_trigger_value($allocation, $trigger);
  $startAt = evidence_parse_date_value($startRaw);
  $dueAt = $startAt ? $startAt->modify('+' . $years . ' years') : null;
  $hold = is_array($allocation['retention_hold'] ?? null) ? $allocation['retention_hold'] : [];
  $holdActive = !empty($hold['active']);
  $daysRemaining = null;
  if ($dueAt) {
    $daysRemaining = (int)floor(($dueAt->getTimestamp() - time()) / 86400);
  }

  $state = 'active';
  if ($holdActive) $state = 'on_hold';
  elseif ($dueAt && $daysRemaining !== null && $daysRemaining < 0) $state = 'due_for_disposition';
  elseif ($dueAt && $daysRemaining !== null && $daysRemaining <= 90) $state = 'due_soon';

  return [
    'record_type' => $recordType,
    'policy' => $policy,
    'start_at' => $startAt ? $startAt->format(DateTimeInterface::ATOM) : '',
    'due_at' => $dueAt ? $dueAt->format(DateTimeInterface::ATOM) : '',
    'state' => $state,
    'days_remaining' => $daysRemaining,
    'legal_hold' => [
      'active' => $holdActive,
      'reason' => trim((string)($hold['reason'] ?? '')),
      'set_at' => trim((string)($hold['set_at'] ?? '')),
      'set_by' => trim((string)($hold['set_by'] ?? '')),
    ],
  ];
}

function evidence_review_sla_default_roles(string $departmentOwner, string $category = ''): array {
  $departmentOwner = strtoupper(trim($departmentOwner));
  $category = strtolower(trim($category));
  if ($departmentOwner === 'QA') return ['qa_manager', 'quality_manager'];
  if ($departmentOwner === 'ENG') return ['engineering_manager', 'qa_manager'];
  if ($departmentOwner === 'PRO') return ['production_manager', 'qa_manager'];
  if ($departmentOwner === 'HR') return ['admin', 'ceo'];
  if ($departmentOwner === 'EXE') return ['ceo', 'admin'];
  if ($departmentOwner === 'IT') return ['it_admin', 'admin'];
  if ($departmentOwner === 'SCM' || $departmentOwner === 'WH') return ['production_manager', 'qa_manager'];
  if ($category === 'engineering') return ['engineering_manager', 'qa_manager'];
  if ($category === 'quality') return ['qa_manager', 'quality_manager'];
  return ['admin', 'ceo'];
}

function evidence_review_sla_default_store(array $recordTypes = []): array {
  $defaults = [
    'review_hours' => 72,
    'warn_hours_before_due' => 12,
    'escalate_hours_after_due' => 24,
    'escalation_roles' => ['qa_manager', 'quality_manager'],
  ];
  $overrides = [
    'NCR' => ['review_hours' => 48, 'warn_hours_before_due' => 12, 'escalate_hours_after_due' => 12, 'escalation_roles' => ['qa_manager', 'quality_manager']],
    'CAPA' => ['review_hours' => 48, 'warn_hours_before_due' => 12, 'escalate_hours_after_due' => 12, 'escalation_roles' => ['qa_manager', 'quality_manager']],
    'AUD' => ['review_hours' => 48, 'warn_hours_before_due' => 12, 'escalate_hours_after_due' => 12, 'escalation_roles' => ['qa_manager', 'quality_manager']],
    'FAI' => ['review_hours' => 72, 'warn_hours_before_due' => 24, 'escalate_hours_after_due' => 12, 'escalation_roles' => ['qa_manager', 'production_manager']],
    'SCAR' => ['review_hours' => 72, 'warn_hours_before_due' => 24, 'escalate_hours_after_due' => 12, 'escalation_roles' => ['qa_manager', 'quality_manager']],
    'ECR' => ['review_hours' => 72, 'warn_hours_before_due' => 24, 'escalate_hours_after_due' => 24, 'escalation_roles' => ['engineering_manager', 'qa_manager']],
    'MR' => ['review_hours' => 72, 'warn_hours_before_due' => 24, 'escalate_hours_after_due' => 24, 'escalation_roles' => ['ceo', 'admin']],
    'RISK' => ['review_hours' => 48, 'warn_hours_before_due' => 12, 'escalate_hours_after_due' => 24, 'escalation_roles' => ['ceo', 'qa_manager']],
    'TRN' => ['review_hours' => 72, 'warn_hours_before_due' => 24, 'escalate_hours_after_due' => 24, 'escalation_roles' => ['admin', 'ceo']],
    'CAL' => ['review_hours' => 72, 'warn_hours_before_due' => 24, 'escalate_hours_after_due' => 24, 'escalation_roles' => ['qa_manager', 'quality_manager']],
  ];

  if (!$recordTypes) {
    global $DATA_DIR;
    $file = $DATA_DIR . '/config/record_type_expanded.json';
    if (is_file($file)) {
      $data = json_decode((string)file_get_contents($file), true);
      $recordTypes = is_array($data['record_types'] ?? null) ? $data['record_types'] : [];
    }
  }

  $recordTypePolicies = [];
  foreach ($recordTypes as $code => $recordType) {
    $category = strtolower(trim((string)($recordType['category'] ?? '')));
    $departmentOwner = strtoupper(trim((string)($recordType['department_owner'] ?? '')));
    $categoryDefaults = [];
    if ($category === 'quality') $categoryDefaults = ['review_hours' => 48, 'warn_hours_before_due' => 12, 'escalate_hours_after_due' => 12];
    if ($category === 'engineering') $categoryDefaults = ['review_hours' => 72, 'warn_hours_before_due' => 24, 'escalate_hours_after_due' => 24];
    if ($category === 'admin') $categoryDefaults = ['review_hours' => 72, 'warn_hours_before_due' => 24, 'escalate_hours_after_due' => 24];
    if ($category === 'hr') $categoryDefaults = ['review_hours' => 72, 'warn_hours_before_due' => 24, 'escalate_hours_after_due' => 24];
    if ($category === 'maintenance') $categoryDefaults = ['review_hours' => 72, 'warn_hours_before_due' => 24, 'escalate_hours_after_due' => 24];
    $recordTypePolicies[$code] = array_merge(
      $defaults,
      $categoryDefaults,
      ['escalation_roles' => evidence_review_sla_default_roles($departmentOwner, $category)],
      $overrides[$code] ?? []
    );
  }

  return [
    '_meta' => [
      'version' => '1.0',
      'updated_at' => now_iso(),
      'updated_by' => 'system',
    ],
    'defaults' => $defaults,
    'record_types' => $recordTypePolicies,
  ];
}

function load_evidence_review_sla_policy_store(array $recordTypes = []): array {
  global $EVIDENCE_REVIEW_SLA_POLICY_FILE;
  if (!is_file($EVIDENCE_REVIEW_SLA_POLICY_FILE)) {
    return evidence_review_sla_default_store($recordTypes);
  }
  $data = json_decode((string)file_get_contents($EVIDENCE_REVIEW_SLA_POLICY_FILE), true);
  if (!is_array($data)) return evidence_review_sla_default_store($recordTypes);
  $defaults = is_array($data['defaults'] ?? null) ? $data['defaults'] : [];
  $recordTypePolicies = is_array($data['record_types'] ?? null) ? $data['record_types'] : [];
  return [
    '_meta' => is_array($data['_meta'] ?? null) ? $data['_meta'] : ['version' => '1.0', 'updated_at' => now_iso(), 'updated_by' => 'system'],
    'defaults' => array_merge(evidence_review_sla_default_store($recordTypes)['defaults'], $defaults),
    'record_types' => $recordTypePolicies,
  ];
}

function save_evidence_review_sla_policy_store(array $store): void {
  global $EVIDENCE_REVIEW_SLA_POLICY_FILE;
  $store['_meta']['updated_at'] = now_iso();
  file_put_contents($EVIDENCE_REVIEW_SLA_POLICY_FILE, json_encode($store, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES), LOCK_EX);
}

function evidence_review_sla_policy_for_type(string $recordType, array $recordTypes = []): array {
  $recordType = strtoupper(trim($recordType));
  $defaultStore = evidence_review_sla_default_store($recordTypes);
  $store = load_evidence_review_sla_policy_store($recordTypes);
  $defaults = is_array($defaultStore['defaults'] ?? null) ? $defaultStore['defaults'] : [];
  $baseByType = is_array($defaultStore['record_types'][$recordType] ?? null) ? $defaultStore['record_types'][$recordType] : [];
  $savedByType = is_array($store['record_types'][$recordType] ?? null) ? $store['record_types'][$recordType] : [];
  $policy = array_merge($defaults, $baseByType, $savedByType, ['record_type' => $recordType]);
  $policy['escalation_roles'] = array_values(array_unique(array_values(array_filter(array_map(
    static fn($role) => strtolower(trim((string)$role)),
    is_array($policy['escalation_roles'] ?? null) ? $policy['escalation_roles'] : []
  )))));
  return $policy;
}

function evidence_review_sla_management_roles(): array {
  return ['admin', 'it_admin', 'ceo', 'qa_manager', 'quality_manager', 'engineering_manager', 'production_manager', 'qms_engineer'];
}

function evidence_review_sla_can_manage(array $user): bool {
  return user_has_any_role($user, evidence_review_sla_management_roles());
}

function evidence_review_sla_schema_patch(array $schema): array {
  $reviewCfg = is_array($schema['evidence_review'] ?? null) ? $schema['evidence_review'] : [];
  $patch = [];
  $reviewHours = (int)($reviewCfg['review_hours'] ?? ($reviewCfg['sla_review_hours'] ?? ($reviewCfg['sla_hours'] ?? 0)));
  if ($reviewHours > 0) $patch['review_hours'] = $reviewHours;
  $warnHours = (int)($reviewCfg['warn_hours_before_due'] ?? ($reviewCfg['warning_hours_before_due'] ?? 0));
  if ($warnHours > 0) $patch['warn_hours_before_due'] = $warnHours;
  $escalateHours = (int)($reviewCfg['escalate_hours_after_due'] ?? ($reviewCfg['escalation_hours_after_due'] ?? 0));
  if ($escalateHours > 0) $patch['escalate_hours_after_due'] = $escalateHours;
  $roles = is_array($reviewCfg['escalation_roles'] ?? null) ? $reviewCfg['escalation_roles'] : [];
  $roles = array_values(array_unique(array_values(array_filter(array_map(
    static fn($role) => strtolower(trim((string)$role)),
    $roles
  )))));
  if (!empty($roles)) $patch['escalation_roles'] = $roles;
  return $patch;
}

function evidence_review_sla_policy_for_allocation(array $allocation, array $recordTypes = [], array $schema = []): array {
  $snapshot = is_array($allocation['review_sla']['policy_snapshot'] ?? null) ? $allocation['review_sla']['policy_snapshot'] : [];
  if (!empty($snapshot)) {
    $snapshot['record_type'] = strtoupper(trim((string)($snapshot['record_type'] ?? $allocation['record_type'] ?? '')));
    $snapshot['escalation_roles'] = array_values(array_unique(array_values(array_filter(array_map(
      static fn($role) => strtolower(trim((string)$role)),
      is_array($snapshot['escalation_roles'] ?? null) ? $snapshot['escalation_roles'] : []
    )))));
    return $snapshot;
  }
  $recordType = strtoupper(trim((string)($allocation['record_type'] ?? '')));
  return array_merge(
    evidence_review_sla_policy_for_type($recordType, $recordTypes),
    evidence_review_sla_schema_patch($schema),
    ['record_type' => $recordType]
  );
}

function evidence_review_started_at(array $allocation): string {
  $candidate = trim((string)($allocation['review_started_at'] ?? ''));
  if ($candidate !== '') return $candidate;
  $history = is_array($allocation['history'] ?? null) ? array_reverse($allocation['history']) : [];
  foreach ($history as $event) {
    if (!is_array($event)) continue;
    if (allocation_status_normalize((string)($event['status'] ?? '')) !== 'in_review') continue;
    $at = trim((string)($event['at'] ?? ''));
    if ($at !== '') return $at;
  }
  foreach (['submitted_at', 'received_at', 'updated_at', 'created_at'] as $field) {
    $value = trim((string)($allocation[$field] ?? ''));
    if ($value !== '') return $value;
  }
  return '';
}

function evidence_review_closed_at(array $allocation): string {
  foreach (['review_closed_at', 'approved_at', 'rejected_at'] as $field) {
    $value = trim((string)($allocation[$field] ?? ''));
    if ($value !== '') return $value;
  }
  $history = is_array($allocation['history'] ?? null) ? array_reverse($allocation['history']) : [];
  foreach ($history as $event) {
    if (!is_array($event)) continue;
    $status = allocation_status_normalize((string)($event['status'] ?? ''));
    if (!in_array($status, ['approved', 'rejected'], true)) continue;
    $at = trim((string)($event['at'] ?? ''));
    if ($at !== '') return $at;
  }
  return '';
}

function evidence_review_sla_reset(array &$allocation): void {
  unset($allocation['review_started_at'], $allocation['review_closed_at'], $allocation['review_sla']);
}

function evidence_review_sla_evaluate(array $allocation, array $recordTypes = [], array $schema = []): array {
  $policy = evidence_review_sla_policy_for_allocation($allocation, $recordTypes, $schema);
  $reviewHours = max(1, (int)($policy['review_hours'] ?? 72));
  $warnHours = max(1, (int)($policy['warn_hours_before_due'] ?? 12));
  $warnHours = min($reviewHours, $warnHours);
  $escalateHours = max(1, (int)($policy['escalate_hours_after_due'] ?? 24));
  $startedRaw = evidence_review_started_at($allocation);
  $completedRaw = evidence_review_closed_at($allocation);
  $startedAt = evidence_parse_date_value($startedRaw);
  $completedAt = evidence_parse_date_value($completedRaw);
  $dueAt = $startedAt ? $startedAt->modify('+' . $reviewHours . ' hours') : null;
  $escalationDueAt = $dueAt ? $dueAt->modify('+' . $escalateHours . ' hours') : null;
  $status = allocation_status_normalize((string)($allocation['status'] ?? 'allocated'));
  $now = new DateTimeImmutable(now_iso());

  $remainingHours = null;
  $overdueHours = null;
  $hoursToEscalation = null;
  if ($dueAt) {
    $remainingHours = (int)floor(($dueAt->getTimestamp() - $now->getTimestamp()) / 3600);
    if ($remainingHours < 0) $overdueHours = (int)ceil(($now->getTimestamp() - $dueAt->getTimestamp()) / 3600);
  }
  if ($escalationDueAt) {
    $hoursToEscalation = (int)floor(($escalationDueAt->getTimestamp() - $now->getTimestamp()) / 3600);
  }

  $state = 'not_started';
  if (in_array($status, ['approved', 'rejected'], true)) {
    if ($completedAt && $escalationDueAt && $completedAt->getTimestamp() >= $escalationDueAt->getTimestamp()) {
      $state = 'closed_after_escalation';
    } elseif ($completedAt && $dueAt && $completedAt->getTimestamp() > $dueAt->getTimestamp()) {
      $state = 'closed_late';
    } else {
      $state = 'closed_on_time';
    }
  } elseif ($status === 'in_review') {
    if ($escalationDueAt && $now->getTimestamp() >= $escalationDueAt->getTimestamp()) {
      $state = 'escalated';
    } elseif ($dueAt && $now->getTimestamp() > $dueAt->getTimestamp()) {
      $state = 'overdue';
    } elseif ($dueAt && $remainingHours !== null && $remainingHours <= $warnHours) {
      $state = 'due_soon';
    } else {
      $state = 'tracking';
    }
  }

  return [
    'record_type' => strtoupper(trim((string)($allocation['record_type'] ?? $policy['record_type'] ?? ''))),
    'status' => $status,
    'state' => $state,
    'policy_snapshot' => [
      'record_type' => strtoupper(trim((string)($policy['record_type'] ?? $allocation['record_type'] ?? ''))),
      'review_hours' => $reviewHours,
      'warn_hours_before_due' => $warnHours,
      'escalate_hours_after_due' => $escalateHours,
      'escalation_roles' => array_values((array)($policy['escalation_roles'] ?? [])),
    ],
    'started_at' => $startedAt ? $startedAt->format(DateTimeInterface::ATOM) : '',
    'due_at' => $dueAt ? $dueAt->format(DateTimeInterface::ATOM) : '',
    'escalation_due_at' => $escalationDueAt ? $escalationDueAt->format(DateTimeInterface::ATOM) : '',
    'completed_at' => $completedAt ? $completedAt->format(DateTimeInterface::ATOM) : '',
    'remaining_hours' => $remainingHours,
    'overdue_hours' => $overdueHours,
    'hours_to_escalation' => $hoursToEscalation,
    'escalated' => in_array($state, ['escalated', 'closed_after_escalation'], true),
    'escalation_roles' => array_values((array)($policy['escalation_roles'] ?? [])),
  ];
}

function evidence_review_sla_materialize(array &$allocation, array $recordTypes = [], array $schema = []): array {
  $previous = is_array($allocation['review_sla'] ?? null) ? $allocation['review_sla'] : [];
  $evaluated = evidence_review_sla_evaluate($allocation, $recordTypes, $schema);
  $username = strtolower(trim((string)($allocation['updated_by'] ?? $allocation['created_by'] ?? 'system')));
  $now = now_iso();

  if ($evaluated['state'] === 'overdue' && trim((string)($previous['overdue_logged_at'] ?? '')) === '') {
    $previous['overdue_logged_at'] = $now;
    allocation_append_audit_log($allocation, 'review_sla_overdue', $username, 'review_sla_overdue', [
      'record_type' => (string)($evaluated['record_type'] ?? ''),
      'due_at' => (string)($evaluated['due_at'] ?? ''),
      'remaining_hours' => (int)($evaluated['remaining_hours'] ?? 0),
    ]);
  }
  if ($evaluated['escalated'] && trim((string)($previous['escalated_at'] ?? '')) === '') {
    $previous['escalated_at'] = $now;
    allocation_append_audit_log($allocation, 'review_sla_escalated', $username, 'review_sla_escalated', [
      'record_type' => (string)($evaluated['record_type'] ?? ''),
      'due_at' => (string)($evaluated['due_at'] ?? ''),
      'escalation_due_at' => (string)($evaluated['escalation_due_at'] ?? ''),
      'escalation_roles' => array_values((array)($evaluated['escalation_roles'] ?? [])),
    ]);
  }
  if (in_array($evaluated['state'], ['closed_on_time', 'closed_late', 'closed_after_escalation'], true) && trim((string)($previous['closed_logged_at'] ?? '')) === '') {
    $previous['closed_logged_at'] = $now;
  }

  $stored = array_merge($previous, [
    'record_type' => $evaluated['record_type'],
    'status' => $evaluated['status'],
    'state' => $evaluated['state'],
    'policy_snapshot' => is_array($previous['policy_snapshot'] ?? null) ? $previous['policy_snapshot'] : $evaluated['policy_snapshot'],
    'started_at' => $evaluated['started_at'],
    'due_at' => $evaluated['due_at'],
    'escalation_due_at' => $evaluated['escalation_due_at'],
    'completed_at' => $evaluated['completed_at'],
    'escalated' => $evaluated['escalated'],
    'escalation_roles' => $evaluated['escalation_roles'],
    'last_transition_at' => (($previous['state'] ?? '') !== $evaluated['state']) ? $now : (string)($previous['last_transition_at'] ?? $now),
  ]);
  $allocation['review_sla'] = $stored;
  return array_merge($stored, [
    'remaining_hours' => $evaluated['remaining_hours'],
    'overdue_hours' => $evaluated['overdue_hours'],
    'hours_to_escalation' => $evaluated['hours_to_escalation'],
  ]);
}

function evidence_review_sla_queue_rows(): array {
  $allocationStore = load_allocation_store();
  $recordTypes = load_record_type_registry();
  $schemaCache = [];
  $rows = [];

  foreach ((array)($allocationStore['allocations'] ?? []) as $allocation) {
    if (!is_array($allocation)) continue;
    if (allocation_status_normalize((string)($allocation['status'] ?? 'allocated')) !== 'in_review') continue;

    $formCode = trim((string)($allocation['form_code'] ?? ''));
    if ($formCode !== '' && !array_key_exists($formCode, $schemaCache)) {
      $schemaCache[$formCode] = load_form_schema_by_code($formCode) ?: [];
    }
    $schema = is_array($schemaCache[$formCode] ?? null) ? $schemaCache[$formCode] : [];
    $reviewConfig = evidence_review_config($schema);
    $reviewSla = evidence_review_sla_evaluate($allocation, $recordTypes, $schema);
    $state = strtolower(trim((string)($reviewSla['state'] ?? 'not_started')));
    if (!in_array($state, ['due_soon', 'overdue', 'escalated'], true)) continue;

    $notifications = is_array($allocation['review_sla']['notifications'] ?? null)
      ? $allocation['review_sla']['notifications']
      : [];
    $reviewRoles = array_values((array)($reviewConfig['roles_allowed'] ?? []));
    $escalationRoles = array_values((array)($reviewSla['escalation_roles'] ?? []));
    $recordId = trim((string)($allocation['record_id'] ?? $allocation['allocation_id'] ?? ''));

    $summaryVi = match ($state) {
      'escalated' => 'Hồ sơ duyệt đã bị escalation và cần xử lý ngay.',
      'overdue' => 'Hồ sơ duyệt đã quá hạn SLA.',
      default => 'Hồ sơ duyệt sắp đến hạn và cần xử lý trước khi quá hạn.',
    };
    $summaryEn = match ($state) {
      'escalated' => 'The review has escalated and needs immediate action.',
      'overdue' => 'The review is already outside the SLA window.',
      default => 'The review is approaching its SLA due time and should be handled early.',
    };

    $rows[] = [
      'allocation_id' => (string)($allocation['allocation_id'] ?? ''),
      'record_id' => $recordId,
      'record_type' => (string)($reviewSla['record_type'] ?? $allocation['record_type'] ?? ''),
      'form_code' => $formCode,
      'department' => (string)($allocation['department'] ?? ''),
      'allocated_to' => (string)($allocation['allocated_to'] ?? ''),
      'downloaded_by' => (string)($allocation['downloaded_by'] ?? ''),
      'state' => $state,
      'band' => $state === 'due_soon' ? 'warning' : 'critical',
      'started_at' => (string)($reviewSla['started_at'] ?? ''),
      'due_at' => (string)($reviewSla['due_at'] ?? ''),
      'escalation_due_at' => (string)($reviewSla['escalation_due_at'] ?? ''),
      'remaining_hours' => $reviewSla['remaining_hours'] ?? null,
      'overdue_hours' => $reviewSla['overdue_hours'] ?? null,
      'hours_to_escalation' => $reviewSla['hours_to_escalation'] ?? null,
      'review_roles' => $reviewRoles,
      'escalation_roles' => $escalationRoles,
      'notifications' => [
        'warn_sent_at' => (string)($notifications['warn_sent_at'] ?? ''),
        'overdue_sent_at' => (string)($notifications['overdue_sent_at'] ?? ''),
        'escalated_sent_at' => (string)($notifications['escalated_sent_at'] ?? ''),
      ],
      'summary_vi' => $summaryVi,
      'summary_en' => $summaryEn,
    ];
  }

  usort($rows, static function ($a, $b) {
    $priority = ['escalated' => 0, 'overdue' => 1, 'due_soon' => 2];
    $ap = $priority[(string)($a['state'] ?? 'due_soon')] ?? 9;
    $bp = $priority[(string)($b['state'] ?? 'due_soon')] ?? 9;
    if ($ap !== $bp) return $ap <=> $bp;
    $ad = (string)($a['due_at'] ?? $a['escalation_due_at'] ?? '');
    $bd = (string)($b['due_at'] ?? $b['escalation_due_at'] ?? '');
    return strcmp($ad, $bd);
  });

  return $rows;
}

function load_form_schema_by_code(string $formCode): ?array {
  global $DATA_DIR;
  $file = $DATA_DIR . '/online-forms/schemas/' . basename($formCode) . '.json';
  if (!is_file($file)) return null;
  $data = json_decode((string)file_get_contents($file), true);
  return is_array($data) ? $data : null;
}

function normalize_online_form_code(string $formCode): string {
  $formCode = strtoupper(trim($formCode));
  if ($formCode === '') {
    throw new RuntimeException('missing_form_code');
  }
  if (!preg_match('/^[A-Z0-9._-]+$/', $formCode)) {
    throw new RuntimeException('invalid_form_code');
  }
  return $formCode;
}

function require_online_form_code(string $formCode): string {
  try {
    return normalize_online_form_code($formCode);
  } catch (RuntimeException $e) {
    $message = $e->getMessage();
    api_json(['ok' => false, 'error' => $message === 'missing_form_code' ? 'missing_form_code' : 'invalid_form_code'], 400);
  }
}

function require_existing_online_form(string $formCode): array {
  $formCode = require_online_form_code($formCode);
  $schema = load_form_schema_by_code($formCode);
  $registry = load_form_registry_entry($formCode);
  if (!is_array($schema) && !is_array($registry)) {
    api_json(['ok' => false, 'error' => 'form_not_found'], 404);
  }

  return [
    'code' => $formCode,
    'schema' => $schema,
    'registry' => $registry,
  ];
}

function load_form_registry_entry(string $formCode): ?array {
  global $FORM_CONTROL_REGISTRY_FILE;
  if (!is_file($FORM_CONTROL_REGISTRY_FILE)) return null;
  $data = json_decode((string)file_get_contents($FORM_CONTROL_REGISTRY_FILE), true);
  if (!is_array($data) || !isset($data[$formCode]) || !is_array($data[$formCode])) return null;
  return $data[$formCode];
}

function online_form_entries_file(string $formCode): string {
  global $DATA_DIR;
  return $DATA_DIR . '/online-forms/entries/' . basename($formCode) . '.json';
}

function load_online_form_entries_store(string $formCode): array {
  $entryFile = online_form_entries_file($formCode);
  if (!is_file($entryFile)) return [];
  $data = json_decode((string)file_get_contents($entryFile), true);
  return is_array($data) ? $data : [];
}

function save_online_form_entries_store(string $formCode, array $entries): void {
  $entryFile = online_form_entries_file($formCode);
  ensure_dir(dirname($entryFile));
  file_put_contents($entryFile, json_encode($entries, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES), LOCK_EX);
}

function online_form_draft_file(string $allocationId): string {
  global $DATA_DIR;
  return $DATA_DIR . '/online-forms/drafts/' . basename($allocationId) . '.json';
}

function load_online_form_draft(string $allocationId): ?array {
  if ($allocationId === '') return null;
  $draftFile = online_form_draft_file($allocationId);
  if (!is_file($draftFile)) return null;
  $raw = @file_get_contents($draftFile);
  $draft = $raw ? json_decode($raw, true) : null;
  return is_array($draft) ? $draft : null;
}

function save_online_form_draft(string $allocationId, array $payload): void {
  $draftFile = online_form_draft_file($allocationId);
  ensure_dir(dirname($draftFile));
  file_put_contents($draftFile, json_encode($payload, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES), LOCK_EX);
}

function delete_online_form_draft(string $allocationId): void {
  $draftFile = online_form_draft_file($allocationId);
  if (is_file($draftFile)) @unlink($draftFile);
}

function list_online_form_drafts(): array {
  global $DATA_DIR;
  $dir = $DATA_DIR . '/online-forms/drafts';
  if (!is_dir($dir)) return [];
  $out = [];
  foreach (glob($dir . '/*.json') ?: [] as $file) {
    $raw = @file_get_contents($file);
    $draft = $raw ? json_decode($raw, true) : null;
    if (is_array($draft) && !empty($draft['allocation_id'])) $out[] = $draft;
  }
  return $out;
}

function find_online_form_entry_index(array $entries, string $entryId = '', string $allocationId = ''): int {
  foreach ($entries as $idx => $entry) {
    if (!is_array($entry)) continue;
    if ($entryId !== '' && (string)($entry['entry_id'] ?? '') === $entryId) return $idx;
    if ($allocationId !== '' && (string)($entry['allocation_id'] ?? '') === $allocationId) return $idx;
  }
  return -1;
}

function eqms_locked_workflow_states(): array {
  return ['submitted', 'received', 'in_review', 'approved', 'closed', 'finalized', 'rejected'];
}

function eqms_is_locked_workflow_state(string $state): bool {
  return in_array(strtolower(trim($state)), eqms_locked_workflow_states(), true);
}

function eqms_entry_workflow_state(array $entry): string {
  return strtolower(trim((string)($entry['workflow_state'] ?? $entry['approval_state'] ?? $entry['_status'] ?? '')));
}

function eqms_change_authority_from_payload(array $payload): string {
  foreach (['change_authority_id', 'change_authority', 'authority_id', 'change_order_id', 'change_order_number', 'plm_change_order_id', 'change_order_ref', 'change_request_id', 'change_id'] as $key) {
    $value = trim((string)($payload[$key] ?? ''));
    if ($value !== '') return $value;
  }
  return '';
}

function eqms_change_authority_format_valid(string $authority): bool {
  $authority = trim($authority);
  if ($authority === '') return false;
  if (preg_match('/^[0-9a-f]{8}-[0-9a-f]{4}-[1-5][0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/i', $authority)) return true;
  return (bool)preg_match('/^[A-Z]{2,12}[A-Z0-9._\/-]{2,80}$/i', $authority);
}

function eqms_change_authority_service(): ?object {
  $serviceFile = __DIR__ . '/api/services/ChangeControl/ChangeAuthorityService.php';
  if (!is_file($serviceFile)) return null;
  require_once $serviceFile;
  if (!class_exists('\MOM\Services\ChangeControl\ChangeAuthorityService')) return null;
  try {
    return new \MOM\Services\ChangeControl\ChangeAuthorityService(portal_system_db_connection());
  } catch (Throwable $e) {
    @error_log('[EQMS] Change authority service unavailable: ' . $e->getMessage());
    return null;
  }
}

function eqms_form_control_metadata_fields(): array {
  return [
    'entry_id' => true,
    'record_id' => true,
    'allocation_id' => true,
    'form_code' => true,
    'form_version' => true,
    'workflow_state' => true,
    'approval_state' => true,
    '_status' => true,
    '_ip' => true,
    '_server_time' => true,
    '_session_user' => true,
    'submitted_at' => true,
    'submitted_by' => true,
    'submitted_name' => true,
    'updated_at' => true,
    'updated_by' => true,
    'created_at' => true,
    'created_by' => true,
    'submission_revision' => true,
    'submission_count' => true,
    'resubmission_count' => true,
    'amendment_count' => true,
    'edit_origin' => true,
    'source_entry_id' => true,
    'source_submission_revision' => true,
    'change_authority_id' => true,
    'amendment_reason' => true,
    'change_authority_decisions' => true,
    'version_created_at' => true,
    'version_created_by' => true,
    'source_created_at' => true,
    'source_created_by' => true,
    'master_context' => true,
    'history' => true,
    'signatures' => true,
    'runtime_mode' => true,
  ];
}

function eqms_form_content_fields(array $payload): array {
  $fields = is_array($payload['fieldValues'] ?? null) ? $payload['fieldValues'] : $payload;
  if (!is_array($fields)) return [];
  $metadataFields = eqms_form_control_metadata_fields();
  $out = [];
  foreach ($fields as $key => $value) {
    $field = trim((string)$key);
    if ($field === '' || str_starts_with($field, '_') || isset($metadataFields[$field])) continue;
    $out[$field] = $value;
  }
  ksort($out);
  return $out;
}

function eqms_same_canonical_value(mixed $left, mixed $right): bool {
  return json_encode($left, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES)
    === json_encode($right, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
}

function eqms_form_change_effectivity(array $entry, array $allocation = []): array {
  $context = is_array($entry['master_context'] ?? null) ? $entry['master_context'] : [];
  if (is_array($allocation['master_context'] ?? null)) {
    $context = array_merge((array)$allocation['master_context'], $context);
  }
  return array_filter([
    'site' => $context['site'] ?? $context['site_id'] ?? $entry['site_id'] ?? $allocation['site_id'] ?? null,
    'plant' => $context['plant'] ?? $context['plant_id'] ?? $entry['plant_id'] ?? $allocation['plant_id'] ?? null,
    'lot' => $context['lot'] ?? $context['lot_number'] ?? $entry['lot_number'] ?? $allocation['lot_number'] ?? null,
    'serial' => $context['serial'] ?? $context['serial_number'] ?? $entry['serial_number'] ?? $allocation['serial_number'] ?? null,
    'order_id' => $context['order_id'] ?? $entry['work_order'] ?? $entry['job_number'] ?? $allocation['record_id'] ?? null,
  ], static fn($value): bool => $value !== null && trim((string)$value) !== '');
}

function eqms_assert_online_form_change_authority(
  string $formCode,
  array $previous,
  array $candidate,
  string $changeAuthorityId,
  array $allocation = []
): array {
  $service = eqms_change_authority_service();
  if ($service === null || !method_exists($service, 'assertFieldEditAllowed')) {
    return [
      'ok' => false,
      'error' => 'change_authority_unavailable',
      'message' => 'Change authority service is unavailable; governed amendment denied.',
      'decisions' => [],
    ];
  }

  $previousFields = eqms_form_content_fields($previous);
  $candidateFields = eqms_form_content_fields($candidate);
  $allFields = array_values(array_unique(array_merge(array_keys($previousFields), array_keys($candidateFields))));
  sort($allFields);

  $objectId = trim((string)($previous['record_id'] ?? ''));
  if ($objectId === '') $objectId = trim((string)($previous['entry_id'] ?? ''));
  if ($objectId === '') $objectId = trim((string)($candidate['source_entry_id'] ?? $candidate['entry_id'] ?? $formCode));

  $lifecycleState = eqms_entry_workflow_state($previous);
  if ($lifecycleState === '') $lifecycleState = 'locked';

  $decisions = [];
  foreach ($allFields as $fieldPath) {
    $oldValue = $previousFields[$fieldPath] ?? null;
    $newValue = $candidateFields[$fieldPath] ?? null;
    if (eqms_same_canonical_value($oldValue, $newValue)) continue;

    try {
      $decision = $service->assertFieldEditAllowed(
        'form_record',
        $objectId,
        $fieldPath,
        $oldValue,
        $newValue,
        $lifecycleState,
        [
          'change_authority_id' => $changeAuthorityId,
          'requested_effect' => 'amend',
          'form_code' => $formCode,
          'source_entry_id' => (string)($previous['entry_id'] ?? ''),
          'source_submission_revision' => (int)($previous['submission_revision'] ?? 0),
          'effectivity' => eqms_form_change_effectivity($candidate, $allocation),
        ]
      );
    } catch (Throwable $e) {
      return [
        'ok' => false,
        'error' => 'change_authority_check_failed',
        'message' => $e->getMessage(),
        'decisions' => $decisions,
      ];
    }

    $item = [
      'field_path' => $fieldPath,
      'allowed' => (bool)($decision->allowed ?? false),
      'message' => (string)($decision->message ?? ''),
      'error_code' => (string)($decision->errorCode ?? ''),
      'data' => is_array($decision->data ?? null) ? $decision->data : [],
    ];
    $decisions[] = $item;
    if (!$item['allowed']) {
      return [
        'ok' => false,
        'error' => $item['error_code'] !== '' ? $item['error_code'] : 'change_authority_required',
        'message' => $item['message'],
        'field_path' => $fieldPath,
        'decisions' => $decisions,
      ];
    }
  }

  return ['ok' => true, 'decisions' => $decisions];
}

function eqms_new_amendment_entry_id(string $formCode): string {
  return $formCode . '-AMD-' . date('YmdHis') . '-' . substr(bin2hex(random_bytes(4)), 0, 8);
}

function form_is_online_runtime(string $formCode): bool {
  $schema = load_form_schema_by_code($formCode);
  if (!$schema) return false;
  return ($schema['online'] ?? true) !== false;
}

function eqms_workflow_status_from_entry(?array $entry, ?array $allocation = null, ?array $draft = null): string {
  if (is_array($draft)) return 'draft';
  if (is_array($entry)) {
    $workflow = strtolower(trim((string)($entry['workflow_state'] ?? '')));
    if ($workflow !== '') return $workflow;
  }
  $allocationStatus = strtolower(trim((string)($allocation['status'] ?? '')));
  return match ($allocationStatus) {
    'received' => 'received',
    'submitted' => 'submitted',
    'rejected' => 'rejected',
    'approved' => 'approved',
    'void' => 'void',
    default => 'allocated',
  };
}

function eqms_record_title_for_form_code(string $formCode): string {
  $schema = load_form_schema_by_code($formCode);
  if (is_array($schema) && !empty($schema['title'])) return (string)$schema['title'];
  $registry = load_form_registry_entry($formCode);
  if (is_array($registry) && !empty($registry['title'])) return (string)$registry['title'];
  return $formCode;
}

function eqms_latest_entries_by_allocation(): array {
  global $DATA_DIR;
  $schemasDir = $DATA_DIR . '/online-forms/entries';
  if (!is_dir($schemasDir)) return [];
  $map = [];
  foreach (glob($schemasDir . '/*.json') ?: [] as $file) {
    $formEntries = json_decode((string)@file_get_contents($file), true);
    if (!is_array($formEntries)) continue;
    foreach ($formEntries as $entry) {
      if (!is_array($entry)) continue;
      $allocationId = trim((string)($entry['allocation_id'] ?? ''));
      if ($allocationId === '') continue;
      $existing = $map[$allocationId] ?? null;
      $candidateRevision = (int)($entry['submission_revision'] ?? $entry['submission_count'] ?? 0);
      $existingRevision = is_array($existing) ? (int)($existing['submission_revision'] ?? $existing['submission_count'] ?? 0) : -1;
      $candidateTime = (string)($entry['updated_at'] ?? $entry['submitted_at'] ?? $entry['created_at'] ?? '');
      $existingTime = is_array($existing) ? (string)($existing['updated_at'] ?? $existing['submitted_at'] ?? $existing['created_at'] ?? '') : '';
      if (!$existing || $candidateRevision > $existingRevision || ($candidateRevision === $existingRevision && $candidateTime >= $existingTime)) {
        $map[$allocationId] = $entry;
      }
    }
  }
  return $map;
}

function evidence_schema_field_map(array $schema): array {
  $map = [];
  foreach ((array)($schema['fields'] ?? []) as $field) {
    if (!is_array($field)) continue;
    $fieldId = trim((string)($field['id'] ?? ''));
    if ($fieldId === '') continue;
    $map[$fieldId] = $field;
  }
  return $map;
}

function evidence_field_label(array $schema, string $fieldId, string $locale = 'vi'): string {
  $field = evidence_schema_field_map($schema)[$fieldId] ?? null;
  if (!is_array($field)) return $fieldId;
  if ($locale === 'en') return trim((string)($field['label_en'] ?? $field['label'] ?? $fieldId));
  return trim((string)($field['label_vi'] ?? $field['label'] ?? $fieldId));
}

function evidence_signature_label(array $schema, string $signatureId, string $locale = 'vi'): string {
  foreach ((array)($schema['signature_blocks'] ?? []) as $block) {
    if (!is_array($block)) continue;
    if (trim((string)($block['id'] ?? '')) !== $signatureId) continue;
    if ($locale === 'en') return trim((string)($block['label_en'] ?? $block['label'] ?? $signatureId));
    return trim((string)($block['label_vi'] ?? $block['label'] ?? $signatureId));
  }
  return $signatureId;
}

function evidence_find_field_definition(array $schema, string $fieldId): array {
  foreach ((array)($schema['fields'] ?? []) as $field) {
    if (!is_array($field)) continue;
    if (trim((string)($field['id'] ?? '')) === $fieldId) return $field;
  }
  return ['id' => $fieldId, 'type' => 'text', 'label' => $fieldId, 'label_vi' => $fieldId];
}

function evidence_field_option_label(array $schema, string $fieldId, string $value, string $locale = 'vi'): string {
  $field = evidence_find_field_definition($schema, $fieldId);
  foreach ((array)($field['options'] ?? []) as $option) {
    if (!is_array($option)) continue;
    if (trim((string)($option['value'] ?? '')) !== $value) continue;
    if ($locale === 'en') return trim((string)($option['label_en'] ?? $option['label'] ?? $value));
    return trim((string)($option['label_vi'] ?? $option['label'] ?? $value));
  }
  return $value;
}

function evidence_entry_value_present(array $field, $value): bool {
  $type = strtolower(trim((string)($field['type'] ?? 'text')));
  if ($type === 'multi_select') return is_array($value) && !empty($value);
  if ($type === 'checkbox') return $value === true || $value === 1 || $value === '1' || $value === 'true';
  if (is_array($value)) return !empty($value);
  return trim((string)$value) !== '';
}

function evidence_parse_date_value($value): ?DateTimeImmutable {
  $raw = trim((string)$value);
  if ($raw === '') return null;
  try {
    return new DateTimeImmutable($raw);
  } catch (Throwable $e) {
    return null;
  }
}

function evidence_find_online_entry(string $formCode, string $allocationId = '', string $entryId = ''): ?array {
  if ($formCode === '' || ($allocationId === '' && $entryId === '')) return null;
  $entries = load_online_form_entries_store($formCode);
  $idx = find_online_form_entry_index($entries, $entryId, $allocationId);
  return $idx >= 0 && is_array($entries[$idx] ?? null) ? $entries[$idx] : null;
}

function evidence_review_config(array $schema): array {
  $config = is_array($schema['evidence_review'] ?? null) ? $schema['evidence_review'] : [];
  $mode = strtolower(trim((string)($config['approval_mode'] ?? 'serial')));
  if ($mode !== 'parallel') $mode = 'serial';

  $rolesAllowed = $config['roles_allowed'] ?? $schema['roles_allowed'] ?? [];
  if (is_array($rolesAllowed)) {
    $hasNested = false;
    foreach ($rolesAllowed as $value) {
      if (is_array($value)) { $hasNested = true; break; }
    }
    if ($hasNested) {
      $flattened = [];
      foreach (['review', 'approve'] as $bucket) {
        if (is_array($rolesAllowed[$bucket] ?? null)) {
          $flattened = array_merge($flattened, array_values($rolesAllowed[$bucket]));
        }
      }
      if (empty($flattened)) {
        foreach ($rolesAllowed as $value) {
          if (is_array($value)) $flattened = array_merge($flattened, array_values($value));
        }
      }
      $rolesAllowed = $flattened;
    }
  }
  $rolesAllowed = array_values(array_unique(array_values(array_filter(array_map(
    static fn($role) => strtolower(trim((string)$role)),
    is_array($rolesAllowed) ? $rolesAllowed : []
  )))));

  $minimumApprovals = (int)($config['minimum_approvals'] ?? ($config['min_approvals'] ?? 0));
  if ($mode === 'parallel') {
    if ($minimumApprovals < 1) $minimumApprovals = 2;
    if (!empty($rolesAllowed)) $minimumApprovals = min($minimumApprovals, count($rolesAllowed));
    if ($minimumApprovals < 1) $minimumApprovals = 1;
  } else {
    $minimumApprovals = 1;
  }

  return [
    'approval_mode' => $mode,
    'minimum_approvals' => $minimumApprovals,
    'roles_allowed' => $rolesAllowed,
    'label_vi' => trim((string)($config['label_vi'] ?? ($mode === 'parallel' ? 'Phê duyệt song song' : 'Phê duyệt tuần tự'))),
    'label_en' => trim((string)($config['label_en'] ?? ($mode === 'parallel' ? 'Parallel approval' : 'Serial approval'))),
  ];
}

function evidence_user_roles(array $user): array {
  $roles = is_array($user['roles'] ?? null) ? $user['roles'] : [(string)($user['role'] ?? '')];
  return array_values(array_unique(array_values(array_filter(array_map(
    static fn($role) => strtolower(trim((string)$role)),
    $roles
  )))));
}

function evidence_user_can_review(array $schema, array $user): bool {
  $config = evidence_review_config($schema);
  $rolesAllowed = $config['roles_allowed'];
  if (empty($rolesAllowed)) return true;
  foreach (evidence_user_roles($user) as $userRole) {
    if (in_array($userRole, $rolesAllowed, true)) return true;
  }
  return false;
}

function evidence_signature_meaning_normalize(string $meaning, string $fallback = 'approved'): string {
  $normalized = strtolower(trim($meaning));
  if (in_array($normalized, ['approved', 'reviewed', 'rejected', 'witnessed'], true)) {
    return $normalized;
  }
  $fallbackNormalized = strtolower(trim($fallback));
  return in_array($fallbackNormalized, ['approved', 'reviewed', 'rejected', 'witnessed'], true)
    ? $fallbackNormalized
    : 'approved';
}

function evidence_normalize_approval_records(array $allocation): array {
  $records = is_array($allocation['approval_records'] ?? null) ? $allocation['approval_records'] : [];
  if (empty($records) && trim((string)($allocation['approved_by'] ?? '')) !== '') {
    $records[] = [
      'username' => (string)($allocation['approved_by'] ?? ''),
      'display_name' => (string)($allocation['approved_by'] ?? ''),
      'approved_at' => (string)($allocation['approved_at'] ?? ''),
      'reason' => (string)($allocation['approval_reason'] ?? ''),
      'meaning' => 'approved',
      'roles' => [],
      'signature' => is_array($allocation['approval_signature'] ?? null) ? $allocation['approval_signature'] : null,
    ];
  }

  $normalized = [];
  foreach ($records as $record) {
    if (!is_array($record)) continue;
    $username = strtolower(trim((string)($record['username'] ?? $record['approved_by'] ?? $record['user'] ?? '')));
    if ($username === '') continue;

    $normalized[$username] = [
      'username' => $username,
      'display_name' => trim((string)($record['display_name'] ?? $record['signer_name'] ?? $record['username'] ?? $username)),
      'approved_at' => trim((string)($record['approved_at'] ?? $record['signed_at'] ?? $allocation['approved_at'] ?? '')),
      'reason' => trim((string)($record['reason'] ?? '')),
      'meaning' => evidence_signature_meaning_normalize((string)($record['meaning'] ?? $record['decision'] ?? 'approved')),
      'roles' => array_values(array_unique(array_values(array_filter(array_map(
        static fn($role) => strtolower(trim((string)$role)),
        is_array($record['roles'] ?? null) ? $record['roles'] : []
      ))))),
      'signature' => is_array($record['signature'] ?? null)
        ? $record['signature']
        : (is_array($record['signature_data'] ?? null) ? $record['signature_data'] : null),
    ];
  }

  uasort($normalized, static function (array $left, array $right): int {
    $leftAt = trim((string)($left['approved_at'] ?? ''));
    $rightAt = trim((string)($right['approved_at'] ?? ''));
    if ($leftAt === $rightAt) return strcmp((string)($left['username'] ?? ''), (string)($right['username'] ?? ''));
    if ($leftAt === '') return 1;
    if ($rightAt === '') return -1;
    return strcmp($leftAt, $rightAt);
  });

  return array_values($normalized);
}

function evidence_approval_summary(array $allocation, array $schema): array {
  $config = evidence_review_config($schema);
  $records = evidence_normalize_approval_records($allocation);
  $required = $config['minimum_approvals'];
  $collected = count($records);

  return [
    'approval_mode' => $config['approval_mode'],
    'label_vi' => $config['label_vi'],
    'label_en' => $config['label_en'],
    'roles_allowed' => $config['roles_allowed'],
    'minimum_approvals' => $required,
    'collected_approvals' => $collected,
    'remaining_approvals' => max(0, $required - $collected),
    'is_complete' => $collected >= $required,
    'approvers' => array_map(static function (array $record): array {
      return [
        'username' => (string)($record['username'] ?? ''),
        'display_name' => (string)($record['display_name'] ?? ''),
        'approved_at' => (string)($record['approved_at'] ?? ''),
        'reason' => (string)($record['reason'] ?? ''),
        'meaning' => evidence_signature_meaning_normalize((string)($record['meaning'] ?? 'approved')),
        'roles' => array_values((array)($record['roles'] ?? [])),
      ];
    }, $records),
  ];
}

function evidence_refresh_approval_summary(array &$allocation, array $schema): array {
  $records = evidence_normalize_approval_records($allocation);
  if (!empty($records)) {
    $allocation['approval_records'] = $records;
  } else {
    unset($allocation['approval_records']);
  }
  $summary = evidence_approval_summary($allocation, $schema);
  $allocation['approval_summary'] = $summary;
  return $summary;
}

function evidence_clear_review_outcome(array &$allocation): void {
  unset($allocation['approval_signature'], $allocation['approved_at'], $allocation['approved_by'], $allocation['approval_reason']);
  unset($allocation['rejected_at'], $allocation['rejected_by'], $allocation['rejection_reason']);
  unset($allocation['approval_records'], $allocation['approval_summary']);
}

function evidence_default_requirements(array $allocation, array $schema): array {
  $deliveryMode = strtolower(trim((string)($allocation['delivery_mode'] ?? (($schema['online'] ?? true) !== false ? 'online' : 'offline'))));
  $requiredContext = array_values(array_filter(array_map('trim', (array)($schema['record_context']['required'] ?? []))));
  $requirements = [];

  if (!empty($requiredContext)) {
    $requirements[] = [
      'id' => 'context_required',
      'kind' => 'record_context',
      'label' => 'Governed traceability context',
      'label_vi' => 'Ngữ cảnh truy xuất bắt buộc',
      'required_keys' => $requiredContext,
      'required_stages' => ['review', 'approval'],
    ];
  }

  if ($deliveryMode === 'online') {
    $requirements[] = [
      'id' => 'required_fields_complete',
      'kind' => 'required_fields',
      'label' => 'Required form fields completed',
      'label_vi' => 'Trường bắt buộc đã hoàn tất',
      'required_stages' => ['review', 'approval'],
    ];
    $requiredSignatures = [];
    foreach ((array)($schema['signature_blocks'] ?? []) as $block) {
      if (!is_array($block) || empty($block['required_on_submit'])) continue;
      $signatureId = trim((string)($block['id'] ?? ''));
      if ($signatureId !== '') $requiredSignatures[] = $signatureId;
    }
    if (!empty($requiredSignatures)) {
      $requirements[] = [
        'id' => 'signatures_required',
        'kind' => 'signatures',
        'label' => 'Required signatures captured',
        'label_vi' => 'Chữ ký bắt buộc đã có',
        'required_ids' => $requiredSignatures,
        'required_stages' => ['review', 'approval'],
      ];
    }
    $requirements[] = [
      'id' => 'online_submission',
      'kind' => 'online_submission',
      'label' => 'Online submission saved',
      'label_vi' => 'Bản nộp online đã được lưu',
      'required_stages' => ['review', 'approval'],
    ];
  } else {
    $requirements[] = [
      'id' => 'offline_package_issued',
      'kind' => 'offline_package',
      'label' => 'Governed workbook issued',
      'label_vi' => 'Workbook kiểm soát đã được cấp phát',
      'required_stages' => ['review', 'approval'],
    ];
    $requirements[] = [
      'id' => 'received_workbook',
      'kind' => 'received_workbook',
      'label' => 'Completed workbook received',
      'label_vi' => 'Workbook đã điền đã được tiếp nhận',
      'required_stages' => ['review', 'approval'],
    ];
  }

  foreach ((array)($schema['evidence_requirements'] ?? []) as $custom) {
    if (!is_array($custom)) continue;
    $customId = trim((string)($custom['id'] ?? ''));
    if ($customId === '') continue;
    $merged = false;
    foreach ($requirements as $idx => $existing) {
      if (($existing['id'] ?? '') !== $customId) continue;
      $requirements[$idx] = array_merge($existing, $custom);
      $merged = true;
      break;
    }
    if (!$merged) $requirements[] = $custom;
  }

  return $requirements;
}

function evidence_requirement_applies(array $requirement, string $stage): bool {
  $stage = strtolower(trim($stage));
  $stages = array_values(array_filter(array_map(static fn($v) => strtolower(trim((string)$v)), (array)($requirement['required_stages'] ?? []))));
  if (!empty($stages)) return in_array($stage, $stages, true);
  if ($stage === 'approval' && array_key_exists('required_for_approval', $requirement)) return !empty($requirement['required_for_approval']);
  if ($stage === 'review' && array_key_exists('required_for_review', $requirement)) return !empty($requirement['required_for_review']);
  return true;
}

function evidence_evaluate_requirement(array $requirement, array $allocation, array $schema, ?array $entry = null): array {
  $kind = strtolower(trim((string)($requirement['kind'] ?? '')));
  $item = [
    'id' => trim((string)($requirement['id'] ?? $kind)),
    'kind' => $kind,
    'label' => trim((string)($requirement['label'] ?? $kind)),
    'label_vi' => trim((string)($requirement['label_vi'] ?? $requirement['label'] ?? $kind)),
    'ok' => false,
    'missing' => [],
    'detail_en' => '',
    'detail_vi' => '',
  ];

  $masterContext = normalize_master_context((array)($allocation['master_context'] ?? []));
  $entry = is_array($entry) ? $entry : null;

  switch ($kind) {
    case 'record_context': {
      $requiredKeys = array_values(array_filter(array_map('trim', (array)($requirement['required_keys'] ?? []))));
      $missing = [];
      foreach ($requiredKeys as $key) {
        if (!array_key_exists($key, $masterContext) || trim((string)$masterContext[$key]) === '') {
          $missing[] = [
            'key' => $key,
            'label' => evidence_field_label($schema, $key, 'en'),
            'label_vi' => evidence_field_label($schema, $key, 'vi'),
          ];
        }
      }
      $item['ok'] = empty($missing);
      $item['missing'] = $missing;
      $item['detail_vi'] = $item['ok']
        ? 'Đủ ngữ cảnh truy xuất bắt buộc.'
        : 'Thiếu ngữ cảnh: ' . implode(', ', array_map(static fn($row) => (string)($row['label_vi'] ?? $row['key'] ?? ''), $missing));
      $item['detail_en'] = $item['ok']
        ? 'Required traceability context is complete.'
        : 'Missing context: ' . implode(', ', array_map(static fn($row) => (string)($row['label'] ?? $row['key'] ?? ''), $missing));
      break;
    }

    case 'required_fields': {
      $missing = [];
      foreach ((array)($schema['fields'] ?? []) as $field) {
        if (!is_array($field) || empty($field['required'])) continue;
        $fieldId = trim((string)($field['id'] ?? ''));
        if ($fieldId === '') continue;
        $value = $entry[$fieldId] ?? null;
        if (!evidence_entry_value_present($field, $value)) {
          $missing[] = [
            'key' => $fieldId,
            'label' => evidence_field_label($schema, $fieldId, 'en'),
            'label_vi' => evidence_field_label($schema, $fieldId, 'vi'),
          ];
        }
      }
      $item['ok'] = empty($missing) && $entry !== null;
      $item['missing'] = $missing;
      $item['detail_vi'] = $entry === null
        ? 'Chưa có bản nộp online để kiểm tra trường bắt buộc.'
        : ($item['ok'] ? 'Tất cả trường bắt buộc đã được điền.' : 'Thiếu trường bắt buộc: ' . implode(', ', array_map(static fn($row) => (string)($row['label_vi'] ?? $row['key'] ?? ''), $missing)));
      $item['detail_en'] = $entry === null
        ? 'No online submission is available to validate required fields.'
        : ($item['ok'] ? 'All required fields are complete.' : 'Missing required fields: ' . implode(', ', array_map(static fn($row) => (string)($row['label'] ?? $row['key'] ?? ''), $missing)));
      break;
    }

    case 'fields_present': {
      $fieldIds = array_values(array_filter(array_map('trim', (array)($requirement['field_ids'] ?? []))));
      $missing = [];
      foreach ($fieldIds as $fieldId) {
        $fieldDef = evidence_find_field_definition($schema, $fieldId);
        $value = $entry[$fieldId] ?? null;
        if (!evidence_entry_value_present($fieldDef, $value)) {
          $missing[] = [
            'key' => $fieldId,
            'label' => evidence_field_label($schema, $fieldId, 'en'),
            'label_vi' => evidence_field_label($schema, $fieldId, 'vi'),
          ];
        }
      }
      $item['ok'] = empty($missing) && $entry !== null;
      $item['missing'] = $missing;
      $item['detail_vi'] = $entry === null
        ? 'Chưa có bản nộp online để kiểm tra các trường bắt buộc của CAPA.'
        : ($item['ok'] ? 'Các trường bắt buộc cho CAPA đã đủ.' : 'Thiếu thông tin: ' . implode(', ', array_map(static fn($row) => (string)($row['label_vi'] ?? $row['key'] ?? ''), $missing)));
      $item['detail_en'] = $entry === null
        ? 'No online submission is available to validate the CAPA fields.'
        : ($item['ok'] ? 'The required CAPA fields are complete.' : 'Missing fields: ' . implode(', ', array_map(static fn($row) => (string)($row['label'] ?? $row['key'] ?? ''), $missing)));
      break;
    }

    case 'capa_effectiveness': {
      $completionField = trim((string)($requirement['completion_field'] ?? 'completion_date'));
      $verificationMethodField = trim((string)($requirement['verification_method_field'] ?? 'verification_method'));
      $verificationResultField = trim((string)($requirement['verification_result_field'] ?? 'verification_result'));
      $effectivenessDateField = trim((string)($requirement['effectiveness_date_field'] ?? 'effectiveness_check_date'));
      $effectivenessResultField = trim((string)($requirement['effectiveness_result_field'] ?? 'effectiveness_result'));
      $statusField = trim((string)($requirement['status_field'] ?? 'status'));
      $allowedStatuses = array_values(array_filter(array_map(static fn($v) => strtolower(trim((string)$v)), (array)($requirement['allowed_statuses'] ?? ['closed']))));
      $minDaysAfter = max(0, (int)($requirement['min_days_after'] ?? 30));
      $maxDaysAfter = max($minDaysAfter, (int)($requirement['max_days_after'] ?? 90));

      $missing = [];
      $requiredFieldIds = array_values(array_filter([$completionField, $verificationMethodField, $verificationResultField, $effectivenessDateField, $effectivenessResultField, $statusField]));
      foreach ($requiredFieldIds as $fieldId) {
        $fieldDef = evidence_find_field_definition($schema, $fieldId);
        $value = $entry[$fieldId] ?? null;
        if (!evidence_entry_value_present($fieldDef, $value)) {
          $missing[] = [
            'key' => $fieldId,
            'label' => evidence_field_label($schema, $fieldId, 'en'),
            'label_vi' => evidence_field_label($schema, $fieldId, 'vi'),
          ];
        }
      }

      $completionDate = evidence_parse_date_value($entry[$completionField] ?? '');
      $effectivenessDate = evidence_parse_date_value($entry[$effectivenessDateField] ?? '');
      $statusValue = strtolower(trim((string)($entry[$statusField] ?? '')));
      $windowOk = false;
      $windowMessageVi = '';
      $windowMessageEn = '';
      if ($completionDate && $effectivenessDate) {
        $diffDays = (int)$completionDate->diff($effectivenessDate)->format('%r%a');
        $windowOk = $diffDays >= $minDaysAfter && $diffDays <= $maxDaysAfter;
        if ($windowOk) {
          $windowMessageVi = 'Ngày kiểm tra hiệu lực nằm trong cửa sổ ' . $minDaysAfter . '-' . $maxDaysAfter . ' ngày.';
          $windowMessageEn = 'The effectiveness check date is within the ' . $minDaysAfter . '-' . $maxDaysAfter . ' day window.';
        } else {
          $windowMessageVi = 'Ngày kiểm tra hiệu lực phải nằm trong cửa sổ ' . $minDaysAfter . '-' . $maxDaysAfter . ' ngày kể từ ngày hoàn thành.';
          $windowMessageEn = 'The effectiveness check date must fall within the ' . $minDaysAfter . '-' . $maxDaysAfter . ' day window after completion.';
        }
      } elseif ($entry !== null) {
        $windowMessageVi = 'Chưa đủ ngày hoàn thành và ngày kiểm tra hiệu lực để đánh giá cửa sổ theo dõi.';
        $windowMessageEn = 'Completion date and effectiveness date are required to evaluate the follow-up window.';
      }

      $statusOk = $statusValue !== '' && in_array($statusValue, $allowedStatuses, true);
      $statusMessageVi = $statusOk
        ? 'Trạng thái CAPA phù hợp để đóng hồ sơ.'
        : 'Trạng thái CAPA phải là ' . implode(', ', array_map(static fn($v) => evidence_field_option_label($schema, $statusField, $v, 'vi'), $allowedStatuses)) . '.';
      $statusMessageEn = $statusOk
        ? 'The CAPA status is acceptable for closure.'
        : 'CAPA status must be one of: ' . implode(', ', array_map(static fn($v) => evidence_field_option_label($schema, $statusField, $v, 'en'), $allowedStatuses)) . '.';

      $item['meta'] = [
        'completion_date' => (string)($entry[$completionField] ?? ''),
        'effectiveness_check_date' => (string)($entry[$effectivenessDateField] ?? ''),
        'status_value' => $statusValue,
        'window_min_days' => $minDaysAfter,
        'window_max_days' => $maxDaysAfter,
        'window_ok' => $windowOk,
        'status_ok' => $statusOk,
      ];
      $item['ok'] = $entry !== null && empty($missing) && $windowOk && $statusOk;
      $item['missing'] = $missing;
      if ($entry === null) {
        $item['detail_vi'] = 'Chưa có bản nộp CAPA để đánh giá hiệu lực.';
        $item['detail_en'] = 'No CAPA submission is available for effectiveness evaluation.';
      } else {
        $partsVi = [];
        $partsEn = [];
        if (!empty($missing)) {
          $partsVi[] = 'Thiếu thông tin: ' . implode(', ', array_map(static fn($row) => (string)($row['label_vi'] ?? $row['key'] ?? ''), $missing));
          $partsEn[] = 'Missing fields: ' . implode(', ', array_map(static fn($row) => (string)($row['label'] ?? $row['key'] ?? ''), $missing));
        }
        $partsVi[] = $windowMessageVi;
        $partsEn[] = $windowMessageEn;
        $partsVi[] = $statusMessageVi;
        $partsEn[] = $statusMessageEn;
        $item['detail_vi'] = implode(' ', array_filter($partsVi));
        $item['detail_en'] = implode(' ', array_filter($partsEn));
      }
      break;
    }

    case 'signatures': {
      $requiredIds = array_values(array_filter(array_map('trim', (array)($requirement['required_ids'] ?? []))));
      $signatures = is_array($allocation['signatures'] ?? null) ? $allocation['signatures'] : [];
      if ($entry && is_array($entry['signatures'] ?? null)) $signatures = array_merge($signatures, $entry['signatures']);
      $missing = [];
      foreach ($requiredIds as $signatureId) {
        if (!is_array($signatures[$signatureId] ?? null)) {
          $missing[] = [
            'key' => $signatureId,
            'label' => evidence_signature_label($schema, $signatureId, 'en'),
            'label_vi' => evidence_signature_label($schema, $signatureId, 'vi'),
          ];
        }
      }
      $item['ok'] = empty($missing);
      $item['missing'] = $missing;
      $item['detail_vi'] = $item['ok']
        ? 'Các chữ ký bắt buộc đã được ghi nhận.'
        : 'Thiếu chữ ký: ' . implode(', ', array_map(static fn($row) => (string)($row['label_vi'] ?? $row['key'] ?? ''), $missing));
      $item['detail_en'] = $item['ok']
        ? 'Required signatures are present.'
        : 'Missing signatures: ' . implode(', ', array_map(static fn($row) => (string)($row['label'] ?? $row['key'] ?? ''), $missing));
      break;
    }

    case 'online_submission': {
      $entryId = trim((string)($allocation['online_submission']['entry_id'] ?? ''));
      $item['ok'] = $entryId !== '' && $entry !== null;
      $item['detail_vi'] = $item['ok'] ? 'Bản nộp online đã được lưu trên hệ thống.' : 'Chưa có bản nộp online hợp lệ trên hệ thống.';
      $item['detail_en'] = $item['ok'] ? 'The online submission is stored on the server.' : 'No valid online submission is stored on the server.';
      break;
    }

    case 'offline_package': {
      $issued = trim((string)($allocation['offline_package']['filename'] ?? '')) !== '' || trim((string)($allocation['downloaded_at'] ?? '')) !== '';
      $item['ok'] = $issued;
      $item['detail_vi'] = $item['ok'] ? 'Workbook kiểm soát đã được cấp phát.' : 'Chưa cấp phát workbook kiểm soát cho allocation này.';
      $item['detail_en'] = $item['ok'] ? 'A governed workbook has been issued.' : 'No governed workbook has been issued for this allocation.';
      break;
    }

    case 'received_workbook': {
      $receiptCount = count((array)($allocation['receipts'] ?? []));
      $item['ok'] = $receiptCount > 0 && trim((string)($allocation['latest_stored_filename'] ?? '')) !== '';
      $item['detail_vi'] = $item['ok']
        ? 'Workbook đã điền đã được tiếp nhận. Phiên bản mới nhất: ' . (string)($allocation['latest_stored_filename'] ?? '')
        : 'Chưa có workbook đã điền nào được tiếp nhận.';
      $item['detail_en'] = $item['ok']
        ? 'A completed workbook has been received. Latest file: ' . (string)($allocation['latest_stored_filename'] ?? '')
        : 'No completed workbook has been received yet.';
      break;
    }
  }

  return $item;
}

function evidence_evaluate_checklist(array $allocation, string $stage = 'review'): array {
  $stage = strtolower(trim($stage));
  if (!in_array($stage, ['review', 'approval'], true)) $stage = 'review';

  $formCode = trim((string)($allocation['form_code'] ?? ''));
  $schema = $formCode !== '' ? (load_form_schema_by_code($formCode) ?: []) : [];
  $entry = null;
  if ($formCode !== '' && (($allocation['delivery_mode'] ?? '') === 'online' || ($schema['online'] ?? true) !== false)) {
    $entry = evidence_find_online_entry(
      $formCode,
      trim((string)($allocation['allocation_id'] ?? '')),
      trim((string)($allocation['online_submission']['entry_id'] ?? ''))
    );
  }

  $items = [];
  $requiredCount = 0;
  $completeCount = 0;
  foreach (evidence_default_requirements($allocation, $schema) as $requirement) {
    $required = evidence_requirement_applies($requirement, $stage);
    $item = evidence_evaluate_requirement($requirement, $allocation, $schema, $entry);
    $item['required'] = $required;
    if ($required) {
      $requiredCount++;
      if (!empty($item['ok'])) $completeCount++;
    }
    $items[] = $item;
  }

  $missingIds = [];
  foreach ($items as $item) {
    if (!empty($item['required']) && empty($item['ok'])) $missingIds[] = (string)($item['id'] ?? '');
  }

  return [
    'ok' => empty($missingIds),
    'stage' => $stage,
    'evaluated_at' => now_iso(),
    'required_count' => $requiredCount,
    'complete_count' => $completeCount,
    'missing_ids' => $missingIds,
    'items' => $items,
  ];
}

function build_user_initials(string $username): string {
  $parts = preg_split('/[\.\-_@\s]+/', strtoupper(trim($username)));
  $initials = '';
  foreach ($parts as $part) {
    if ($part !== '') $initials .= substr($part, 0, 1);
  }
  if (strlen($initials) < 2) {
    $letters = preg_replace('/[^A-Z0-9]/', '', strtoupper($username));
    $initials = substr($letters, 0, 3);
  }
  return $initials !== '' ? $initials : 'USR';
}

function qms_runtime_secret(): string {
  global $ROOT_DIR;
  $secret = trim((string)(getenv('QMS_RUNTIME_SECRET') ?: ''));
  if ($secret !== '') return $secret;
  return hash('sha256', 'hesem-qms|' . $ROOT_DIR);
}

function allocation_base_dir(): string {
  global $DATA_DIR;
  $dir = $DATA_DIR . '/allocations';
  ensure_dir($dir);
  ensure_dir($dir . '/downloads');
  ensure_dir($dir . '/uploads');
  ensure_dir($dir . '/tmp');
  return $dir;
}

function allocation_store_file(): string {
  return allocation_base_dir() . '/allocations.json';
}

function load_allocation_store(): array {
  $file = allocation_store_file();
  if (!is_file($file)) {
    return [
      '_meta' => ['version' => '1.0', 'created_at' => now_iso(), 'updated_at' => now_iso()],
      'allocations' => [],
      'evidence_links' => [],
    ];
  }
  $data = json_decode((string)file_get_contents($file), true);
  if (!is_array($data)) {
    return [
      '_meta' => ['version' => '1.0', 'created_at' => now_iso(), 'updated_at' => now_iso()],
      'allocations' => [],
      'evidence_links' => [],
    ];
  }
  if (!isset($data['allocations']) || !is_array($data['allocations'])) $data['allocations'] = [];
  if (!isset($data['evidence_links']) || !is_array($data['evidence_links'])) $data['evidence_links'] = [];
  return $data;
}

function save_allocation_store(array $store): void {
  $store['_meta']['updated_at'] = now_iso();
  file_put_contents(allocation_store_file(), json_encode($store, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES), LOCK_EX);
}

function allocation_uuid(): string {
  $bytes = random_bytes(16);
  $bytes[6] = chr((ord($bytes[6]) & 0x0f) | 0x40);
  $bytes[8] = chr((ord($bytes[8]) & 0x3f) | 0x80);
  $hex = bin2hex($bytes);
  return vsprintf('%s%s-%s-%s-%s-%s%s%s', str_split($hex, 4));
}

function allocation_status_normalize(string $status): string {
  $status = strtolower(trim($status));
  return match ($status) {
    'form_downloaded' => 'downloaded',
    'allocated', 'downloaded', 'submitted', 'received', 'void',
    'in_review', 'approved', 'rejected' => $status,
    default => 'allocated',
  };
}

function allocation_append_event(array &$allocation, string $status, string $user, string $note = '', array $meta = []): void {
  $status = allocation_status_normalize($status);
  $allocation['history'] = is_array($allocation['history'] ?? null) ? $allocation['history'] : [];
  $allocation['history'][] = [
    'status' => $status,
    'at' => now_iso(),
    'by' => $user,
    'note' => $note,
    'meta' => $meta,
  ];
  $allocation['status'] = $status;
  $allocation['updated_at'] = now_iso();
  $allocation['updated_by'] = $user;
  allocation_append_audit_log($allocation, 'status_change', $user, $note, array_merge(['status' => $status], $meta));
}

function allocation_append_audit_log(array &$allocation, string $action, string $user, string $note = '', array $meta = []): void {
  $allocation['events'] = is_array($allocation['events'] ?? null) ? $allocation['events'] : [];
  $allocation['events'][] = [
    'action' => trim($action) !== '' ? trim($action) : 'note',
    'at' => now_iso(),
    'by' => $user,
    'note' => $note,
    'meta' => $meta,
  ];
  $allocation['updated_at'] = now_iso();
  $allocation['updated_by'] = $user;
}

function &allocation_find_ref(array &$store, string $allocationId) {
  foreach ($store['allocations'] as $idx => &$row) {
    if (is_array($row) && (string)($row['allocation_id'] ?? '') === $allocationId) {
      return $row;
    }
  }
  $null = null;
  return $null;
}

function allocation_find(array $store, string $allocationId): ?array {
  foreach ($store['allocations'] as $row) {
    if (is_array($row) && (string)($row['allocation_id'] ?? '') === $allocationId) {
      return $row;
    }
  }
  return null;
}

function allocation_find_by_record_id(array $store, string $recordId): ?array {
  foreach ($store['allocations'] as $row) {
    if (is_array($row) && (string)($row['record_id'] ?? '') === $recordId) {
      return $row;
    }
  }
  return null;
}

function evidence_link_catalog(): array {
  return [
    'related' => [
      'label_vi' => 'Liên quan',
      'label_en' => 'Related',
      'inverse_label_vi' => 'Liên quan',
      'inverse_label_en' => 'Related',
    ],
    'corrective_for' => [
      'label_vi' => 'Khắc phục cho',
      'label_en' => 'Corrective for',
      'inverse_label_vi' => 'Được khắc phục bởi',
      'inverse_label_en' => 'Corrected by',
    ],
    'caused_by' => [
      'label_vi' => 'Phát sinh từ',
      'label_en' => 'Caused by',
      'inverse_label_vi' => 'Gây ra',
      'inverse_label_en' => 'Causes',
    ],
    'verifies' => [
      'label_vi' => 'Xác minh cho',
      'label_en' => 'Verifies',
      'inverse_label_vi' => 'Được xác minh bởi',
      'inverse_label_en' => 'Verified by',
    ],
    'references' => [
      'label_vi' => 'Tham chiếu',
      'label_en' => 'References',
      'inverse_label_vi' => 'Được tham chiếu bởi',
      'inverse_label_en' => 'Referenced by',
    ],
    'supersedes' => [
      'label_vi' => 'Thay thế',
      'label_en' => 'Supersedes',
      'inverse_label_vi' => 'Bị thay thế bởi',
      'inverse_label_en' => 'Superseded by',
    ],
    'training_for' => [
      'label_vi' => 'Đào tạo cho',
      'label_en' => 'Training for',
      'inverse_label_vi' => 'Được đào tạo bởi',
      'inverse_label_en' => 'Trained by',
    ],
  ];
}

function evidence_link_type_normalize(string $type): string {
  $type = strtolower(trim($type));
  $catalog = evidence_link_catalog();
  return isset($catalog[$type]) ? $type : 'related';
}

function evidence_link_label(string $type, bool $inverse = false, string $locale = 'vi'): string {
  $catalog = evidence_link_catalog();
  $entry = $catalog[evidence_link_type_normalize($type)] ?? $catalog['related'];
  if ($inverse) {
    return $locale === 'en'
      ? (string)($entry['inverse_label_en'] ?? $entry['label_en'] ?? 'Related')
      : (string)($entry['inverse_label_vi'] ?? $entry['label_vi'] ?? 'Liên quan');
  }
  return $locale === 'en'
    ? (string)($entry['label_en'] ?? 'Related')
    : (string)($entry['label_vi'] ?? 'Liên quan');
}

function allocation_trace_summary(array $allocation): string {
  $ctx = is_array($allocation['master_context'] ?? null) ? $allocation['master_context'] : [];
  $parts = [];
  foreach (['customer_id', 'so_number', 'jo_number', 'wo_number'] as $key) {
    $value = trim((string)($ctx[$key] ?? ''));
    if ($value !== '') $parts[] = $value;
  }
  $part = trim((string)($ctx['part_number'] ?? ''));
  $rev = trim((string)($ctx['part_revision'] ?? ''));
  if ($part !== '' || $rev !== '') $parts[] = implode('/', array_filter([$part, $rev], fn($v) => $v !== ''));
  $capa = trim((string)($ctx['capa_number'] ?? ''));
  if ($capa !== '') $parts[] = $capa;
  return implode(' · ', $parts);
}

function allocation_summary(array $allocation): array {
  $formCode = trim((string)($allocation['form_code'] ?? ''));
  $schema = $formCode !== '' ? load_form_schema_by_code($formCode) : null;
  $registry = $formCode !== '' ? load_form_registry_entry($formCode) : null;
  return [
    'allocation_id' => (string)($allocation['allocation_id'] ?? ''),
    'record_id' => (string)($allocation['record_id'] ?? ''),
    'record_type' => (string)($allocation['record_type'] ?? ''),
    'form_code' => $formCode,
    'form_title_vi' => (string)($schema['title_vi'] ?? $schema['title'] ?? $registry['title_vi'] ?? $registry['title'] ?? ''),
    'form_title_en' => (string)($schema['title_en'] ?? $schema['title'] ?? $registry['title_en'] ?? $registry['title'] ?? ''),
    'status' => (string)($allocation['status'] ?? ''),
    'delivery_mode' => (string)($allocation['delivery_mode'] ?? ''),
    'department' => (string)($allocation['department'] ?? ''),
    'updated_at' => (string)($allocation['updated_at'] ?? $allocation['created_at'] ?? ''),
    'created_at' => (string)($allocation['created_at'] ?? ''),
    'master_context' => is_array($allocation['master_context'] ?? null) ? $allocation['master_context'] : [],
    'trace_summary' => allocation_trace_summary($allocation),
  ];
}

function evidence_links_for_allocation(array $store, string $allocationId): array {
  $links = [];
  foreach ((array)($store['evidence_links'] ?? []) as $row) {
    if (!is_array($row)) continue;
    $sourceId = trim((string)($row['source_allocation_id'] ?? ''));
    $targetId = trim((string)($row['target_allocation_id'] ?? ''));
    if ($sourceId !== $allocationId && $targetId !== $allocationId) continue;

    $incoming = $targetId === $allocationId;
    $counterpartId = $incoming ? $sourceId : $targetId;
    $counterpart = $counterpartId !== '' ? allocation_find($store, $counterpartId) : null;
    $relationType = evidence_link_type_normalize((string)($row['relation_type'] ?? 'related'));

    $links[] = [
      'link_id' => (string)($row['link_id'] ?? ''),
      'relation_type' => $relationType,
      'direction' => $incoming ? 'incoming' : 'outgoing',
      'relation_label_vi' => evidence_link_label($relationType, $incoming, 'vi'),
      'relation_label_en' => evidence_link_label($relationType, $incoming, 'en'),
      'created_at' => (string)($row['created_at'] ?? ''),
      'created_by' => (string)($row['created_by'] ?? ''),
      'notes' => (string)($row['notes'] ?? ''),
      'source_allocation_id' => $sourceId,
      'target_allocation_id' => $targetId,
      'counterpart' => $counterpart ? allocation_summary($counterpart) : ['allocation_id' => $counterpartId],
    ];
  }

  usort($links, function ($a, $b) {
    return strcmp((string)($b['created_at'] ?? ''), (string)($a['created_at'] ?? ''));
  });
  return $links;
}

function allocation_resolve_received_file(array $allocation, int $version = 0): ?array {
  $allocationId = trim((string)($allocation['allocation_id'] ?? ''));
  if ($allocationId === '') return null;

  $receipts = array_values(array_filter((array)($allocation['receipts'] ?? []), fn($row) => is_array($row)));
  if (!$receipts) {
    $filename = trim((string)($allocation['latest_stored_filename'] ?? ''));
    if ($filename === '') return null;
    $path = allocation_base_dir() . '/uploads/' . $allocationId . '/' . $filename;
    if (!is_file($path)) return null;
    return [
      'version' => (int)($allocation['receipt_version'] ?? 0),
      'stored_filename' => $filename,
      'server_path' => $path,
      'uploaded_at' => (string)($allocation['latest_upload_timestamp'] ?? ''),
      'uploaded_by' => '',
    ];
  }

  $selected = null;
  if ($version > 0) {
    foreach ($receipts as $row) {
      if ((int)($row['version'] ?? 0) === $version) {
        $selected = $row;
        break;
      }
    }
  }
  if (!$selected) {
    usort($receipts, fn($a, $b) => (int)($b['version'] ?? 0) <=> (int)($a['version'] ?? 0));
    $selected = $receipts[0] ?? null;
  }
  if (!is_array($selected)) return null;

  $filename = trim((string)($selected['stored_filename'] ?? ''));
  if ($filename === '') return null;
  $path = trim((string)($selected['server_path'] ?? ''));
  if ($path === '') $path = allocation_base_dir() . '/uploads/' . $allocationId . '/' . $filename;
  if (!is_file($path)) return null;

  return [
    'version' => (int)($selected['version'] ?? 0),
    'stored_filename' => $filename,
    'server_path' => $path,
    'uploaded_at' => (string)($selected['uploaded_at'] ?? ''),
    'uploaded_by' => (string)($selected['uploaded_by'] ?? ''),
  ];
}

function next_record_id_value(string $recordType, string $year): array {
  global $DATA_DIR;

  $prefix = strtoupper(trim($recordType));
  if ($prefix === '') {
    throw new RuntimeException('missing_prefix');
  }
  if (!preg_match('/^20[2-3][0-9]$/', $year)) {
    throw new RuntimeException('invalid_year');
  }

  $counterRegistryFile = $DATA_DIR . '/counters/_registry.json';
  $counterRegistry = is_file($counterRegistryFile) ? (json_decode((string)file_get_contents($counterRegistryFile), true) ?: []) : [];
  $recordRegistry = load_record_type_registry();

  $digits = (int)($counterRegistry[$prefix]['digits'] ?? $recordRegistry[$prefix]['digits'] ?? 3);
  if ($digits < 2) $digits = 3;

  $countersDir = $DATA_DIR . '/counters';
  ensure_dir($countersDir);
  $counterFile = $countersDir . '/' . $prefix . '-' . $year . '.txt';

  $fp = @fopen($counterFile, 'c+');
  if (!$fp) throw new RuntimeException('counter_file_error');
  if (!flock($fp, LOCK_EX)) {
    fclose($fp);
    throw new RuntimeException('counter_lock_failed');
  }
  $raw = fread($fp, 20);
  $current = $raw !== false ? (int)trim($raw) : 0;
  $next = $current + 1;
  $padded = str_pad((string)$next, $digits, '0', STR_PAD_LEFT);
  ftruncate($fp, 0);
  rewind($fp);
  fwrite($fp, $padded);
  fflush($fp);
  flock($fp, LOCK_UN);
  fclose($fp);

  $recordId = $prefix . '-' . $year . '-' . $padded;
  @file_put_contents(
    $countersDir . '/_allocation_log.jsonl',
    json_encode([
      'record_id' => $recordId,
      'prefix' => $prefix,
      'year' => $year,
      'seq' => $next,
      'time' => now_iso(),
      'user' => $_SESSION['user'] ?? 'anonymous',
      'ip' => client_ip(),
    ], JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES) . "\n",
    FILE_APPEND | LOCK_EX
  );

  return ['record_id' => $recordId, 'seq' => $next, 'digits' => $digits];
}

function normalize_master_context(array $context): array {
  $keys = ['customer_id', 'supplier_id', 'so_number', 'jo_number', 'wo_number', 'part_number', 'part_revision', 'capa_number'];
  $normalized = [];
  foreach ($keys as $key) {
    $value = trim((string)($context[$key] ?? ''));
    if ($value !== '') $normalized[$key] = $value;
  }
  return $normalized;
}

function build_issued_filename(string $formCode, string $formRevision, string $recordId, string $username, string $ext = 'xlsx'): string {
  $dt = new DateTimeImmutable('now', new DateTimeZone('Asia/Ho_Chi_Minh'));
  $stampDate = $dt->format('Ymd');
  $stampTime = $dt->format('Hi');
  $initials = build_user_initials($username);
  return sprintf('%s_%s_%s_%s_%s-%s.%s', $formCode, $formRevision, $recordId, $stampDate, $stampTime, $initials, $ext);
}

function build_received_filename(array $allocation, int $receiptVersion, string $ext = 'xlsx'): string {
  $formCode = (string)($allocation['form_code'] ?? 'FORM');
  $formRevision = (string)($allocation['form_revision'] ?? 'V0');
  $recordId = (string)($allocation['record_id'] ?? 'RECORD');
  $dt = new DateTimeImmutable('now', new DateTimeZone('Asia/Ho_Chi_Minh'));
  return sprintf('%s_%s_%s_%s_R%02d.%s', $formCode, $formRevision, $recordId, $dt->format('Ymd'), $receiptVersion, $ext);
}

function build_expected_filename_pattern(string $formCode, string $formRevision, string $recordId, string $ext = 'xlsx'): string {
  return '^' . preg_quote($formCode, '/') . '_' . preg_quote($formRevision, '/') . '_' . preg_quote($recordId, '/') . '_\\d{8}_\\d{4}-[A-Z0-9]{2,6}\\.' . preg_quote($ext, '/') . '$';
}

function build_hidden_sheet_payload(array $allocation, array $formEntry): array {
  $issuedAt = (string)($allocation['downloaded_at'] ?? now_iso());
  $downloadUser = (string)($allocation['downloaded_by'] ?? $allocation['created_by'] ?? 'system');
  $payload = [
    'form_code' => (string)($allocation['form_code'] ?? ''),
    'form_revision' => (string)($allocation['form_revision'] ?? 'V0'),
    'download_timestamp' => $issuedAt,
    'download_user' => $downloadUser,
    'system_origin' => 'HESEM-MOM-v3',
    'allocation_id' => (string)($allocation['allocation_id'] ?? ''),
    'expected_filename_pattern' => (string)($allocation['expected_filename_pattern'] ?? ''),
    'max_file_size_mb' => 25,
    'allowed_macros' => false,
    'template_checksum' => (string)($allocation['template_checksum'] ?? ''),
    'issued_record_id' => (string)($allocation['record_id'] ?? ''),
    'issued_to_user' => $downloadUser,
    'issued_at' => $issuedAt,
    'receipt_status' => allocation_status_normalize((string)($allocation['status'] ?? 'allocated')),
    'receipt_version' => (int)($allocation['receipt_version'] ?? 0),
    'master_context_json' => normalize_master_context((array)($allocation['master_context'] ?? [])),
    'receipt_history_json' => (array)($allocation['receipts'] ?? []),
    'latest_stored_filename' => (string)($allocation['latest_stored_filename'] ?? ''),
    'latest_upload_timestamp' => (string)($allocation['latest_upload_timestamp'] ?? ''),
  ];
  $payload['download_hash'] = hash('sha256', implode('|', [
    $payload['form_code'],
    $payload['form_revision'],
    $payload['download_timestamp'],
    $payload['download_user'],
    qms_runtime_secret(),
  ]));
  return $payload;
}

function python_runtime_command(array $args): string {
  $script = __DIR__ . '/tools/excel_hidden_sheet_runtime.py';
  $parts = ['python', escapeshellarg($script)];
  foreach ($args as $arg) {
    $parts[] = escapeshellarg((string)$arg);
  }
  return implode(' ', $parts);
}

function run_python_runtime(array $args): array {
  $exitCode = 0;
  $output = shell_run(python_runtime_command($args), $exitCode);
  if ($exitCode !== 0) {
    throw new RuntimeException('excel_runtime_failed: ' . $output);
  }
  $data = json_decode($output, true);
  if (!is_array($data)) {
    throw new RuntimeException('excel_runtime_invalid_json');
  }
  return $data;
}

function write_temp_json_file(array $payload, string $prefix = 'qms-'): string {
  $file = allocation_base_dir() . '/tmp/' . $prefix . bin2hex(random_bytes(6)) . '.json';
  file_put_contents($file, json_encode($payload, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES), LOCK_EX);
  return $file;
}

function inspect_uploaded_workbook(string $sourcePath): array {
  global $DATA_DIR;
  $spec = $DATA_DIR . '/config/excel_hidden_sheet_spec.json';
  if (!is_file($spec)) throw new RuntimeException('excel_hidden_sheet_spec_missing');
  return run_python_runtime(['inspect', '--src', $sourcePath, '--spec', $spec]);
}

function issue_offline_workbook_package(string $sourcePath, string $targetPath, array $payload): array {
  global $DATA_DIR;
  $spec = $DATA_DIR . '/config/excel_hidden_sheet_spec.json';
  if (!is_file($spec)) throw new RuntimeException('excel_hidden_sheet_spec_missing');
  $metaFile = write_temp_json_file($payload, 'issue-');
  try {
    return run_python_runtime(['issue', '--src', $sourcePath, '--dst', $targetPath, '--spec', $spec, '--meta', $metaFile]);
  } finally {
    @unlink($metaFile);
  }
}

function append_receipt_to_workbook(string $sourcePath, string $targetPath, array $receiptPayload): array {
  global $DATA_DIR;
  $spec = $DATA_DIR . '/config/excel_hidden_sheet_spec.json';
  if (!is_file($spec)) throw new RuntimeException('excel_hidden_sheet_spec_missing');
  $receiptFile = write_temp_json_file($receiptPayload, 'receipt-');
  try {
    return run_python_runtime(['append-receipt', '--src', $sourcePath, '--dst', $targetPath, '--spec', $spec, '--receipt', $receiptFile]);
  } finally {
    @unlink($receiptFile);
  }
}

function stream_download_file(string $path, string $filename): void {
  if (!is_file($path)) api_json(['ok' => false, 'error' => 'file_not_found'], 404);
  if (session_status() === PHP_SESSION_ACTIVE) @session_write_close();
  http_response_code(200);
  header('Content-Type: application/octet-stream');
  header('Content-Length: ' . filesize($path));
  header('Content-Disposition: attachment; filename="' . rawurlencode($filename) . '"; filename*=UTF-8\'\'' . rawurlencode($filename));
  header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
  readfile($path);
  exit;
}

function allocation_history_query(array $filters = []): array {
  $store = load_allocation_store();
  $rows = array_values(array_filter((array)($store['allocations'] ?? []), function ($row) use ($filters) {
    if (!is_array($row)) return false;
    if (!empty($filters['record_type']) && (string)($row['record_type'] ?? '') !== (string)$filters['record_type']) return false;
    if (!empty($filters['department']) && (string)($row['department'] ?? '') !== (string)$filters['department']) return false;
    if (!empty($filters['form_code']) && (string)($row['form_code'] ?? '') !== (string)$filters['form_code']) return false;
    if (!empty($filters['delivery_mode']) && (string)($row['delivery_mode'] ?? '') !== (string)$filters['delivery_mode']) return false;
    if (!empty($filters['status']) && allocation_status_normalize((string)($row['status'] ?? 'allocated')) !== allocation_status_normalize((string)$filters['status'])) return false;
    $updatedAt = (string)($row['updated_at'] ?? $row['created_at'] ?? '');
    if (!empty($filters['date_from']) && substr($updatedAt, 0, 10) < (string)$filters['date_from']) return false;
    if (!empty($filters['date_to']) && substr($updatedAt, 0, 10) > (string)$filters['date_to']) return false;
    if (!empty($filters['search'])) {
      $haystack = strtolower(json_encode([
        $row['record_id'] ?? '',
        $row['record_type'] ?? '',
        $row['department'] ?? '',
        $row['form_code'] ?? '',
        $row['master_context'] ?? [],
        $row['notes'] ?? '',
      ], JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES));
      if (!str_contains($haystack, strtolower((string)$filters['search']))) return false;
    }
    return true;
  }));

  usort($rows, function ($a, $b) {
    return strcmp((string)($b['updated_at'] ?? ''), (string)($a['updated_at'] ?? ''));
  });

  $page = max(1, (int)($filters['page'] ?? 1));
  $pageSize = max(1, min(100, (int)($filters['page_size'] ?? 20)));
  $total = count($rows);
  $items = array_slice($rows, ($page - 1) * $pageSize, $pageSize);

  return [
    'entries' => $items,
    'page' => $page,
    'page_size' => $pageSize,
    'total' => $total,
    'total_pages' => max(1, (int)ceil($total / $pageSize)),
  ];
}

function verify_hidden_sheet_metadata(array $metadata, ?array $allocation, string $originalFilename): array {
  $issues = [];
  $warnings = [];
  $status = 'verified';

  if (($metadata['system_origin'] ?? '') !== 'HESEM-MOM-v3') {
    $issues[] = 'origin_invalid';
  }

  $expectedHash = hash('sha256', implode('|', [
    (string)($metadata['form_code'] ?? ''),
    (string)($metadata['form_revision'] ?? ''),
    (string)($metadata['download_timestamp'] ?? ''),
    (string)($metadata['download_user'] ?? ''),
    qms_runtime_secret(),
  ]));
  if (($metadata['download_hash'] ?? '') !== $expectedHash) {
    $issues[] = 'hash_mismatch';
  }

  if (!$allocation) {
    $issues[] = 'allocation_not_found';
  } else {
    $state = allocation_status_normalize((string)($allocation['status'] ?? 'allocated'));
    if (!in_array($state, ['downloaded', 'submitted', 'received'], true)) {
      $issues[] = 'allocation_wrong_state';
    }
    if (($metadata['issued_record_id'] ?? '') !== '' && (string)($metadata['issued_record_id'] ?? '') !== (string)($allocation['record_id'] ?? '')) {
      $issues[] = 'record_id_mismatch';
    }
    if (($metadata['form_code'] ?? '') !== '' && (string)($metadata['form_code'] ?? '') !== (string)($allocation['form_code'] ?? '')) {
      $issues[] = 'form_code_mismatch';
    }
    if (($metadata['template_checksum'] ?? '') !== '' && (string)($metadata['template_checksum'] ?? '') !== (string)($allocation['template_checksum'] ?? '')) {
      $issues[] = 'template_checksum_mismatch';
    }
  }

  $pattern = (string)($metadata['expected_filename_pattern'] ?? '');
  if ($pattern !== '' && @preg_match('/' . $pattern . '/i', '') !== false && !preg_match('/' . $pattern . '/i', $originalFilename)) {
    $issues[] = 'filename_mismatch';
  }

  if ($issues) {
    $status = 'rejected';
  } elseif ($warnings) {
    $status = 'warning';
  }

  return [
    'status' => $status,
    'issues' => $issues,
    'warnings' => $warnings,
    'hash_valid' => !in_array('hash_mismatch', $issues, true),
    'origin_valid' => !in_array('origin_invalid', $issues, true),
    'allocation_valid' => !in_array('allocation_not_found', $issues, true) && !in_array('allocation_wrong_state', $issues, true),
  ];
}

function allocation_duplicate_receipt_candidates(?array $allocation, string $sha256): array {
  $sha256 = strtolower(trim($sha256));
  if (!$allocation || $sha256 === '') return [];
  $matches = [];
  foreach ((array)($allocation['receipts'] ?? []) as $receipt) {
    if (!is_array($receipt)) continue;
    $receiptHash = strtolower(trim((string)($receipt['sha256_hash'] ?? '')));
    if ($receiptHash !== '' && hash_equals($receiptHash, $sha256)) {
      $matches[] = [
        'version' => (int)($receipt['version'] ?? 0),
        'uploaded_at' => (string)($receipt['uploaded_at'] ?? ''),
        'uploaded_by' => (string)($receipt['uploaded_by'] ?? ''),
        'stored_filename' => (string)($receipt['stored_filename'] ?? ''),
        'sha256_hash' => $receiptHash,
      ];
    }
  }
  return $matches;
}

function file_head_bytes(string $path, int $length = 4096): string {
  if (!is_file($path) || $length < 1) return '';
  $fh = @fopen($path, 'rb');
  if (!$fh) return '';
  $bytes = (string)@fread($fh, $length);
  @fclose($fh);
  return $bytes;
}

function csv_payload_looks_textual(string $payload): bool {
  if ($payload === '' || str_contains($payload, "\0")) return false;
  $len = strlen($payload);
  $controlCount = 0;
  for ($i = 0; $i < $len; $i++) {
    $ord = ord($payload[$i]);
    $isAllowedControl = in_array($ord, [9, 10, 13], true);
    if (($ord < 32 && !$isAllowedControl) || $ord === 127) $controlCount++;
  }
  return ($controlCount / max(1, $len)) < 0.02;
}

function workbook_zip_structure_valid(string $path): bool {
  if (!class_exists('ZipArchive')) return true;
  $zip = new ZipArchive();
  if ($zip->open($path) !== true) return false;
  foreach (['[Content_Types].xml', '_rels/.rels', 'xl/workbook.xml'] as $entry) {
    if ($zip->locateName($entry, ZipArchive::FL_NOCASE) === false) {
      $zip->close();
      return false;
    }
  }
  $zip->close();
  return true;
}

function uploaded_workbook_signature_valid(string $path, string $ext): bool {
  $ext = strtolower(trim($ext));
  $head = file_head_bytes($path, 4096);
  if ($head === '') return false;

  return match ($ext) {
    'xlsx', 'xlsm' => str_starts_with($head, "PK\x03\x04") && workbook_zip_structure_valid($path),
    'xls' => str_starts_with($head, hex2bin('D0CF11E0A1B11AE1')),
    'csv' => csv_payload_looks_textual($head),
    default => false,
  };
}

function validate_signature_payloads(array $schema, array $signatures): array {
  $blocks = is_array($schema['signature_blocks'] ?? null) ? $schema['signature_blocks'] : [];
  $errors = [];
  $summary = [];

  foreach ($blocks as $block) {
    if (!is_array($block)) continue;
    $blockId = trim((string)($block['id'] ?? ''));
    if ($blockId === '') continue;

    $signature = $signatures[$blockId] ?? null;
    if (!is_array($signature)) {
      if (!empty($block['required_on_submit'])) {
        $errors[] = ['signature_block' => $blockId, 'error' => 'missing_required_signature'];
      }
      continue;
    }

    $summary[$blockId] = [
      'signer_id' => trim((string)($signature['signer_id'] ?? '')),
      'signer_name' => trim((string)($signature['signer_name'] ?? '')),
      'signed_at' => trim((string)($signature['signed_at'] ?? '')),
      'pin_confirmed' => !empty($signature['pin_confirmed']),
      'hash_prefix' => substr(trim((string)($signature['hash'] ?? '')), 0, 16),
    ];

    foreach (['signer_id', 'signer_name', 'signed_at', 'hash'] as $requiredKey) {
      if (trim((string)($signature[$requiredKey] ?? '')) === '') {
        $errors[] = ['signature_block' => $blockId, 'error' => 'signature_field_missing', 'field' => $requiredKey];
      }
    }

    if (!empty($block['require_pin']) && empty($signature['pin_confirmed'])) {
      $errors[] = ['signature_block' => $blockId, 'error' => 'pin_confirmation_required'];
    }

    $appliedTo = trim((string)($signature['applied_to'] ?? ''));
    if ($appliedTo !== '' && substr($appliedTo, -strlen(':' . $blockId)) !== ':' . $blockId) {
      $errors[] = ['signature_block' => $blockId, 'error' => 'signature_target_mismatch'];
    }
  }

  return [
    'ok' => !$errors,
    'errors' => $errors,
    'summary' => $summary,
  ];
}

function client_ip(): string {
  return $_SERVER['REMOTE_ADDR'] ?? '0.0.0.0';
}

function pending_auth_ttl_seconds(): int {
  global $PENDING_AUTH_TTL_SECONDS;
  return max(60, (int)$PENDING_AUTH_TTL_SECONDS);
}

function pending_auth_remaining_seconds(int $startedAt): int {
  if ($startedAt <= 0) return 0;
  return max(0, pending_auth_ttl_seconds() - (time() - $startedAt));
}

function clear_preauth_session_state(): void {
  unset($_SESSION['preauth_user'], $_SESSION['preauth_started']);
  if (empty($_SESSION['user'])) {
    unset($_SESSION['mfa_ok']);
  }
}

function clear_enroll_session_state(): void {
  unset($_SESSION['enroll_user'], $_SESSION['enroll_secret'], $_SESSION['enroll_started']);
}

function clear_pending_auth_session_state(): void {
  clear_enroll_session_state();
  clear_preauth_session_state();
}

function clear_auth_session_state(): void {
  unset(
    $_SESSION['user'],
    $_SESSION['preauth_user'],
    $_SESSION['preauth_started'],
    $_SESSION['mfa_ok'],
    $_SESSION['enroll_user'],
    $_SESSION['enroll_secret'],
    $_SESSION['enroll_started'],
    $_SESSION['last_active'],
    $_SESSION['user_scope'],
    $_SESSION['org_scope']
  );
}

function extract_user_scope(array $user): array {
  $scope = [];
  foreach (['org_company_code', 'org_legal_entity_code', 'org_plant_id', 'org_site_id'] as $field) {
    $value = $user[$field] ?? null;
    if (!is_scalar($value)) continue;
    $text = trim((string)$value);
    if ($text === '') continue;
    $scope[$field] = $text;
  }
  return $scope;
}

function set_preauth_session(string $username): void {
  if (session_status() !== PHP_SESSION_ACTIVE) session_init();
  session_regenerate_id_safe(true);
  clear_auth_session_state();
  $_SESSION['preauth_user'] = strtolower(trim($username));
  $_SESSION['preauth_started'] = time();
  $_SESSION['mfa_ok'] = false;
}

function set_authenticated_session(string $username, array $user = []): void {
  if (session_status() !== PHP_SESSION_ACTIVE) session_init();
  session_regenerate_id_safe(true);
  clear_auth_session_state();
  $_SESSION['user'] = strtolower(trim($username));
  $_SESSION['mfa_ok'] = true;
  $_SESSION['last_active'] = time();
  $scope = extract_user_scope($user);
  if ($scope !== []) {
    $_SESSION['user_scope'] = $scope;
    $_SESSION['org_scope'] = $scope;
  }
}

function destroy_auth_session(): void {
  if (session_status() !== PHP_SESSION_ACTIVE) session_init();
  clear_auth_session_state();
  if (ini_get('session.use_cookies') && !headers_sent()) {
    $params = session_get_cookie_params();
    setcookie(session_name(), '', time() - 3600, $params['path'] ?: '/', $params['domain'] ?? '', (bool)($params['secure'] ?? false), (bool)($params['httponly'] ?? true));
  }
  $_SESSION = [];
  if (session_status() === PHP_SESSION_ACTIVE) {
    session_destroy();
  }
  // Ensure session state is written and file handle is closed
  if (session_status() === PHP_SESSION_ACTIVE) {
    session_write_close();
  }
}

function session_requires_completed_mfa(array $user, array $settings = []): bool {
  $systemRequiresMfa = (bool)($settings['require_mfa'] ?? true);
  // When system MFA is disabled globally, skip MFA for ALL users
  if (!$systemRequiresMfa) {
    return false;
  }
  $userMfa = $user['mfa'] ?? [];
  $userHasMfa = is_array($userMfa) && (bool)($userMfa['enabled'] ?? false);
  return $systemRequiresMfa || $userHasMfa;
}

function now_iso(): string {
  return gmdate('c');
}

function password_policy(string $pw): array {
  if (strlen($pw) < 10) return [false, 'Password must be at least 10 characters'];
  if (!preg_match('/[a-z]/', $pw)) return [false, 'Password must include a lowercase letter'];
  if (!preg_match('/[A-Z]/', $pw)) return [false, 'Password must include an uppercase letter'];
  if (!preg_match('/\d/', $pw)) return [false, 'Password must include a number'];
  if (!preg_match('/[^A-Za-z0-9]/', $pw)) return [false, 'Password must include a symbol'];
  return [true, ''];
}

function normalize_session_dir(string $path): string {
  $path = trim($path);
  if ($path === '') return '';
  if (strpos($path, ';') !== false) {
    $parts = explode(';', $path);
    $path = (string)end($parts);
  }
  return rtrim($path, "/\\");
}

function session_dir_candidates(): array {
  global $DATA_DIR;

  // Ensure primary session dir exists early (VPS deployments)
  $primary = $DATA_DIR . '/sessions';
  if ($primary !== '' && !is_dir($primary)) {
    @mkdir($primary, 0775, true);
  }

  $candidates = [
    $primary,
    sys_get_temp_dir() . '/hesem-sessions',
    normalize_session_dir((string)session_save_path()),
    '/var/lib/php/sessions',
    sys_get_temp_dir(),
  ];

  $unique = [];
  foreach ($candidates as $candidate) {
    $candidate = normalize_session_dir((string)$candidate);
    if ($candidate === '' || in_array($candidate, $unique, true)) continue;
    $unique[] = $candidate;
  }

  return $unique;
}

// ---------- Session + Cookies ----------
function session_init(): void {
  if (session_status() === PHP_SESSION_ACTIVE) return;

  $isCliLike = in_array(PHP_SAPI, ['cli', 'phpdbg'], true);
  $https = (!empty($_SERVER['HTTPS']) && $_SERVER['HTTPS'] !== 'off')
    || (strtolower((string)($_SERVER['HTTP_X_FORWARDED_PROTO'] ?? '')) === 'https')
    || ((string)($_SERVER['HTTP_X_FORWARDED_SSL'] ?? '') === 'on');
  $headersMutable = !headers_sent();
  $headerlessSessionMode = $isCliLike || !$headersMutable;

  // Smoke tests and CLI helpers may touch session_init() after writing output.
  // In that case we only need an in-memory session array, not HTTP cookie/session I/O.
  if ($isCliLike && !$headersMutable) {
    if (!is_array($_SESSION ?? null)) {
      $_SESSION = [];
    }
    return;
  }

  if ($headerlessSessionMode) {
    @ini_set('session.use_cookies', '0');
    if (PHP_VERSION_ID < 80500) {
      @ini_set('session.use_only_cookies', '0');
    }
    @ini_set('session.cache_limiter', '');
  } else {
    @ini_set('session.use_only_cookies', '1');
    @ini_set('session.use_strict_mode', '1');
    @ini_set('session.cookie_httponly', '1');
    @ini_set('session.cookie_samesite', 'Lax');
    if ($https) {
      @ini_set('session.cookie_secure', '1');
    }
  }

  // Host-only cookie (do not set Domain attribute) to maximize compatibility on subdomains
  $domain = '';
  $sessionName = $https ? '__Host-HESEMSESSID' : 'HESEMSESSID';

  if (!$headerlessSessionMode) {
    session_name($sessionName);
    session_set_cookie_params([
      'lifetime' => 0,
      'path' => '/',
      'domain' => $domain,
      'secure' => $https,
      'httponly' => true,
      'samesite' => 'Lax',
    ]);
  }

  $lastError = null;
  foreach (session_dir_candidates() as $sessDir) {
    ensure_dir($sessDir);
    if (!is_dir($sessDir) || !is_writable($sessDir)) {
      continue;
    }

    if ($headersMutable) {
      @session_save_path($sessDir);
    }

    if ($headerlessSessionMode && session_id() === '') {
      @session_id(bin2hex(random_bytes(16)));
    }

    try {
      session_start();
      return;
    } catch (\Throwable $e) {
      $lastError = $e;
      if (session_status() === PHP_SESSION_ACTIVE) {
        @session_write_close();
      }
      if (session_exception_allows_fresh_start($e)) {
        if (session_start_with_fresh_id()) {
          return;
        }
      }
    }
  }

  if ($lastError instanceof \Throwable) {
    throw $lastError;
  }

  session_start();
}

function session_exception_allows_fresh_start(\Throwable $e): bool {
  $message = strtolower(trim($e->getMessage()));
  if ($message === '') return false;

  return str_contains($message, 'session_start(): open(')
    || str_contains($message, 'failed to read session data')
    || str_contains($message, 'session data file is not created by your uid')
    || str_contains($message, 'permission denied')
    || str_contains($message, 'no such file or directory');
}

function session_start_with_fresh_id(): bool {
  if (in_array(PHP_SAPI, ['cli', 'phpdbg'], true) && headers_sent()) {
    if (!is_array($_SESSION ?? null)) {
      $_SESSION = [];
    }
    return true;
  }

  $cookieName = session_name();
  if ($cookieName !== '' && isset($_COOKIE[$cookieName])) {
    unset($_COOKIE[$cookieName]);
  }

  if (session_status() === PHP_SESSION_ACTIVE) {
    @session_write_close();
  }

  @ini_set('session.use_cookies', '0');
  if (PHP_VERSION_ID < 80500) {
    @ini_set('session.use_only_cookies', '0');
  }
  @ini_set('session.cache_limiter', '');
  @session_id(bin2hex(random_bytes(16)));

  try {
    session_start();
    return true;
  } catch (\Throwable $retryError) {
    @error_log('[API] Session recovery failed: ' . $retryError->getMessage() . ' in ' . $retryError->getFile() . ':' . $retryError->getLine());
    if (session_status() === PHP_SESSION_ACTIVE) {
      @session_write_close();
    }
  }

  return false;
}

function session_regenerate_id_safe(bool $deleteOldSession = true): void {
  if (session_status() !== PHP_SESSION_ACTIVE) {
    return;
  }

  try {
    if (@session_regenerate_id($deleteOldSession)) {
      return;
    }
  } catch (Throwable $e) {
    @error_log('[API] session_regenerate_id failed: ' . $e->getMessage());
  }

  if ($deleteOldSession) {
    try {
      if (@session_regenerate_id(false)) {
        @error_log('[API] session_regenerate_id fallback kept old session file');
        return;
      }
    } catch (Throwable $e) {
      @error_log('[API] session_regenerate_id fallback failed: ' . $e->getMessage());
    }
  }

  @error_log('[API] session_regenerate_id skipped; continuing with current session id');
}

function csrf_token(): string {
  session_init();
  $ttlSeconds = 3600;
  $generatedAt = isset($_SESSION['csrf_generated_at']) ? (int)$_SESSION['csrf_generated_at'] : null;
  $expired = $generatedAt !== null && (time() - $generatedAt) > $ttlSeconds;
  if (empty($_SESSION['csrf']) || $expired) {
    $_SESSION['csrf'] = bin2hex(random_bytes(32));
    $_SESSION['csrf_generated_at'] = time();
  } elseif ($generatedAt === null) {
    $_SESSION['csrf_generated_at'] = time();
  }
  return (string)$_SESSION['csrf'];
}

function require_csrf(): void {
  session_init();
  $token = $_SERVER['HTTP_X_CSRF_TOKEN'] ?? '';
  if ($token === '' || empty($_SESSION['csrf']) || !hash_equals((string)$_SESSION['csrf'], (string)$token)) {
    api_json(['ok' => false, 'error' => 'csrf_failed'], 403);
  }
  $generatedAt = isset($_SESSION['csrf_generated_at']) ? (int)$_SESSION['csrf_generated_at'] : null;
  if ($generatedAt !== null && (time() - $generatedAt) > 3600) {
    api_json(['ok' => false, 'error' => 'csrf_expired'], 403);
  }
}

function api_request_allowed_origins(): array {
  $defaults = [
    'https://eqms.hesemeng.com',
    'https://*.hesemeng.com',
    'https://qms.hesem.com.vn',
    'https://*.hesem.com.vn',
    'http://localhost:3000',
    'http://127.0.0.1:3000',
    'http://localhost:4173',
    'http://127.0.0.1:4173',
    'http://localhost:5173',
    'http://127.0.0.1:5173',
  ];

  $raw = getenv('QMS_API_ALLOWED_ORIGINS');
  if ($raw !== false && trim((string)$raw) !== '') {
    $defaults = array_values(array_filter(array_map(
      static fn(string $item): string => trim($item),
      explode(',', (string)$raw)
    ), static fn(string $item): bool => $item !== ''));
  }

  $https = (!empty($_SERVER['HTTPS']) && $_SERVER['HTTPS'] !== 'off')
    || (strtolower((string)($_SERVER['HTTP_X_FORWARDED_PROTO'] ?? '')) === 'https')
    || ((string)($_SERVER['HTTP_X_FORWARDED_SSL'] ?? '') === 'on');
  $host = trim((string)($_SERVER['HTTP_HOST'] ?? ''));
  if ($host !== '') {
    $defaults[] = ($https ? 'https' : 'http') . '://' . strtolower($host);
  }

  $out = [];
  $seen = [];
  foreach ($defaults as $origin) {
    $origin = strtolower(trim((string)$origin));
    if ($origin === '' || isset($seen[$origin])) continue;
    $seen[$origin] = true;
    $out[] = $origin;
  }

  return $out;
}

function api_origin_matches_pattern(string $origin, string $allowed): bool {
  $origin = strtolower(trim($origin));
  $allowed = strtolower(trim($allowed));
  if ($origin === '' || $allowed === '') return false;
  if ($origin === $allowed) return true;
  if (!str_contains($allowed, '*')) return false;

  $regex = '/^' . str_replace('\*', '[a-z0-9.-]+', preg_quote($allowed, '/')) . '$/';
  return (bool)preg_match($regex, $origin);
}

function api_request_origin_candidate(): string {
  $origin = strtolower(trim((string)($_SERVER['HTTP_ORIGIN'] ?? '')));
  if ($origin !== '') {
    return $origin;
  }

  $referer = trim((string)($_SERVER['HTTP_REFERER'] ?? ''));
  if ($referer === '') {
    return '';
  }

  $parts = parse_url($referer);
  if (!is_array($parts)) {
    return '';
  }

  $scheme = strtolower(trim((string)($parts['scheme'] ?? '')));
  $host = strtolower(trim((string)($parts['host'] ?? '')));
  if ($scheme === '' || $host === '') {
    return '';
  }

  $candidate = $scheme . '://' . $host;
  if (isset($parts['port'])) {
    $candidate .= ':' . (int)$parts['port'];
  }

  return $candidate;
}

function request_has_allowed_origin(array $extraAllowedOrigins = []): bool {
  $candidate = api_request_origin_candidate();
  if ($candidate === '') {
    // No Origin or Referer header present.
    // This is either a same-origin browser request (some browsers omit Origin
    // for same-origin POST) or a non-browser client (curl, Postman, server-to-server).
    // Neither is a cross-origin CSRF attack vector, so allow through.
    // Additional protection is provided by CSRF tokens and rate limiting.
    return true;
  }

  $allowed = array_merge(api_request_allowed_origins(), $extraAllowedOrigins);
  foreach ($allowed as $pattern) {
    if (api_origin_matches_pattern($candidate, (string)$pattern)) {
      return true;
    }
  }

  return false;
}

function require_allowed_origin(array $extraAllowedOrigins = []): void {
  if (!request_has_allowed_origin($extraAllowedOrigins)) {
    api_json(['ok' => false, 'error' => 'origin_not_allowed'], 403);
  }
}

function shell_exec_available(): bool {
  if (!function_exists('exec')) return false;
  $disabled = array_map('trim', explode(',', (string)ini_get('disable_functions')));
  return !in_array('exec', $disabled, true);
}

function shell_run(string $command, ?int &$exitCode = null): string {
  if (!shell_exec_available()) {
    throw new RuntimeException('exec_unavailable');
  }
  $output = [];
  $code = 0;
  exec($command . ' 2>&1', $output, $code);
  $exitCode = $code;
  return trim(implode("\n", $output));
}

function git_resolve_binary(): string {
  // Cache: PHP-FPM may have a stripped PATH (no /usr/local/bin), so a bare
  // `git` in shell_exec returns 127. Try the standard install locations and
  // memoise the first one that exists; fall back to bare `git` so any
  // environment that DOES have it on PATH still works.
  static $resolved = null;
  if ($resolved !== null) return $resolved;
  $candidates = [
    '/usr/bin/git',
    '/usr/local/bin/git',
    '/opt/homebrew/bin/git',
    '/opt/local/bin/git',
  ];
  foreach ($candidates as $path) {
    if (is_file($path) && is_executable($path)) {
      return $resolved = $path;
    }
  }
  return $resolved = 'git';
}

function git_shell_command(string $repoDir, array $args): string {
  $safeDirectories = array_values(array_unique(array_filter([
    str_replace('\\', '/', trim($repoDir)),
    (($real = realpath($repoDir)) !== false) ? str_replace('\\', '/', $real) : '',
  ], static fn($value) => is_string($value) && $value !== '')));
  $parts = [
    'GIT_TERMINAL_PROMPT=0',
    'GIT_SSH_COMMAND=' . escapeshellarg('ssh -oBatchMode=yes'),
    escapeshellarg(git_resolve_binary()),
  ];
  foreach ($safeDirectories as $safeDirectory) {
    $parts[] = '-c';
    $parts[] = escapeshellarg('safe.directory=' . $safeDirectory);
  }
  $parts[] = '-C';
  $parts[] = escapeshellarg($repoDir);
  foreach ($args as $arg) {
    $parts[] = escapeshellarg((string)$arg);
  }
  return implode(' ', $parts);
}

function git_command(array $args, string $repoDir, ?int &$exitCode = null): string {
  return shell_run(git_shell_command($repoDir, $args), $exitCode);
}

function split_nonempty_lines(string $text): array {
  $lines = preg_split("/\r\n|\n|\r/", trim($text));
  if (!is_array($lines)) return [];
  return array_values(array_filter(array_map('trim', $lines), static fn($line) => $line !== ''));
}

function git_status_entry_path(string $line): string {
  $raw = trim(substr($line, 3));
  if ($raw === '') return '';
  if (str_contains($raw, ' -> ')) {
    $parts = explode(' -> ', $raw);
    $raw = (string)end($parts);
  }
  $raw = trim($raw);
  if ($raw !== '' && $raw[0] === '"' && substr($raw, -1) === '"') {
    $raw = stripcslashes(substr($raw, 1, -1));
  }
  return str_replace('\\', '/', $raw);
}

function git_qms_data_relative_path(string $path): string {
  $p = ltrim(str_replace('\\', '/', trim($path)), '/');
  if ($p === '') return '';
  $marker = 'data/';
  $pos = strpos($p, $marker);
  if ($pos !== false) {
    return substr($p, $pos);
  }
  return $p;
}

function git_is_runtime_noise_path(string $path): bool {
  $p = git_qms_data_relative_path($path);
  if ($p === '') return false;
  if ($p === 'data/config/users.json') return true;
  if ($p === 'data/audit.log') return true;
  if ($p === 'data/php_error.log') return true;
  if ($p === 'data/scan_cache.json') return true;
  if (str_starts_with($p, 'data/sessions/')) {
    return basename($p) !== 'README.md';
  }
  if (str_starts_with($p, 'data/ratelimit/')) {
    return basename($p) !== 'README.md';
  }
  if (str_starts_with($p, 'data/allocations/')) {
    return !in_array(basename($p), ['.htaccess', 'README.md'], true);
  }
  if (str_starts_with($p, 'data/counters/')) {
    return !in_array(basename($p), ['_registry.json', '.htaccess', 'README.md'], true);
  }
  if (str_starts_with($p, 'data/online-forms/drafts/')) {
    return !in_array(basename($p), ['.htaccess', 'README.md'], true);
  }
  if (str_starts_with($p, 'data/online-forms/audit/')) {
    return !in_array(basename($p), ['.htaccess', 'README.md'], true);
  }
  if (str_starts_with($p, 'data/form-workflow/')) return true;
  return false;
}

function git_is_presync_telemetry_path(string $path): bool {
  $p = git_qms_data_relative_path($path);
  if ($p === '') return false;
  if (str_starts_with($p, 'data/runtime-shadow/')) return true;
  return (bool)preg_match('#^data/audit/audit_\d{4}-\d{2}\.jsonl$#', $p);
}

function git_filter_non_runtime_status_lines(array $statusLines, bool $excludePresyncTelemetry = false): array {
  $kept = [];
  foreach ($statusLines as $line) {
    if (!is_string($line) || trim($line) === '') continue;
    $path = git_status_entry_path($line);
    if (git_is_runtime_noise_path($path)) continue;
    if ($excludePresyncTelemetry && git_is_presync_telemetry_path($path)) continue;
    $kept[] = $line;
  }
  return $kept;
}

function git_collect_paths_from_status_lines(array $statusLines): array {
  $paths = [];
  foreach ($statusLines as $line) {
    if (!is_string($line) || trim($line) === '') continue;
    $path = git_status_entry_path($line);
    if ($path !== '') $paths[] = $path;
  }
  return array_values(array_unique($paths));
}

function git_head_commit(string $repoReal, string $ref = 'HEAD'): string {
  $code = 0;
  $out = trim((string)git_command(['rev-parse', $ref], $repoReal, $code));
  return $code === 0 ? $out : '';
}

function git_commit_overview(string $repoReal, string $ref = 'HEAD'): array {
  $code = 0;
  $out = trim((string)git_command([
    'show',
    '-s',
    '--format=%H%x1f%h%x1f%s%x1f%an%x1f%ae%x1f%cI',
    $ref
  ], $repoReal, $code));
  if ($code !== 0 || $out === '') {
    return [
      'hash' => '',
      'short_hash' => '',
      'subject' => '',
      'author_name' => '',
      'author_email' => '',
      'committed_at' => '',
    ];
  }
  $parts = explode("\x1f", $out);
  return [
    'hash' => (string)($parts[0] ?? ''),
    'short_hash' => (string)($parts[1] ?? ''),
    'subject' => (string)($parts[2] ?? ''),
    'author_name' => (string)($parts[3] ?? ''),
    'author_email' => (string)($parts[4] ?? ''),
    'committed_at' => (string)($parts[5] ?? ''),
  ];
}

function git_remote_url(string $repoReal, string $remote = 'origin'): string {
  $code = 0;
  $out = trim((string)git_command(['config', '--get', 'remote.' . $remote . '.url'], $repoReal, $code));
  return $code === 0 ? $out : '';
}

function git_repository_status(string $repoDir, bool $fetchRemote = false): array {
  $repoReal = realpath($repoDir);
  if ($repoReal === false || !is_dir($repoReal)) {
    throw new RuntimeException('repo_not_found');
  }

  $checkCode = 0;
  $checkOut = git_command(['rev-parse', '--is-inside-work-tree'], $repoReal, $checkCode);
  if ($checkCode !== 0 || trim($checkOut) !== 'true') {
    throw new RuntimeException('not_a_git_repo');
  }

  $branchCode = 0;
  $branch = trim((string)git_command(['branch', '--show-current'], $repoReal, $branchCode));
  if ($branchCode !== 0 || $branch === '') $branch = 'main';
  $remoteBranch = 'origin/' . $branch;
  $remoteUrl = git_remote_url($repoReal);

  // The status panel never writes to .git/. We use `git ls-remote` (network
  // read-only — it stores nothing inside .git) to learn the live origin tip,
  // so PHP-FPM does not need write permission on .git/FETCH_HEAD or
  // .git/objects. This keeps the deploy user as the only writer of the repo.
  $remoteOriginHash = '';
  $fetchError = '';
  if ($fetchRemote && $remoteUrl !== '' && $branch !== '') {
    $lsRemoteCode = 0;
    $lsRemoteOut = git_command(['ls-remote', '--heads', 'origin', $branch], $repoReal, $lsRemoteCode);
    if ($lsRemoteCode !== 0) {
      $fetchError = 'git_lsremote_failed' . ($lsRemoteOut !== '' ? ': ' . $lsRemoteOut : '');
    } else {
      $firstLine = strtok($lsRemoteOut, "\n");
      if (is_string($firstLine) && preg_match('/^([0-9a-f]{40})\s/', $firstLine, $m)) {
        $remoteOriginHash = $m[1];
      }
    }
  }

  $head = git_commit_overview($repoReal, 'HEAD');

  // Prefer the live origin tip discovered via ls-remote, but only if its
  // commit object actually lives in the local repo. Otherwise fall back to
  // the cached origin/<branch> ref so ahead/behind counts still mean
  // something — they may be slightly stale until the next deploy fetch.
  $remoteHashForCompare = $remoteBranch;
  $remoteRefStale = false;
  if ($remoteOriginHash !== '') {
    $existsCode = 0;
    git_command(['cat-file', '-e', $remoteOriginHash . '^{commit}'], $repoReal, $existsCode);
    if ($existsCode === 0) {
      $remoteHashForCompare = $remoteOriginHash;
    } else {
      // Live origin has commits the local repo has not fetched yet.
      $remoteRefStale = true;
    }
  }
  $remoteHead = git_commit_overview($repoReal, $remoteHashForCompare);

  $aheadCount = 0;
  $behindCount = 0;
  if ((string)($remoteHead['hash'] ?? '') !== '') {
    $aheadCode = 0;
    $aheadOut = git_command(['rev-list', '--count', $remoteHashForCompare . '..' . $branch], $repoReal, $aheadCode);
    if ($aheadCode === 0) $aheadCount = (int)trim($aheadOut);

    $behindCode = 0;
    $behindOut = git_command(['rev-list', '--count', $branch . '..' . $remoteHashForCompare], $repoReal, $behindCode);
    if ($behindCode === 0) $behindCount = (int)trim($behindOut);
  }

  $statusCode = 0;
  $statusOut = git_command(['status', '--porcelain', '--untracked-files=all'], $repoReal, $statusCode);
  if ($statusCode !== 0) {
    throw new RuntimeException('git_status_failed');
  }
  $statusLines = split_nonempty_lines($statusOut);
  $meaningfulLines = git_filter_non_runtime_status_lines($statusLines, true);
  $meaningfulEntries = git_parse_status_entries($meaningfulLines);
  $meaningfulPaths = git_collect_paths_from_status_lines($meaningfulLines);

  return [
    'repo_path' => str_replace('\\', '/', $repoReal),
    'remote_url' => $remoteUrl,
    'branch' => $branch,
    'remote_branch' => $remoteBranch,
    'head' => $head,
    'remote_head' => $remoteHead,
    'ahead_count' => $aheadCount,
    'behind_count' => $behindCount,
    'working_tree_clean' => empty($meaningfulLines),
    'meaningful_dirty_count' => count($meaningfulEntries),
    'meaningful_dirty_paths' => $meaningfulPaths,
    'meaningful_dirty_entries' => $meaningfulEntries,
    'remote_origin_hash' => $remoteOriginHash,
    'remote_ref_stale' => $remoteRefStale,
    'fetch_error' => $fetchError,
  ];
}

function git_parse_status_entries(array $statusLines): array {
  $entries = [];
  foreach ($statusLines as $line) {
    if (!is_string($line) || strlen($line) < 3) continue;
    $path = git_status_entry_path($line);
    if ($path === '') continue;
    $entries[] = [
      'xy' => substr($line, 0, 2),
      'path' => $path,
    ];
  }
  return $entries;
}

// ---------- Rate limit (simple) ----------
function rate_limit_check(string $key, int $maxHits, int $windowSec, string $rlDir): void {
  ensure_dir($rlDir);
  $file = $rlDir . '/' . preg_replace('/[^a-zA-Z0-9_\-\.]/', '_', $key) . '.json';
  $t = time();

  $state = ['start' => $t, 'hits' => 0];
  if (is_file($file)) {
    $raw = @file_get_contents($file);
    $tmp = json_decode((string)$raw, true);
    if (is_array($tmp) && isset($tmp['start'], $tmp['hits'])) $state = $tmp;
  }

  if (($t - (int)$state['start']) >= $windowSec) {
    $state = ['start' => $t, 'hits' => 0];
  }
  $state['hits'] = (int)$state['hits'] + 1;

  @file_put_contents($file, json_encode($state), LOCK_EX);

  if ((int)$state['hits'] > $maxHits) {
    $retryAfter = max(1, (int)$windowSec - ((int)$t - (int)$state['start']));
    http_response_code(429);
    header('Retry-After: ' . $retryAfter);
    api_json(['ok' => false, 'error' => 'rate_limited', 'retry_after' => $retryAfter], 429);
  }
}

// ---------- Users store ----------
function users_load(string $usersFile): ?array {
  if (!is_file($usersFile)) return null;
  $raw = @file_get_contents($usersFile);
  if ($raw === false) return null;
  $data = json_decode($raw, true);
  return is_array($data) ? $data : null;
}

function users_save(string $usersFile, array $store): void {
  $dir = dirname($usersFile);
  ensure_dir($dir);

  // Self-heal: if the file exists but is not writable by the current process,
  // attempt to restore group-writable permissions (works when process owns the file
  // or has CAP_DAC_OVERRIDE; silently ignored otherwise).
  if (is_file($usersFile) && !is_writable($usersFile)) {
    @chmod($usersFile, 0664);
  }

  $json = json_encode($store, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);
  if ($json === false) {
    throw new RuntimeException(
      'Cannot JSON-encode user store (json_last_error=' . json_last_error() . ' ' . json_last_error_msg() . ')'
    );
  }

  // Prefer atomic write (tmp + rename). Some hosts may block rename() across
  // file systems; fall back to direct write in that case.
  $tmp = $usersFile . '.tmp';

  // Clean up any orphaned .tmp left by a previous failed write.
  if (is_file($tmp) && !@unlink($tmp)) {
    @chmod($tmp, 0664);
    @unlink($tmp);
  }

  $wroteTmp = false;
  try {
    $wroteTmp = @file_put_contents($tmp, $json, LOCK_EX);
  } catch (Throwable $e) {
    $wroteTmp = false;
  }

  if ($wroteTmp === false) {
    $dirInfo = sprintf('dir_writable=%s file_writable=%s owner=%s euid=%s',
      is_writable($dir) ? 'yes' : 'no',
      is_file($usersFile) ? (is_writable($usersFile) ? 'yes' : 'no') : 'new',
      (string)(@fileowner($usersFile) ?: @fileowner($dir) ?: '?'),
      function_exists('posix_geteuid') ? (string)@posix_geteuid() : '?'
    );
    try {
      $wrote = @file_put_contents($usersFile, $json, LOCK_EX);
    } catch (Throwable $e) {
      $wrote = false;
    }
    if ($wrote === false) {
      throw new RuntimeException(
        'Cannot write users file (' . $dirInfo . '). Path: ' . $usersFile
      );
    }
    @chmod($usersFile, 0664);
    return;
  }

  $renamed = false;
  try {
    $renamed = @rename($tmp, $usersFile);
  } catch (Throwable $e) {
    $renamed = false;
  }

  if (!$renamed) {
    // Fallback: direct write / copy
    try {
      $wrote = @file_put_contents($usersFile, $json, LOCK_EX);
    } catch (Throwable $e) {
      $wrote = false;
    }
    if ($wrote === false) {
      $copied = false;
      try {
        $copied = @copy($tmp, $usersFile);
      } catch (Throwable $e) {
        $copied = false;
      }
      if (!$copied) {
        @unlink($tmp);
        throw new RuntimeException(
          'Cannot replace users file (rename+copy both failed). Path: ' . $usersFile
        );
      }
    }
    @unlink($tmp);
  }

  @chmod($usersFile, 0664);
}

function invalidate_scan_cache(string $dataDir): void {
  $cacheFile = $dataDir . '/scan_cache.json';
  if (is_file($cacheFile)) {
    @unlink($cacheFile);
  }
}

function filename_matches_doc_code(string $filename, string $code): bool {
  $expected = strtoupper(trim($code));
  if ($expected === '') return false;
  if (scan_extract_code($filename) === $expected) return true;

  $stem = strtolower(pathinfo($filename, PATHINFO_FILENAME));
  $slug = slugify($expected);
  if ($slug === '') return false;

  return $stem === $slug || str_starts_with($stem, $slug . '-');
}

function find_user_by_username(array $store, string $username): ?array {
  $u = strtolower(trim($username));
  foreach (($store['users'] ?? []) as $user) {
    if (is_array($user) && strtolower((string)($user['username'] ?? '')) === $u) return $user;
  }
  return null;
}

function update_user(array &$store, array $newUser): void {
  $u = strtolower((string)($newUser['username'] ?? ''));
  $users = $store['users'] ?? [];
  foreach ($users as $i => $user) {
    if (is_array($user) && strtolower((string)($user['username'] ?? '')) === $u) {
      $users[$i] = $newUser;
      $store['users'] = $users;
      return;
    }
  }
  $users[] = $newUser;
  $store['users'] = $users;
}

// ---------- Base32 + TOTP ----------
function base32_charset(): string { return 'ABCDEFGHIJKLMNOPQRSTUVWXYZ234567'; }

function base32_encode(string $bin): string {
  $alphabet = base32_charset();
  $bits = '';
  for ($i=0; $i<strlen($bin); $i++) {
    $bits .= str_pad(decbin(ord($bin[$i])), 8, '0', STR_PAD_LEFT);
  }
  $out = '';
  for ($i=0; $i<strlen($bits); $i += 5) {
    $chunk = substr($bits, $i, 5);
    if (strlen($chunk) < 5) $chunk = str_pad($chunk, 5, '0', STR_PAD_RIGHT);
    $out .= $alphabet[bindec($chunk)];
  }
  return $out;
}

function base32_decode(string $b32): string {
  $alphabet = base32_charset();
  $b32 = strtoupper(preg_replace('/[^A-Z2-7]/', '', $b32));
  $bits = '';
  for ($i=0; $i<strlen($b32); $i++) {
    $val = strpos($alphabet, $b32[$i]);
    if ($val === false) continue;
    $bits .= str_pad(decbin($val), 5, '0', STR_PAD_LEFT);
  }
  $out = '';
  for ($i=0; $i<strlen($bits); $i += 8) {
    $byte = substr($bits, $i, 8);
    if (strlen($byte) < 8) break;
    $out .= chr(bindec($byte));
  }
  return $out;
}

function hotp(string $secretBin, int $counter, int $digits = 6): string {
  $ctr = pack('N*', 0) . pack('N*', $counter);
  $hash = hash_hmac('sha1', $ctr, $secretBin, true);
  $offset = ord(substr($hash, -1)) & 0x0F;
  $part = substr($hash, $offset, 4);
  $num = unpack('N', $part)[1] & 0x7FFFFFFF;
  $mod = 10 ** $digits;
  return str_pad((string)($num % $mod), $digits, '0', STR_PAD_LEFT);
}

function totp_verify(string $secretB32, string $code, int $window = 1, int $period = 30, int $digits = 6): bool {
  $code = preg_replace('/\D/', '', $code);
  if ($code === '' || strlen($code) !== $digits) return false;
  $secretBin = base32_decode($secretB32);
  if ($secretBin === '') return false;

  $t = time();
  $counter = intdiv($t, $period);

  for ($i = -$window; $i <= $window; $i++) {
    $cand = hotp($secretBin, $counter + $i, $digits);
    if (hash_equals($cand, $code)) return true;
  }
  return false;
}

function otpauth_url(string $issuer, string $account, string $secretB32): string {
  // For maximum Authenticator compatibility: encode issuer/account separately and KEEP the ":" unescaped.
  $issuerEnc  = rawurlencode($issuer);
  $accountEnc = rawurlencode($account);
  $label = $issuerEnc . ':' . $accountEnc;
  return "otpauth://totp/{$label}?secret={$secretB32}&issuer={$issuerEnc}&algorithm=SHA1&digits=6&period=30";
}

/**
 * Mask a Vietnamese CCCD/CMND value, showing only the last 4 digits.
 *
 * CCCD is the Vietnamese national identification number — 12 digits, highly
 * sensitive PII under Decree 13/2023. Showing the full value to non-privileged
 * viewers is a data-protection violation. This helper returns the form
 * "••••••••1234" (8 bullets + last 4 digits).
 *
 * Returns the unmasked value if it's shorter than 5 chars (cannot meaningfully
 * mask) or empty.
 */
function mask_cccd(string $cccd): string {
  $clean = trim($cccd);
  if ($clean === '' || strlen($clean) < 5) return $clean;
  return str_repeat('•', max(0, strlen($clean) - 4)) . substr($clean, -4);
}

/**
 * Decide whether the viewing context is privileged enough to see full PII.
 *
 * Returns true if the viewer is an admin role OR is looking at their own
 * profile. Returns false (= mask PII) otherwise. Called by
 * sanitize_user_for_client() to gate cccd / phone / personal_email exposure.
 *
 * Phase 0 security hardening per .ai/USER_IDENTITY_SSOT.md — replaces the
 * earlier "always send full CCCD to client" behavior which leaked every
 * employee's national ID to anyone with a session.
 */
function viewer_may_see_full_pii(?array $viewer, array $target): bool {
  if (!is_array($viewer)) return false;
  $viewerRole = strtolower(trim((string)($viewer['role'] ?? '')));
  if (in_array($viewerRole, admin_roles(), true)) return true;
  // HR manager handles PII as part of their job per role definition in ROLES.
  if ($viewerRole === 'hr_manager') return true;
  // Viewing your own profile — you may always see your own PII.
  $viewerUsername = strtolower(trim((string)($viewer['username'] ?? '')));
  $targetUsername = strtolower(trim((string)($target['username'] ?? '')));
  if ($viewerUsername !== '' && $viewerUsername === $targetUsername) return true;
  return false;
}

function sanitize_user_for_client(array $user, ?array $viewer = null): array {
  // Backwards compat: if no viewer is passed, fall back to the current session
  // user. This lets every existing caller keep working without parameter changes.
  // We use the lightweight $_SESSION['user'] lookup (username) and reconstruct
  // a {username, role} dict — that's all viewer_may_see_full_pii() needs.
  if ($viewer === null && !empty($_SESSION['user'])) {
    $sessUsername = strtolower(trim((string)$_SESSION['user']));
    // If we're sanitizing the same user as the session, we can short-circuit
    // — they're looking at their own profile and qualify for full PII.
    if ($sessUsername === strtolower(trim((string)($user['username'] ?? '')))) {
      $viewer = ['username' => $sessUsername, 'role' => (string)($user['role'] ?? '')];
    } else {
      // Different target: derive the viewer's role from the store. We re-read
      // users.json here because the global $store may not be available in every
      // call path. Cached via static for the duration of the request.
      static $viewerCache = [];
      if (!array_key_exists($sessUsername, $viewerCache)) {
        global $USERS_FILE;
        $viewerRole = '';
        try {
          if ($USERS_FILE && is_file($USERS_FILE)) {
            $raw = json_decode((string)file_get_contents($USERS_FILE), true);
            foreach ((is_array($raw['users'] ?? null) ? $raw['users'] : []) as $u) {
              if (is_array($u) && strtolower((string)($u['username'] ?? '')) === $sessUsername) {
                $viewerRole = (string)($u['role'] ?? '');
                break;
              }
            }
          }
        } catch (\Throwable $e) { /* fail closed: no role → mask PII */ }
        $viewerCache[$sessUsername] = ['username' => $sessUsername, 'role' => $viewerRole];
      }
      $viewer = $viewerCache[$sessUsername];
    }
  }
  $fullPii = viewer_may_see_full_pii($viewer, $user);
  // Decrypt-on-read for PII fields stored encrypted at rest (Phase 0 hardening
  // via PiiCryptoService). Legacy plaintext values pass through unchanged.
  $cccdRaw = \MOM\Api\Services\PiiCryptoService::decrypt((string)($user['cccd'] ?? ''));
  $phoneRaw = (string)($user['phone'] ?? '');
  $emailRaw = (string)($user['personal_email'] ?? '');
  return [
    'employee_id' => (string)($user['employee_id'] ?? ''),
    'username' => (string)($user['username'] ?? ''),
    'active'   => (bool)($user['active'] ?? true),
    'role'     => (string)($user['role'] ?? 'user'),
    'name'     => (string)($user['name'] ?? ''),
    'dept'     => (string)($user['dept'] ?? ''),
    'title'    => (string)($user['title'] ?? ''),
    'avatar'   => (string)($user['avatar'] ?? ''),
    'avatar_icon' => (string)($user['avatar_icon'] ?? ($user['avatar'] ?? '')),
    'avatar_image' => (string)($user['avatar_image'] ?? ''),
    'avatar_url' => (string)($user['avatar_url'] ?? ''),
    'jd_code'  => (string)($user['jd_code'] ?? ''),
    'jd_title' => (string)($user['jd_title'] ?? ''),
    'role_source' => is_array($user['role_source'] ?? null) ? (array)$user['role_source'] : new stdClass(),
    'hcm_org_unit_id' => (string)($user['hcm_org_unit_id'] ?? ''),
    'hcm_position_id' => (string)($user['hcm_position_id'] ?? ''),
    'cccd'     => $fullPii ? $cccdRaw : mask_cccd($cccdRaw),
    'cccd_last4' => $cccdRaw !== '' ? substr($cccdRaw, -4) : '',
    'cccd_masked' => !$fullPii,
    'phone'    => $fullPii ? $phoneRaw : mask_cccd($phoneRaw),  // same masking shape
    'personal_email' => $fullPii ? $emailRaw : '',
    'org_company_code' => (string)($user['org_company_code'] ?? ''),
    'org_legal_entity_code' => (string)($user['org_legal_entity_code'] ?? ''),
    'org_plant_id' => (string)($user['org_plant_id'] ?? ''),
    'org_site_id' => (string)($user['org_site_id'] ?? ''),
    'mfa'      => ['enabled' => (bool)(($user['mfa']['enabled'] ?? false))],
    'portal_language' => (string)($user['portal_language'] ?? 'vi'),
    'updated_at' => (string)($user['updated_at'] ?? ''),
    'created_at' => (string)($user['created_at'] ?? ''),
    // Phase 0.5 / 0.8 advisory flags — set in-memory by auth_login when the
    // admin is non-compliant in soft mode. Exposed so the portal can show
    // a banner urging the user to enroll MFA / change password.
    'admin_mfa_advisory' => (bool)($user['_admin_mfa_advisory'] ?? false),
    'password_expired_advisory' => (bool)($user['_password_expired_advisory'] ?? false),
  ];
}

function random_password(int $len = 12): string {
  // Policy-friendly password generator (meets password_policy):
  // - at least 10 chars
  // - includes lower/upper/number/symbol
  // Avoid ambiguous characters (O/0, I/1, l/1)
  if ($len < 10) $len = 10;

  $upper = 'ABCDEFGHJKLMNPQRSTUVWXYZ';
  $lower = 'abcdefghijkmnopqrstuvwxyz';
  $digits = '23456789';
  $symbols = '!@#$%^&*_-+=?';
  $all = $upper . $lower . $digits . $symbols;

  $pw = [];
  $pw[] = $upper[random_int(0, strlen($upper) - 1)];
  $pw[] = $lower[random_int(0, strlen($lower) - 1)];
  $pw[] = $digits[random_int(0, strlen($digits) - 1)];
  $pw[] = $symbols[random_int(0, strlen($symbols) - 1)];

  for ($i = 4; $i < $len; $i++) {
    $pw[] = $all[random_int(0, strlen($all) - 1)];
  }

  // Fisher–Yates shuffle
  for ($i = count($pw) - 1; $i > 0; $i--) {
    $j = random_int(0, $i);
    $tmp = $pw[$i];
    $pw[$i] = $pw[$j];
    $pw[$j] = $tmp;
  }

  return implode('', $pw);
}




// ---------- Guard for api/index.php MVC bootstrap ----------
// When api/index.php loads this file, it only needs the helper functions above.
// The constant API_HELPERS_ONLY prevents executing the boot + switch below.
if (defined('API_HELPERS_ONLY')) {
    return;
}

// ---------- Boot ----------
ensure_dir($DATA_DIR);
migrate_legacy_data_dir($LEGACY_DATA_DIR, $DATA_DIR, true);
if ($DATA_DIR === normalize_runtime_dir($LEGACY_DATA_DIR) && is_dir($LEGACY_COMPAT_DATA_DIR)) {
  migrate_legacy_data_dir($LEGACY_COMPAT_DATA_DIR, $DATA_DIR, true);
}
ensure_dir($CONF_DIR);
ensure_dir($RL_DIR);
session_init();

$action = (string)($_GET['action'] ?? ($_POST['action'] ?? ''));
$method = $_SERVER['REQUEST_METHOD'] ?? 'GET';
$store = users_load($USERS_FILE);

// Normalize action aliases
$action = match ($action) {
  'auth_status' => 'status',
  'login' => 'auth_login',
  'mfa_verify', 'verify' => 'auth_mfa_verify',
  'enroll_verify', 'enroll' => 'auth_enroll_verify',
  'logout' => 'auth_logout',
  default => $action
};

// ── Global user-activity audit hook ────────────────────────────────────────
// Records ALL authenticated API actions so every user's activity appears in
// the admin "Kiểm soát hành vi" tab — not just the 4 admin-specific actions
// that previously called portal_legacy_admin_audit_log explicitly.
// Actions that have dedicated detailed audit handlers are excluded to avoid
// duplicate entries with empty payload (they log richer context themselves).
(static function () use ($action, $method): void {
    static $skip = [
        '', 'status',
        'auth_login', 'auth_logout', 'auth_mfa_verify', 'auth_enroll_verify',
        'admin_docs_visibility_save', 'admin_portal_display_config_save',
        'admin_module_access_save', 'save_data_settings',
    ];
    if (empty($_SESSION['user']) || in_array($action, $skip, true)) {
        return;
    }
    try {
        runtime_data_layer()->logEvent(
            $action,
            'api_action',
            $action,
            [],
            [
                'actor_name' => strtolower((string)$_SESSION['user']),
                'ip_address'  => (string)($_SERVER['REMOTE_ADDR'] ?? ''),
                'session_id'  => session_status() === PHP_SESSION_ACTIVE ? session_id() : null,
                'metadata'    => ['source' => 'global_api_hook', 'method' => strtoupper($method)],
            ]
        );
    } catch (Throwable $e) {
        @error_log('[api] global_audit_hook failed: ' . $e->getMessage());
    }
})();

// ──────────────────────────────────────────────────────────────────────────
// Authorization kernel bridge for the legacy switch path.
//
// The portal frontend (apiCall in 02-state-auth-ui.js) sends requests to
// `api.php?action=...` which resolves to /mom/api.php directly (NOT
// /api/index.php). That bypasses the MVC Router so kernelized controllers
// like UserController::upsert never execute on this code path.
//
// To preserve the matrix-driven authorization promise without rewriting
// every legacy switch case, we load the AuthorizationKernel up front and
// expose a helper $authz_kernel_check($permission, $context) the affected
// cases call BEFORE the legacy admin_roles() check. The kernel decision is
// authoritative; legacy admin_roles() is now a fallback only when the
// kernel cannot reach the DB (returns null).
//
// Loaded inline so api.php remains self-contained when accessed directly.
$authz_kernel = null;
$authz_kernel_check = static function (string $perm, array $context = []) use (&$authz_kernel, $CONF_DIR, $store) {
    // Lazy-load on first request.
    if ($authz_kernel === false) return; // Tried and failed earlier; skip.
    if ($authz_kernel === null) {
        $autoload = __DIR__ . '/vendor/autoload.php';
        if (!is_file($autoload)) { $authz_kernel = false; return; }
        require_once $autoload;
        if (!class_exists('\\MOM\\Api\\Services\\AuthorizationKernel')) { $authz_kernel = false; return; }
        $authz_kernel = new \MOM\Api\Services\AuthorizationKernel($CONF_DIR);
    }
    $me = require_logged_in($store);
    $d  = $authz_kernel->decide($me, $perm, $context + ['route_action' => 'legacy:' . ($_GET['action'] ?? '')]);
    if ($d->isAllow()) return;
    if ($d->isStepUp()) {
        api_json([
            'ok'           => false,
            'error'        => 'step_up_required',
            'permission'   => $perm,
            'required_aal' => $d->requiredAal,
            'current_aal'  => $d->currentAal,
        ], 401);
    }
    api_json([
        'ok'         => false,
        'error'      => 'forbidden',
        'reason'     => $d->reason,
        'permission' => $perm,
    ], 403);
};

switch ($action) {
  case 'status': {
    $logged = false;
    $mfaPending = false;
    $enrollPending = false;
    $pendingExpiresIn = null;
    $authExpired = null;
    $user = null;
    if (!empty($_SESSION['user']) && is_array($store)) {
      $u = find_user_by_username($store, (string)$_SESSION['user']);
      if ($u) {
        $mfaPending = session_requires_completed_mfa($u, is_array($store['settings'] ?? null) ? $store['settings'] : []) && empty($_SESSION['mfa_ok']);
        if (!$mfaPending) {
          $logged = true;
          $user = sanitize_user_for_client($u);
        }
      }
    }
    $enrollUser = (string)($_SESSION['enroll_user'] ?? '');
    $enrollSecret = (string)($_SESSION['enroll_secret'] ?? '');
    $enrollStarted = (int)($_SESSION['enroll_started'] ?? 0);
    $enrollRemaining = pending_auth_remaining_seconds($enrollStarted);
    if (
      !$logged &&
      $enrollUser !== '' &&
      $enrollSecret !== '' &&
      $enrollRemaining > 0
    ) {
      $settings = is_array($store['settings'] ?? null) ? $store['settings'] : [];
      $issuer = (string)($settings['issuer'] ?? 'HESEM MOM');
      $mfaPending = false;
      $enrollPending = true;
      api_json([
        'ok' => true,
        'logged_in' => false,
        'mfa_pending' => false,
        'enroll_pending' => true,
        'issuer' => $issuer,
        'account' => $enrollUser,
        'username' => $enrollUser,
        'secret' => $enrollSecret,
        'otpauth_url' => otpauth_url($issuer, $enrollUser, $enrollSecret),
        'user' => null,
        'csrf_token' => csrf_token(),
        'pending_expires_in' => $enrollRemaining,
        'auth_expired' => null,
        'server_time' => now_iso(),
        'initialized' => is_array($store),
      ]);
    }
    if (!$logged && ($enrollUser !== '' || $enrollSecret !== '' || $enrollStarted > 0) && !$enrollPending) {
      clear_pending_auth_session_state();
      $authExpired = 'enroll';
      $enrollUser = '';
      $enrollSecret = '';
      $enrollStarted = 0;
    }
    $preauthUser = (string)($_SESSION['preauth_user'] ?? '');
    $preauthStarted = (int)($_SESSION['preauth_started'] ?? 0);
    $preauthRemaining = pending_auth_remaining_seconds($preauthStarted);
    if (!$logged && !$enrollPending && $preauthUser !== '' && $preauthRemaining <= 0) {
      clear_pending_auth_session_state();
      $authExpired = $authExpired ?: 'mfa';
      $preauthUser = '';
      $preauthStarted = 0;
    }
    if (!$logged && !$enrollPending && $preauthUser !== '' && is_array($store)) {
      $u = find_user_by_username($store, $preauthUser);
      if ($u && session_requires_completed_mfa($u, is_array($store['settings'] ?? null) ? $store['settings'] : []) && empty($_SESSION['mfa_ok'])) {
        $mfaPending = true;
        $pendingExpiresIn = $preauthRemaining > 0 ? $preauthRemaining : null;
      }
    }
    api_json([
      'ok' => true,
      'logged_in' => (bool)$logged,
      'mfa_pending' => (bool)$mfaPending,
      'enroll_pending' => (bool)$enrollPending,
      'pending_expires_in' => $pendingExpiresIn,
      'auth_expired' => $authExpired,
      'user' => $user,
      'csrf_token' => csrf_token(),
      'server_time' => now_iso(),
      'initialized' => is_array($store),
    ]);
  }



