    if (!$requireMfa) {
      set_authenticated_session($username, $user);
      $user['last_login'] = now_iso();
      $user['updated_at'] = now_iso();
      update_user($store, $user);
      try { users_save($USERS_FILE, $store); } catch (Throwable $e) {}
      portal_audit_session_event('user_login', $username, ['mfa' => false]);
      api_json([
        'ok' => true,
        'logged_in' => true,
        'user' => sanitize_user_for_client($user),
        'csrf_token' => csrf_token(),
      ]);
    }

    if ($mfaEnabled) {
  $secretB32 = (string)($mfa['secret_b32'] ?? '');

  // If client already supplies OTP in the same login call, verify and finish login (no separate verify call needed)
  if ($code !== '') {
    if ($secretB32 === '' || !totp_verify($secretB32, $code, 1, 30, 6)) {
      api_json(['ok' => false, 'error' => 'invalid_code'], 401);
    }

    set_authenticated_session($username, $user);

    $user['last_login'] = now_iso();
    $user['updated_at'] = now_iso();
    update_user($store, $user);
    try{
      users_save($USERS_FILE, $store);
    }catch(Throwable $e){
      // Non-blocking: auth succeeded; last_login write is best-effort.
      @error_log('[API] auth_login(inline-otp): last_login write failed for "' . $username . '": ' . $e->getMessage());
    }

    portal_audit_session_event('user_login', $username, ['mfa' => true, 'inline_otp' => true]);
    api_json([
      'ok' => true,
      'logged_in' => true,
      'user' => sanitize_user_for_client($user),
      'csrf_token' => csrf_token(),
    ]);
  }

  set_preauth_session($username);
  api_json([
    'ok' => true,
    'mfa_required' => true,
    'enroll_required' => false,
    'message' => 'Enter your authenticator code',
    'pending_expires_in' => pending_auth_ttl_seconds(),
    'csrf_token' => csrf_token(),
  ]);
}


    if ($requireMfa) {
      set_preauth_session($username);
      $secretBin = random_bytes(20);
      $secretB32 = base32_encode($secretBin);

      $_SESSION['enroll_user'] = $username;
      $_SESSION['enroll_secret'] = $secretB32;
      $_SESSION['enroll_started'] = time();

      $issuer = (string)($settings['issuer'] ?? 'HESEM MOM');

