  case 'online_form_submit': {
    if ($method !== 'POST') api_json(['ok' => false, 'error' => 'method_not_allowed'], 405);
    require_logged_in($store);
    require_csrf();
    $input = json_decode(file_get_contents('php://input'), true);
    if (!$input || empty($input['form_code']) || empty($input['data'])) {
      api_json(['ok' => false, 'error' => 'invalid_payload'], 400);
    }
    $form = require_existing_online_form((string)$input['form_code']);
    $code = (string)$form['code'];
    $data = $input['data'];
    $status = (string)($input['status'] ?? 'submitted');
    $entriesDir = $DATA_DIR . '/online-forms/entries';
    if (!is_dir($entriesDir)) @mkdir($entriesDir, 0755, true);
    $entryFile = $entriesDir . '/' . $code . '.json';
    $existing = [];
    if (file_exists($entryFile)) {
      $raw = @file_get_contents($entryFile);
      $existing = $raw ? json_decode($raw, true) : [];
      if (!is_array($existing)) $existing = [];
    }
    $legacyEntryId = trim((string)($data['entry_id'] ?? ''));
    $legacySourceEntryId = trim((string)($data['source_entry_id'] ?? ''));
    $legacyAllocationId = trim((string)($data['allocation_id'] ?? $input['allocation_id'] ?? ''));
    $legacyPreviousIdx = $legacySourceEntryId !== ''
      ? find_online_form_entry_index($existing, $legacySourceEntryId, '')
      : find_online_form_entry_index($existing, $legacyEntryId, $legacyAllocationId);
    $legacyPrevious = $legacyPreviousIdx >= 0 && is_array($existing[$legacyPreviousIdx] ?? null) ? $existing[$legacyPreviousIdx] : null;
    $legacyPreviousState = $legacyPrevious ? eqms_entry_workflow_state($legacyPrevious) : '';
    if ($legacyPrevious && eqms_is_locked_workflow_state($legacyPreviousState)) {
      $legacyChangeAuthorityId = eqms_change_authority_from_payload($data);
      $legacyAmendmentReason = trim((string)($data['amendment_reason'] ?? ''));
      if (!eqms_change_authority_format_valid($legacyChangeAuthorityId)) {
        api_json([
          'ok' => false,
          'error' => 'change_authority_required',
          'message' => 'Final/submitted records cannot be overwritten directly. Create an amendment with a valid released change authority.',
          'allowed_action' => 'create_amendment',
          'locked_state' => $legacyPreviousState,
        ], 409);
      }
      if ($legacyAmendmentReason === '') {
        api_json(['ok' => false, 'error' => 'amendment_reason_required'], 422);
      }
      $authorityCheck = eqms_assert_online_form_change_authority($code, $legacyPrevious, $data, $legacyChangeAuthorityId);
      if (!($authorityCheck['ok'] ?? false)) {
        api_json([
          'ok' => false,
          'error' => (string)($authorityCheck['error'] ?? 'change_authority_required'),
          'message' => (string)($authorityCheck['message'] ?? 'Change authority does not cover this amendment.'),
          'field_path' => (string)($authorityCheck['field_path'] ?? ''),
          'decisions' => $authorityCheck['decisions'] ?? [],
          'allowed_action' => 'create_amendment_with_released_change_order',
          'locked_state' => $legacyPreviousState,
        ], 409);
      }
      $data['source_entry_id'] = (string)($legacyPrevious['entry_id'] ?? $legacySourceEntryId);
      $data['source_submission_revision'] = (int)($legacyPrevious['submission_revision'] ?? 0);
      $data['entry_id'] = eqms_new_amendment_entry_id($code);
      $data['edit_origin'] = 'amendment';
      $data['change_authority_id'] = $legacyChangeAuthorityId;
      $data['amendment_reason'] = $legacyAmendmentReason;
      $data['change_authority_decisions'] = $authorityCheck['decisions'] ?? [];
    } elseif ($legacyEntryId === '') {
      $data['entry_id'] = $code . '-' . date('YmdHis') . '-' . substr(bin2hex(random_bytes(4)), 0, 8);
    }
    // Add server-side metadata
    $legacyServerTime = now_iso();
    $legacyUsername = strtolower(trim((string)($_SESSION['user'] ?? 'anonymous')));
    if (($data['edit_origin'] ?? '') === 'amendment') {
      $data['version_created_at'] = $legacyServerTime;
      $data['version_created_by'] = $legacyUsername;
      if ($legacyPrevious) {
        $data['source_created_at'] = (string)($legacyPrevious['created_at'] ?? '');
        $data['source_created_by'] = (string)($legacyPrevious['created_by'] ?? '');
      }
    }
    $data['_server_time'] = $legacyServerTime;
    $data['_status'] = $status;
    $data['_ip'] = $_SERVER['REMOTE_ADDR'] ?? '';
    if (!empty($_SESSION['user'])) $data['_session_user'] = (string)$_SESSION['user'];
    array_unshift($existing, $data);
    // Keep max 1000 entries per form
    if (count($existing) > 1000) $existing = array_slice($existing, 0, 1000);
    file_put_contents($entryFile, json_encode($existing, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE), LOCK_EX);

    // ── G2 P1-01: Auto-link evidence to order context on form submit ──
    $ofsAutoLink = null;
    $ofsRecordId = strtoupper(trim((string)($data['record_id'] ?? $data['entry_id'] ?? '')));
    $ofsJobNumber = trim((string)($data['job_number'] ?? $input['job_number'] ?? ''));
    $ofsWorkOrder = trim((string)($data['work_order'] ?? $input['work_order'] ?? ''));
    if ($ofsRecordId !== '' && ($ofsJobNumber !== '' || $ofsWorkOrder !== '')) {
      $ofsOrderType = $ofsWorkOrder !== '' ? 'wo' : 'jo';
      $ofsOrderId   = $ofsWorkOrder !== '' ? $ofsWorkOrder : $ofsJobNumber;
      $ofsOrders = load_orders_store();
      if (find_order_record($ofsOrders, $ofsOrderType, $ofsOrderId)) {
        $ofsDup = false;
        foreach (($ofsOrders['form_links'] ?? []) as $el) {
          if (is_array($el)
              && (string)($el['order_type'] ?? '') === $ofsOrderType
              && (string)($el['order_id'] ?? '') === $ofsOrderId
              && (string)($el['record_id'] ?? '') === $ofsRecordId) {
            $ofsDup = true;
            break;
          }
        }
        if (!$ofsDup) {
          $ofsLink = [
            'link_id'    => 'LINK-' . date('YmdHis') . '-' . substr(md5($ofsOrderType . '|' . $ofsOrderId . '|' . $ofsRecordId), 0, 8),
            'order_id'   => $ofsOrderId,
            'order_type' => $ofsOrderType,
            'record_id'  => $ofsRecordId,
            'form_code'  => $code,
            'status'     => 'linked',
            'auto_linked'=> true,
            'linked_at'  => now_iso(),
            'linked_by'  => (string)($_SESSION['user'] ?? 'system'),
          ];
          $ofsOrders['form_links'][] = $ofsLink;
          save_orders_store($ofsOrders);
          $ofsAutoLink = $ofsLink;
        }
      }
    }

    api_json(['ok' => true, 'entry_id' => $data['entry_id'] ?? '', 'count' => count($existing), 'auto_link' => $ofsAutoLink]);
  }

  case 'online_form_entries': {
    require_logged_in($store);
    $form = require_existing_online_form((string)($_GET['code'] ?? ''));
    $code = (string)$form['code'];
    $entryFile = $DATA_DIR . '/online-forms/entries/' . $code . '.json';
    $entries = [];
    if (file_exists($entryFile)) {
      $raw = @file_get_contents($entryFile);
      $entries = $raw ? json_decode($raw, true) : [];
    }
    api_json(['ok' => true, 'entries' => is_array($entries) ? $entries : []]);
  }

  case 'online_form_entry_get': {
    require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $form = require_existing_online_form((string)($body['form_code'] ?? $_GET['form_code'] ?? ''));
    $code = (string)$form['code'];
    $entryId = trim((string)($body['entry_id'] ?? $_GET['entry_id'] ?? ''));
    $allocationId = trim((string)($body['allocation_id'] ?? $_GET['allocation_id'] ?? ''));
    if ($entryId === '' && $allocationId === '') { api_json(['ok' => false, 'error' => 'missing_entry_selector'], 400); }
    $entries = load_online_form_entries_store($code);
    $entryIndex = find_online_form_entry_index($entries, $entryId, $allocationId);
    if ($entryIndex < 0 || !is_array($entries[$entryIndex] ?? null)) { api_json(['ok' => false, 'error' => 'entry_not_found'], 404); }
    api_json(['ok' => true, 'entry' => $entries[$entryIndex]]);
  }

  case 'eqms_record_registry': {
    $me = require_logged_in($store);
    $formCode = trim((string)($_GET['form_code'] ?? $_POST['form_code'] ?? ''));
    $deliveryMode = trim((string)($_GET['delivery_mode'] ?? $_POST['delivery_mode'] ?? ''));
    $stateFilter = strtolower(trim((string)($_GET['state'] ?? $_POST['state'] ?? '')));
    $search = strtolower(trim((string)($_GET['search'] ?? $_POST['search'] ?? '')));
    $mineOnly = filter_var($_GET['mine_only'] ?? $_POST['mine_only'] ?? false, FILTER_VALIDATE_BOOL);
    $completedOnly = filter_var($_GET['completed_only'] ?? $_POST['completed_only'] ?? false, FILTER_VALIDATE_BOOL);
    $page = max(1, (int)($_GET['page'] ?? $_POST['page'] ?? 1));
    $pageSize = max(1, min(200, (int)($_GET['page_size'] ?? $_POST['page_size'] ?? 50)));

    $allocationStore = load_allocation_store();
    $allocations = array_values((array)($allocationStore['allocations'] ?? []));
    $entryMap = eqms_latest_entries_by_allocation();
    $draftMap = [];
    foreach (list_online_form_drafts() as $draft) {
      if (!is_array($draft)) continue;
      $allocationId = trim((string)($draft['allocation_id'] ?? ''));
      if ($allocationId === '') continue;
      $existing = $draftMap[$allocationId] ?? null;
      $candidateTime = (string)($draft['saved_at'] ?? '');
      $existingTime = is_array($existing) ? (string)($existing['saved_at'] ?? '') : '';
      if (!$existing || $candidateTime >= $existingTime) $draftMap[$allocationId] = $draft;
    }

    $username = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));
    $rows = [];

    foreach ($allocations as $allocation) {
      if (!is_array($allocation)) continue;
      $allocationId = trim((string)($allocation['allocation_id'] ?? ''));
      if ($allocationId === '') continue;
      $entry = is_array($entryMap[$allocationId] ?? null) ? $entryMap[$allocationId] : null;
      $draft = is_array($draftMap[$allocationId] ?? null) ? $draftMap[$allocationId] : null;
      $rowFormCode = trim((string)($allocation['form_code'] ?? ($draft['form_code'] ?? $entry['form_code'] ?? '')));
      $rowDeliveryMode = trim((string)($allocation['delivery_mode'] ?? ''));
      $workflowState = eqms_workflow_status_from_entry($entry, $allocation, $draft);
      $submissionCount = $rowDeliveryMode === 'offline'
        ? max((int)($allocation['receipt_version'] ?? 0), count((array)($allocation['receipts'] ?? [])))
        : max((int)($entry['submission_count'] ?? 0), (int)($entry['submission_revision'] ?? 0), (int)($allocation['online_submission']['submission_count'] ?? 0), (int)($allocation['online_submission']['submission_revision'] ?? 0));
      if ($submissionCount === 0 && ($entry || strtolower(trim((string)($allocation['status'] ?? ''))) === 'submitted')) $submissionCount = 1;
      $resubmissionCount = max(0, $submissionCount - 1);
      $amendmentCount = max((int)($entry['amendment_count'] ?? 0), (int)($allocation['online_submission']['amendment_count'] ?? 0));
      $reopenCount = 0;
      foreach ((array)($allocation['history'] ?? []) as $evt) {
        if (!is_array($evt)) continue;
        $note = strtolower(trim((string)($evt['note'] ?? '')));
        if ($note === 'evidence_reopened' || $note === 'controlled_edit_started') $reopenCount++;
      }
      $latestReceipt = null;
      $receipts = array_values((array)($allocation['receipts'] ?? []));
      if ($receipts) $latestReceipt = $receipts[count($receipts) - 1];
      $lastActionAt = (string)($draft['saved_at'] ?? $entry['updated_at'] ?? $entry['submitted_at'] ?? $allocation['updated_at'] ?? $allocation['created_at'] ?? '');
      if (is_array($latestReceipt) && !empty($latestReceipt['received_at']) && (string)$latestReceipt['received_at'] > $lastActionAt) {
        $lastActionAt = (string)$latestReceipt['received_at'];
      }

      $isMine = in_array($username, array_filter([
        strtolower(trim((string)($allocation['created_by'] ?? ''))),
        strtolower(trim((string)($entry['created_by'] ?? ''))),
        strtolower(trim((string)($entry['submitted_by'] ?? ''))),
        strtolower(trim((string)($draft['saved_by'] ?? ''))),
      ]), true);

      $isCompleted = in_array($workflowState, ['approved', 'closed', 'received'], true) || strtolower(trim((string)($allocation['status'] ?? ''))) === 'received';
      if ($mineOnly && !$isMine) continue;
      if ($completedOnly && !$isCompleted) continue;
      if ($formCode !== '' && strcasecmp($rowFormCode, $formCode) !== 0) continue;
      if ($deliveryMode !== '' && strcasecmp($rowDeliveryMode, $deliveryMode) !== 0) continue;
      if ($stateFilter !== '' && $stateFilter !== strtolower($workflowState) && $stateFilter !== strtolower(trim((string)($allocation['status'] ?? '')))) continue;

      $haystack = strtolower(implode(' ', array_filter([
        $allocationId,
        (string)($allocation['record_id'] ?? ''),
        $rowFormCode,
        eqms_record_title_for_form_code($rowFormCode),
        (string)($allocation['suggested_filename'] ?? ''),
        (string)($latestReceipt['stored_filename'] ?? ''),
      ])));
      if ($search !== '' && !str_contains($haystack, $search)) continue;

      $rows[] = [
        'allocation_id' => $allocationId,
        'record_id' => (string)($allocation['record_id'] ?? ''),
        'record_type' => (string)($allocation['record_type'] ?? ''),
        'form_code' => $rowFormCode,
        'form_title' => eqms_record_title_for_form_code($rowFormCode),
        'delivery_mode' => $rowDeliveryMode,
        'status' => (string)($allocation['status'] ?? ''),
        'workflow_state' => $workflowState,
        'created_at' => (string)($allocation['created_at'] ?? ''),
        'created_by' => (string)($allocation['created_by'] ?? ''),
        'updated_at' => (string)($allocation['updated_at'] ?? ''),
        'last_action_at' => $lastActionAt,
        'draft_exists' => (bool)$draft,
        'draft_saved_at' => (string)($draft['saved_at'] ?? ''),
        'entry_id' => (string)($entry['entry_id'] ?? $allocation['online_submission']['entry_id'] ?? ''),
        'submitted_at' => (string)($entry['submitted_at'] ?? $allocation['online_submission']['submitted_at'] ?? ''),
        'submitted_by' => (string)($entry['submitted_by'] ?? $allocation['online_submission']['submitted_by'] ?? ''),
        'submission_count' => $submissionCount,
        'resubmission_count' => $resubmissionCount,
        'amendment_count' => $amendmentCount,
        'reopen_count' => $reopenCount,
        'receipt_version' => (int)($allocation['receipt_version'] ?? 0),
        'latest_submission_ref' => ($rowDeliveryMode === 'offline'
          ? ('R' . str_pad((string)max(0, (int)($allocation['receipt_version'] ?? 0)), 2, '0', STR_PAD_LEFT))
          : ('S' . max(0, $submissionCount))),
        'latest_filename' => (string)($latestReceipt['stored_filename'] ?? $allocation['offline_package']['filename'] ?? $allocation['suggested_filename'] ?? ''),
        'latest_receipt_at' => (string)($latestReceipt['received_at'] ?? ''),
        'mine' => $isMine,
        'completed' => $isCompleted,
      ];
    }

    usort($rows, static function($a, $b){
      return strcmp((string)($b['last_action_at'] ?? ''), (string)($a['last_action_at'] ?? ''));
    });

    $summary = [
      'issued_count' => count($rows),
      'draft_count' => count(array_filter($rows, static fn($row) => !empty($row['draft_exists']))),
      'submitted_count' => count(array_filter($rows, static fn($row) => (int)($row['submission_count'] ?? 0) > 0)),
      'resubmitted_count' => count(array_filter($rows, static fn($row) => (int)($row['resubmission_count'] ?? 0) > 0)),
      'completed_count' => count(array_filter($rows, static fn($row) => !empty($row['completed']))),
    ];

    $total = count($rows);
    $pages = max(1, (int)ceil($total / $pageSize));
    $offset = ($page - 1) * $pageSize;
    $slice = array_slice($rows, $offset, $pageSize);

    api_json([
      'ok' => true,
      'rows' => $slice,
      'summary' => $summary,
      'total' => $total,
      'page' => $page,
      'pages' => $pages,
    ]);
  }

  // ── Dashboard, KPI & SPC Analytics ─────────────────────────────────────
  case 'dashboard_executive':
  case 'dashboard_quality':
  case 'dashboard_production':
  case 'dashboard_supplier':
  case 'dashboard_department':
  case 'dashboard_widget':
  case 'kpi_get':
  case 'kpi_trend':
  case 'kpi_alerts':
  case 'spc_capability':
  case 'spc_chart':
  case 'spc_summary':
  case 'spc_alerts': {
    require_logged_in($store);
    // Delegate to DashboardController (MVC layer)
    require_once __DIR__ . '/api/controllers/BaseController.php';
    require_once __DIR__ . '/api/controllers/DashboardController.php';
    require_once __DIR__ . '/api/services/KpiEngine.php';
    require_once __DIR__ . '/api/services/SpcEngine.php';
    require_once __DIR__ . '/api/services/DashboardService.php';
    require_once __DIR__ . '/database/Connection.php';
    require_once __DIR__ . '/database/DataLayer.php';

    $dataLayer = new \MOM\Database\DataLayer($DATA_DIR, $ROOT_DIR);
    $ctrl = new \MOM\Api\Controllers\DashboardController($dataLayer, $ROOT_DIR, $DATA_DIR);
    $ctrl->setStore($store);
    $ctrl->handleAction($action);
    break; // handleAction() calls exit, but break for safety
  }

  // ── Master Data Runtime ────────────────────────────────────────────────
  case 'master_data_snapshot': {
    require_logged_in($store);
    $bundle = runtime_read_model_bundle(false);
    $data = master_data_apply_admin_operator_projection($bundle['master'], $store);
    api_json([
      'ok' => true,
      'data' => $data,
      'source' => (string)($bundle['sources']['master_data']['source'] ?? 'json'),
      'read_sources' => $bundle['sources'],
      'runtime_mode' => $bundle['runtime_mode'],
      'summary' => [
        'customers' => count($data['customers'] ?? []),
        'customer_sites' => count($data['customer_sites'] ?? []),
        'commercial_accounts' => count($data['commercial_accounts'] ?? []),
        'suppliers' => count($data['suppliers'] ?? []),
        'parts' => count($data['parts'] ?? []),
        'revisions' => count($data['revisions'] ?? []),
        'incoterms' => count($data['incoterms'] ?? []),
        'payment_terms' => count($data['payment_terms'] ?? []),
        'shipping_methods' => count($data['shipping_methods'] ?? []),
        'promise_policies' => count($data['promise_policies'] ?? []),
        'routing_library' => count($data['routing_library'] ?? []),
        'bom_library' => count($data['bom_library'] ?? []),
        'control_plans' => count($data['control_plans'] ?? []),
        'inspection_plans' => count($data['inspection_plans'] ?? []),
        'traveler_templates' => count($data['traveler_templates'] ?? []),
        'quality_gate_profiles' => count($data['quality_gate_profiles'] ?? []),
        'launch_gate_templates' => count($data['launch_gate_templates'] ?? []),
        'customer_item_approvals' => count($data['customer_item_approvals'] ?? []),
        'supplier_process_approvals' => count($data['supplier_process_approvals'] ?? []),
        'warehouse_locations' => count($data['warehouse_locations'] ?? []),
        'defect_catalog' => count($data['defect_catalog'] ?? []),
        'nc_program_releases' => count($data['nc_program_releases'] ?? []),
        'capas' => count($data['capas'] ?? []),
        'work_centers' => count($data['work_centers'] ?? []),
        'machines' => count($data['machines'] ?? []),
        'operators' => count($data['operators'] ?? []),
        'tooling_assets' => count($data['tooling_assets'] ?? []),
        'downtime_reason_codes' => count($data['downtime_reason_codes'] ?? []),
        'downtime_resolution_codes' => count($data['downtime_resolution_codes'] ?? []),
        'mes_connectivity_adapters' => count($data['mes_connectivity_adapters'] ?? []),
        'mes_alarm_catalog' => count($data['mes_alarm_catalog'] ?? []),
        'mes_alarm_playbooks' => count($data['mes_alarm_playbooks'] ?? []),
        'tool_assemblies' => count($data['tool_assemblies'] ?? []),
      ],
      'operator_authority' => is_array($data['_meta']['operator_authority'] ?? null) ? $data['_meta']['operator_authority'] : [],
    ]);
  }

  case 'master_data_upsert': {
    if (!is_array($store)) api_json(['ok' => false, 'error' => 'system_not_initialized'], 500);
    $me = require_logged_in($store);
    require_csrf();

    $role = migrate_role((string)($me['role'] ?? ''));
    $allowedRoles = ['ceo', 'qa_manager', 'qms_engineer', 'sales_manager', 'estimator', 'customer_service', 'buyer', 'supply_chain_manager', 'production_manager', 'planning_manager', 'maintenance_manager', 'supervisor', 'shift_leader'];
    if (!in_array($role, $allowedRoles, true) && !in_array($role, admin_roles(), true)) {
      api_json(['ok' => false, 'error' => 'forbidden'], 403);
    }

    $body = read_json_body();
    $entity = trim((string)($body['entity'] ?? ''));
    $item = is_array($body['item'] ?? null) ? $body['item'] : null;
    if ($entity === '' || $item === null) api_json(['ok' => false, 'error' => 'invalid_payload'], 400);
    $requestScope = trim((string)($body['scope'] ?? ''));
    if ($requestScope === 'machine_runtime' && !in_array($entity, manual_runtime_machine_entity_keys(), true)) {
      api_json([
        'ok' => false,
        'error' => 'entity_outside_machine_runtime_scope',
        'message' => 'Module Nhập tay vận hành chỉ được lưu các bảng máy/MES. Dữ liệu quy trình phải đi qua endpoint nghiệp vụ riêng.',
      ], 400);
    }
    if ($entity === 'operators') {
      api_json([
        'ok' => false,
        'error' => 'admin_authority_entity',
        'message' => 'Người vận hành được quản trị tại Admin > Người dùng / Sơ đồ tổ chức, không được nhập như dữ liệu nền độc lập.',
      ], 409);
    }
    $item = master_data_normalize_item($entity, $item);
    $idKey = master_data_entity_key($entity);
    if ($idKey === null) api_json(['ok' => false, 'error' => 'invalid_master_entity'], 400);

    try {
      $username = (string)($_SESSION['user'] ?? 'system');
      $service = master_data_service();
      $currentStore = load_master_data_active_store();
      $requestedRecordId = trim((string)($body['record_id'] ?? ''));
      $itemRecordId = trim((string)($item[$idKey] ?? ''));
      if ($requestedRecordId !== '' && $itemRecordId !== '' && $requestedRecordId !== $itemRecordId) {
        api_json([
          'ok' => false,
          'error' => 'immutable_master_key',
          'message' => 'Không được đổi khóa chính của dữ liệu nền. Hãy tạo bản ghi mới hoặc archive bản ghi cũ theo đúng lifecycle.',
          'key' => $idKey,
        ], 409);
      }
      $recordId = $requestedRecordId !== '' ? $requestedRecordId : $itemRecordId;
      if ($recordId !== '') {
        $item[$idKey] = $recordId;
      }
      if ($recordId === '') api_json(['ok' => false, 'error' => 'missing_master_key'], 400);

      $existing = null;
      foreach (($currentStore[$entity] ?? []) as $row) {
        if (is_array($row) && (string)($row[$idKey] ?? '') === $recordId) {
          $existing = $row;
          break;
        }
      }

      $requestedStatus = trim((string)($item['status'] ?? ''));
      $reason = trim((string)($body['reason'] ?? ''));
      if ($reason === '') {
        $reason = $existing ? 'Cập nhật dữ liệu nền qua Master Data Control' : 'Tạo dữ liệu nền qua Master Data Control';
      }

      if ($existing === null) {
        $createResult = $service->create($entity, $item, $username);
        if (!$createResult->ok) {
          $statusCode = in_array($createResult->errorCode, ['duplicate', 'duplicate_key'], true) ? 409 : 400;
          api_json([
            'ok' => false,
            'error' => $createResult->errorCode ?? 'master_data_create_failed',
            'message' => $createResult->message,
            'data' => $createResult->data,
          ], $statusCode);
        }
        $currentStore = load_master_data_active_store();
        $saved = null;
        foreach (($currentStore[$entity] ?? []) as $row) {
          if (is_array($row) && (string)($row[$idKey] ?? '') === $recordId) {
            $saved = $row;
            break;
          }
        }
        shadow_sync_master_data_store($currentStore);
        api_json([
          'ok' => true,
          'entity' => $entity,
          'item' => $saved ?? ($createResult->data ?? $item),
          'message' => $createResult->message,
          'pending' => false,
        ]);
      }

      $changes = [];
      foreach ($item as $field => $value) {
        if (in_array((string)$field, [$idKey, 'created_at', 'created_by', 'updated_at', 'updated_by', 'status'], true)) {
          continue;
        }
        $oldValue = $existing[$field] ?? '';
        if (json_encode($oldValue, JSON_UNESCAPED_UNICODE) === json_encode($value, JSON_UNESCAPED_UNICODE)) {
          continue;
        }
        $changes[$field] = $value;
      }

      $pending = false;
      $pendingMeta = [];
      if (!empty($changes)) {
        $updateResult = $service->update($entity, $recordId, $changes, $username, $reason);
        if (!$updateResult->ok) {
          $statusCode = $updateResult->errorCode === 'not_found' ? 404 : 400;
          api_json([
            'ok' => false,
            'error' => $updateResult->errorCode ?? 'master_data_update_failed',
            'message' => $updateResult->message,
            'data' => $updateResult->data,
          ], $statusCode);
        }
        $pending = (($updateResult->data['status'] ?? '') === 'pending');
        $pendingMeta = is_array($updateResult->data ?? null) ? $updateResult->data : [];
        if ($pending) {
          $changeId = trim((string)($pendingMeta['change_id'] ?? ''));
          if ($changeId === '' || !$service->approvePendingChange($changeId, $username)) {
            api_json([
              'ok' => false,
              'error' => 'master_data_auto_approve_failed',
              'message' => 'Không thể tự động duyệt thay đổi dữ liệu nền vừa tạo.',
            ], 409);
          }
          $pending = false;
        }
      }

      if (!$pending && $requestedStatus !== '' && strtolower((string)($existing['status'] ?? '')) !== strtolower($requestedStatus)) {
        if (!$service->changeStatus($entity, $recordId, strtolower($requestedStatus), $username)) {
          api_json([
            'ok' => false,
            'error' => 'invalid_status_transition',
            'message' => 'Không thể chuyển trạng thái dữ liệu nền theo lifecycle rule hiện tại.',
          ], 409);
        }
      }

      $currentStore = load_master_data_active_store();
      $saved = $existing;
      foreach (($currentStore[$entity] ?? []) as $row) {
        if (is_array($row) && (string)($row[$idKey] ?? '') === $recordId) {
          $saved = $row;
          break;
        }
      }
      $message = $pending
        ? 'Yêu cầu thay đổi đã được đưa vào hàng chờ phê duyệt.'
        : (!empty($pendingMeta['change_id']) ? 'Đã tự động duyệt và lưu dữ liệu nền.' : 'Đã lưu dữ liệu nền có kiểm soát.');
      if (!$pending) {
        shadow_sync_master_data_store($currentStore);
      }
      api_json([
        'ok' => true,
        'entity' => $entity,
        'item' => $saved,
        'pending' => $pending,
        'message' => $message,
        'change_id' => $pendingMeta['change_id'] ?? null,
      ]);
    } catch (Throwable $e) {
      api_json(['ok' => false, 'error' => $e->getMessage()], 400);
    }
  }

  // ── Order Management Runtime ───────────────────────────────────────────
  case 'mes_snapshot': {
    require_logged_in($store);
    $bundle = runtime_read_model_bundle(true);
    $orders = $bundle['orders'];
    $master = $bundle['master'];
    $mes = $bundle['mes'];
    api_json([
      'ok' => true,
      'data' => build_mes_snapshot($orders, $master, $mes),
      'read_sources' => $bundle['sources'],
      'runtime_mode' => $bundle['runtime_mode'],
      'orders_updated' => (string)($orders['_meta']['updated'] ?? ''),
      'master_updated' => (string)($master['_meta']['updated'] ?? ''),
      'mes_updated' => (string)($mes['_meta']['updated'] ?? ''),
    ]);
  }

  case 'mes_stream': {
    require_logged_in($store);
    if (session_status() === PHP_SESSION_ACTIVE) {
      @session_write_close();
    }

    @set_time_limit(0);
    @ignore_user_abort(true);
    @ini_set('zlib.output_compression', '0');
    while (ob_get_level() > 0) {
      @ob_end_flush();
    }

    header('Content-Type: text/event-stream; charset=utf-8');
    header('Cache-Control: no-store, no-cache, must-revalidate, max-age=0');
    header('X-Accel-Buffering: no');
    header('Connection: keep-alive');

    $tickCount = min(30, max(5, (int)($_GET['ticks'] ?? 20)));
    $intervalMs = min(10000, max(1000, (int)($_GET['interval_ms'] ?? 2000)));
    $lastHash = '';
    $runtimeMode = runtime_data_layer_summary();
    $streamMode = mes_runtime_supports_live_stream($runtimeMode) ? 'live' : 'polling_fallback';
    $notifyStream = $streamMode === 'live' ? mes_pg_open_notify_stream() : null;
    $liveEventSource = $notifyStream ? 'postgres_notify' : 'snapshot_poll';

    api_stream_event('ready', [
      'ok' => true,
      'stream' => 'mes_stream',
      'stream_mode' => $streamMode,
      'live_event_source' => $liveEventSource,
      'interval_ms' => $intervalMs,
      'ticks' => $tickCount,
      'recommended_interval_ms' => $streamMode === 'live' ? $intervalMs : 30000,
      'runtime_mode' => $runtimeMode,
      'notify_channels' => $notifyStream ? array_values((array)($notifyStream['channels'] ?? [])) : [],
      'started_at' => now_iso(),
    ]);

    if ($streamMode !== 'live') {
      $bundle = runtime_read_model_bundle(true);
      $orders = $bundle['orders'];
      $master = $bundle['master'];
      $mes = $bundle['mes'];
      $snapshot = build_mes_snapshot($orders, $master, $mes);
      $exceptions = build_exception_dashboard_data($bundle, $snapshot);
      api_stream_event('mes_snapshot', [
        'ok' => true,
        'stream_mode' => 'polling_fallback',
        'recommended_interval_ms' => 30000,
        'snapshot' => $snapshot,
        'master' => $master,
        'exceptions' => $exceptions,
        'read_sources' => $bundle['sources'],
        'runtime_mode' => $bundle['runtime_mode'],
        'streamed_at' => now_iso(),
      ]);
      exit;
    }

    for ($tick = 0; $tick < $tickCount; $tick++) {
      if (connection_aborted()) {
        break;
      }

      $notify = null;
      if ($notifyStream && isset($notifyStream['pdo'])) {
        $notify = mes_pg_wait_for_notify($notifyStream['pdo'], $intervalMs);
      }

      $bundle = runtime_read_model_bundle(true);
      $orders = $bundle['orders'];
      $master = $bundle['master'];
      $mes = $bundle['mes'];
      $snapshot = build_mes_snapshot($orders, $master, $mes);
      $exceptions = build_exception_dashboard_data($bundle, $snapshot);

      $payload = [
        'ok' => true,
        'snapshot' => $snapshot,
        'master' => $master,
        'exceptions' => $exceptions,
        'read_sources' => $bundle['sources'],
        'runtime_mode' => $bundle['runtime_mode'],
        'live_event_source' => $liveEventSource,
        'trigger' => $notify ? 'postgres_notify' : 'snapshot_refresh',
        'notify' => $notify,
        'streamed_at' => now_iso(),
      ];

      $hash = hash('sha256', json_encode([
        'snapshot_meta' => [
          'mes_updated' => (string)($mes['_meta']['updated'] ?? ''),
          'orders_updated' => (string)($orders['_meta']['updated'] ?? ''),
          'master_updated' => (string)($master['_meta']['updated'] ?? ''),
        ],
        'counts' => [
          'launch_blockers' => (int)($snapshot['kpis']['launch_blocker_hotspots'] ?? 0),
          'connector_risk' => (int)($snapshot['kpis']['connectors_stale'] ?? 0),
          'cutover_drift_entities' => (int)($snapshot['kpis']['cutover_drift_entities'] ?? 0),
          'exceptions' => $exceptions,
        ],
      ], JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES));

      if ($hash !== $lastHash || $tick === 0) {
        api_stream_event('mes_snapshot', $payload);
        $lastHash = $hash;
      } else {
        api_stream_event('heartbeat', [
          'ok' => true,
          'streamed_at' => now_iso(),
          'runtime_mode' => $bundle['runtime_mode'],
          'read_sources' => $bundle['sources'],
          'live_event_source' => $liveEventSource,
          'notify' => $notify,
        ]);
      }

      if (!$notifyStream && $tick < ($tickCount - 1)) {
        usleep($intervalMs * 1000);
      }
    }
    exit;
  }

