    if ($reasonCode === '') api_json(['ok' => false, 'error' => 'missing_reason_code'], 400);
    $reasonMeta = $reasonCodes[$reasonCode] ?? null;
    if (!is_array($reasonMeta)) api_json(['ok' => false, 'error' => 'downtime_reason_not_found'], 404);
    if (strtolower(trim((string)($reasonMeta['status'] ?? 'active'))) !== 'active') api_json(['ok' => false, 'error' => 'downtime_reason_inactive'], 409);

    $woNumber = trim((string)($body['wo_number'] ?? ''));
    $jo = [];
    $wo = [];
    if ($woNumber !== '') {
      $wo = find_order_record($orders, 'wo', $woNumber) ?? [];
      if (!$wo) api_json(['ok' => false, 'error' => 'work_order_not_found'], 404);
      $jo = find_order_record($orders, 'jo', (string)($wo['jo_number'] ?? '')) ?? [];
    }

    $event = [
      'downtime_id' => mes_runtime_id('DT'),
      'machine_id' => $machineId,
      'machine_name' => (string)($machines[$machineId]['machine_name'] ?? ''),
      'work_center_id' => trim((string)($body['work_center_id'] ?? $machines[$machineId]['work_center_id'] ?? '')),
      'wo_number' => $woNumber,
      'category' => strtolower(trim((string)($reasonMeta['category'] ?? $category))),
      'severity' => strtolower(trim((string)($body['severity'] ?? $reasonMeta['default_severity'] ?? 'major'))),
      'tool_id' => $toolId,
      'tool_name' => (string)($toolAssets[$toolId]['tool_name'] ?? ''),
      'reason_code' => $reasonCode,
      'reason_name' => trim((string)($reasonMeta['reason_name'] ?? '')),
      'reason_name_vi' => trim((string)($reasonMeta['reason_name_vi'] ?? '')),
      'reason_group' => trim((string)($reasonMeta['reason_group'] ?? '')),
      'planned_flag' => in_array(strtolower(trim((string)($reasonMeta['planned_flag'] ?? 'no'))), ['yes', 'true', '1'], true),
      'reason' => trim((string)($body['reason'] ?? '')),
      'note' => trim((string)($body['note'] ?? '')),
      'started_at' => trim((string)($body['started_at'] ?? now_iso())),
      'status' => 'open',
      'reported_by' => $username,
      'record_context' => normalize_master_context([
        'so_number' => (string)($jo['so_number'] ?? ''),
        'jo_number' => (string)($wo['jo_number'] ?? ''),
        'wo_number' => $woNumber,
        'customer_id' => (string)($jo['customer_id'] ?? ''),
        'part_number' => (string)($jo['part_number'] ?? ''),
        'part_revision' => (string)($jo['part_revision'] ?? ''),
      ]),
    ];
    $mes['downtime_events'][] = $event;

    if ($wo) {
      $workflow = order_workflow_service();
      $currentWo = find_order_record($orders, 'wo', $woNumber);
      $currentStatus = strtolower(trim((string)($currentWo['status'] ?? 'scheduled')));
      if ($currentStatus !== 'completed' && $currentStatus !== 'on_hold') {
        $transitionCheck = $workflow->validateTransition('wo', $currentStatus, 'on_hold', (string)($me['role'] ?? ''));
        if ($transitionCheck->ok) {
          $transitionResult = $workflow->executeTransition('wo', $woNumber, 'on_hold', $username, 'downtime:' . $event['downtime_id']);
          if ($transitionResult->ok) {
            $orders = load_orders_store();
          }
        }
      }
    }

    save_orders_store($orders);
    save_mes_runtime_store($mes);
    api_json(['ok' => true, 'downtime' => $event, 'data' => build_mes_snapshot($orders, $master, $mes)]);
  }

  case 'mes_downtime_resolve': {
    if (!is_array($store)) api_json(['ok' => false, 'error' => 'system_not_initialized'], 500);
    $me = require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $downtimeId = trim((string)($body['downtime_id'] ?? ''));
    if ($downtimeId === '') api_json(['ok' => false, 'error' => 'missing_downtime_id'], 400);

    $orders = load_orders_store();
    $master = load_master_data_store();
    $mes = load_mes_runtime_store();
    $username = (string)($_SESSION['user'] ?? $me['username'] ?? 'system');
    $resolutionCodes = master_index_by((array)($master['downtime_resolution_codes'] ?? []), 'resolution_code');
    $resolutionCode = trim((string)($body['resolution_code'] ?? ''));
    if ($resolutionCode === '') api_json(['ok' => false, 'error' => 'missing_resolution_code'], 400);
    $resolutionMeta = $resolutionCodes[$resolutionCode] ?? null;
    if (!is_array($resolutionMeta)) api_json(['ok' => false, 'error' => 'downtime_resolution_not_found'], 404);
    if (strtolower(trim((string)($resolutionMeta['status'] ?? 'active'))) !== 'active') api_json(['ok' => false, 'error' => 'downtime_resolution_inactive'], 409);
    $resolved = null;
    foreach ($mes['downtime_events'] as $idx => $row) {
      if (!is_array($row) || (string)($row['downtime_id'] ?? '') !== $downtimeId) continue;
      $mes['downtime_events'][$idx]['status'] = 'resolved';
      $mes['downtime_events'][$idx]['resolved_at'] = trim((string)($body['resolved_at'] ?? now_iso()));
      $mes['downtime_events'][$idx]['resolved_by'] = $username;
      $mes['downtime_events'][$idx]['corrective_action'] = trim((string)($body['corrective_action'] ?? ''));
      $mes['downtime_events'][$idx]['resolution_code'] = $resolutionCode;
      $mes['downtime_events'][$idx]['resolution_name'] = trim((string)($resolutionMeta['resolution_name'] ?? ''));
      $mes['downtime_events'][$idx]['resolution_name_vi'] = trim((string)($resolutionMeta['resolution_name_vi'] ?? ''));
      $resolved = $mes['downtime_events'][$idx];
      break;
    }
    if (!$resolved) api_json(['ok' => false, 'error' => 'downtime_not_found'], 404);

    $resumeStatus = strtolower(trim((string)($body['resume_status'] ?? 'running')));
    $woNumber = trim((string)($resolved['wo_number'] ?? ''));
    if ($woNumber !== '') {
      $workflow = order_workflow_service();
      $currentWo = find_order_record($orders, 'wo', $woNumber);
      $currentStatus = strtolower(trim((string)($currentWo['status'] ?? 'on_hold')));
      $transitionCheck = $workflow->validateTransition('wo', $currentStatus, $resumeStatus, (string)($me['role'] ?? ''));
      if ($transitionCheck->ok) {
        $ordersPreview = $orders;
        foreach ($ordersPreview['work_orders'] as $idx => $row) {
          if (!is_array($row) || (string)($row['wo_number'] ?? '') !== $woNumber) continue;
          $ordersPreview['work_orders'][$idx]['status'] = $resumeStatus;
          break;
        }
        $launchGuard = mes_wo_transition_guard($ordersPreview, $master, $mes, $woNumber, $resumeStatus);
        if ($launchGuard) api_json($launchGuard, 409);
        $transitionResult = $workflow->executeTransition('wo', $woNumber, $resumeStatus, $username, 'downtime_resolved:' . $downtimeId);
        if ($transitionResult->ok) {
          $orders = load_orders_store();
        }
      }
    }

    save_orders_store($orders);
    save_mes_runtime_store($mes);
    api_json(['ok' => true, 'downtime' => $resolved, 'data' => build_mes_snapshot($orders, $master, $mes)]);
  }

