  case 'order_detail': {
    $me = require_logged_in($store);
    $body = read_json_body();
    $orderId = trim((string)($body['order_id'] ?? $_GET['order_id'] ?? ''));
    $orderType = strtolower(trim((string)($body['order_type'] ?? $_GET['order_type'] ?? '')));
    if ($orderId === '' || !in_array($orderType, ['so', 'jo', 'wo'], true)) {
      api_json(['ok' => false, 'error' => 'invalid_order_detail_request'], 400);
    }
    require_order_permission($me, $orderType, 'view');

    $bundle = runtime_read_model_bundle(true);
    $orders = $bundle['orders'];
    $master = $bundle['master'];
    $mesSnapshot = build_mes_snapshot($orders, $master, $bundle['mes']);
    $hierarchy = build_order_hierarchy($orders, $master, $mesSnapshot);
    $record = order_find_enriched_record($hierarchy, $orderType, $orderId);
    if (!$record) api_json(['ok' => false, 'error' => 'not_found'], 404);

    $links = array_values(array_filter((array)($orders['form_links'] ?? []), fn($row) => is_array($row) && (string)($row['order_type'] ?? '') === $orderType && (string)($row['order_id'] ?? '') === $orderId));

    if ($orderType === 'wo') {
      $parentJo = (string)($record['jo_number'] ?? '');
      if ($parentJo !== '') {
        $record['job_order'] = order_find_enriched_record($hierarchy, 'jo', $parentJo);
      }
    }

    $record['linked_forms'] = $links;
    $record['master_data_ref'] = [
      'customer_id' => (string)($record['customer_id'] ?? ''),
      'part_number' => (string)($record['part_number'] ?? ''),
      'part_revision' => (string)($record['part_revision'] ?? ''),
    ];
    $record['_mes_kpis'] = (array)($mesSnapshot['kpis'] ?? []);
    $record['_read_sources'] = $bundle['sources'];
    api_json(['ok' => true, 'data' => $record]);
  }

  case 'order_so_create':
  case 'order_jo_create':
  case 'order_wo_create': {
    if (!is_array($store)) api_json(['ok' => false, 'error' => 'system_not_initialized'], 500);
    $me = require_logged_in($store);
    require_csrf();
    $entity = str_contains($action, '_so_') ? 'so' : (str_contains($action, '_jo_') ? 'jo' : 'wo');
    require_order_permission($me, $entity, 'create');

    $body = read_json_body();
    $orders = load_orders_store();
    $master = load_master_data_store();
    $meta = order_entity_config($entity);
    $idKey = $meta['number_key'];
    $now = now_iso();
    $username = (string)($_SESSION['user'] ?? 'system');

    $record = $body;
    $manualId = strtoupper(trim((string)($record[$idKey] ?? '')));
    if ($manualId !== '') {
      if (!preg_match('/^[A-Z0-9][A-Z0-9._-]{2,47}$/', $manualId)) {
        api_json(['ok' => false, 'error' => 'invalid_manual_order_number', 'field' => $idKey], 400);
      }
      if (find_order_record($orders, $entity, $manualId)) {
        api_json(['ok' => false, 'error' => 'duplicate_order_number', 'field' => $idKey, 'value' => $manualId], 409);
      }
      $record[$idKey] = $manualId;
      order_sync_counter_with_manual_number($orders, $entity, $manualId);
    } else {
      $record[$idKey] = next_order_number($orders, $entity);
    }
    $record['status'] = strtolower(trim((string)($record['status'] ?? $meta['default_status'])));
    $record['created_at'] = $now;
    $record['created_by'] = $username;
    $record['updated_at'] = $now;
    $record['updated_by'] = $username;
    $record['status_history'] = [[
      'status' => $record['status'],
      'timestamp' => $now,
      'user' => $username,
      'note' => 'created'
    ]];

    if ($entity === 'so') {
      $customerId = trim((string)($record['customer_id'] ?? ''));
      if ($customerId === '' || trim((string)($record['customer_po'] ?? '')) === '' || trim((string)($record['order_date'] ?? '')) === '' || trim((string)($record['due_date'] ?? '')) === '') {
        api_json(['ok' => false, 'error' => 'missing_required_fields'], 400);
      }
      $customerMeta = [];
      foreach (($master['customers'] ?? []) as $customer) {
        if (is_array($customer) && (string)($customer['customer_id'] ?? '') === $customerId) {
          $customerMeta = $customer;
          $record['customer_name'] = (string)($customer['customer_name'] ?? '');
          break;
        }
      }
      if (($record['customer_site_id'] ?? '') === '') {
        foreach (($master['customer_sites'] ?? []) as $site) {
          if (!is_array($site) || (string)($site['customer_id'] ?? '') !== $customerId) continue;
          $record['customer_site_id'] = (string)($site['site_id'] ?? '');
          if (($record['ship_to_site_id'] ?? '') === '') $record['ship_to_site_id'] = (string)($site['site_id'] ?? '');
          if (($record['packing_spec_code'] ?? '') === '') $record['packing_spec_code'] = (string)($site['packing_spec_code'] ?? '');
          if (($record['label_spec_code'] ?? '') === '') $record['label_spec_code'] = (string)($site['label_spec_code'] ?? '');
          if (($record['shipping_method_id'] ?? '') === '') $record['shipping_method_id'] = (string)($site['default_shipping_method_id'] ?? '');
          if (($record['incoterm_code'] ?? '') === '') $record['incoterm_code'] = (string)($site['default_incoterm_code'] ?? '');
          if (($record['payment_term_code'] ?? '') === '') $record['payment_term_code'] = (string)($site['default_payment_term_code'] ?? '');
          if (($record['certificate_of_conformance_required'] ?? null) === null) $record['certificate_of_conformance_required'] = mes_truthy($site['certificate_of_conformance_required'] ?? false);
          if (($record['certificate_of_analysis_required'] ?? null) === null) $record['certificate_of_analysis_required'] = mes_truthy($site['certificate_of_analysis_required'] ?? false);
          if (($record['export_control_required'] ?? null) === null) $record['export_control_required'] = mes_truthy($site['export_control_required'] ?? false);
          break;
        }
      }
      $record['requested_date'] = trim((string)($record['requested_date'] ?? $record['due_date'] ?? ''));
      $record['promise_date'] = trim((string)($record['promise_date'] ?? $record['due_date'] ?? ''));
      $record['commit_date'] = trim((string)($record['commit_date'] ?? $record['promise_date'] ?? $record['due_date'] ?? ''));
      if (($record['incoterm_code'] ?? '') === '') $record['incoterm_code'] = (string)($customerMeta['default_incoterm_code'] ?? 'FCA');
      if (($record['payment_term_code'] ?? '') === '') $record['payment_term_code'] = (string)($customerMeta['default_payment_term_code'] ?? 'NET30');
      if (($record['shipping_method_id'] ?? '') === '') $record['shipping_method_id'] = (string)($customerMeta['default_shipping_method_id'] ?? '');
      $record['contract_review_status'] = trim((string)($record['contract_review_status'] ?? (($record['contract_review'] ?? '') !== '' ? 'approved' : 'pending')));
      $record['fulfillment_status'] = trim((string)($record['fulfillment_status'] ?? 'pending'));
      $record['document_requirements'] = array_values((array)($record['document_requirements'] ?? order_document_requirements($record)));
      $record['milestones'] = array_values((array)($record['milestones'] ?? order_build_milestones('so', $record)));
      $orders['sales_orders'][] = $record;
    } elseif ($entity === 'jo') {
      $soNumber = trim((string)($record['so_number'] ?? ''));
      $partNumber = trim((string)($record['part_number'] ?? ''));
      if ($soNumber === '' || $partNumber === '' || trim((string)($record['part_revision'] ?? '')) === '' || trim((string)($record['start_date'] ?? '')) === '' || trim((string)($record['due_date'] ?? '')) === '') {
        api_json(['ok' => false, 'error' => 'missing_required_fields'], 400);
      }
      $parentSo = find_order_record($orders, 'so', $soNumber);
      if (!$parentSo) api_json(['ok' => false, 'error' => 'parent_so_not_found'], 404);
      $record['customer_id'] = (string)($parentSo['customer_id'] ?? '');
      $partMeta = [];
      foreach (($master['parts'] ?? []) as $part) {
        if (!is_array($part) || (string)($part['part_number'] ?? '') !== $partNumber) continue;
        $partMeta = $part;
        if (($record['part_description'] ?? '') === '') $record['part_description'] = (string)($part['part_description'] ?? '');
        break;
      }
      foreach ([
        'routing_library' => 'routing_id',
        'bom_library' => 'bom_id',
        'control_plans' => 'control_plan_id',
        'inspection_plans' => 'inspection_plan_id',
        'traveler_templates' => 'traveler_template_id',
      ] as $entityKey => $fieldKey) {
        if (($record[$fieldKey] ?? '') !== '') continue;
        foreach (($master[$entityKey] ?? []) as $row) {
          if (!is_array($row) || (string)($row['part_number'] ?? '') !== $partNumber) continue;
          $rowRevision = trim((string)($row['part_revision'] ?? $row['revision'] ?? ''));
          if ($rowRevision !== '' && $rowRevision !== trim((string)($record['part_revision'] ?? ''))) continue;
          $candidateKey = $fieldKey === 'routing_id' ? 'routing_id'
            : ($fieldKey === 'bom_id' ? 'bom_id'
            : ($fieldKey === 'control_plan_id' ? 'control_plan_id'
            : ($fieldKey === 'inspection_plan_id' ? 'inspection_plan_id' : 'traveler_template_id')));
          $record[$fieldKey] = (string)($row[$candidateKey] ?? '');
          break;
        }
      }
      $releaseStatus = 'pending';
      foreach (($master['revisions'] ?? []) as $revision) {
        if (!is_array($revision)) continue;
        if ((string)($revision['part_number'] ?? '') !== $partNumber) continue;
        if ((string)($revision['revision'] ?? '') !== (string)($record['part_revision'] ?? '')) continue;
        $releaseStatus = strtolower(trim((string)($revision['status'] ?? 'pending')));
        break;
      }
      $record['release_target_date'] = trim((string)($record['release_target_date'] ?? $record['start_date'] ?? ''));
      $record['engineering_release_status'] = trim((string)($record['engineering_release_status'] ?? ($releaseStatus === 'released' ? 'released' : 'pending')));
      $record['material_ready_status'] = trim((string)($record['material_ready_status'] ?? 'pending'));
      $record['quality_plan_status'] = trim((string)($record['quality_plan_status'] ?? ((($record['control_plan_id'] ?? '') !== '' || ($record['inspection_plan_id'] ?? '') !== '') ? 'planned' : 'pending')));
      $record['source_inspection_status'] = trim((string)($record['source_inspection_status'] ?? (($record['customer_source_inspection'] ?? false) ? 'pending' : 'not_required')));
      $record['traceability_level'] = trim((string)($record['traceability_level'] ?? $partMeta['traceability_level'] ?? ''));
      $record['outside_processing_required'] = (($record['special_process'] ?? '') !== '') || (($record['special_process_supplier_id'] ?? '') !== '');
      $record['outside_processing_status'] = trim((string)($record['outside_processing_status'] ?? ($record['outside_processing_required'] ? 'pending' : 'not_required')));
      $record['milestones'] = array_values((array)($record['milestones'] ?? order_build_milestones('jo', $record)));
      $orders['job_orders'][] = $record;
    } else {
      $joNumber = trim((string)($record['jo_number'] ?? ''));
      if ($joNumber === '' || trim((string)($record['operation_number'] ?? '')) === '' || trim((string)($record['operation_desc'] ?? '')) === '' || trim((string)($record['machine_id'] ?? '')) === '' || trim((string)($record['work_center_id'] ?? '')) === '') {
        api_json(['ok' => false, 'error' => 'missing_required_fields'], 400);
      }
      $parentJo = find_order_record($orders, 'jo', $joNumber);
      if (!$parentJo) api_json(['ok' => false, 'error' => 'parent_jo_not_found'], 404);
      // Inherit traceability context from parent JO (AS9100D 8.5.2)
      if (($record['part_number'] ?? '') === '') $record['part_number'] = (string)($parentJo['part_number'] ?? '');
      if (($record['part_revision'] ?? '') === '') $record['part_revision'] = (string)($parentJo['part_revision'] ?? '');
      if (($record['customer_id'] ?? '') === '') $record['customer_id'] = (string)($parentJo['customer_id'] ?? '');
      if (($record['part_description'] ?? '') === '') $record['part_description'] = (string)($parentJo['part_description'] ?? '');
      if (($record['material_spec'] ?? '') === '') $record['material_spec'] = (string)($parentJo['material_spec'] ?? '');
      $parentSo = find_order_record($orders, 'so', (string)($parentJo['so_number'] ?? ''));
      $record['dispatch_priority'] = trim((string)($record['dispatch_priority'] ?? strtolower((string)($parentSo['priority'] ?? 'standard'))));
      $record['quality_gate_status'] = trim((string)($record['quality_gate_status'] ?? 'pending'));
      $record['first_piece_status'] = trim((string)($record['first_piece_status'] ?? (($parentJo['fai_required'] ?? false) ? 'pending' : 'not_required')));
      $record['handover_status'] = trim((string)($record['handover_status'] ?? 'pending'));
      $record['milestones'] = array_values((array)($record['milestones'] ?? order_build_milestones('wo', $record)));
      $orders['work_orders'][] = $record;
      $launchGuard = mes_wo_transition_guard($orders, $master, load_mes_runtime_store(), (string)($record['wo_number'] ?? ''), (string)($record['status'] ?? 'scheduled'));
      if ($launchGuard) api_json($launchGuard, 409);
    }

    save_orders_store($orders);
    api_json(['ok' => true, 'data' => $record]);
  }

  case 'order_so_update_status':
  case 'order_jo_update_status':
  case 'order_wo_update_status': {
    if (!is_array($store)) api_json(['ok' => false, 'error' => 'system_not_initialized'], 500);
    $me = require_logged_in($store);
    require_csrf();
    $entity = str_contains($action, '_so_') ? 'so' : (str_contains($action, '_jo_') ? 'jo' : 'wo');
    require_order_permission($me, $entity, 'edit');

    $body = read_json_body();
    $orderId = trim((string)($body['order_id'] ?? ''));
    $newStatus = strtolower(trim((string)($body['status'] ?? '')));
    if ($orderId === '' || $newStatus === '') api_json(['ok' => false, 'error' => 'invalid_payload'], 400);

    $orders = load_orders_store();
    $workflow = order_workflow_service();
    $master = $entity === 'wo' ? load_master_data_store() : [];
    $mes = $entity === 'wo' ? load_mes_runtime_store() : [];
    $meta = order_entity_config($entity);
    $storeKey = $meta['store_key'];
    $idKey = $meta['number_key'];
    $existing = null;
    $currentStatus = '';
    foreach ($orders[$storeKey] as $idx => $row) {
      if (!is_array($row) || (string)($row[$idKey] ?? '') !== $orderId) continue;
      $existing = $row;
      $currentStatus = strtolower(trim((string)($row['status'] ?? '')));
      $transitionCheck = $workflow->validateTransition($entity, $currentStatus, $newStatus, (string)($me['role'] ?? ''));
      if (!$transitionCheck->ok) {
        api_json([
          'ok' => false,
          'error' => $transitionCheck->errorCode ?? 'invalid_status_transition',
          'message' => $transitionCheck->message,
          'from' => $currentStatus,
          'to' => $newStatus,
          'allowed' => $transitionCheck->data['allowed'] ?? [],
        ], 409);
      }
      if ($entity === 'wo') {
        $ordersPreview = $orders;
        $ordersPreview[$storeKey][$idx]['status'] = $newStatus;
        $launchGuard = mes_wo_transition_guard($ordersPreview, $master, $mes, $orderId, $newStatus);
        if ($launchGuard) api_json($launchGuard, 409);
      }
      break;
    }
    if (!$existing) api_json(['ok' => false, 'error' => 'not_found'], 404);

    $statusNote = trim((string)($body['note'] ?? ''));
    $result = $workflow->executeTransition($entity, $orderId, $newStatus, (string)($_SESSION['user'] ?? 'system'), $statusNote !== '' ? $statusNote : null);
    if (!$result->ok) {
      $statusCode = $result->errorCode === 'not_found' ? 404 : 409;
      api_json([
        'ok' => false,
        'error' => $result->errorCode ?? 'transition_failed',
        'message' => $result->message,
        'data' => $result->data,
      ], $statusCode);
    }
    shadow_sync_orders_store(load_orders_store());
    api_json(['ok' => true, 'data' => $result->data]);
  }

  // ── G2 P1-01: Retrieve linked forms for an order ────────────────
  case 'order_update_fields': {
    if (!is_array($store)) api_json(['ok' => false, 'error' => 'system_not_initialized'], 500);
    $me = require_logged_in($store);
    require_csrf();

    $body = read_json_body();
    $entity = strtolower(trim((string)($body['order_type'] ?? '')));
    $orderId = trim((string)($body['order_id'] ?? ''));
    $changes = is_array($body['changes'] ?? null) ? $body['changes'] : [];
    if (!in_array($entity, ['so', 'jo', 'wo'], true) || $orderId === '' || !$changes) {
      api_json(['ok' => false, 'error' => 'invalid_payload'], 400);
    }
    require_order_permission($me, $entity, 'edit');

    $orders = load_orders_store();
    $workflow = order_workflow_service();
    $master = load_master_data_store();
    $meta = order_entity_config($entity);
    $storeKey = $meta['store_key'];
    $idKey = $meta['number_key'];
    $allowed = array_flip(order_editable_fields($entity));
    $username = (string)($_SESSION['user'] ?? 'system');

    $machines = master_index_by((array)($master['machines'] ?? []), 'machine_id');
    $operators = master_index_by((array)($master['operators'] ?? []), 'operator_id');
    $workCenters = master_index_by((array)($master['work_centers'] ?? []), 'work_center_id');
    $revisions = (array)($master['revisions'] ?? []);

    $existing = null;
    foreach ($orders[$storeKey] as $row) {
      if (is_array($row) && (string)($row[$idKey] ?? '') === $orderId) {
        $existing = $row;
        break;
      }
    }
    if (!$existing) api_json(['ok' => false, 'error' => 'not_found'], 404);

    $sanitizedChanges = [];
    foreach ($changes as $field => $rawValue) {
      if (!is_string($field) || !isset($allowed[$field])) continue;
      $newValue = order_normalize_edit_value($field, $rawValue);
      $oldValue = $existing[$field] ?? null;
      if (json_encode($oldValue, JSON_UNESCAPED_UNICODE) === json_encode($newValue, JSON_UNESCAPED_UNICODE)) {
        continue;
      }
      $sanitizedChanges[$field] = $newValue;
    }

    if (!$sanitizedChanges) {
      api_json(['ok' => true, 'data' => $existing]);
    }

    $preview = array_merge($existing, $sanitizedChanges);

    if ($entity === 'jo') {
      $partNumber = trim((string)($preview['part_number'] ?? ''));
      $partRevision = trim((string)($preview['part_revision'] ?? ''));
      $matchedRev = null;
      foreach ($revisions as $revision) {
        if (!is_array($revision)) continue;
        if ((string)($revision['part_number'] ?? '') === $partNumber && (string)($revision['revision'] ?? '') === $partRevision) {
          $matchedRev = $revision;
          break;
        }
      }
      if (!$matchedRev) {
        api_json(['ok' => false, 'error' => 'revision_not_found_for_part', 'message' => "Revision {$partRevision} not found for part {$partNumber}."], 422);
      }
      // REV-02: Only released revisions may be used on job orders
      $revStatus = strtolower(trim((string)($matchedRev['status'] ?? '')));
      if ($revStatus !== '' && $revStatus !== 'released') {
        api_json(['ok' => false, 'error' => 'revision_not_released', 'message' => "Revision {$partRevision} has status '{$revStatus}'. Only released revisions are allowed."], 422);
      }
    }

    if ($entity === 'wo') {
      $machineId = trim((string)($preview['machine_id'] ?? ''));
      if ($machineId !== '') {
        if (!isset($machines[$machineId])) api_json(['ok' => false, 'error' => 'machine_not_found'], 404);
        $machineWorkCenter = trim((string)($machines[$machineId]['work_center_id'] ?? ''));
        if ($machineWorkCenter !== '') {
          $preview['work_center_id'] = $machineWorkCenter;
          $sanitizedChanges['work_center_id'] = $machineWorkCenter;
        }
      }
      $workCenterId = trim((string)($preview['work_center_id'] ?? ''));
      $operatorId = trim((string)($preview['operator_id'] ?? ''));
      if ($workCenterId !== '' && !isset($workCenters[$workCenterId])) api_json(['ok' => false, 'error' => 'work_center_not_found'], 404);
      if ($operatorId !== '' && !isset($operators[$operatorId])) api_json(['ok' => false, 'error' => 'operator_not_found'], 404);

      $ordersPreview = $orders;
      foreach ($ordersPreview[$storeKey] as $idx => $row) {
        if (!is_array($row) || (string)($row[$idKey] ?? '') !== $orderId) continue;
        $ordersPreview[$storeKey][$idx] = array_merge($row, $preview);
        break;
      }
      $mes = load_mes_runtime_store();
      $currentStatus = strtolower(trim((string)($existing['status'] ?? 'scheduled')));
      $launchGuard = mes_wo_transition_guard($ordersPreview, $master, $mes, $orderId, $currentStatus);
      if ($launchGuard) api_json($launchGuard, 409);
    }

    $reason = trim((string)($body['note'] ?? ''));
    if ($reason === '') {
      $reason = 'Controlled field update via Order Management';
    }
    $changeAuthorityContext = [
      'actor_id' => $username,
      'change_order_id' => trim((string)($body['change_order_id'] ?? $body['plm_change_order_id'] ?? '')),
      'change_order_number' => trim((string)($body['change_order_number'] ?? $body['change_order_ref'] ?? '')),
      'effectivity' => is_array($body['effectivity'] ?? null) ? $body['effectivity'] : [],
    ];
    $result = $workflow->executeFieldEdit($entity, $orderId, $sanitizedChanges, $username, $reason, $changeAuthorityContext);
    if (!$result->ok) {
      $statusCode = match ($result->errorCode) {
        'not_found' => 404,
        'forbidden' => 403,
        'validation_failed', 'field_locked', 'ecr_required', 'change_authority_required', 'change_authority_unavailable', 'status_locked' => 409,
        default => 400,
      };
      api_json([
        'ok' => false,
        'error' => $result->errorCode ?? 'order_edit_failed',
        'message' => $result->message,
        'data' => $result->data,
      ], $statusCode);
    }

    shadow_sync_orders_store(load_orders_store());
    api_json(['ok' => true, 'data' => $result->data]);
  }

  case 'order_get_linked_forms': {
    $me = require_logged_in($store);
    $orderType = strtolower(trim((string)($_GET['order_type'] ?? '')));
    $orderId   = trim((string)($_GET['order_id'] ?? ''));
    if ($orderId === '' || !in_array($orderType, ['so', 'jo', 'wo'], true)) {
      api_json(['ok' => false, 'error' => 'invalid_payload'], 400);
    }
    require_order_permission($me, $orderType, 'view');

    $orders = load_orders_store();
    if (!find_order_record($orders, $orderType, $orderId)) {
      api_json(['ok' => false, 'error' => 'order_not_found'], 404);
    }
    $links = array_values(array_filter((array)($orders['form_links'] ?? []), function ($row) use ($orderType, $orderId) {
      return is_array($row)
        && (string)($row['order_type'] ?? '') === $orderType
        && (string)($row['order_id'] ?? '') === $orderId;
    }));

    // Enrich each link with basic allocation/entry info when available
    $allocationStore = null;
    $enriched = array_map(function ($link) use (&$allocationStore) {
      $rid = (string)($link['record_id'] ?? '');
      $fc  = (string)($link['form_code'] ?? '');
      $info = [
        'link_id'     => (string)($link['link_id'] ?? ''),
        'record_id'   => $rid,
        'form_code'   => $fc,
        'status'      => (string)($link['status'] ?? 'linked'),
        'auto_linked' => (bool)($link['auto_linked'] ?? false),
        'linked_at'   => (string)($link['linked_at'] ?? ''),
        'linked_by'   => (string)($link['linked_by'] ?? ''),
      ];
      // Try to pull allocation status
      if ($rid !== '') {
        if ($allocationStore === null) $allocationStore = load_allocation_store();
        foreach (($allocationStore['allocations'] ?? []) as $alloc) {
          if (is_array($alloc) && (string)($alloc['record_id'] ?? '') === $rid) {
            $info['alloc_status'] = (string)($alloc['status'] ?? '');
            $info['delivery_mode'] = (string)($alloc['delivery_mode'] ?? '');
            $info['created_at'] = (string)($alloc['created_at'] ?? '');
            $info['created_by'] = (string)($alloc['created_by'] ?? '');
            break;
          }
        }
      }
      return $info;
    }, $links);

    api_json(['ok' => true, 'forms' => $enriched]);
  }

  case 'order_link_form': {
    if (!is_array($store)) api_json(['ok' => false, 'error' => 'system_not_initialized'], 500);
    $me = require_logged_in($store);
    require_csrf();

    $body = read_json_body();
    $orderId = trim((string)($body['order_id'] ?? ''));
    $orderType = strtolower(trim((string)($body['order_type'] ?? '')));
    $recordId = strtoupper(trim((string)($body['record_id'] ?? '')));
    if ($orderId === '' || $recordId === '' || !in_array($orderType, ['so', 'jo', 'wo'], true)) {
      api_json(['ok' => false, 'error' => 'invalid_payload'], 400);
    }
    require_order_permission($me, $orderType, 'edit');

    $orders = load_orders_store();
    if (!find_order_record($orders, $orderType, $orderId)) api_json(['ok' => false, 'error' => 'order_not_found'], 404);
    foreach (($orders['form_links'] ?? []) as $link) {
      if (!is_array($link)) continue;
      if ((string)($link['order_type'] ?? '') === $orderType && (string)($link['order_id'] ?? '') === $orderId && (string)($link['record_id'] ?? '') === $recordId) {
        api_json(['ok' => false, 'error' => 'link_exists'], 400);
      }
    }
    $link = [
      'link_id' => 'LINK-' . date('YmdHis') . '-' . substr(md5($orderType . '|' . $orderId . '|' . $recordId), 0, 8),
      'order_id' => $orderId,
      'order_type' => $orderType,
      'record_id' => $recordId,
      'status' => 'linked',
      'linked_at' => now_iso(),
      'linked_by' => (string)($_SESSION['user'] ?? 'system'),
    ];
    $orders['form_links'][] = $link;
    save_orders_store($orders);
    api_json(['ok' => true, 'data' => $link]);
  }

  // ── Form Fill: Load Schema, Save Draft, History ─────────────────────────
  case 'form_fill_load_schema': {
    $code = trim((string)($_GET['form_code'] ?? ''));
    if ($code === '') api_json(['ok' => false, 'error' => 'missing_form_code'], 400);
    // Sanitise: allow only alphanumeric, dash, underscore, dot
    if (!preg_match('/^[A-Za-z0-9._-]+$/', $code)) api_json(['ok' => false, 'error' => 'invalid_form_code'], 400);
    $schemasDir = $DATA_DIR . '/online-forms/schemas';
    $file = $schemasDir . '/' . $code . '.json';
    if (!file_exists($file)) api_json(['ok' => false, 'error' => 'schema_not_found'], 404);
    $schema = json_decode(file_get_contents($file), true);
    if (!$schema) api_json(['ok' => false, 'error' => 'invalid_schema'], 500);
    api_json(['ok' => true, 'schema' => $schema]);
  }

  case 'form_fill_save_draft': {
    $me = require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $allocationId = trim((string)($body['allocation_id'] ?? ''));
    $formCode = trim((string)($body['form_code'] ?? ''));
    $data = is_array($body['data'] ?? null) ? $body['data'] : [];
    $entryId = trim((string)($body['entry_id'] ?? ''));
    $recordId = trim((string)($body['record_id'] ?? ''));
    $editOrigin = trim((string)($body['edit_origin'] ?? 'draft'));
	    $sourceEntryId = trim((string)($body['source_entry_id'] ?? ''));
	    $sourceRevision = (int)($body['source_submission_revision'] ?? 0);
	    $changeAuthorityId = eqms_change_authority_from_payload($body);
	    $amendmentReason = trim((string)($body['amendment_reason'] ?? ''));
	    if ($allocationId === '' || $formCode === '') {
	      api_json(['ok' => false, 'error' => 'missing_allocation_id_or_form_code'], 400);
	    }
	    // Sanitise allocation_id
	    if (!preg_match('/^[A-Za-z0-9._-]+$/', $allocationId)) api_json(['ok' => false, 'error' => 'invalid_allocation_id'], 400);
	    $entries = load_online_form_entries_store($formCode);
	    $existingIdx = find_online_form_entry_index($entries, $entryId, $allocationId);
	    $previous = $existingIdx >= 0 && is_array($entries[$existingIdx] ?? null) ? $entries[$existingIdx] : null;
	    $previousState = $previous ? eqms_entry_workflow_state($previous) : '';
	    if ($previous && eqms_is_locked_workflow_state($previousState)) {
	      if ($editOrigin !== 'amendment' || !eqms_change_authority_format_valid($changeAuthorityId)) {
	        api_json([
	          'ok' => false,
	          'error' => 'change_authority_required',
	          'message' => 'Locked records require an amendment draft with change authority.',
	          'allowed_action' => 'create_amendment',
	          'locked_state' => $previousState,
	        ], 409);
	      }
	      if ($amendmentReason === '') {
	        api_json(['ok' => false, 'error' => 'amendment_reason_required'], 422);
	      }
	      $draftCandidate = is_array($data['fieldValues'] ?? null) ? $data['fieldValues'] : $data;
	      $draftCandidate['source_entry_id'] = $sourceEntryId !== '' ? $sourceEntryId : (string)($previous['entry_id'] ?? '');
	      $draftCandidate['entry_id'] = $entryId;
	      $authorityCheck = eqms_assert_online_form_change_authority($formCode, $previous, $draftCandidate, $changeAuthorityId);
	      if (!($authorityCheck['ok'] ?? false)) {
	        api_json([
	          'ok' => false,
	          'error' => (string)($authorityCheck['error'] ?? 'change_authority_required'),
	          'message' => (string)($authorityCheck['message'] ?? 'Change authority does not cover this amendment draft.'),
	          'field_path' => (string)($authorityCheck['field_path'] ?? ''),
	          'decisions' => $authorityCheck['decisions'] ?? [],
	          'allowed_action' => 'create_amendment_with_released_change_order',
	          'locked_state' => $previousState,
	        ], 409);
	      }
	    }
	    $username = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));
	    $draftPayload = [
      'allocation_id' => $allocationId,
      'form_code' => $formCode,
      'entry_id' => $entryId,
      'record_id' => $recordId,
      'data' => $data,
	      'edit_origin' => $editOrigin !== '' ? $editOrigin : 'draft',
	      'source_entry_id' => $sourceEntryId,
	      'source_submission_revision' => $sourceRevision,
	      'change_authority_id' => $changeAuthorityId,
	      'amendment_reason' => $amendmentReason,
	      'change_authority_decisions' => $authorityCheck['decisions'] ?? [],
	      'saved_at' => date('c'),
      'saved_by' => $username,
    ];
    save_online_form_draft($allocationId, $draftPayload);
    api_json(['ok' => true]);
  }

  case 'form_fill_discard_draft': {
    require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $allocationId = trim((string)($body['allocation_id'] ?? ''));
    if ($allocationId === '') {
      api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);
    }
    if (!preg_match('/^[A-Za-z0-9._-]+$/', $allocationId)) {
      api_json(['ok' => false, 'error' => 'invalid_allocation_id'], 400);
    }
    delete_online_form_draft($allocationId);
    api_json(['ok' => true, 'allocation_id' => $allocationId, 'server_time' => now_iso()]);
  }

  case 'form_fill_get_draft': {
    require_logged_in($store);
    $allocationId = trim((string)($_GET['allocation_id'] ?? $_POST['allocation_id'] ?? ''));
    if ($allocationId === '') {
      api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);
    }
    if (!preg_match('/^[A-Za-z0-9._-]+$/', $allocationId)) {
      api_json(['ok' => false, 'error' => 'invalid_allocation_id'], 400);
    }
    $draftFile = $DATA_DIR . '/online-forms/drafts/' . $allocationId . '.json';
    if (!is_file($draftFile)) {
      api_json(['ok' => true, 'draft' => null, 'server_time' => now_iso()]);
    }
    $raw = @file_get_contents($draftFile);
    $draft = $raw ? json_decode($raw, true) : null;
    if (!is_array($draft)) {
      api_json(['ok' => true, 'draft' => null, 'server_time' => now_iso()]);
    }
    api_json(['ok' => true, 'draft' => $draft, 'server_time' => now_iso()]);
  }

  case 'form_fill_history': {
    require_logged_in($store);
    $formCode = trim((string)($_GET['form_code'] ?? ''));
    $userFilter = trim((string)($_GET['user'] ?? ''));
    $page = max(1, (int)($_GET['page'] ?? 1));
    $pageSize = max(1, min(100, (int)($_GET['page_size'] ?? 20)));
    if ($formCode === '') api_json(['ok' => false, 'error' => 'missing_form_code'], 400);
    $entries = load_online_form_entries_store($formCode);
    if ($userFilter !== '') {
      $userFilterLc = strtolower($userFilter);
      $entries = array_values(array_filter($entries, function ($e) use ($userFilterLc) {
        return strtolower(trim((string)($e['submitted_by'] ?? $e['created_by'] ?? $e['_session_user'] ?? ''))) === $userFilterLc;
      }));
    }
    $total = count($entries);
    $pages = max(1, (int)ceil($total / $pageSize));
    $offset = ($page - 1) * $pageSize;
    $slice = array_slice($entries, $offset, $pageSize);
    api_json(['ok' => true, 'entries' => $slice, 'total' => $total, 'page' => $page, 'pages' => $pages]);
  }

  // ── Evidence Approval Engine (G3 P1-02) ─────────────────────────────────

  case 'evidence_checklist': {
    require_logged_in($store);
    $body = read_json_body();
    $allocationId = trim((string)($body['allocation_id'] ?? $_GET['allocation_id'] ?? ''));
    $stage = trim((string)($body['stage'] ?? $_GET['stage'] ?? 'review'));
    if ($allocationId === '') api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);

    $allocation = allocation_find(load_allocation_store(), $allocationId);
    if (!$allocation) api_json(['ok' => false, 'error' => 'allocation_not_found'], 404);

    $checklist = evidence_evaluate_checklist($allocation, $stage);
    api_json(['ok' => true, 'checklist' => $checklist, 'allocation' => $allocation]);
  }

  case 'capa_effectiveness_evaluate': {
    require_logged_in($store);
    $body = read_json_body();
    $allocationId = trim((string)($body['allocation_id'] ?? $_GET['allocation_id'] ?? ''));
    if ($allocationId === '') api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);

    $allocation = allocation_find(load_allocation_store(), $allocationId);
    if (!$allocation) api_json(['ok' => false, 'error' => 'allocation_not_found'], 404);

    $formCode = trim((string)($allocation['form_code'] ?? ''));
    $schema = $formCode !== '' ? (load_form_schema_by_code($formCode) ?: []) : [];
    if (empty($schema)) api_json(['ok' => false, 'error' => 'schema_not_found'], 404);

    $requirement = null;
    foreach ((array)($schema['evidence_requirements'] ?? []) as $candidate) {
      if (!is_array($candidate)) continue;
      $kind = strtolower(trim((string)($candidate['kind'] ?? '')));
      $id = trim((string)($candidate['id'] ?? ''));
      if ($kind === 'capa_effectiveness' || $id === 'capa_effectiveness_review') {
        $requirement = $candidate;
        break;
      }
    }
    if (!$requirement) api_json(['ok' => false, 'error' => 'capa_effectiveness_requirement_not_configured'], 404);

    $entry = evidence_find_online_entry(
      $formCode,
      trim((string)($allocation['allocation_id'] ?? '')),
      trim((string)($allocation['online_submission']['entry_id'] ?? ''))
    );
    $evaluation = evidence_evaluate_requirement($requirement, $allocation, $schema, $entry);
    $evaluation['required'] = evidence_requirement_applies($requirement, 'approval');

    api_json([
      'ok' => true,
      'allocation' => $allocation,
      'evaluation' => $evaluation,
    ]);
  }

  case 'evidence_link_list': {
    require_logged_in($store);
    $allocationId = trim((string)($_GET['allocation_id'] ?? $_POST['allocation_id'] ?? ''));
    if ($allocationId === '') api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);

    $allocationStore = load_allocation_store();
    $allocation = allocation_find($allocationStore, $allocationId);
    if (!$allocation) api_json(['ok' => false, 'error' => 'allocation_not_found'], 404);

    api_json([
      'ok' => true,
      'allocation' => allocation_summary($allocation),
      'links' => evidence_links_for_allocation($allocationStore, $allocationId),
    ]);
  }

  case 'evidence_link_add': {
    $me = require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $allocationId = trim((string)($body['allocation_id'] ?? ''));
    $targetAllocationId = trim((string)($body['target_allocation_id'] ?? ''));
    $relationType = evidence_link_type_normalize((string)($body['relation_type'] ?? 'related'));
    $notes = trim((string)($body['notes'] ?? ''));
    if ($allocationId === '' || $targetAllocationId === '') api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);
    if ($allocationId === $targetAllocationId) api_json(['ok' => false, 'error' => 'self_link_not_allowed'], 400);

    $allocationStore = load_allocation_store();
    $sourceAllocation =& allocation_find_ref($allocationStore, $allocationId);
    if (!is_array($sourceAllocation)) api_json(['ok' => false, 'error' => 'allocation_not_found'], 404);
    $targetAllocation =& allocation_find_ref($allocationStore, $targetAllocationId);
    if (!is_array($targetAllocation)) api_json(['ok' => false, 'error' => 'target_allocation_not_found'], 404);

    foreach ((array)($allocationStore['evidence_links'] ?? []) as $existing) {
      if (!is_array($existing)) continue;
      if ((string)($existing['source_allocation_id'] ?? '') === $allocationId
        && (string)($existing['target_allocation_id'] ?? '') === $targetAllocationId
        && evidence_link_type_normalize((string)($existing['relation_type'] ?? 'related')) === $relationType) {
        api_json(['ok' => false, 'error' => 'link_exists'], 409);
      }
    }

    $username = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));
    $link = [
      'link_id' => 'EVL-' . date('YmdHis') . '-' . substr(md5($allocationId . '|' . $targetAllocationId . '|' . $relationType), 0, 8),
      'source_allocation_id' => $allocationId,
      'target_allocation_id' => $targetAllocationId,
      'relation_type' => $relationType,
      'notes' => $notes,
      'created_at' => now_iso(),
      'created_by' => $username,
    ];
    $allocationStore['evidence_links'][] = $link;

    $targetRecordId = trim((string)($targetAllocation['record_id'] ?? ''));
    $sourceRecordId = trim((string)($sourceAllocation['record_id'] ?? ''));
    allocation_append_audit_log($sourceAllocation, 'evidence_link_add', $username, 'linked_to_related_record', [
      'link_id' => $link['link_id'],
      'relation_type' => $relationType,
      'relation_label_vi' => evidence_link_label($relationType, false, 'vi'),
      'target_allocation_id' => $targetAllocationId,
      'target_record_id' => $targetRecordId,
      'notes' => $notes,
    ]);
    allocation_append_audit_log($targetAllocation, 'evidence_link_add', $username, 'linked_from_related_record', [
      'link_id' => $link['link_id'],
      'relation_type' => $relationType,
      'relation_label_vi' => evidence_link_label($relationType, true, 'vi'),
      'source_allocation_id' => $allocationId,
      'source_record_id' => $sourceRecordId,
      'notes' => $notes,
    ]);

    save_allocation_store($allocationStore);
    api_json([
      'ok' => true,
      'link' => $link,
      'links' => evidence_links_for_allocation($allocationStore, $allocationId),
    ]);
  }

  case 'evidence_link_remove': {
    $me = require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $allocationId = trim((string)($body['allocation_id'] ?? ''));
    $linkId = trim((string)($body['link_id'] ?? ''));
    if ($allocationId === '' || $linkId === '') api_json(['ok' => false, 'error' => 'missing_payload'], 400);

    $allocationStore = load_allocation_store();
    $index = null;
    $link = null;
    foreach ((array)($allocationStore['evidence_links'] ?? []) as $idx => $candidate) {
      if (!is_array($candidate)) continue;
      if ((string)($candidate['link_id'] ?? '') === $linkId) {
        $index = $idx;
        $link = $candidate;
        break;
      }
    }
    if ($index === null || !$link) api_json(['ok' => false, 'error' => 'link_not_found'], 404);

    $sourceId = trim((string)($link['source_allocation_id'] ?? ''));
    $targetId = trim((string)($link['target_allocation_id'] ?? ''));
    if ($allocationId !== $sourceId && $allocationId !== $targetId) api_json(['ok' => false, 'error' => 'link_not_owned_by_allocation'], 403);

    $sourceAllocation =& allocation_find_ref($allocationStore, $sourceId);
    $targetAllocation =& allocation_find_ref($allocationStore, $targetId);
    $username = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));
    $relationType = evidence_link_type_normalize((string)($link['relation_type'] ?? 'related'));

    if (is_array($sourceAllocation)) {
      allocation_append_audit_log($sourceAllocation, 'evidence_link_remove', $username, 'unlinked_related_record', [
        'link_id' => $linkId,
        'relation_type' => $relationType,
        'counterpart_record_id' => (string)($targetAllocation['record_id'] ?? ''),
      ]);
    }
    if (is_array($targetAllocation)) {
      allocation_append_audit_log($targetAllocation, 'evidence_link_remove', $username, 'unlinked_related_record', [
        'link_id' => $linkId,
        'relation_type' => $relationType,
        'counterpart_record_id' => (string)($sourceAllocation['record_id'] ?? ''),
      ]);
    }

    unset($allocationStore['evidence_links'][$index]);
    $allocationStore['evidence_links'] = array_values($allocationStore['evidence_links']);
    save_allocation_store($allocationStore);

    api_json([
      'ok' => true,
      'links' => evidence_links_for_allocation($allocationStore, $allocationId),
    ]);
  }

  case 'evidence_retention_status': {
    $me = require_logged_in($store);
    $allocationId = trim((string)($_GET['allocation_id'] ?? $_POST['allocation_id'] ?? ''));
    if ($allocationId === '') api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);

    $recordTypes = load_record_type_registry();
    $allocation = allocation_find(load_allocation_store(), $allocationId);
    if (!$allocation) api_json(['ok' => false, 'error' => 'allocation_not_found'], 404);

    api_json([
      'ok' => true,
      'allocation' => allocation_summary($allocation),
      'retention' => evidence_retention_evaluate($allocation, $recordTypes),
      'can_manage' => evidence_retention_can_manage($me),
    ]);
  }

  case 'evidence_retention_policy_save': {
    $me = require_logged_in($store);
    require_csrf();
    if (!evidence_retention_can_manage($me)) api_json(['ok' => false, 'error' => 'insufficient_role'], 403);

    $body = read_json_body();
    $recordType = strtoupper(trim((string)($body['record_type'] ?? '')));
    $retentionYears = max(1, min(50, (int)($body['retention_years'] ?? 5)));
    $retentionTrigger = strtolower(trim((string)($body['retention_trigger'] ?? 'approved')));
    $dispositionAction = strtolower(trim((string)($body['disposition_action'] ?? 'review_before_disposal')));

    if ($recordType === '') api_json(['ok' => false, 'error' => 'missing_record_type'], 400);
    if (!in_array($retentionTrigger, ['approved', 'received', 'submitted', 'created', 'updated'], true)) {
      api_json(['ok' => false, 'error' => 'invalid_retention_trigger'], 400);
    }
    if (!in_array($dispositionAction, ['review_before_disposal', 'archive_only'], true)) {
      api_json(['ok' => false, 'error' => 'invalid_disposition_action'], 400);
    }

    $recordTypes = load_record_type_registry();
    if (!isset($recordTypes[$recordType])) api_json(['ok' => false, 'error' => 'record_type_not_found'], 404);

    $store = load_evidence_retention_policy_store($recordTypes);
    $store['record_types'][$recordType] = array_merge(
      evidence_retention_policy_for_type($recordType, $recordTypes),
      [
        'retention_years' => $retentionYears,
        'retention_trigger' => $retentionTrigger,
        'disposition_action' => $dispositionAction,
      ]
    );
    $store['_meta']['updated_by'] = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));
    save_evidence_retention_policy_store($store);

    api_json([
      'ok' => true,
      'record_type' => $recordType,
      'policy' => evidence_retention_policy_for_type($recordType, $recordTypes),
    ]);
  }

  case 'evidence_retention_hold': {
    $me = require_logged_in($store);
    require_csrf();
    if (!evidence_retention_can_manage($me)) api_json(['ok' => false, 'error' => 'insufficient_role'], 403);

    $body = read_json_body();
    $allocationId = trim((string)($body['allocation_id'] ?? ''));
    $holdAction = strtolower(trim((string)($body['action'] ?? 'set')));
    $reason = trim((string)($body['reason'] ?? ''));
    if ($allocationId === '') api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);
    if (!in_array($holdAction, ['set', 'release'], true)) api_json(['ok' => false, 'error' => 'invalid_action'], 400);
    if ($reason === '') api_json(['ok' => false, 'error' => 'reason_required'], 400);

    $allocationStore = load_allocation_store();
    $allocation =& allocation_find_ref($allocationStore, $allocationId);
    if (!is_array($allocation)) api_json(['ok' => false, 'error' => 'allocation_not_found'], 404);

    $username = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));
    if ($holdAction === 'set') {
      $allocation['retention_hold'] = [
        'active' => true,
        'reason' => $reason,
        'set_at' => now_iso(),
        'set_by' => $username,
      ];
      allocation_append_audit_log($allocation, 'retention_hold_set', $username, $reason, ['hold_action' => 'set']);
    } else {
      $allocation['retention_hold'] = [
        'active' => false,
        'reason' => $reason,
        'set_at' => now_iso(),
        'set_by' => $username,
      ];
      allocation_append_audit_log($allocation, 'retention_hold_released', $username, $reason, ['hold_action' => 'release']);
    }
    save_allocation_store($allocationStore);

    api_json([
      'ok' => true,
      'allocation' => $allocation,
      'retention' => evidence_retention_evaluate($allocation, load_record_type_registry()),
    ]);
  }

  case 'evidence_sla_status': {
    $me = require_logged_in($store);
    $allocationId = trim((string)($_GET['allocation_id'] ?? $_POST['allocation_id'] ?? ''));
    if ($allocationId === '') api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);

    $recordTypes = load_record_type_registry();
    $allocationStore = load_allocation_store();
    $allocation =& allocation_find_ref($allocationStore, $allocationId);
    if (!is_array($allocation)) api_json(['ok' => false, 'error' => 'allocation_not_found'], 404);
    $formCode = trim((string)($allocation['form_code'] ?? ''));
    $schema = $formCode !== '' ? (load_form_schema_by_code($formCode) ?: []) : [];
    $beforeStored = is_array($allocation['review_sla'] ?? null) ? $allocation['review_sla'] : [];
    $reviewSla = evidence_review_sla_materialize($allocation, $recordTypes, $schema);
    $afterStored = is_array($allocation['review_sla'] ?? null) ? $allocation['review_sla'] : [];
    if ($beforeStored !== $afterStored) save_allocation_store($allocationStore);

    api_json([
      'ok' => true,
      'allocation' => allocation_summary($allocation),
      'review_sla' => $reviewSla,
      'current_policy' => evidence_review_sla_policy_for_type((string)($allocation['record_type'] ?? ''), $recordTypes),
      'can_manage' => evidence_review_sla_can_manage($me),
    ]);
  }

  case 'evidence_sla_policy_save': {
    $me = require_logged_in($store);
    require_csrf();
    if (!evidence_review_sla_can_manage($me)) api_json(['ok' => false, 'error' => 'insufficient_role'], 403);

    $body = read_json_body();
    $recordType = strtoupper(trim((string)($body['record_type'] ?? '')));
    $reviewHours = max(1, min(240, (int)($body['review_hours'] ?? 72)));
    $warnHours = max(1, min($reviewHours, (int)($body['warn_hours_before_due'] ?? 12)));
    $escalateHours = max(1, min(240, (int)($body['escalate_hours_after_due'] ?? 24)));
    $rolesRaw = $body['escalation_roles'] ?? [];
    if (!is_array($rolesRaw)) {
      $rolesRaw = preg_split('/[\s,;]+/', trim((string)$rolesRaw)) ?: [];
    }
    $escalationRoles = array_values(array_unique(array_values(array_filter(array_map(
      static fn($role) => strtolower(trim((string)$role)),
      $rolesRaw
    )))));

    if ($recordType === '') api_json(['ok' => false, 'error' => 'missing_record_type'], 400);
    $recordTypes = load_record_type_registry();
    if (!isset($recordTypes[$recordType])) api_json(['ok' => false, 'error' => 'record_type_not_found'], 404);

    $store = load_evidence_review_sla_policy_store($recordTypes);
    $store['record_types'][$recordType] = array_merge(
      evidence_review_sla_policy_for_type($recordType, $recordTypes),
      [
        'review_hours' => $reviewHours,
        'warn_hours_before_due' => $warnHours,
        'escalate_hours_after_due' => $escalateHours,
        'escalation_roles' => $escalationRoles,
      ]
    );
    $store['_meta']['updated_by'] = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));
    save_evidence_review_sla_policy_store($store);

    api_json([
      'ok' => true,
      'record_type' => $recordType,
      'policy' => evidence_review_sla_policy_for_type($recordType, $recordTypes),
    ]);
  }

  case 'evidence_sla_notifications_run': {
    $me = require_logged_in($store);
    require_csrf();
    if (!evidence_review_sla_can_manage($me)) api_json(['ok' => false, 'error' => 'insufficient_role'], 403);

    require_once __DIR__ . '/api/services/ScheduledJobs.php';
    $jobs = new \MOM\Services\ScheduledJobs($DATA_DIR);
    $result = $jobs->runEvidenceReviewSlaNotifications();
    $bundle = runtime_read_model_bundle(true);

    api_json([
      'ok' => true,
      'result' => $result,
      'data' => build_mes_snapshot($bundle['orders'], $bundle['master'], $bundle['mes']),
      'exceptions' => build_exception_dashboard_data($bundle),
      'updated_at' => now_iso(),
    ]);
  }

  case 'release_followup_overview': {
    $me = require_logged_in($store);
    $scope = strtolower(trim((string)($_GET['scope'] ?? $_POST['scope'] ?? 'open')));
    $rows = array_values(array_filter(release_followup_queue_rows(), static fn($row) => is_array($row) && release_followup_is_visible_to_user($row, $me)));
    if ($scope === 'overdue') {
      $rows = array_values(array_filter($rows, static fn($row) => (string)($row['queue_state'] ?? '') === 'overdue'));
    } elseif ($scope === 'due_soon') {
      $rows = array_values(array_filter($rows, static fn($row) => in_array((string)($row['queue_state'] ?? ''), ['due_soon', 'overdue'], true)));
    } elseif ($scope === 'in_progress') {
      $rows = array_values(array_filter($rows, static fn($row) => (string)($row['status'] ?? '') === 'in_progress'));
    }
    api_json([
      'ok' => true,
      'scope' => $scope,
      'summary' => release_followup_summary($rows),
      'items' => array_slice($rows, 0, 100),
      'server_time' => now_iso(),
    ]);
  }

  case 'release_followup_update': {
    if ($method !== 'POST') api_json(['ok' => false, 'error' => 'method_not_allowed'], 405);
    $me = require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $releaseId = trim((string)($body['release_id'] ?? ''));
    $action = strtolower(trim((string)($body['action'] ?? '')));
    $note = trim((string)($body['note'] ?? ''));
    if ($releaseId === '' || $action === '') api_json(['ok' => false, 'error' => 'invalid_payload'], 400);

    $followupStore = load_release_followup_store();
    $targetIdx = -1;
    foreach ((array)($followupStore['items'] ?? []) as $idx => $item) {
      if (!is_array($item)) continue;
      if ((string)($item['release_id'] ?? '') !== $releaseId) continue;
      $targetIdx = $idx;
      break;
    }
    if ($targetIdx < 0) api_json(['ok' => false, 'error' => 'release_followup_not_found'], 404);

    $item = is_array($followupStore['items'][$targetIdx] ?? null) ? $followupStore['items'][$targetIdx] : [];
    if (!release_followup_can_manage($item, $me)) api_json(['ok' => false, 'error' => 'insufficient_role'], 403);

    $actor = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));
    switch ($action) {
      case 'acknowledge':
      case 'start':
        $item['status'] = 'in_progress';
        $item['acknowledged_at'] = now_iso();
        $item['acknowledged_by'] = $actor;
        if ($note !== '') $item['completion_note'] = $note;
        release_followup_append_history($item, 'acknowledged', $actor, $note);
        break;
      case 'complete':
        $item['status'] = 'completed';
        if (trim((string)($item['acknowledged_at'] ?? '')) === '') {
          $item['acknowledged_at'] = now_iso();
          $item['acknowledged_by'] = $actor;
        }
        $item['completed_at'] = now_iso();
        $item['completed_by'] = $actor;
        $item['completion_note'] = $note;
        release_followup_append_history($item, 'completed', $actor, $note);
        break;
      case 'reopen':
        $item['status'] = 'open';
        $item['completed_at'] = '';
        $item['completed_by'] = '';
        if ($note !== '') $item['completion_note'] = $note;
        release_followup_append_history($item, 'reopened', $actor, $note);
        break;
      default:
        api_json(['ok' => false, 'error' => 'unsupported_action'], 400);
    }

    $item['updated_at'] = now_iso();
    $followupStore['items'][$targetIdx] = $item;
    $followupStore['_meta']['updated_by'] = $actor;
    save_release_followup_store($followupStore);

    api_json([
      'ok' => true,
      'item' => release_followup_row_from_item($item),
      'summary' => release_followup_summary(),
      'server_time' => now_iso(),
    ]);
  }

  case 'evidence_pack_export': {
    require_logged_in($store);
    $allocationId = trim((string)($_GET['allocation_id'] ?? $_POST['allocation_id'] ?? ''));
    if ($allocationId === '') api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);
    if (!class_exists('ZipArchive')) api_json(['ok' => false, 'error' => 'zip_archive_not_available'], 500);

    $allocation = allocation_find(load_allocation_store(), $allocationId);
    if (!$allocation) api_json(['ok' => false, 'error' => 'allocation_not_found'], 404);

    $tmpDir = allocation_base_dir() . '/tmp';
    ensure_dir($tmpDir);
    $safeBase = preg_replace('/[^A-Za-z0-9._-]/', '-', (string)($allocation['record_id'] ?? $allocationId));
    $downloadName = ($safeBase !== '' ? $safeBase : $allocationId) . '-evidence-pack.zip';
    $tmpFile = $tmpDir . '/evidence-pack-' . $allocationId . '-' . date('YmdHis') . '.zip';

    $zip = new ZipArchive();
    if ($zip->open($tmpFile, ZipArchive::CREATE | ZipArchive::OVERWRITE) !== true) {
      api_json(['ok' => false, 'error' => 'zip_open_failed'], 500);
    }

    $formCode = trim((string)($allocation['form_code'] ?? ''));
    $schema = $formCode !== '' ? (load_form_schema_by_code($formCode) ?: []) : [];
    $recordTypes = load_record_type_registry();
    $approvalSummary = evidence_refresh_approval_summary($allocation, $schema);
    $reviewSla = evidence_review_sla_materialize($allocation, $recordTypes, $schema);
    $graphicsRegistryPath = __DIR__ . '/data/registry/graphics-governance-registry.json';
    $graphicsManifestPath = __DIR__ . '/data/registry/system-contract-manifest.json';
    $graphicsRegistry = is_file($graphicsRegistryPath) ? (json_decode((string)file_get_contents($graphicsRegistryPath), true) ?: []) : [];
    $graphicsManifest = is_file($graphicsManifestPath) ? (json_decode((string)file_get_contents($graphicsManifestPath), true) ?: []) : [];
    $graphicsReleaseLink = is_array($graphicsRegistry['graphicsReleaseLink'] ?? null)
      ? $graphicsRegistry['graphicsReleaseLink']
      : (is_array($graphicsManifest['graphicsReleaseLink'] ?? null) ? $graphicsManifest['graphicsReleaseLink'] : []);

    $manifest = [
      'generated_at' => now_iso(),
      'record_id' => (string)($allocation['record_id'] ?? ''),
      'allocation_id' => $allocationId,
      'allocation' => $allocation,
      'approval_summary' => $approvalSummary,
      'related_records' => evidence_links_for_allocation(load_allocation_store(), $allocationId),
      'retention' => evidence_retention_evaluate($allocation, $recordTypes),
      'review_sla' => $reviewSla,
      'review_checklist' => evidence_evaluate_checklist($allocation, 'review'),
      'approval_checklist' => evidence_evaluate_checklist($allocation, 'approval'),
      'graphics_evidence' => [
        'graphicsReleaseLink' => $graphicsReleaseLink,
        'complianceSnapshotRef' => 'graphics/graphics-governance-registry.json#/moduleGraphicsCompliance',
        'releaseManifestRef' => 'graphics/system-contract-manifest.json#/graphicsReleaseLink',
        'releaseBlocked' => (bool)($graphicsReleaseLink['releaseBlocked'] ?? false),
        'blockerCount' => (int)($graphicsReleaseLink['blockerCount'] ?? 0),
      ],
    ];
    $zip->addFromString('manifest.json', json_encode($manifest, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES));
    if (is_file($graphicsRegistryPath)) {
      $zip->addFile($graphicsRegistryPath, 'graphics/graphics-governance-registry.json');
    }
    if (is_file($graphicsManifestPath)) {
      $zip->addFile($graphicsManifestPath, 'graphics/system-contract-manifest.json');
    }

    if (!empty($allocation['events']) && is_array($allocation['events'])) {
      $zip->addFromString('audit-trail.json', json_encode($allocation['events'], JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES));
    }
    if (!empty($allocation['approval_signature']) && is_array($allocation['approval_signature'])) {
      $zip->addFromString('approval-signature.json', json_encode($allocation['approval_signature'], JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES));
    }
    if (!empty($allocation['approval_records']) && is_array($allocation['approval_records'])) {
      $zip->addFromString('approval-records.json', json_encode($allocation['approval_records'], JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES));
    }
    if (!empty($allocation['approval_summary']) && is_array($allocation['approval_summary'])) {
      $zip->addFromString('approval-summary.json', json_encode($allocation['approval_summary'], JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES));
    }
    if (!empty($allocation['review_sla']) && is_array($allocation['review_sla'])) {
      $zip->addFromString('review-sla.json', json_encode($allocation['review_sla'], JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES));
    }

    $entryId = trim((string)($allocation['online_submission']['entry_id'] ?? ''));
    if ($formCode !== '') {
      $entry = evidence_find_online_entry($formCode, $allocationId, $entryId);
      if ($entry) {
        $zip->addFromString('online-submission.json', json_encode($entry, JSON_PRETTY_PRINT | JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES));
      }
    }

    $issuedPath = trim((string)($allocation['offline_package']['issued_path'] ?? ''));
    $issuedName = trim((string)($allocation['offline_package']['filename'] ?? ''));
    if ($issuedPath !== '' && is_file($issuedPath)) {
      $zip->addFile($issuedPath, 'issued/' . ($issuedName !== '' ? $issuedName : basename($issuedPath)));
    }

    $receipts = array_values(array_filter((array)($allocation['receipts'] ?? []), fn($row) => is_array($row)));
    if ($receipts) {
      foreach ($receipts as $receipt) {
        $serverPath = trim((string)($receipt['server_path'] ?? ''));
        if ($serverPath === '' || !is_file($serverPath)) continue;
        $version = (int)($receipt['version'] ?? 0);
        $storedFilename = trim((string)($receipt['stored_filename'] ?? basename($serverPath)));
        $entryName = 'received/' . ($version > 0 ? ('R' . $version . '_') : '') . $storedFilename;
        $zip->addFile($serverPath, $entryName);
      }
    } else {
      $receipt = allocation_resolve_received_file($allocation, 0);
      if ($receipt && is_file((string)($receipt['server_path'] ?? ''))) {
        $zip->addFile((string)$receipt['server_path'], 'received/' . (string)($receipt['stored_filename'] ?? basename((string)$receipt['server_path'])));
      }
    }

    $zip->close();
    stream_download_file($tmpFile, $downloadName);
  }

  case 'evidence_submit_for_review': {
    $me = require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $allocationId = trim((string)($body['allocation_id'] ?? ''));
    if ($allocationId === '') api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);

    $allocationStore = load_allocation_store();
    $allocation =& allocation_find_ref($allocationStore, $allocationId);
    if (!is_array($allocation)) api_json(['ok' => false, 'error' => 'allocation_not_found'], 404);

    $currentStatus = allocation_status_normalize((string)($allocation['status'] ?? 'allocated'));
    if (!in_array($currentStatus, ['submitted', 'received'], true)) {
      api_json(['ok' => false, 'error' => 'invalid_status_for_review', 'current_status' => $currentStatus], 409);
    }

    $formCode = trim((string)($allocation['form_code'] ?? ''));
    $schema = $formCode !== '' ? (load_form_schema_by_code($formCode) ?: []) : [];
    $recordTypes = load_record_type_registry();
    $checklist = evidence_evaluate_checklist($allocation, 'review');
    if (!($checklist['ok'] ?? false)) {
      api_json(['ok' => false, 'error' => 'evidence_incomplete', 'checklist' => $checklist], 422);
    }

    $username = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));
    evidence_clear_review_outcome($allocation);
    evidence_refresh_approval_summary($allocation, $schema);
    $allocation['review_started_at'] = now_iso();
    unset($allocation['review_closed_at']);
    allocation_append_event($allocation, 'in_review', $username, 'evidence_submitted_for_review');
    $reviewSla = evidence_review_sla_materialize($allocation, $recordTypes, $schema);
    save_allocation_store($allocationStore);

    api_json([
      'ok' => true,
      'allocation' => $allocation,
      'checklist' => $checklist,
      'approval_summary' => evidence_approval_summary($allocation, $schema),
      'review_sla' => $reviewSla,
    ]);
  }

  case 'evidence_review': {
    $me = require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $allocationId = trim((string)($body['allocation_id'] ?? ''));
    $reviewAction = strtolower(trim((string)($body['action'] ?? '')));
    $reason = trim((string)($body['reason'] ?? ''));
    $signatureData = is_array($body['signature_data'] ?? null) ? $body['signature_data'] : null;
    // 21 CFR Part 11 §11.50: signature meaning is MANDATORY
    $rawMeaning = trim((string)($body['signature_meaning'] ?? ''));
    if ($rawMeaning === '' && $reviewAction === 'approve') {
      // Default to 'approval' but require explicit meaning for compliance
      $rawMeaning = 'approval';
    }
    $signatureMeaning = evidence_signature_meaning_normalize_strict(
      $rawMeaning !== '' ? $rawMeaning : ($reviewAction === 'reject' ? 'review' : 'approval')
    );

    if ($allocationId === '') api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);
    if (!in_array($reviewAction, ['approve', 'reject'], true)) {
      api_json(['ok' => false, 'error' => 'invalid_action', 'hint' => 'action must be approve or reject'], 400);
    }

    $allocationStore = load_allocation_store();
    $allocation =& allocation_find_ref($allocationStore, $allocationId);
    if (!is_array($allocation)) api_json(['ok' => false, 'error' => 'allocation_not_found'], 404);

    $currentStatus = allocation_status_normalize((string)($allocation['status'] ?? 'allocated'));
    if ($currentStatus !== 'in_review') {
      api_json(['ok' => false, 'error' => 'allocation_not_in_review', 'current_status' => $currentStatus], 409);
    }

    $formCode = trim((string)($allocation['form_code'] ?? ''));
    $schema = $formCode !== '' ? (load_form_schema_by_code($formCode) ?: []) : [];
    $recordTypes = load_record_type_registry();
    $reviewConfig = evidence_review_config($schema);
    if ($formCode !== '' && !evidence_user_can_review($schema, $me)) {
      api_json(['ok' => false, 'error' => 'insufficient_role', 'required' => $reviewConfig['roles_allowed']], 403);
    }

    $username = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));

    if ($reviewAction === 'approve') {
      $checklist = evidence_evaluate_checklist($allocation, 'approval');
      if (!($checklist['ok'] ?? false)) {
        api_json(['ok' => false, 'error' => 'evidence_incomplete', 'checklist' => $checklist], 422);
      }

      // Step-up re-auth: verify password
      $password = trim((string)($body['password'] ?? ''));
      if ($password === '') {
        api_json(['ok' => false, 'error' => 'password_required'], 400);
      }
      global $DATA_DIR;
      $usersData = json_decode((string)file_get_contents($DATA_DIR . '/config/users.json'), true);
      $authUser = null;
      foreach (($usersData['users'] ?? []) as $u) {
        if (is_array($u) && (string)($u['username'] ?? '') === $username) { $authUser = $u; break; }
      }
      if (!$authUser || !\MOM\Api\Services\PasswordService::verify($password, (string)($authUser['password_hash'] ?? ''))['ok']) {
        api_json(['ok' => false, 'error' => 'invalid_password'], 403);
      }

      if (($reviewConfig['approval_mode'] ?? 'serial') === 'parallel') {
        $records = evidence_normalize_approval_records($allocation);
        $userRoles = evidence_user_roles($me);
        $record = [
          'username' => $username,
          'display_name' => trim((string)($me['display_name'] ?? $me['name'] ?? $username)),
          'approved_at' => now_iso(),
          'reason' => $reason,
          'meaning' => $signatureMeaning,
          'roles' => $userRoles,
          'signature' => $signatureData,
        ];
        $updatedExisting = false;
        foreach ($records as $idx => $existingRecord) {
          if (!is_array($existingRecord) || strtolower(trim((string)($existingRecord['username'] ?? ''))) !== $username) continue;
          $records[$idx] = $record;
          $updatedExisting = true;
          break;
        }
        if (!$updatedExisting) $records[] = $record;
        $allocation['approval_records'] = $records;

        $approvalSummary = evidence_refresh_approval_summary($allocation, $schema);
        if ($approvalSummary['is_complete'] ?? false) {
          if ($signatureData !== null) {
            $allocation['approval_signature'] = $signatureData;
          }
          $allocation['approved_at'] = now_iso();
          $allocation['approved_by'] = $username;
          $allocation['approval_reason'] = $reason;
          $allocation['review_closed_at'] = now_iso();
          allocation_append_event($allocation, 'approved', $username, $reason ?: 'evidence_approved_parallel', [
            'approval_mode' => 'parallel',
            'signature_meaning' => $signatureMeaning,
            'collected_approvals' => (int)($approvalSummary['collected_approvals'] ?? 0),
            'required_approvals' => (int)($approvalSummary['minimum_approvals'] ?? 1),
            'signature_hash' => is_array($signatureData) ? (string)($signatureData['hash'] ?? '') : '',
            'signature_signer' => is_array($signatureData) ? (string)($signatureData['signerName'] ?? '') : '',
          ]);
        } else {
          allocation_append_event($allocation, 'in_review', $username, $reason ?: ($updatedExisting ? 'evidence_parallel_approval_updated' : 'evidence_parallel_approval_recorded'), [
            'approval_mode' => 'parallel',
            'signature_meaning' => $signatureMeaning,
            'collected_approvals' => (int)($approvalSummary['collected_approvals'] ?? 0),
            'required_approvals' => (int)($approvalSummary['minimum_approvals'] ?? 1),
            'signature_hash' => is_array($signatureData) ? (string)($signatureData['hash'] ?? '') : '',
            'signature_signer' => is_array($signatureData) ? (string)($signatureData['signerName'] ?? '') : '',
          ]);
        }
      } else {
        if ($signatureData !== null) {
          $allocation['approval_signature'] = $signatureData;
        }
        $allocation['approval_records'] = [[
          'username' => $username,
          'display_name' => trim((string)($me['display_name'] ?? $me['name'] ?? $username)),
          'approved_at' => now_iso(),
          'reason' => $reason,
          'meaning' => $signatureMeaning,
          'roles' => evidence_user_roles($me),
          'signature' => $signatureData,
        ]];
        evidence_refresh_approval_summary($allocation, $schema);
        $allocation['approved_at'] = now_iso();
        $allocation['approved_by'] = $username;
        $allocation['approval_reason'] = $reason;
        $allocation['review_closed_at'] = now_iso();
        allocation_append_event($allocation, 'approved', $username, $reason ?: 'evidence_approved', [
          'approval_mode' => 'serial',
          'signature_meaning' => $signatureMeaning,
          'signature_hash' => is_array($signatureData) ? (string)($signatureData['hash'] ?? '') : '',
          'signature_signer' => is_array($signatureData) ? (string)($signatureData['signerName'] ?? '') : '',
        ]);
      }
    } else {
      // Reject
      if ($reason === '') {
        api_json(['ok' => false, 'error' => 'reason_required_for_rejection'], 400);
      }
      $allocation['rejected_at'] = now_iso();
      $allocation['rejected_by'] = $username;
      $allocation['rejection_reason'] = $reason;
      $allocation['review_closed_at'] = now_iso();
      allocation_append_event($allocation, 'rejected', $username, $reason, [
        'review_action' => 'reject',
        'approval_mode' => $reviewConfig['approval_mode'] ?? 'serial',
      ]);
    }

    $approvalSummary = evidence_refresh_approval_summary($allocation, $schema);
    $reviewSla = evidence_review_sla_materialize($allocation, $recordTypes, $schema);
    save_allocation_store($allocationStore);

    $newStatus = allocation_status_normalize((string)($allocation['status'] ?? ''));
    api_json([
      'ok' => true,
      'status' => $newStatus,
      'allocation' => $allocation,
      'approval_summary' => $approvalSummary,
      'review_sla' => $reviewSla,
      'checklist' => evidence_evaluate_checklist($allocation, $newStatus === 'approved' ? 'approval' : 'review'),
    ]);
  }

  case 'evidence_reopen': {
    $me = require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $allocationId = trim((string)($body['allocation_id'] ?? ''));
    $reason = trim((string)($body['reason'] ?? ''));

    if ($allocationId === '') api_json(['ok' => false, 'error' => 'missing_allocation_id'], 400);
    if ($reason === '') api_json(['ok' => false, 'error' => 'reason_required'], 400);

    // Only managers can reopen
    $userRoles = is_array($me['roles'] ?? null) ? $me['roles'] : [(string)($me['role'] ?? '')];
    $managerRoles = ['admin', 'qa_manager', 'quality_manager', 'production_manager', 'engineering_manager', 'production_director', 'engineering_lead', 'qms_engineer'];
    $isManager = false;
    foreach ($userRoles as $userRole) {
      if (in_array(strtolower(trim((string)$userRole)), $managerRoles, true)) {
        $isManager = true;
        break;
      }
    }
    if (!$isManager) {
      api_json(['ok' => false, 'error' => 'only_managers_can_reopen'], 403);
    }

    $allocationStore = load_allocation_store();
    $allocation =& allocation_find_ref($allocationStore, $allocationId);
    if (!is_array($allocation)) api_json(['ok' => false, 'error' => 'allocation_not_found'], 404);

    $currentStatus = allocation_status_normalize((string)($allocation['status'] ?? 'allocated'));
    if (!in_array($currentStatus, ['in_review', 'approved', 'rejected'], true)) {
      api_json(['ok' => false, 'error' => 'cannot_reopen_from_status', 'current_status' => $currentStatus], 409);
    }

    $username = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));
    // Clear previous approval/rejection metadata
    evidence_clear_review_outcome($allocation);
    evidence_review_sla_reset($allocation);
    allocation_append_event($allocation, 'submitted', $username, $reason, [
      'review_action' => 'reopen',
      'reopened_from' => $currentStatus,
    ]);
    save_allocation_store($allocationStore);

    api_json(['ok' => true, 'allocation' => $allocation]);
  }

  case 'evidence_get_pending': {
    require_logged_in($store);
    $department = strtoupper(trim((string)($_GET['department'] ?? '')));
    $formCode = trim((string)($_GET['form_code'] ?? ''));

    $allocationStore = load_allocation_store();
    $recordTypes = load_record_type_registry();
    $pending = array_values(array_filter((array)($allocationStore['allocations'] ?? []), function ($row) use ($department, $formCode) {
      if (!is_array($row)) return false;
      if (allocation_status_normalize((string)($row['status'] ?? '')) !== 'in_review') return false;
      if ($department !== '' && strtoupper(trim((string)($row['department'] ?? ''))) !== $department) return false;
      if ($formCode !== '' && trim((string)($row['form_code'] ?? '')) !== $formCode) return false;
      return true;
    }));

    $schemaCache = [];
    $dirty = false;
    foreach ($pending as &$row) {
      if (!is_array($row)) continue;
      $rowFormCode = trim((string)($row['form_code'] ?? ''));
      $schema = [];
      if ($rowFormCode !== '') {
        if (!array_key_exists($rowFormCode, $schemaCache)) {
          $schemaCache[$rowFormCode] = load_form_schema_by_code($rowFormCode) ?: [];
        }
        $schema = $schemaCache[$rowFormCode];
      }
      $allocationId = trim((string)($row['allocation_id'] ?? ''));
      $row['approval_summary'] = evidence_approval_summary($row, $schema);
      if ($allocationId !== '') {
        $actualRow =& allocation_find_ref($allocationStore, $allocationId);
        if (is_array($actualRow)) {
          $beforeStored = is_array($actualRow['review_sla'] ?? null) ? $actualRow['review_sla'] : [];
          $actualRow['approval_summary'] = evidence_approval_summary($actualRow, $schema);
          $row['approval_summary'] = $actualRow['approval_summary'];
          $row['review_sla'] = evidence_review_sla_materialize($actualRow, $recordTypes, $schema);
          $afterStored = is_array($actualRow['review_sla'] ?? null) ? $actualRow['review_sla'] : [];
          if ($beforeStored !== $afterStored) $dirty = true;
        } else {
          $row['review_sla'] = evidence_review_sla_evaluate($row, $recordTypes, $schema);
        }
      } else {
        $row['review_sla'] = evidence_review_sla_evaluate($row, $recordTypes, $schema);
      }
    }
    unset($row);
    if ($dirty) save_allocation_store($allocationStore);

    api_json(['ok' => true, 'pending' => $pending, 'count' => count($pending)]);
  }

  // ── G5 P1-03: Upload Hardening — quarantine flow ───────────────────────
  case 'upload_quarantine': {
    $me = require_logged_in($store);
    require_csrf();
    if (empty($_FILES['file']) || !is_array($_FILES['file'])) {
      api_json(['ok' => false, 'error' => 'missing_file'], 400);
    }
    require_once __DIR__ . '/api/services/UploadHardeningService.php';
    $svc = new UploadHardeningService($DATA_DIR);
    $username = strtolower(trim((string)($me['username'] ?? $_SESSION['user'] ?? 'anonymous')));
    $extra = [
      'allocation_id' => trim((string)($_POST['allocation_id'] ?? '')),
      'form_code'     => trim((string)($_POST['form_code'] ?? '')),
      'context'       => trim((string)($_POST['context'] ?? '')),
    ];
    $result = $svc->quarantineFile($_FILES['file'], $username, $extra);
    if (!$result->ok) {
      api_json(['ok' => false, 'error' => 'quarantine_failed', 'message' => $result->message], 422);
    }
    api_json(['ok' => true, 'quarantine_id' => $result->quarantineId, 'metadata' => $result->metadata]);
  }

  case 'upload_verify_quarantine': {
    $me = require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $quarantineId = trim((string)($body['quarantine_id'] ?? $_GET['quarantine_id'] ?? ''));
    if ($quarantineId === '') api_json(['ok' => false, 'error' => 'missing_quarantine_id'], 400);

    require_once __DIR__ . '/api/services/UploadHardeningService.php';
    $svc = new UploadHardeningService($DATA_DIR);
    $vr = $svc->verifyQuarantinedFile($quarantineId);
    $sidecarPath = $DATA_DIR . '/uploads/quarantine/' . $quarantineId . '.json';
    $metadata = is_file($sidecarPath) ? (json_decode((string)file_get_contents($sidecarPath), true) ?: null) : null;
    api_json(['ok' => $vr->ok, 'status' => $vr->status, 'message' => $vr->message, 'checks' => $vr->checks, 'metadata' => $metadata]);
  }

  case 'upload_accept': {
    $me = require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $quarantineId = trim((string)($body['quarantine_id'] ?? ''));
    $targetDir = trim((string)($body['target_dir'] ?? ''));
    if ($quarantineId === '') api_json(['ok' => false, 'error' => 'missing_quarantine_id'], 400);

    require_once __DIR__ . '/api/services/UploadHardeningService.php';
    $svc = new UploadHardeningService($DATA_DIR);
    $sidecarPath = $DATA_DIR . '/uploads/quarantine/' . $quarantineId . '.json';
    $metadata = is_file($sidecarPath) ? (json_decode((string)file_get_contents($sidecarPath), true) ?: null) : null;
    if (!is_array($metadata)) api_json(['ok' => false, 'error' => 'quarantine_metadata_not_found'], 404);
    if ((string)($metadata['status'] ?? 'quarantined') !== 'verified') {
      api_json(['ok' => false, 'error' => 'quarantine_not_verified', 'metadata' => $metadata], 409);
    }
    try {
      $path = $svc->acceptFile($quarantineId, $targetDir);
      api_json(['ok' => true, 'accepted_path' => $path, 'metadata' => $metadata]);
    } catch (Throwable $e) {
      api_json(['ok' => false, 'error' => $e->getMessage()], 500);
    }
  }

  case 'upload_reject': {
    $me = require_logged_in($store);
    require_csrf();
    $body = read_json_body();
    $quarantineId = trim((string)($body['quarantine_id'] ?? ''));
    $reason = trim((string)($body['reason'] ?? 'Bị từ chối bởi quản trị viên'));
    if ($quarantineId === '') api_json(['ok' => false, 'error' => 'missing_quarantine_id'], 400);

    require_once __DIR__ . '/api/services/UploadHardeningService.php';
    $svc = new UploadHardeningService($DATA_DIR);
    try {
      $svc->rejectFile($quarantineId, $reason);
      api_json(['ok' => true]);
    } catch (Throwable $e) {
      api_json(['ok' => false, 'error' => $e->getMessage()], 500);
    }
  }

  case 'upload_exception_queue': {
    require_logged_in($store);
    require_once __DIR__ . '/api/services/UploadHardeningService.php';
    $svc = new UploadHardeningService($DATA_DIR);
    $days = max(1, min(365, (int)($_GET['days'] ?? 30)));
    $department = strtoupper(trim((string)($_GET['department'] ?? '')));
    $formCode = trim((string)($_GET['form_code'] ?? ''));
    $statusFilter = trim((string)($_GET['status'] ?? ''));
    $dateFrom = trim((string)($_GET['date_from'] ?? ''));
    $dateTo = trim((string)($_GET['date_to'] ?? ''));
    $exceptions = $svc->getExceptionQueue($days);
    $allocationStore = load_allocation_store();
    $allocationIndex = [];
    foreach ((array)($allocationStore['allocations'] ?? []) as $allocationRow) {
      if (!is_array($allocationRow)) continue;
      $aid = trim((string)($allocationRow['allocation_id'] ?? ''));
      if ($aid === '') continue;
      $allocationIndex[$aid] = $allocationRow;
    }

    $exceptions = array_values(array_filter(array_map(function ($row) use ($allocationIndex) {
      if (!is_array($row)) return null;
      $extra = is_array($row['extra'] ?? null) ? $row['extra'] : [];
      $allocationId = trim((string)($extra['allocation_id'] ?? ''));
      $allocation = $allocationId !== '' ? ($allocationIndex[$allocationId] ?? null) : null;

      if ($allocation) {
        $row['allocation_id'] = $allocationId;
        $row['record_id'] = (string)($allocation['record_id'] ?? '');
        $row['department'] = (string)($allocation['department'] ?? '');
        $row['form_code'] = trim((string)($extra['form_code'] ?? $allocation['form_code'] ?? ''));
        $row['delivery_mode'] = (string)($allocation['delivery_mode'] ?? '');
        $row['master_context'] = is_array($allocation['master_context'] ?? null) ? $allocation['master_context'] : [];
        $row['allocation_status'] = (string)($allocation['status'] ?? '');
      } else {
        $row['allocation_id'] = $allocationId;
        $row['record_id'] = '';
        $row['department'] = trim((string)($extra['department'] ?? ''));
        $row['form_code'] = trim((string)($extra['form_code'] ?? ''));
        $row['delivery_mode'] = '';
        $row['master_context'] = [];
        $row['allocation_status'] = '';
      }

      $row['quarantine_id'] = trim((string)($extra['quarantine_id'] ?? ''));
      return $row;
    }, $exceptions), function ($row) use ($department, $formCode, $statusFilter, $dateFrom, $dateTo) {
      if (!is_array($row)) return false;
      $rowDept = strtoupper(trim((string)($row['department'] ?? '')));
      $rowForm = trim((string)($row['form_code'] ?? ''));
      $rowType = trim((string)($row['type'] ?? ''));
      $rowTime = strtotime((string)($row['timestamp'] ?? ''));
      if ($department !== '' && $rowDept !== $department) return false;
      if ($formCode !== '' && $rowForm !== $formCode) return false;
      if ($statusFilter !== '' && $rowType !== $statusFilter) return false;
      if ($dateFrom !== '') {
        $fromTs = strtotime($dateFrom . ' 00:00:00');
        if ($fromTs !== false && ($rowTime === false || $rowTime < $fromTs)) return false;
      }
      if ($dateTo !== '') {
        $toTs = strtotime($dateTo . ' 23:59:59');
        if ($toTs !== false && ($rowTime === false || $rowTime > $toTs)) return false;
      }
      return true;
    }));
    api_json(['ok' => true, 'exceptions' => $exceptions, 'count' => count($exceptions)]);
  }

  case 'upload_cleanup_quarantine': {
    $me = require_logged_in($store);
