    require_csrf();

    require_once __DIR__ . '/api/services/UploadHardeningService.php';
    $svc = new UploadHardeningService($DATA_DIR);
    $maxDays = max(1, (int)($_GET['max_days'] ?? 7));
    $purged = $svc->cleanupExpired($maxDays);
    api_json(['ok' => true, 'purged' => $purged]);
