            'type' => 'review_sla',
            'department' => (string)($row['department'] ?? ''),
            'date' => substr((string)($row['due_at'] ?? $row['escalation_due_at'] ?? ''), 0, 10),
            'responsible' => implode(', ', $roles),
            'detail' => implode(' · ', array_filter([
