        $orders = $bundle['orders'];
        $master = $bundle['master'];
        $mes = $bundle['mes'];
        $snapshot = build_mes_snapshot($orders, $master, $mes);
        foreach ((array)($snapshot['epicor_sync_queue'] ?? []) as $row) {
          if (!is_array($row)) continue;
          $items[] = [
            'id'         => (string)($row['exception_id'] ?? $row['sync_run_id'] ?? $row['outbox_event_id'] ?? ''),
            'type'       => (string)($row['type'] ?? 'epicor_sync'),
            'department' => (string)($row['sync_domain'] ?? ''),
            'date'       => substr((string)($row['updated_at'] ?? $row['detected_at'] ?? $row['created_at'] ?? ''), 0, 10),
            'responsible'=> (string)($row['owner_role'] ?? $row['direction'] ?? ''),
            'detail'     => implode(' · ', array_filter([
              (string)($row['sync_domain'] ?? ''),
              (string)($row['status'] ?? ''),
              (string)($row['message_vi'] ?? $row['message_en'] ?? ''),
              (string)($row['difference_summary'] ?? ''),
            ])),
          ];
        }
        break;
      }
      default:
        api_json(['ok' => false, 'error' => 'invalid_exception_type'], 400);
    }

    $total = count($items);
    $pages = max(1, (int)ceil($total / $perPage));
    $offset = ($page - 1) * $perPage;
    $pagedItems = array_slice($items, $offset, $perPage);

    api_json([
      'ok'    => true,
      'items' => $pagedItems,
      'total' => $total,
      'page'  => $page,
      'pages' => $pages,
    ]);
  }

  default:
    // Forward unknown actions to MVC Router (api/index.php)
    // Guard against recursion: api/index.php sets API_HELPERS_ONLY when loading this file
    if (!defined('API_HELPERS_ONLY') && !defined('MVC_ROUTER_LOADED')) {
        define('MVC_ROUTER_LOADED', true);
        $mvcRouter = __DIR__ . '/api/index.php';
        if (is_file($mvcRouter)) {
            require $mvcRouter;
            // api/index.php now owns the response lifecycle for forwarded actions.
            // Do not continue into legacy unknown_action handling or headers/body
            // may be emitted twice, corrupting JSON responses.
            return;
        }
    }
    api_json(['ok' => false, 'error' => 'unknown_action'], 400);
}
